import React, { useEffect, useRef } from 'react';
import { STAGES, STEP_ICONS } from '../constants.ts';
import { Stage } from '../types.ts';
import { Check } from 'lucide-react';

interface TimelineProps {
  currentStageId: string;
  onSelectStage: (stage: Stage) => void;
}

export const Timeline: React.FC<TimelineProps> = ({ currentStageId, onSelectStage }) => {
  const currentStageIndex = STAGES.findIndex(s => s.id === currentStageId);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Scroll active item into view when stage changes
  useEffect(() => {
    if (scrollRef.current) {
      const activeElement = scrollRef.current.querySelector('[data-active="true"]');
      if (activeElement) {
        activeElement.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
      }
    }
  }, [currentStageId]);

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-white/50 w-full relative overflow-hidden ring-1 ring-gray-200">
      {/* Decorative gradient line */}
      <div className="absolute top-0 left-0 right-0 h-1.5 bg-gradient-to-r from-brand-900 via-brand-700 to-gold-500"></div>

      <div 
        ref={scrollRef}
        className="flex overflow-x-auto gap-4 p-6 scrollbar-hide snap-x bg-gradient-to-b from-white to-gray-50/50"
        style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
      >
        {STAGES.map((stage, index) => {
          const Icon = STEP_ICONS[stage.stepNumber] || STEP_ICONS['1'];
          const isActive = stage.id === currentStageId;
          const isCompleted = index < currentStageIndex;

          return (
            <div 
              key={stage.id}
              data-active={isActive}
              onClick={() => onSelectStage(stage)}
              className={`
                shrink-0 snap-center cursor-pointer transition-all duration-300
                flex flex-col items-center gap-3 p-4 rounded-xl min-w-[140px] max-w-[160px] text-center border relative group
                ${isActive 
                  ? 'bg-white border-gold-400 shadow-xl shadow-gray-100 transform -translate-y-1 z-10 ring-1 ring-gold-100' 
                  : isCompleted
                    ? 'bg-gray-50 border-brand-100 opacity-90 hover:opacity-100 hover:bg-white hover:border-brand-200 hover:shadow-md'
                    : 'bg-transparent border-transparent hover:bg-white hover:border-gray-200 opacity-40 hover:opacity-80'
                }
              `}
            >
              <div 
                className={`
                  flex items-center justify-center w-12 h-12 rounded-full border-2 transition-all shadow-sm relative overflow-hidden
                  ${isActive 
                    ? 'border-brand-900 bg-brand-900 text-gold-400 shadow-brand-200 scale-110' 
                    : isCompleted 
                      ? 'border-gold-500 bg-gold-50 text-gold-600' 
                      : 'border-gray-200 bg-white text-gray-300 group-hover:border-gray-300 group-hover:text-gray-400'
                  }
                `}
              >
                {/* Shine effect on active */}
                {isActive && <div className="absolute inset-0 bg-white/10 blur-sm rounded-full"></div>}
                {isCompleted ? <Check size={20} strokeWidth={3} /> : <Icon size={20} strokeWidth={isActive ? 2.5 : 2} />}
              </div>

              <div className="flex flex-col items-center w-full">
                <span className={`text-[9px] uppercase font-bold tracking-[0.15em] mb-1.5 px-2 py-0.5 rounded-full border ${
                    isActive 
                      ? 'text-brand-800 bg-brand-50 border-brand-100' 
                      : 'text-gray-400 border-transparent'
                  }`}>
                  Passo {stage.stepNumber}
                </span>
                <h3 className={`text-sm font-bold leading-tight ${isActive ? 'text-brand-900' : 'text-gray-500'}`}>
                  {stage.title}
                </h3>
              </div>

              {/* Connector Line (Visual only) */}
              {index < STAGES.length - 1 && (
                <div className={`hidden md:block absolute -right-7 top-10 w-6 h-[2px] z-0 rounded-full
                  ${isCompleted ? 'bg-gold-300' : 'bg-gray-200'}`} 
                />
              )}
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
