interface ContentGeneratorProps {
  stage: Stage;
  client: Client;
  onUpdateNotes: (notes: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

export const ContentGenerator: React.FC<ContentGeneratorProps> = ({ stage, client, onUpdateNotes, onUpdateClientStage }) => {
  const [content, setContent] = useState<GeneratedContent | null>(null);
  const [fieldValues, setFieldValues] = useState<Record<string, string>>({});
  const [isEditing, setIsEditing] = useState(false);
  const [editableBody, setEditableBody] = useState('');

  useEffect(() => {
    setFieldValues({});
    setIsEditing(false);
  }, [stage.id, client.id]);

  useEffect(() => {
    if (stage.template) {
        const currentValues = { ...client.stageData, ...fieldValues };
        const generated = generateTemplateContent(stage, client, currentValues);
        setContent(generated);
        if (!isEditing) {
            setEditableBody(generated.body);
        }
    } else {
        setContent(null);
    }
  }, [stage, client, fieldValues, isEditing]);

  const handleFieldChange = (variable: string, value: string) => {
    setFieldValues(prev => ({ ...prev, [variable]: value }));
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
  };

  const formatDate = (isoString: string) => {
    if (!isoString) return null;
    return new Date(isoString).toLocaleDateString('pt-BR', {
        day: '2-digit',
        month: '2-digit',
        year: 'numeric'
    });
  };

  const formatDateWithTime = (isoString: string) => {
    if (!isoString) return null;
    return new Date(isoString).toLocaleDateString('pt-BR', {
        day: '2-digit',
        month: '2-digit',
        year: 'numeric',
        hour: '2-digit',
        minute: '2-digit'
    });
  };

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    const diffTime = Math.abs(end.getTime() - start.getTime());
    return Math.floor(diffTime / (1000 * 60 * 60 * 24));
  };

  const calculateDeadlineDate = (createdAt: string) => {
    const date = new Date(createdAt);
    date.setDate(date.getDate() + 120);
    return date.toLocaleDateString('pt-BR', {
        day: '2-digit',
        month: '2-digit',
        year: 'numeric'
    });
  };

  const handleWhatsAppClick = () => {
    if (!client.phone) {
      alert("Este cliente não tem telefone cadastrado!");
      return;
    }

    const cleanPhone = client.phone.replace(/\D/g, '');
    const encodedText = encodeURIComponent(editableBody);
    const url = `https://api.whatsapp.com/send?phone=55${cleanPhone}&text=${encodedText}`;
    window.open(url, '_blank');

    onUpdateClientStage(client.id, stage.id, fieldValues);
  };

  const requiredFields = stage.requiredFields || [];
  const areAllFieldsFilled = requiredFields.every(field => {
      const val = fieldValues[field] || client.stageData?.[field];
      return val && val.trim().length > 0;
  });

  const isDelivered = client.currentStageId === '7';
  const finishDate = client.stageHistory['7'];
  const totalDaysToDeliver = finishDate ? calculateDaysElapsed(client.createdAt, finishDate) : null;
  const daysElapsed = calculateDaysElapsed(client.createdAt);
  const deadlineDate = calculateDeadlineDate(client.createdAt);
  const isWarning = daysElapsed > 90;
  const isCritical = daysElapsed > 120;

  // Render para a etapa final "Entregue"
  if (stage.id === '7') {
    const savingsDays = totalDaysToDeliver !== null ? 120 - totalDaysToDeliver : null;

    return (
      <div className="bg-white rounded-xl shadow-lg border border-gray-200 flex flex-col h-full overflow-hidden">
        <div className="bg-green-600 p-8 text-white flex flex-col items-center justify-center gap-4 text-center">
