import React, { useState, useEffect } from 'react';
import { Stage, Client, GeneratedContent } from '../types.ts';
import { generateTemplateContent } from '../services/templateService.ts';
import { Copy, Phone, Zap, Hash, Calendar, Edit2, Save, MessageSquare, Clock, CheckCircle, Timer, Trophy, CheckCircle2, History, AlertTriangle } from 'lucide-react';
import { STAGES } from '../constants.ts';

interface ContentGeneratorProps {
  stage: Stage;
  client: Client;
  onUpdateNotes: (notes: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

export const ContentGenerator: React.FC<ContentGeneratorProps> = ({ stage, client, onUpdateNotes, onUpdateClientStage }) => {
  const [fieldValues, setFieldValues] = useState<Record<string, string>>({});
  const [isEditing, setIsEditing] = useState(false);
  const [editableBody, setEditableBody] = useState('');

  useEffect(() => {
    setFieldValues({});
    setIsEditing(false);
    if (stage.template) {
        const generated = generateTemplateContent(stage, client, client.stageData || {});
        setEditableBody(generated.body);
    }
  }, [stage.id, client.id]);

  useEffect(() => {
    if (!isEditing && stage.template) {
        const generated = generateTemplateContent(stage, client, fieldValues);
        setEditableBody(generated.body);
    }
  }, [fieldValues, stage, client, isEditing]);

  const handleFieldChange = (variable: string, value: string) => {
    setFieldValues(prev => ({ ...prev, [variable]: value }));
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    alert("Copiado!");
  };

  const calculateDates = () => {
    const start = new Date(client.createdAt);
    const deadline = new Date(start.getTime() + (120 * 24 * 60 * 60 * 1000));
    const now = client.currentStageId === '7' && client.stageHistory['7'] 
        ? new Date(client.stageHistory['7']) 
        : new Date();

    const elapsed = Math.floor(Math.abs(now.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));

    let statusLabel = '🟢 NO PRAZO';
    let statusColor = 'text-green-600';
    if (elapsed > 120) {
        statusLabel = '🔴 CRÍTICO';
        statusColor = 'text-red-600';
    } else if (elapsed > 90) {
        statusLabel = '🟡 ATENÇÃO';
        statusColor = 'text-orange-500';
    }

    return {
        start: start.toLocaleDateString('pt-BR'),
        deadline: deadline.toLocaleDateString('pt-BR'),
        elapsed,
        statusLabel,
        statusColor
    };
  };

  const info = calculateDates();

  const handleWhatsAppClick = () => {
    if (!client.phone) return;
    const cleanPhone = client.phone.replace(/\D/g, '');
    const encodedText = encodeURIComponent(editableBody);
    window.open(`https://api.whatsapp.com/send?phone=55${cleanPhone}&text=${encodedText}`, '_blank');
    onUpdateClientStage(client.id, stage.id, fieldValues);
  };

  if (stage.id === '7') {
    return (
      <div className="bg-white rounded-xl shadow-lg border border-gray-200 p-8 flex flex-col items-center justify-center text-center h-full">
          <div className="bg-green-100 p-6 rounded-full text-green-600 mb-6">
              <Trophy size={64} />
          </div>
          <h2 className="text-3xl font-black text-brand-900 mb-2 uppercase">Projeto Concluído!</h2>
          <p className="text-gray-500 mb-6">A jornada de {client.name} foi finalizada em {info.elapsed} dias.</p>
          <div className="grid grid-cols-2 gap-4 w-full max-w-md">
              <div className="bg-gray-50 p-4 rounded-xl border border-gray-100">
                  <p className="text-[10px] font-bold text-gray-400 uppercase">Início</p>
                  <p className="font-bold">{info.start}</p>
              </div>
              <div className="bg-gray-50 p-4 rounded-xl border border-gray-100">
                  <p className="text-[10px] font-bold text-gray-400 uppercase">Finalizado em</p>
                  <p className="font-bold">{new Date(client.stageHistory['7']).toLocaleDateString('pt-BR')}</p>
              </div>
          </div>
      </div>
    );
  }

  const requiredFields = stage.requiredFields || [];
  const areAllFieldsFilled = requiredFields.every(f => (fieldValues[f] || client.stageData?.[f])?.trim());

  return (
    <div className="bg-white rounded-xl shadow-lg border border-gray-200 flex flex-col h-full overflow-hidden">
      <div className="bg-brand-900 p-6 shrink-0 flex items-center justify-between text-white">
        <div>
          <h2 className="text-xl font-bold tracking-tight">Etapa {stage.stepNumber}: {stage.title}</h2>
          <p className="text-brand-300 text-xs">{stage.description}</p>
        </div>
        <div className="flex gap-2">
            <button onClick={() => setIsEditing(!isEditing)} className="p-2 hover:bg-white/10 rounded-lg transition">
                {isEditing ? <Save size={20} /> : <Edit2 size={20} />}
            </button>
        </div>
      </div>

      <div className="flex flex-col lg:flex-row flex-1 overflow-hidden">
        {/* Coluna de Status e Histórico */}
        <div className="lg:w-80 p-6 overflow-y-auto border-r border-gray-100 bg-gray-50/30 flex flex-col gap-6 scrollbar-hide">

           {/* Painel Status da Obra */}
           <div className="bg-white p-5 rounded-2xl border border-gold-200 shadow-sm">
                <h3 className="text-[10px] font-black uppercase text-brand-800 tracking-widest mb-4 flex items-center gap-2">
                    <Zap size={14} className="text-gold-500" /> Status da Obra
                </h3>
                <div className="space-y-3">
                    <div className="flex justify-between text-xs font-medium">
                        <span className="text-gray-400">Início:</span>
                        <span className="text-brand-900">{info.start}</span>
                    </div>
                    <div className="flex justify-between text-xs font-medium">
                        <span className="text-gray-400">Prazo Final:</span>
                        <span className="text-brand-900">{info.deadline}</span>
                    </div>
                    <div className="flex justify-between text-xs font-medium">
                        <span className="text-gray-400">Dias Decorridos:</span>
                        <span className="font-bold text-brand-900">{info.elapsed} / 120</span>
                    </div>
                    <div className="pt-2 border-t border-gray-50 mt-2">
                        <div className={`text-xs font-black uppercase text-center py-2 rounded-lg bg-gray-50 ${info.statusColor}`}>
                            {info.statusLabel}
                        </div>
                    </div>
                </div>
           </div>

           {/* Histórico Detalhado */}
           <div>
               <h3 className="text-[10px] font-black uppercase text-brand-800 tracking-widest mb-4 flex items-center gap-2">
                   <History size={14} /> Histórico de Etapas
               </h3>
               <div className="space-y-4">
                   {STAGES.filter(s => client.stageHistory[s.id]).map((s, idx, arr) => {
                       const completionDate = new Date(client.stageHistory[s.id]);
                       const prevDate = idx > 0 ? new Date(client.stageHistory[arr[idx-1].id]) : new Date(client.createdAt);
                       const diff = Math.floor(Math.abs(completionDate.getTime() - prevDate.getTime()) / (1000 * 60 * 60 * 24));

                       return (
                           <div key={s.id} className="relative pl-6 border-l-2 border-brand-100 pb-2">
                               <div className="absolute -left-[9px] top-0 w-4 h-4 rounded-full bg-brand-500 border-2 border-white flex items-center justify-center">
                                   <CheckCircle2 size={10} className="text-white" />
                               </div>
                               <div className="flex flex-col">
                                   <span className="text-xs font-bold text-brand-900">{s.title}</span>
                                   <div className="flex justify-between items-center mt-1">
                                       <span className="text-[10px] text-gray-400 font-medium">{completionDate.toLocaleDateString('pt-BR')}</span>
                                       <span className="text-[9px] bg-brand-50 text-brand-600 px-1.5 py-0.5 rounded font-bold">
                                           {diff} dias
                                       </span>
                                   </div>
                               </div>
                           </div>
                       );
                   })}
                   <div className="relative pl-6 border-l-2 border-dashed border-gray-200">
                        <div className="absolute -left-[9px] top-0 w-4 h-4 rounded-full bg-white border-2 border-brand-200 animate-pulse"></div>
                        <span className="text-xs font-bold text-gray-400">Próxima: {STAGES[STAGES.findIndex(s => s.id === client.currentStageId) + 1]?.title || 'Finalização'}</span>
                   </div>
               </div>
           </div>

           {requiredFields.length > 0 && (
               <div className="space-y-4 pt-4 border-t border-gray-100">
                   <h3 className="text-[10px] font-black uppercase text-brand-800 tracking-widest">Dados Necessários</h3>
                   {requiredFields.map(field => (
                       <div key={field}>
                           <label className="text-xs font-bold text-gray-500 mb-1 block capitalize">{field}</label>
                           <input 
                             type="text"
                             className="w-full p-2 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-gold-500/20 outline-none"
                             value={fieldValues[field] || client.stageData?.[field] || ''}
                             onChange={e => handleFieldChange(field, e.target.value)}
                             placeholder={`Informe ${field}...`}
                           />
                       </div>
                   ))}
               </div>
           )}
        </div>

        {/* Gerador de Mensagem */}
        <div className="flex-1 p-6 flex flex-col gap-4">
            <div className="flex-1 bg-white border border-gray-200 rounded-2xl overflow-hidden flex flex-col shadow-inner">
                <div className="bg-gray-50 px-4 py-2 border-b border-gray-100 flex justify-between items-center">
                    <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Preview da Mensagem</span>
                    <button onClick={() => copyToClipboard(editableBody)} className="flex items-center gap-1.5 text-xs font-bold text-brand-600 hover:text-brand-800 transition">
                        <Copy size={14} /> Copiar
                    </button>
                </div>
                {isEditing ? (
                    <textarea 
                      className="flex-1 p-6 text-sm font-sans resize-none outline-none leading-relaxed"
                      value={editableBody}
                      onChange={e => setEditableBody(e.target.value)}
                    />
                ) : (
                    <div className="flex-1 p-6 text-sm whitespace-pre-wrap font-sans overflow-y-auto bg-gray-50/5 leading-relaxed text-slate-700">
                        {editableBody}
                    </div>
                )}
            </div>
            <button 
                onClick={handleWhatsAppClick}
                disabled={!areAllFieldsFilled}
                className={`w-full py-4 rounded-xl font-black uppercase tracking-widest flex items-center justify-center gap-3 transition shadow-xl
                    ${areAllFieldsFilled ? 'bg-[#25D366] text-white hover:bg-[#1fb355] scale-[1.01] active:scale-100' : 'bg-gray-200 text-gray-400 cursor-not-allowed'}`}
            >
                <Phone size={20} />
                Enviar Atualização via WhatsApp
            </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Client, Stage } from '../types.ts';
import { Plus, Search, User, Zap, Hash, List, Kanban, Phone as PhoneIcon, X, Flag, Calendar, Clock, Timer, Trophy, ChevronRight } from 'lucide-react';
import { STAGES } from '../constants.ts';
import { generateTemplateContent } from '../services/templateService.ts';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onUpdateClientStage }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'list' | 'pipeline'>('list');

  const [draggedClientId, setDraggedClientId] = useState<string | null>(null);
  const [transitionTargetStage, setTransitionTargetStage] = useState<Stage | null>(null);
  const [transitionClientId, setTransitionClientId] = useState<string | null>(null);
  const [transitionValues, setTransitionValues] = useState<Record<string, string>>({});

  const [initialStageId, setInitialStageId] = useState<string>(STAGES[0].id);
  const [initialStageValues, setInitialStageValues] = useState<Record<string, string>>({});

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '',
    clientNumber: '',
    prgd: '',
    phone: '',
    titularName: '',
    projectName: '',
    additionalNotes: ''
  });

  const activeClients = clients.filter(c => c.currentStageId !== '7');
  const deliveredClientsCount = clients.filter(c => c.currentStageId === '7').length;

  const formatPhoneNumber = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 11) {
       return numbers.replace(/(\d{2})(\d{5})(\d{4})/, '($1) $2-$3');
    }
    return value;
  };

  const formatDate = (isoString: string) => {
    if (!isoString) return '-';
    return new Date(isoString).toLocaleDateString('pt-BR');
  };

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const getStatusInfo = (days: number, isDelivered: boolean) => {
    if (isDelivered) return { label: '🟢 CONCLUÍDO', color: 'text-green-600', bg: 'bg-green-50' };
    if (days > 120) return { label: '🔴 CRÍTICO', color: 'text-red-600', bg: 'bg-red-50' };
    if (days > 90) return { label: '🟡 ATENÇÃO', color: 'text-orange-500', bg: 'bg-orange-50' };
    return { label: '🟢 NO PRAZO', color: 'text-green-600', bg: 'bg-green-50' };
  };

  const openWhatsApp = (client: Client, stage: Stage, values: Record<string, string> = {}) => {
      if (!client.phone || !stage.template) return;
      const mergedValues = { ...client.stageData, ...values };
      const content = generateTemplateContent(stage, client, mergedValues);
      const cleanPhone = client.phone.replace(/\D/g, '');
      const encodedText = encodeURIComponent(content.body);
      window.open(`https://api.whatsapp.com/send?phone=55${cleanPhone}&text=${encodedText}`, '_blank');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.clientNumber || !formData.prgd || !formData.phone) {
      alert("Campos obrigatórios: Nome, Telefone, Nº Cliente e PRGD.");
      return;
    }
    const selectedStage = STAGES.find(s => s.id === initialStageId);
    const now = new Date().toISOString();
    const newClient: Client = {
      id: Date.now().toString(),
      name: formData.name || '',
      clientNumber: formData.clientNumber || '',
      prgd: formData.prgd || '',
      phone: formData.phone || '',
      projectName: formData.projectName || `Projeto ${formData.name}`,
      additionalNotes: formData.additionalNotes || '',
      currentStageId: initialStageId,
      createdAt: now,
      stageHistory: { [initialStageId]: now },
      stageData: initialStageValues
    };
    if (selectedStage?.template) openWhatsApp(newClient, selectedStage, initialStageValues);
    setIsCreating(false);
    onCreateClient(newClient);
  };

  const handleDragStart = (e: React.DragEvent, client: Client) => {
    e.dataTransfer.setData('clientId', client.id);
    setDraggedClientId(client.id);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };

  const handleDrop = (e: React.DragEvent, stageId: string) => {
    e.preventDefault();
    const clientId = e.dataTransfer.getData('clientId');
    setDraggedClientId(null);
    if (!clientId) return;

    const client = clients.find(c => c.id === clientId);
    const targetStage = STAGES.find(s => s.id === stageId);

    if (client && targetStage && client.currentStageId !== stageId) {
      if (targetStage.requiredFields && targetStage.requiredFields.length > 0) {
        setTransitionClientId(clientId);
        setTransitionTargetStage(targetStage);
      } else {
        onUpdateClientStage(clientId, stageId);
        if (targetStage.template) setTimeout(() => openWhatsApp(client, targetStage), 100);
      }
    }
  };

  const handleTransitionSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (transitionClientId && transitionTargetStage) {
      const client = clients.find(c => c.id === transitionClientId);
      onUpdateClientStage(transitionClientId, transitionTargetStage.id, transitionValues);
      if (client && transitionTargetStage.template) openWhatsApp(client, transitionTargetStage, transitionValues);
      setTransitionTargetStage(null);
      setTransitionClientId(null);
      setTransitionValues({});
    }
  };

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.prgd.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-0 h-full flex flex-col relative overflow-hidden">
      {isCreating && (
          <div className="fixed inset-0 bg-brand-900/80 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
              <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl animate-scale-up overflow-hidden">
                  <div className="p-6 bg-brand-900 text-white flex justify-between items-center">
                      <h2 className="text-xl font-bold">Novo Cliente LOOP ENERGIA</h2>
                      <button onClick={() => setIsCreating(false)} className="hover:text-gold-400"><X /></button>
                  </div>
                  <form onSubmit={handleSubmit} className="p-8 space-y-6 max-h-[70vh] overflow-y-auto scrollbar-hide">
                      <div className="grid grid-cols-2 gap-6">
                        <input required placeholder="Nome" className="p-3 border rounded-xl outline-none" onChange={e => setFormData({...formData, name: e.target.value})} />
                        <input required placeholder="Telefone" className="p-3 border rounded-xl outline-none" onChange={e => setFormData({...formData, phone: formatPhoneNumber(e.target.value)})} />
                        <input required placeholder="PRGD" className="p-3 border rounded-xl outline-none" onChange={e => setFormData({...formData, prgd: e.target.value})} />
                        <input required placeholder="Número Cliente" className="p-3 border rounded-xl outline-none" onChange={e => setFormData({...formData, clientNumber: e.target.value})} />
                      </div>
                      <select value={initialStageId} onChange={e => setInitialStageId(e.target.value)} className="w-full p-3 border rounded-xl">
                          {STAGES.map(s => <option key={s.id} value={s.id}>{s.stepNumber} - {s.title}</option>)}
                      </select>
                      <button type="submit" className="w-full bg-brand-900 text-white py-4 rounded-xl font-bold">CADASTRAR E ENVIAR</button>
                  </form>
              </div>
          </div>
      )}

      {transitionTargetStage && (
          <div className="fixed inset-0 bg-brand-900/80 backdrop-blur-sm z-[110] flex items-center justify-center p-4">
              <div className="bg-white rounded-2xl shadow-2xl w-full max-w-md animate-scale-up">
                  <div className="p-6 bg-brand-900 text-white">
                      <h3 className="font-bold">Dados para {transitionTargetStage.title}</h3>
                  </div>
                  <form onSubmit={handleTransitionSubmit} className="p-6 space-y-4">
                      {transitionTargetStage.requiredFields?.map(f => (
                          <div key={f}>
                              <label className="text-xs font-bold uppercase block mb-1">{f}</label>
                              <input required className="w-full p-3 border rounded-xl" onChange={e => setTransitionValues({...transitionValues, [f]: e.target.value})} />
                          </div>
                      ))}
                      <div className="flex gap-2 pt-4">
                          <button type="button" onClick={() => setTransitionTargetStage(null)} className="flex-1 p-3 text-gray-500 font-bold">Cancelar</button>
                          <button type="submit" className="flex-1 bg-gold-500 text-brand-900 p-3 rounded-xl font-bold">Confirmar</button>
                      </div>
                  </form>
              </div>
          </div>
      )}

      <div className="p-6 border-b flex justify-between items-center bg-gray-50/50">
        <div>
          <h2 className="text-2xl font-black text-brand-900 uppercase tracking-tighter">Carteira de Clientes</h2>
          <div className="flex gap-2 mt-1">
              <span className="text-[10px] font-black bg-brand-100 text-brand-700 px-2 py-0.5 rounded uppercase tracking-widest">{activeClients.length} Ativos</span>
              <span className="text-[10px] font-black bg-green-100 text-green-700 px-2 py-0.5 rounded uppercase tracking-widest">{deliveredClientsCount} Entregues</span>
          </div>
        </div>
        <div className="flex gap-3">
             <div className="bg-white p-1 rounded-lg flex border shadow-sm">
                <button onClick={() => setViewMode('list')} className={`p-2 rounded-md ${viewMode === 'list' ? 'bg-brand-900 text-white' : 'text-gray-400'}`}><List size={18}/></button>
                <button onClick={() => setViewMode('pipeline')} className={`p-2 rounded-md ${viewMode === 'pipeline' ? 'bg-brand-900 text-white' : 'text-gray-400'}`}><Kanban size={18}/></button>
             </div>
             <button onClick={() => setIsCreating(true)} className="bg-brand-900 text-white px-5 py-2.5 rounded-xl font-bold shadow-lg hover:scale-105 transition flex items-center gap-2">
                <Plus size={18} /> Novo Cliente
             </button>
        </div>
      </div>

      <div className="p-4 bg-white border-b">
         <div className="relative">
            <Search className="absolute left-3 top-3 text-gray-400" size={18} />
            <input placeholder="Buscar cliente ou PRGD..." className="w-full pl-10 p-2.5 rounded-xl border bg-gray-50 focus:bg-white outline-none" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
         </div>
      </div>

      <div className="flex-1 overflow-y-auto p-6 scrollbar-hide">
        {viewMode === 'list' ? (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {filteredClients.map(client => {
                    const isDelivered = client.currentStageId === '7';
                    const days = calculateDaysElapsed(client.createdAt, isDelivered ? client.stageHistory['7'] : undefined);
                    const deadlineDate = new Date(new Date(client.createdAt).getTime() + 120 * 24 * 60 * 60 * 1000);
                    const status = getStatusInfo(days, isDelivered);
                    const currentStage = STAGES.find(s => s.id === client.currentStageId);

                    return (
                        <div key={client.id} onClick={() => onSelectClient(client)} className="bg-white border-2 border-gray-100 rounded-2xl p-5 hover:border-gold-400 cursor-pointer transition shadow-sm hover:shadow-xl group flex flex-col gap-4">
                            <div className="flex justify-between items-start">
                                <div>
                                    <h3 className="font-black text-brand-900 uppercase text-sm group-hover:text-gold-600 transition">{client.name}</h3>
                                    <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest">{client.prgd} • #{client.clientNumber}</p>
                                </div>
                                <ChevronRight className="text-gray-200 group-hover:text-gold-500 transition" />
                            </div>

                            <div className={`p-4 rounded-xl border border-gray-50 flex flex-col gap-2 ${status.bg}`}>
                                <h4 className="text-[10px] font-black text-brand-800 uppercase tracking-widest flex items-center gap-1.5">
                                    <Timer size={12} /> Status da Obra
                                </h4>
                                <div className="space-y-1">
                                    <div className="flex justify-between text-[10px] font-bold">
                                        <span className="text-gray-400 uppercase">Início:</span>
                                        <span className="text-brand-900">{formatDate(client.createdAt)}</span>
                                    </div>
                                    <div className="flex justify-between text-[10px] font-bold">
                                        <span className="text-gray-400 uppercase">Prazo Final:</span>
                                        <span className="text-brand-900">{deadlineDate.toLocaleDateString('pt-BR')}</span>
                                    </div>
                                    <div className="flex justify-between text-[10px] font-bold">
                                        <span className="text-gray-400 uppercase">Dias Decorridos:</span>
                                        <span className="text-brand-900">{days} / 120</span>
                                    </div>
                                    <div className={`mt-2 py-1.5 rounded-md text-center text-[10px] font-black tracking-widest bg-white shadow-sm border border-gray-100 ${status.color}`}>
                                        {status.label}
                                    </div>
                                </div>
                            </div>

                            <div className="flex flex-col gap-1">
                                <span className="text-[9px] font-black text-gray-400 uppercase tracking-widest">Etapa Atual</span>
                                <div className="flex items-center gap-2">
                                    <span className="bg-brand-900 text-gold-400 p-1 rounded"><Zap size={10} /></span>
                                    <span className="text-xs font-black text-brand-900 uppercase">{currentStage?.title}</span>
                                </div>
                            </div>
                        </div>
                    );
                })}
             </div>
        ) : (
            <div className="flex gap-4 h-full pb-10">
                {STAGES.map(stage => {
                    const stageClients = clients.filter(c => c.currentStageId === stage.id);
                    return (
                        <div key={stage.id} onDragOver={handleDragOver} onDrop={e => handleDrop(e, stage.id)} className="w-80 shrink-0 bg-gray-50 rounded-2xl border-2 border-gray-100 flex flex-col max-h-full">
                            <div className="p-4 font-black text-xs uppercase tracking-widest text-brand-900 border-b flex justify-between bg-white/50 rounded-t-2xl">
                                <span>{stage.title}</span>
                                <span className="bg-brand-900 text-white px-2 py-0.5 rounded-full">{stageClients.length}</span>
                            </div>
                            <div className="p-3 overflow-y-auto flex flex-col gap-3 scrollbar-hide">
                                {stageClients.map(c => (
                                    <div key={c.id} draggable onDragStart={e => handleDragStart(e, c)} onClick={() => onSelectClient(c)} className="bg-white p-4 rounded-xl border shadow-sm cursor-grab active:cursor-grabbing hover:border-gold-400 transition">
                                        <p className="font-bold text-xs text-brand-900">{c.name}</p>
                                        <p className="text-[9px] text-gray-400 font-bold uppercase mt-1">{c.prgd}</p>
                                        <div className="mt-2 flex justify-between items-center text-[9px] font-black">
                                            <span className={calculateDaysElapsed(c.createdAt) > 120 ? 'text-red-600' : 'text-green-600'}>
                                                {calculateDaysElapsed(c.createdAt)} DIAS
                                            </span>
                                            <span className="text-gray-300">#{c.clientNumber}</span>
                                        </div>
                                    </div>
                                ))}
                            </div>
                        </div>
                    );
                })}
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Timeline } from './components/Timeline.tsx';
import { ContentGenerator } from './components/ContentGenerator.tsx';
import { ClientList } from './components/ClientList.tsx';
import { STAGES } from './constants.ts';
import { Client, Stage } from './types.ts';
import { ArrowLeft, Settings, Zap } from 'lucide-react';

export default function App() {
  const [view, setView] = useState<'list' | 'detail'>('list');
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [currentStageId, setCurrentStageId] = useState<string>(STAGES[0].id);
  const [clients, setClients] = useState<Client[]>([]);

  const handleCreateClient = (newClient: Client) => {
    setClients(prev => [newClient, ...prev]);
    handleSelectClient(newClient);
  };

  const handleSelectClient = (client: Client) => {
    setSelectedClientId(client.id);
    setCurrentStageId(client.currentStageId || STAGES[0].id);
    setView('detail');
  };

  const handleUpdateNotes = (notes: string) => {
    if (!selectedClientId) return;
    setClients(prev => prev.map(c => 
      c.id === selectedClientId ? { ...c, additionalNotes: notes } : c
    ));
  };

  const handleUpdateClientStage = (clientId: string, newStageId: string, stageData?: Record<string, string>) => {
    const now = new Date().toISOString();
    setClients(prev => prev.map(c => {
      if (c.id === clientId) {
        return { 
          ...c, 
          currentStageId: newStageId, 
          stageData: { ...c.stageData, ...stageData },
          stageHistory: { ...c.stageHistory, [newStageId]: now }
        };
      }
      return c;
    }));
    if (selectedClientId === clientId) {
      setCurrentStageId(newStageId);
    }
  };

  const selectedClient = clients.find(c => c.id === selectedClientId);
  const currentStage = STAGES.find(s => s.id === currentStageId) || STAGES[0];

  return (
    <div className="h-screen bg-gray-100 flex flex-col overflow-hidden font-sans">
      <header className="bg-brand-900 h-16 sm:h-20 shrink-0 shadow-lg relative z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 h-full flex items-center justify-between">
          <div className="flex items-center gap-4">
            {view === 'detail' && (
              <button onClick={() => setView('list')} className="p-2 hover:bg-white/10 rounded-full text-gold-400 transition">
                <ArrowLeft size={20} />
              </button>
            )}
            <div className="flex flex-col">
              <h1 className="text-xl sm:text-2xl font-black text-white uppercase tracking-tighter">
                LOOP <span className="text-gold-500">ENERGIA</span>
              </h1>
              <p className="text-[9px] text-brand-400 uppercase tracking-widest font-bold">Gestão de Experiência</p>
            </div>
          </div>
          <div className="flex items-center gap-4">
             <Zap className="text-gold-500 hidden sm:block" size={20} />
             <Settings className="text-brand-300 hover:text-white cursor-pointer transition" size={20} />
          </div>
        </div>
      </header>

      <main className="flex-1 overflow-hidden max-w-7xl mx-auto w-full px-4 sm:px-6 py-4">
        {view === 'list' ? (
          <ClientList 
            clients={clients} 
            onSelectClient={handleSelectClient} 
            onCreateClient={handleCreateClient}
            onUpdateClientStage={handleUpdateClientStage}
          />
        ) : (
          <div className="flex flex-col h-full gap-4">
            <Timeline 
              currentStageId={currentStageId} 
              onSelectStage={(s) => setCurrentStageId(s.id)} 
            />
            <div className="flex-1 min-h-0">
              {selectedClient && (
                <ContentGenerator 
                  stage={currentStage}
                  client={selectedClient}
                  onUpdateNotes={handleUpdateNotes}
                  onUpdateClientStage={handleUpdateClientStage}
                />
              )}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { Client, Stage } from '../types.ts';
import { Plus, Search, User, Zap, Hash, List, Kanban, Phone as PhoneIcon, X, Flag, Calendar, Clock, Timer, Trophy, ChevronRight } from 'lucide-react';
import { STAGES } from '../constants.ts';
import { generateTemplateContent } from '../services/templateService.ts';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onUpdateClientStage }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'list' | 'pipeline'>('list');

  const [draggedClientId, setDraggedClientId] = useState<string | null>(null);
  const [transitionTargetStage, setTransitionTargetStage] = useState<Stage | null>(null);
  const [transitionClientId, setTransitionClientId] = useState<string | null>(null);
  const [transitionValues, setTransitionValues] = useState<Record<string, string>>({});

  const [initialStageId, setInitialStageId] = useState<string>(STAGES[0].id);
  const [initialStageValues, setInitialStageValues] = useState<Record<string, string>>({});

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '',
    clientNumber: '',
    prgd: '',
    phone: '',
    titularName: '',
    projectName: '',
    additionalNotes: ''
  });

  const activeClients = clients.filter(c => c.currentStageId !== '7');
  const deliveredClientsCount = clients.filter(c => c.currentStageId === '7').length;

  const formatPhoneNumber = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 11) {
       return numbers.replace(/(\d{2})(\d{5})(\d{4})/, '($1) $2-$3');
    }
    return value;
  };

  const formatDate = (isoString: string) => {
    if (!isoString) return '-';
    return new Date(isoString).toLocaleDateString('pt-BR');
  };

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const getStatusInfo = (days: number, isDelivered: boolean) => {
    if (isDelivered) return { label: '🟢 CONCLUÍDO', color: 'text-green-600', bg: 'bg-green-50' };
    if (days > 120) return { label: '🔴 CRÍTICO', color: 'text-red-600', bg: 'bg-red-50' };
    if (days > 90) return { label: '🟡 ATENÇÃO', color: 'text-orange-500', bg: 'bg-orange-50' };
    return { label: '🟢 NO PRAZO', color: 'text-green-600', bg: 'bg-green-50' };
  };

  const openWhatsApp = (client: Client, stage: Stage, values: Record<string, string> = {}) => {
      if (!client.phone || !stage.template) return;
      const mergedValues = { ...client.stageData, ...values };
      const content = generateTemplateContent(stage, client, mergedValues);
      const cleanPhone = client.phone.replace(/\D/g, '');
      const encodedText = encodeURIComponent(content.body);
      window.open(`https://api.whatsapp.com/send?phone=55${cleanPhone}&text=${encodedText}`, '_blank');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // Validação rigorosa
    if (!formData.name?.trim() || !formData.clientNumber?.trim() || !formData.prgd?.trim() || !formData.phone?.trim()) {
      alert("⚠️ Atenção: Nome, Telefone, PRGD e Número do Cliente são obrigatórios.");
      return;
    }

    const selectedStage = STAGES.find(s => s.id === initialStageId);
    const now = new Date().toISOString();
    const newClient: Client = {
      id: Date.now().toString(),
      name: formData.name || '',
      clientNumber: formData.clientNumber || '',
      prgd: formData.prgd || '',
      phone: formData.phone || '',
      projectName: formData.projectName || `Projeto ${formData.name}`,
      additionalNotes: formData.additionalNotes || '',
      currentStageId: initialStageId,
      createdAt: now,
      stageHistory: { [initialStageId]: now },
      stageData: initialStageValues
    };
    if (selectedStage?.template) openWhatsApp(newClient, selectedStage, initialStageValues);
    setIsCreating(false);
    onCreateClient(newClient);
    // Limpa o form para o próximo
    setFormData({ name: '', clientNumber: '', prgd: '', phone: '' });
  };

  const handleDragStart = (e: React.DragEvent, client: Client) => {
    e.dataTransfer.setData('clientId', client.id);
    setDraggedClientId(client.id);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };

  const handleDrop = (e: React.DragEvent, stageId: string) => {
    e.preventDefault();
    const clientId = e.dataTransfer.getData('clientId');
    setDraggedClientId(null);
    if (!clientId) return;

    const client = clients.find(c => c.id === clientId);
    const targetStage = STAGES.find(s => s.id === stageId);

    if (client && targetStage && client.currentStageId !== stageId) {
      if (targetStage.requiredFields && targetStage.requiredFields.length > 0) {
        setTransitionClientId(clientId);
        setTransitionTargetStage(targetStage);
      } else {
        onUpdateClientStage(clientId, stageId);
        if (targetStage.template) setTimeout(() => openWhatsApp(client, targetStage), 100);
      }
    }
  };

  const handleTransitionSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (transitionClientId && transitionTargetStage) {
      const client = clients.find(c => c.id === transitionClientId);
      onUpdateClientStage(transitionClientId, transitionTargetStage.id, transitionValues);
      if (client && transitionTargetStage.template) openWhatsApp(client, transitionTargetStage, transitionValues);
      setTransitionTargetStage(null);
      setTransitionClientId(null);
      setTransitionValues({});
    }
  };

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.prgd.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-0 h-full flex flex-col relative overflow-hidden">
      {/* Modal de Criação Melhorado */}
      {isCreating && (
          <div className="fixed inset-0 bg-brand-900/40 backdrop-blur-md z-[100] flex items-center justify-center p-4">
              <div className="bg-white rounded-3xl shadow-2xl w-full max-w-xl animate-scale-up overflow-hidden border border-brand-100">
                  <div className="p-8 pb-4 flex justify-between items-center">
                      <div>
                        <h2 className="text-2xl font-black text-brand-900 uppercase tracking-tighter">Novo Projeto</h2>
                        <p className="text-xs text-gray-400 font-bold uppercase tracking-widest mt-1">Insira os dados obrigatórios para iniciar</p>
                      </div>
                      <button onClick={() => setIsCreating(false)} className="p-2 hover:bg-gray-100 rounded-full transition text-gray-400 hover:text-brand-900"><X size={24} /></button>
                  </div>
                  <form onSubmit={handleSubmit} className="p-8 space-y-6">
                      <div className="space-y-4">
                        <div className="group">
                          <label className="text-[10px] font-black uppercase text-brand-800 tracking-widest mb-1.5 block">Nome do Titular *</label>
                          <input required placeholder="Ex: João Silva" className="w-full p-3.5 bg-gray-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-gold-500/20 focus:bg-white focus:border-gold-500 transition text-sm font-medium" onChange={e => setFormData({...formData, name: e.target.value})} />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-800 tracking-widest mb-1.5 block">Telefone *</label>
                            <input required placeholder="(00) 00000-0000" className="w-full p-3.5 bg-gray-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-gold-500/20 focus:bg-white focus:border-gold-500 transition text-sm font-medium" value={formData.phone} onChange={e => setFormData({...formData, phone: formatPhoneNumber(e.target.value)})} />
                          </div>
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-800 tracking-widest mb-1.5 block">Nº PRGD *</label>
                            <input required placeholder="Ex: GD-2024-00" className="w-full p-3.5 bg-gray-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-gold-500/20 focus:bg-white focus:border-gold-500 transition text-sm font-medium" onChange={e => setFormData({...formData, prgd: e.target.value})} />
                          </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-800 tracking-widest mb-1.5 block">Número Cliente *</label>
                            <input required placeholder="Ex: 100234" className="w-full p-3.5 bg-gray-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-gold-500/20 focus:bg-white focus:border-gold-500 transition text-sm font-medium" onChange={e => setFormData({...formData, clientNumber: e.target.value})} />
                          </div>
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-800 tracking-widest mb-1.5 block">Etapa Inicial</label>
                            <select value={initialStageId} onChange={e => setInitialStageId(e.target.value)} className="w-full p-3.5 bg-gray-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-gold-500/20 focus:bg-white focus:border-gold-500 transition text-sm font-medium appearance-none">
                                {STAGES.map(s => <option key={s.id} value={s.id}>{s.stepNumber} - {s.title}</option>)}
                            </select>
                          </div>
                        </div>
                      </div>

                      <div className="pt-4">
                        <button type="submit" className="w-full bg-brand-900 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-sm hover:bg-brand-800 hover:shadow-xl hover:scale-[1.02] active:scale-100 transition shadow-lg flex items-center justify-center gap-2">
                          <Zap size={18} className="text-gold-500" /> CADASTRAR PROJETO
                        </button>
                      </div>
                  </form>
              </div>
          </div>
      )}

      {/* Modal de Transição de Etapa */}
      {transitionTargetStage && (
          <div className="fixed inset-0 bg-brand-900/40 backdrop-blur-md z-[110] flex items-center justify-center p-4">
              <div className="bg-white rounded-3xl shadow-2xl w-full max-w-md animate-scale-up border border-brand-100">
                  <div className="p-8 pb-4">
                      <h3 className="text-xl font-black text-brand-900 uppercase tracking-tighter">Completar Etapa</h3>
                      <p className="text-xs text-gray-400 font-bold uppercase tracking-widest mt-1">Fase: {transitionTargetStage.title}</p>
                  </div>
                  <form onSubmit={handleTransitionSubmit} className="p-8 pt-4 space-y-4">
                      {transitionTargetStage.requiredFields?.map(f => (
                          <div key={f}>
                              <label className="text-[10px] font-black uppercase text-brand-800 tracking-widest mb-1.5 block">{f} *</label>
                              <input required className="w-full p-3.5 bg-gray-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-gold-500/20 focus:bg-white focus:border-gold-500 transition text-sm font-medium" placeholder={`Informe ${f}...`} onChange={e => setTransitionValues({...transitionValues, [f]: e.target.value})} />
                          </div>
                      ))}
                      <div className="flex gap-3 pt-6">
                          <button type="button" onClick={() => setTransitionTargetStage(null)} className="flex-1 p-4 text-gray-400 font-bold uppercase text-[10px] tracking-widest hover:text-brand-900 transition">Cancelar</button>
                          <button type="submit" className="flex-1 bg-brand-900 text-white p-4 rounded-2xl font-black uppercase text-[10px] tracking-widest hover:bg-brand-800 transition shadow-lg">Confirmar</button>
                      </div>
                  </form>
              </div>
          </div>
      )}

      {/* Cabeçalho da Lista */}
      <div className="p-6 border-b flex justify-between items-center bg-gray-50/50">
        <div>
          <h2 className="text-2xl font-black text-brand-900 uppercase tracking-tighter">Gestão de Carteira</h2>
          <div className="flex gap-2 mt-1">
              <span className="text-[10px] font-black bg-brand-100 text-brand-700 px-2 py-0.5 rounded-full uppercase tracking-widest">{activeClients.length} Ativos</span>
              <span className="text-[10px] font-black bg-green-100 text-green-700 px-2 py-0.5 rounded-full uppercase tracking-widest">{deliveredClientsCount} Entregues</span>
          </div>
        </div>
        <div className="flex gap-3">
             <div className="bg-white p-1.5 rounded-2xl flex border shadow-sm">
                <button onClick={() => setViewMode('list')} className={`p-2.5 rounded-xl transition-all ${viewMode === 'list' ? 'bg-brand-900 text-white shadow-md' : 'text-gray-400 hover:bg-gray-50'}`}><List size={18}/></button>
                <button onClick={() => setViewMode('pipeline')} className={`p-2.5 rounded-xl transition-all ${viewMode === 'pipeline' ? 'bg-brand-900 text-white shadow-md' : 'text-gray-400 hover:bg-gray-50'}`}><Kanban size={18}/></button>
             </div>
             <button onClick={() => setIsCreating(true)} className="bg-brand-900 text-white px-6 py-3 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:scale-105 transition-all flex items-center gap-2">
                <Plus size={18} /> Criar Projeto
             </button>
        </div>
      </div>

      <div className="p-4 bg-white border-b">
         <div className="relative">
            <Search className="absolute left-4 top-3.5 text-gray-300" size={18} />
            <input placeholder="Buscar cliente ou PRGD..." className="w-full pl-12 p-3.5 rounded-2xl border-gray-100 border bg-gray-50 focus:bg-white focus:ring-2 focus:ring-gold-500/10 outline-none transition" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
         </div>
      </div>

      {/* Área Principal (Scrollable) */}
      <div className={`flex-1 overflow-y-auto scrollbar-hide bg-gray-50/30 ${viewMode === 'pipeline' ? 'overflow-x-auto overflow-y-hidden flex' : 'p-6'}`}>
        {viewMode === 'list' ? (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-8">
                {filteredClients.map(client => {
                    const isDelivered = client.currentStageId === '7';
                    const days = calculateDaysElapsed(client.createdAt, isDelivered ? client.stageHistory['7'] : undefined);
                    const deadlineDate = new Date(new Date(client.createdAt).getTime() + 120 * 24 * 60 * 60 * 1000);
                    const status = getStatusInfo(days, isDelivered);
                    const currentStage = STAGES.find(s => s.id === client.currentStageId);

                    return (
                        <div key={client.id} onClick={() => onSelectClient(client)} className="bg-white border border-gray-100 rounded-3xl p-6 hover:border-gold-400 cursor-pointer transition-all shadow-sm hover:shadow-2xl group flex flex-col gap-5">
                            <div className="flex justify-between items-start">
                                <div>
                                    <h3 className="font-black text-brand-900 uppercase text-sm group-hover:text-gold-600 transition tracking-tight">{client.name}</h3>
                                    <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest mt-0.5">{client.prgd} • #{client.clientNumber}</p>
                                </div>
                                <div className="p-2 bg-gray-50 rounded-xl group-hover:bg-gold-50 transition">
                                  <ChevronRight size={16} className="text-gray-300 group-hover:text-gold-500 transition" />
                                </div>
                            </div>

                            <div className={`p-5 rounded-2xl border border-gray-100 flex flex-col gap-3 ${status.bg} shadow-inner`}>
                                <h4 className="text-[10px] font-black text-brand-800 uppercase tracking-widest flex items-center gap-1.5 opacity-60">
                                    <Timer size={12} /> Dashboard do Projeto
                                </h4>
                                <div className="space-y-1.5">
                                    <div className="flex justify-between text-[10px] font-bold">
                                        <span className="text-gray-400 uppercase">Abertura:</span>
                                        <span className="text-brand-900">{formatDate(client.createdAt)}</span>
                                    </div>
                                    <div className="flex justify-between text-[10px] font-bold">
                                        <span className="text-gray-400 uppercase">Tempo de Obra:</span>
                                        <span className="text-brand-900 font-black">{days} / 120 dias</span>
                                    </div>
                                    <div className={`mt-3 py-2 rounded-xl text-center text-[10px] font-black tracking-widest bg-white shadow-sm border border-gray-50 ${status.color}`}>
                                        {status.label}
                                    </div>
                                </div>
                            </div>

                            <div className="flex flex-col gap-1.5 mt-auto">
                                <span className="text-[9px] font-black text-gray-300 uppercase tracking-widest">Etapa Atual</span>
                                <div className="flex items-center gap-2">
                                    <span className="bg-brand-900 text-gold-400 p-1.5 rounded-lg shadow-sm"><Zap size={12} /></span>
                                    <span className="text-xs font-black text-brand-900 uppercase tracking-tight">{currentStage?.title}</span>
                                </div>
                            </div>
                        </div>
                    );
                })}
             </div>
        ) : (
            /* Pipeline com Barra de Rolagem Horizontal Visível */
            <div className="flex gap-6 p-6 h-full min-w-max">
                {STAGES.map(stage => {
                    const stageClients = clients.filter(c => c.currentStageId === stage.id);
                    return (
                        <div key={stage.id} onDragOver={handleDragOver} onDrop={e => handleDrop(e, stage.id)} className="w-80 shrink-0 bg-gray-100/50 rounded-3xl border border-gray-200 flex flex-col max-h-full shadow-sm">
                            <div className="p-5 font-black text-[10px] uppercase tracking-widest text-brand-900 border-b border-gray-200 flex justify-between bg-white rounded-t-3xl items-center sticky top-0">
                                <span>{stage.title}</span>
                                <span className="bg-brand-900 text-gold-400 px-2.5 py-1 rounded-full shadow-sm">{stageClients.length}</span>
                            </div>
                            <div className="p-4 overflow-y-auto flex flex-col gap-4 scrollbar-hide">
                                {stageClients.map(c => (
                                    <div key={c.id} draggable onDragStart={e => handleDragStart(e, c)} onClick={() => onSelectClient(c)} className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm cursor-grab active:cursor-grabbing hover:border-gold-400 transition-all hover:shadow-lg group">
                                        <p className="font-black text-xs text-brand-900 group-hover:text-gold-600 transition uppercase tracking-tight">{c.name}</p>
                                        <p className="text-[9px] text-gray-400 font-black uppercase mt-1 tracking-widest">{c.prgd}</p>
                                        <div className="mt-4 flex justify-between items-center text-[9px] font-black pt-3 border-t border-gray-50">
                                            <span className={`px-2 py-0.5 rounded-full ${calculateDaysElapsed(c.createdAt) > 120 ? 'bg-red-50 text-red-600' : 'bg-green-50 text-green-600'}`}>
                                                {calculateDaysElapsed(c.createdAt)} DIAS
                                            </span>
                                            <span className="text-gray-300 font-medium">#{c.clientNumber}</span>
                                        </div>
                                    </div>
                                ))}
                                {stageClients.length === 0 && (
                                  <div className="border-2 border-dashed border-gray-200 rounded-2xl p-8 flex flex-col items-center justify-center opacity-40">
                                    <User className="text-gray-300 mb-2" size={20} />
                                    <p className="text-[9px] font-black uppercase text-gray-400">Vazio</p>
                                  </div>
                                )}
                            </div>
                        </div>
                    );
                })}
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Stage, Client, GeneratedContent } from '../types.ts';
import { generateTemplateContent } from '../services/templateService.ts';
import { Copy, Phone, Zap, Hash, Calendar, Edit2, Save, MessageSquare, Clock, CheckCircle, Timer, Trophy, CheckCircle2, History, AlertTriangle } from 'lucide-react';
import { STAGES } from '../constants.ts';

interface ContentGeneratorProps {
  stage: Stage;
  client: Client;
  onUpdateNotes: (notes: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

export const ContentGenerator: React.FC<ContentGeneratorProps> = ({ stage, client, onUpdateNotes, onUpdateClientStage }) => {
  const [fieldValues, setFieldValues] = useState<Record<string, string>>({});
  const [isEditing, setIsEditing] = useState(false);
  const [editableBody, setEditableBody] = useState('');

  useEffect(() => {
    setFieldValues({});
    setIsEditing(false);
    if (stage.template) {
        const generated = generateTemplateContent(stage, client, client.stageData || {});
        setEditableBody(generated.body);
    }
  }, [stage.id, client.id]);

  useEffect(() => {
    if (!isEditing && stage.template) {
        const generated = generateTemplateContent(stage, client, fieldValues);
        setEditableBody(generated.body);
    }
  }, [fieldValues, stage, client, isEditing]);

  const handleFieldChange = (variable: string, value: string) => {
    setFieldValues(prev => ({ ...prev, [variable]: value }));
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    alert("Copiado!");
  };

  const calculateDates = () => {
    const start = new Date(client.createdAt);
    const deadline = new Date(start.getTime() + (120 * 24 * 60 * 60 * 1000));
    const isCompleted = client.currentStageId === '7';
    const completionDateStr = client.stageHistory['7'];
    const now = (isCompleted && completionDateStr) 
        ? new Date(completionDateStr) 
        : new Date();

    const elapsed = Math.floor(Math.abs(now.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));

    let statusLabel = '🟢 NO PRAZO';
    let statusColor = 'text-green-600';
    if (elapsed > 120) {
        statusLabel = '🔴 CRÍTICO';
        statusColor = 'text-red-600';
    } else if (elapsed > 90) {
        statusLabel = '🟡 ATENÇÃO';
        statusColor = 'text-orange-500';
    }

    // Cálculo de Antecedência ou Atraso
    const diffDays = 120 - elapsed;
    const performanceMsg = diffDays >= 0 
      ? `✅ Entregue com ${diffDays} dias de antecedência.` 
      : `⚠️ Entregue com ${Math.abs(diffDays)} dias de atraso.`;

    return {
        start: start.toLocaleDateString('pt-BR'),
        deadline: deadline.toLocaleDateString('pt-BR'),
        elapsed,
        statusLabel,
        statusColor,
        performanceMsg,
        completionDateTime: completionDateStr ? new Date(completionDateStr).toLocaleString('pt-BR') : '-'
    };
  };

  const info = calculateDates();

  const handleWhatsAppClick = () => {
    if (!client.phone) return;
    const cleanPhone = client.phone.replace(/\D/g, '');
    const encodedText = encodeURIComponent(editableBody);
    window.open(`https://api.whatsapp.com/send?phone=55${cleanPhone}&text=${encodedText}`, '_blank');
    onUpdateClientStage(client.id, stage.id, fieldValues);
  };

  // TELA DE ENTREGA (STAGE 7)
  if (stage.id === '7') {
    return (
      <div className="bg-white rounded-3xl shadow-xl border border-gray-100 p-10 flex flex-col items-center justify-center text-center h-full max-w-4xl mx-auto overflow-y-auto scrollbar-hide">
          <div className="bg-green-100 p-8 rounded-full text-green-600 mb-8 shadow-inner animate-bounce">
              <Trophy size={80} />
          </div>
          <h2 className="text-4xl font-black text-brand-900 mb-2 uppercase tracking-tighter">Projeto Finalizado!</h2>
          <p className="text-gray-400 font-bold uppercase text-xs tracking-widest mb-10">A jornada de {client.name} foi um sucesso.</p>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 w-full mb-10">
              <div className="bg-gray-50/50 p-6 rounded-3xl border border-gray-100">
                  <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Início da Jornada</p>
                  <p className="font-black text-brand-900 text-lg">{info.start}</p>
              </div>
              <div className="bg-brand-900 p-6 rounded-3xl border border-brand-800 shadow-lg scale-105">
                  <p className="text-[10px] font-black text-brand-300 uppercase tracking-widest mb-2">Data e Hora de Entrega</p>
                  <p className="font-black text-gold-400 text-lg">{info.completionDateTime}</p>
              </div>
              <div className="bg-gray-50/50 p-6 rounded-3xl border border-gray-100">
                  <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Total de Dias</p>
                  <p className="font-black text-brand-900 text-lg">{info.elapsed} dias</p>
              </div>
          </div>

          <div className={`w-full max-w-2xl p-6 rounded-3xl border font-black uppercase text-sm tracking-widest ${info.elapsed <= 120 ? 'bg-green-50 border-green-100 text-green-700' : 'bg-red-50 border-red-100 text-red-700'}`}>
              {info.performanceMsg}
          </div>

          <div className="mt-10 flex flex-col gap-2">
            <p className="text-[10px] font-black text-gray-300 uppercase tracking-widest italic">"Loop Energia: Transformando o futuro da sua energia."</p>
          </div>
      </div>
    );
  }

  const requiredFields = stage.requiredFields || [];
  const areAllFieldsFilled = requiredFields.every(f => (fieldValues[f] || client.stageData?.[f])?.trim());

  return (
    <div className="bg-white rounded-xl shadow-lg border border-gray-200 flex flex-col h-full overflow-hidden">
      <div className="bg-brand-900 p-6 shrink-0 flex items-center justify-between text-white">
        <div>
          <h2 className="text-xl font-bold tracking-tight">Etapa {stage.stepNumber}: {stage.title}</h2>
          <p className="text-brand-300 text-xs">{stage.description}</p>
        </div>
        <div className="flex gap-2">
            <button onClick={() => setIsEditing(!isEditing)} className="p-2 hover:bg-white/10 rounded-lg transition">
                {isEditing ? <Save size={20} /> : <Edit2 size={20} />}
            </button>
        </div>
      </div>

      <div className="flex flex-col lg:flex-row flex-1 overflow-hidden">
        {/* Coluna de Status e Histórico */}
        <div className="lg:w-80 p-6 overflow-y-auto border-r border-gray-100 bg-gray-50/30 flex flex-col gap-6 scrollbar-hide">

           {/* Painel Status da Obra */}
           <div className="bg-white p-5 rounded-2xl border border-gold-200 shadow-sm">
                <h3 className="text-[10px] font-black uppercase text-brand-800 tracking-widest mb-4 flex items-center gap-2">
                    <Zap size={14} className="text-gold-500" /> Status da Obra
                </h3>
                <div className="space-y-3">
                    <div className="flex justify-between text-xs font-medium">
                        <span className="text-gray-400">Início:</span>
                        <span className="text-brand-900">{info.start}</span>
                    </div>
                    <div className="flex justify-between text-xs font-medium">
                        <span className="text-gray-400">Prazo Final:</span>
                        <span className="text-brand-900">{info.deadline}</span>
                    </div>
                    <div className="flex justify-between text-xs font-medium">
                        <span className="text-gray-400">Dias Decorridos:</span>
                        <span className="font-bold text-brand-900">{info.elapsed} / 120</span>
                    </div>
                    <div className="pt-2 border-t border-gray-50 mt-2">
                        <div className={`text-xs font-black uppercase text-center py-2 rounded-lg bg-gray-50 ${info.statusColor}`}>
                            {info.statusLabel}
                        </div>
                    </div>
                </div>
           </div>

           {/* Histórico Detalhado */}
           <div>
               <h3 className="text-[10px] font-black uppercase text-brand-800 tracking-widest mb-4 flex items-center gap-2">
                   <History size={14} /> Histórico de Etapas
               </h3>
               <div className="space-y-4">
                   {STAGES.filter(s => client.stageHistory[s.id]).map((s, idx, arr) => {
                       const completionDate = new Date(client.stageHistory[s.id]);
                       const prevDate = idx > 0 ? new Date(client.stageHistory[arr[idx-1].id]) : new Date(client.createdAt);
                       const diff = Math.floor(Math.abs(completionDate.getTime() - prevDate.getTime()) / (1000 * 60 * 60 * 24));

                       return (
                           <div key={s.id} className="relative pl-6 border-l-2 border-brand-100 pb-2">
                               <div className="absolute -left-[9px] top-0 w-4 h-4 rounded-full bg-brand-500 border-2 border-white flex items-center justify-center">
                                   <CheckCircle2 size={10} className="text-white" />
                               </div>
                               <div className="flex flex-col">
                                   <span className="text-xs font-bold text-brand-900">{s.title}</span>
                                   <div className="flex justify-between items-center mt-1">
                                       <span className="text-[10px] text-gray-400 font-medium">{completionDate.toLocaleDateString('pt-BR')}</span>
                                       <span className="text-[9px] bg-brand-50 text-brand-600 px-1.5 py-0.5 rounded font-bold">
                                           {diff} dias
                                       </span>
                                   </div>
                               </div>
                           </div>
                       );
                   })}
                   <div className="relative pl-6 border-l-2 border-dashed border-gray-200">
                        <div className="absolute -left-[9px] top-0 w-4 h-4 rounded-full bg-white border-2 border-brand-200 animate-pulse"></div>
                        <span className="text-xs font-bold text-gray-400">Próxima: {STAGES[STAGES.findIndex(s => s.id === client.currentStageId) + 1]?.title || 'Finalização'}</span>
                   </div>
               </div>
           </div>

           {requiredFields.length > 0 && (
               <div className="space-y-4 pt-4 border-t border-gray-100">
                   <h3 className="text-[10px] font-black uppercase text-brand-800 tracking-widest">Dados Necessários</h3>
                   {requiredFields.map(field => (
                       <div key={field}>
                           <label className="text-xs font-bold text-gray-500 mb-1 block capitalize">{field}</label>
                           <input 
                             type="text"
                             className="w-full p-2 border border-gray-200 rounded-lg text-sm focus:ring-2 focus:ring-gold-500/20 outline-none"
                             value={fieldValues[field] || client.stageData?.[field] || ''}
                             onChange={e => handleFieldChange(field, e.target.value)}
                             placeholder={`Informe ${field}...`}
                           />
                       </div>
                   ))}
               </div>
           )}
        </div>

        {/* Gerador de Mensagem */}
        <div className="flex-1 p-6 flex flex-col gap-4">
            <div className="flex-1 bg-white border border-gray-200 rounded-2xl overflow-hidden flex flex-col shadow-inner">
                <div className="bg-gray-50 px-4 py-2 border-b border-gray-100 flex justify-between items-center">
                    <span className="text-[10px] font-bold text-gray-400 uppercase tracking-widest">Preview da Mensagem</span>
                    <button onClick={() => copyToClipboard(editableBody)} className="flex items-center gap-1.5 text-xs font-bold text-brand-600 hover:text-brand-800 transition">
                        <Copy size={14} /> Copiar
                    </button>
                </div>
                {isEditing ? (
                    <textarea 
                      className="flex-1 p-6 text-sm font-sans resize-none outline-none leading-relaxed"
                      value={editableBody}
                      onChange={e => setEditableBody(e.target.value)}
                    />
                ) : (
                    <div className="flex-1 p-6 text-sm whitespace-pre-wrap font-sans overflow-y-auto bg-gray-50/5 leading-relaxed text-slate-700">
                        {editableBody}
                    </div>
                )}
            </div>
            <button 
                onClick={handleWhatsAppClick}
                disabled={!areAllFieldsFilled}
                className={`w-full py-4 rounded-xl font-black uppercase tracking-widest flex items-center justify-center gap-3 transition shadow-xl
                    ${areAllFieldsFilled ? 'bg-[#25D366] text-white hover:bg-[#1fb355] scale-[1.01] active:scale-100' : 'bg-gray-200 text-gray-400 cursor-not-allowed'}`}
            >
                <Phone size={20} />
                Enviar Atualização via WhatsApp
            </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Client, Stage } from '../types.ts';
import { Plus, Search, User, Zap, List, Kanban, X, Timer, ChevronRight } from 'lucide-react';
import { STAGES } from '../constants.ts';
import { generateTemplateContent } from '../services/templateService.ts';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onUpdateClientStage }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'list' | 'pipeline'>('list');

  const [draggedClientId, setDraggedClientId] = useState<string | null>(null);
  const [transitionTargetStage, setTransitionTargetStage] = useState<Stage | null>(null);
  const [transitionClientId, setTransitionClientId] = useState<string | null>(null);
  const [transitionValues, setTransitionValues] = useState<Record<string, string>>({});

  const [initialStageId, setInitialStageId] = useState<string>(STAGES[0].id);
  const [initialStageValues, setInitialStageValues] = useState<Record<string, string>>({});

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '',
    clientNumber: '',
    prgd: '',
    phone: '',
    projectName: '',
  });

  const activeClients = clients.filter(c => c.currentStageId !== '7');
  const deliveredClientsCount = clients.filter(c => c.currentStageId === '7').length;

  const formatPhoneNumber = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 11) {
       return numbers.replace(/(\d{2})(\d{5})(\d{4})/, '($1) $2-$3');
    }
    return value;
  };

  const formatDate = (isoString: string) => {
    if (!isoString) return '-';
    return new Date(isoString).toLocaleDateString('pt-BR');
  };

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const getStatusInfo = (days: number, isDelivered: boolean) => {
    if (isDelivered) return { label: '🟢 CONCLUÍDO', color: 'text-green-600', bg: 'bg-green-50' };
    if (days > 120) return { label: '🔴 CRÍTICO', color: 'text-red-600', bg: 'bg-red-50' };
    if (days > 90) return { label: '🟡 ATENÇÃO', color: 'text-orange-500', bg: 'bg-orange-50' };
    return { label: '🟢 NO PRAZO', color: 'text-green-600', bg: 'bg-green-50' };
  };

  const openWhatsApp = (client: Client, stage: Stage, values: Record<string, string> = {}) => {
      if (!client.phone || !stage.template) return;
      const mergedValues = { ...client.stageData, ...values };
      const content = generateTemplateContent(stage, client, mergedValues);
      const cleanPhone = client.phone.replace(/\D/g, '');
      const encodedText = encodeURIComponent(content.body);
      window.open(`https://api.whatsapp.com/send?phone=55${cleanPhone}&text=${encodedText}`, '_blank');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name?.trim() || !formData.clientNumber?.trim() || !formData.prgd?.trim() || !formData.phone?.trim()) {
      alert("⚠️ Atenção: Nome, Telefone, PRGD e Número do Cliente são obrigatórios.");
      return;
    }

    const selectedStage = STAGES.find(s => s.id === initialStageId);
    const now = new Date().toISOString();
    const newClient: Client = {
      id: Date.now().toString(),
      name: formData.name || '',
      clientNumber: formData.clientNumber || '',
      prgd: formData.prgd || '',
      phone: formData.phone || '',
      projectName: formData.projectName || `Projeto ${formData.name}`,
      additionalNotes: '',
      currentStageId: initialStageId,
      createdAt: now,
      stageHistory: { [initialStageId]: now },
      stageData: initialStageValues
    };
    if (selectedStage?.template) openWhatsApp(newClient, selectedStage, initialStageValues);
    setIsCreating(false);
    onCreateClient(newClient);
    setFormData({ name: '', clientNumber: '', prgd: '', phone: '' });
  };

  const handleDragStart = (e: React.DragEvent, client: Client) => {
    e.dataTransfer.setData('clientId', client.id);
    setDraggedClientId(client.id);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };

  const handleDrop = (e: React.DragEvent, stageId: string) => {
    e.preventDefault();
    const clientId = e.dataTransfer.getData('clientId');
    setDraggedClientId(null);
    if (!clientId) return;

    const client = clients.find(c => c.id === clientId);
    const targetStage = STAGES.find(s => s.id === stageId);

    if (client && targetStage && client.currentStageId !== stageId) {
      if (targetStage.requiredFields && targetStage.requiredFields.length > 0) {
        setTransitionClientId(clientId);
        setTransitionTargetStage(targetStage);
      } else {
        onUpdateClientStage(clientId, stageId);
        if (targetStage.template) setTimeout(() => openWhatsApp(client, targetStage), 100);
      }
    }
  };

  const handleTransitionSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (transitionClientId && transitionTargetStage) {
      const client = clients.find(c => c.id === transitionClientId);
      onUpdateClientStage(transitionClientId, transitionTargetStage.id, transitionValues);
      if (client && transitionTargetStage.template) openWhatsApp(client, transitionTargetStage, transitionValues);
      setTransitionTargetStage(null);
      setTransitionClientId(null);
      setTransitionValues({});
    }
  };

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.prgd.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-0 h-full flex flex-col relative overflow-hidden">
      {/* Modal de Criação Clean */}
      {isCreating && (
          <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
              <div className="bg-white rounded-3xl shadow-2xl w-full max-w-xl animate-scale-up border border-gray-100 overflow-hidden">
                  <div className="p-8 pb-4 flex justify-between items-center border-b border-gray-50">
                      <div>
                        <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">Novo Projeto</h2>
                        <p className="text-xs text-gray-400 font-bold uppercase tracking-widest">Os campos com * são obrigatórios</p>
                      </div>
                      <button onClick={() => setIsCreating(false)} className="p-2 hover:bg-gray-100 rounded-full transition text-gray-400 hover:text-brand-600"><X size={24} /></button>
                  </div>
                  <form onSubmit={handleSubmit} className="p-8 space-y-6 bg-white">
                      <div className="space-y-4">
                        <div className="group">
                          <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Nome do Titular *</label>
                          <input required placeholder="Ex: João Silva" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" onChange={e => setFormData({...formData, name: e.target.value})} />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Telefone *</label>
                            <input required placeholder="(00) 00000-0000" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" value={formData.phone} onChange={e => setFormData({...formData, phone: formatPhoneNumber(e.target.value)})} />
                          </div>
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Nº PRGD *</label>
                            <input required placeholder="Ex: GD-2024-00" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" onChange={e => setFormData({...formData, prgd: e.target.value})} />
                          </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Número Cliente *</label>
                            <input required placeholder="Ex: 100234" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" onChange={e => setFormData({...formData, clientNumber: e.target.value})} />
                          </div>
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Etapa Inicial</label>
                            <select value={initialStageId} onChange={e => setInitialStageId(e.target.value)} className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium">
                                {STAGES.map(s => <option key={s.id} value={s.id}>{s.stepNumber} - {s.title}</option>)}
                            </select>
                          </div>
                        </div>
                      </div>

                      <div className="pt-4">
                        <button type="submit" className="w-full bg-brand-500 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-sm hover:bg-brand-600 shadow-lg hover:shadow-brand-500/30 transition-all flex items-center justify-center gap-2">
                          <Zap size={18} className="text-gold-400" /> CADASTRAR PROJETO
                        </button>
                      </div>
                  </form>
              </div>
          </div>
      )}

      {/* Cabeçalho */}
      <div className="p-6 border-b flex justify-between items-center bg-gray-50/30">
        <div>
          <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">Gestão de Carteira</h2>
          <div className="flex gap-2 mt-1">
              <span className="text-[10px] font-black bg-brand-50 text-brand-600 px-2.5 py-1 rounded-full uppercase tracking-widest border border-brand-100">{activeClients.length} Ativos</span>
              <span className="text-[10px] font-black bg-green-50 text-green-600 px-2.5 py-1 rounded-full uppercase tracking-widest border border-green-100">{deliveredClientsCount} Entregues</span>
          </div>
        </div>
        <div className="flex gap-3">
             <div className="bg-white p-1.5 rounded-2xl flex border border-gray-100 shadow-sm">
                <button onClick={() => setViewMode('list')} className={`p-2.5 rounded-xl transition-all ${viewMode === 'list' ? 'bg-brand-600 text-white shadow-md' : 'text-gray-400 hover:bg-gray-50'}`}><List size={18}/></button>
                <button onClick={() => setViewMode('pipeline')} className={`p-2.5 rounded-xl transition-all ${viewMode === 'pipeline' ? 'bg-brand-600 text-white shadow-md' : 'text-gray-400 hover:bg-gray-50'}`}><Kanban size={18}/></button>
             </div>
             <button onClick={() => setIsCreating(true)} className="bg-brand-600 text-white px-6 py-3 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-brand-700 transition-all flex items-center gap-2">
                <Plus size={18} /> Criar Projeto
             </button>
        </div>
      </div>

      <div className="p-4 bg-white border-b">
         <div className="relative">
            <Search className="absolute left-4 top-3.5 text-gray-300" size={18} />
            <input placeholder="Buscar cliente ou PRGD..." className="w-full pl-12 p-3.5 rounded-2xl border-gray-100 border bg-gray-50 focus:bg-white outline-none transition" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
         </div>
      </div>

      {/* Área Principal com Scroll Horizontal Visível no Pipeline */}
      <div className={`flex-1 overflow-auto bg-gray-50/30 ${viewMode === 'pipeline' ? 'flex custom-scroll' : 'p-6'}`}>
        {viewMode === 'list' ? (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-8">
                {filteredClients.map(client => {
                    const isDelivered = client.currentStageId === '7';
                    const days = calculateDaysElapsed(client.createdAt, isDelivered ? client.stageHistory['7'] : undefined);
                    const deadlineDate = new Date(new Date(client.createdAt).getTime() + 120 * 24 * 60 * 60 * 1000);
                    const status = getStatusInfo(days, isDelivered);
                    const currentStage = STAGES.find(s => s.id === client.currentStageId);

                    return (
                        <div key={client.id} onClick={() => onSelectClient(client)} className="bg-white border border-gray-100 rounded-3xl p-6 hover:border-brand-400 cursor-pointer transition-all shadow-sm hover:shadow-2xl group flex flex-col gap-5">
                            <div className="flex justify-between items-start">
                                <div>
                                    <h3 className="font-black text-brand-600 uppercase text-sm group-hover:text-brand-500 transition tracking-tight">{client.name}</h3>
                                    <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest mt-0.5">{client.prgd} • #{client.clientNumber}</p>
                                </div>
                                <div className="p-2 bg-gray-50 rounded-xl group-hover:bg-brand-50 transition">
                                  <ChevronRight size={16} className="text-gray-300 group-hover:text-brand-500 transition" />
                                </div>
                            </div>

                            <div className={`p-5 rounded-2xl border border-gray-100 flex flex-col gap-3 ${status.bg} shadow-inner`}>
                                <h4 className="text-[10px] font-black text-brand-800 uppercase tracking-widest flex items-center gap-1.5 opacity-60">
                                    <Timer size={12} /> Dashboard do Projeto
                                </h4>
                                <div className="space-y-1.5">
                                    <div className="flex justify-between text-[10px] font-bold">
                                        <span className="text-gray-400 uppercase">Abertura:</span>
                                        <span className="text-brand-900">{formatDate(client.createdAt)}</span>
                                    </div>
                                    <div className="flex justify-between text-[10px] font-bold">
                                        <span className="text-gray-400 uppercase">Tempo de Obra:</span>
                                        <span className="text-brand-900 font-black">{days} / 120 dias</span>
                                    </div>
                                    <div className={`mt-3 py-2 rounded-xl text-center text-[10px] font-black tracking-widest bg-white shadow-sm border border-gray-50 ${status.color}`}>
                                        {status.label}
                                    </div>
                                </div>
                            </div>

                            <div className="flex flex-col gap-1.5 mt-auto">
                                <span className="text-[9px] font-black text-gray-300 uppercase tracking-widest">Etapa Atual</span>
                                <div className="flex items-center gap-2">
                                    <span className="bg-brand-600 text-gold-400 p-1.5 rounded-lg shadow-sm"><Zap size={12} /></span>
                                    <span className="text-xs font-black text-brand-900 uppercase tracking-tight">{currentStage?.title}</span>
                                </div>
                            </div>
                        </div>
                    );
                })}
             </div>
        ) : (
            <div className="flex gap-6 p-6 h-full min-w-max">
                {STAGES.map(stage => {
                    const stageClients = clients.filter(c => c.currentStageId === stage.id);
                    return (
                        <div key={stage.id} onDragOver={handleDragOver} onDrop={e => handleDrop(e, stage.id)} className="w-80 shrink-0 bg-gray-100/30 rounded-3xl border border-gray-200 flex flex-col max-h-full shadow-sm">
                            <div className="p-5 font-black text-[10px] uppercase tracking-widest text-brand-600 border-b border-gray-200 flex justify-between bg-white rounded-t-3xl items-center sticky top-0">
                                <span>{stage.title}</span>
                                <span className="bg-brand-600 text-white px-2.5 py-1 rounded-full shadow-sm">{stageClients.length}</span>
                            </div>
                            <div className="p-4 overflow-y-auto flex flex-col gap-4 custom-scroll">
                                {stageClients.map(c => (
                                    <div key={c.id} draggable onDragStart={e => handleDragStart(e, c)} onClick={() => onSelectClient(c)} className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm cursor-grab active:cursor-grabbing hover:border-brand-400 transition-all hover:shadow-lg group">
                                        <p className="font-black text-xs text-brand-600 group-hover:text-brand-500 transition uppercase tracking-tight">{c.name}</p>
                                        <p className="text-[9px] text-gray-400 font-black uppercase mt-1 tracking-widest">{c.prgd}</p>
                                        <div className="mt-4 flex justify-between items-center text-[9px] font-black pt-3 border-t border-gray-50">
                                            <span className={`px-2 py-0.5 rounded-full ${calculateDaysElapsed(c.createdAt) > 120 ? 'bg-red-50 text-red-600' : 'bg-green-50 text-green-600'}`}>
                                                {calculateDaysElapsed(c.createdAt)} DIAS
                                            </span>
                                            <span className="text-gray-300 font-medium">#{c.clientNumber}</span>
                                        </div>
                                    </div>
                                ))}
                                {stageClients.length === 0 && (
                                  <div className="border-2 border-dashed border-gray-100 rounded-2xl p-8 flex flex-col items-center justify-center opacity-30">
                                    <User className="text-gray-300 mb-2" size={20} />
                                    <p className="text-[9px] font-black uppercase text-gray-400">Sem clientes</p>
                                  </div>
                                )}
                            </div>
                        </div>
                    );
                })}
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Stage, Client, GeneratedContent } from '../types.ts';
import { generateTemplateContent } from '../services/templateService.ts';
import { Copy, Phone, Zap, Edit2, Save, Timer, Trophy, CheckCircle2, History } from 'lucide-react';
import { STAGES } from '../constants.ts';

interface ContentGeneratorProps {
  stage: Stage;
  client: Client;
  onUpdateNotes: (notes: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

export const ContentGenerator: React.FC<ContentGeneratorProps> = ({ stage, client, onUpdateNotes, onUpdateClientStage }) => {
  const [fieldValues, setFieldValues] = useState<Record<string, string>>({});
  const [isEditing, setIsEditing] = useState(false);
  const [editableBody, setEditableBody] = useState('');

  useEffect(() => {
    setFieldValues({});
    setIsEditing(false);
    if (stage.template) {
        const generated = generateTemplateContent(stage, client, client.stageData || {});
        setEditableBody(generated.body);
    }
  }, [stage.id, client.id]);

  useEffect(() => {
    if (!isEditing && stage.template) {
        const generated = generateTemplateContent(stage, client, fieldValues);
        setEditableBody(generated.body);
    }
  }, [fieldValues, stage, client, isEditing]);

  const handleFieldChange = (variable: string, value: string) => {
    setFieldValues(prev => ({ ...prev, [variable]: value }));
  };

  const copyToClipboard = (text: string) => {
    navigator.clipboard.writeText(text);
    alert("Copiado!");
  };

  const calculateDates = () => {
    const start = new Date(client.createdAt);
    const deadline = new Date(start.getTime() + (120 * 24 * 60 * 60 * 1000));
    const isCompleted = client.currentStageId === '7';
    const completionDateStr = client.stageHistory['7'];
    const now = (isCompleted && completionDateStr) 
        ? new Date(completionDateStr) 
        : new Date();

    const elapsed = Math.floor(Math.abs(now.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));

    let statusLabel = '🟢 NO PRAZO';
    let statusColor = 'text-green-600';
    if (elapsed > 120) {
        statusLabel = '🔴 CRÍTICO';
        statusColor = 'text-red-600';
    } else if (elapsed > 90) {
        statusLabel = '🟡 ATENÇÃO';
        statusColor = 'text-orange-500';
    }

    const diffDays = 120 - elapsed;
    const performanceMsg = diffDays >= 0 
      ? `🚀 Projeto concluído com ${diffDays} dias de antecedência!` 
      : `⚠️ Projeto finalizado com ${Math.abs(diffDays)} dias além do prazo ideal.`;

    return {
        start: start.toLocaleDateString('pt-BR'),
        deadline: deadline.toLocaleDateString('pt-BR'),
        elapsed,
        statusLabel,
        statusColor,
        performanceMsg,
        completionDateTime: completionDateStr ? new Date(completionDateStr).toLocaleString('pt-BR') : '-'
    };
  };

  const info = calculateDates();

  const handleWhatsAppClick = () => {
    if (!client.phone) return;
    const cleanPhone = client.phone.replace(/\D/g, '');
    const encodedText = encodeURIComponent(editableBody);
    window.open(`https://api.whatsapp.com/send?phone=55${cleanPhone}&text=${encodedText}`, '_blank');
    onUpdateClientStage(client.id, stage.id, fieldValues);
  };

  if (stage.id === '7') {
    return (
      <div className="bg-white rounded-3xl shadow-xl border border-gray-100 p-10 flex flex-col items-center justify-center text-center h-full max-w-4xl mx-auto overflow-y-auto custom-scroll">
          <div className="bg-green-100 p-8 rounded-full text-green-600 mb-8 shadow-inner animate-pulse">
              <Trophy size={80} />
          </div>
          <h2 className="text-4xl font-black text-brand-600 mb-2 uppercase tracking-tighter">Projeto Finalizado!</h2>
          <p className="text-gray-400 font-bold uppercase text-xs tracking-widest mb-10">A jornada de {client.name} foi entregue.</p>

          <div className="grid grid-cols-1 md:grid-cols-3 gap-6 w-full mb-10">
              <div className="bg-gray-50 p-6 rounded-3xl border border-gray-100">
                  <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Início</p>
                  <p className="font-black text-brand-900 text-lg">{info.start}</p>
              </div>
              <div className="bg-brand-600 p-6 rounded-3xl border border-brand-500 shadow-xl scale-105">
                  <p className="text-[10px] font-black text-brand-200 uppercase tracking-widest mb-2 text-white/70">Data e Hora de Entrega</p>
                  <p className="font-black text-white text-lg">{info.completionDateTime}</p>
              </div>
              <div className="bg-gray-50 p-6 rounded-3xl border border-gray-100">
                  <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-2">Tempo Total</p>
                  <p className="font-black text-brand-900 text-lg">{info.elapsed} dias</p>
              </div>
          </div>

          <div className={`w-full max-w-2xl p-6 rounded-3xl border font-black uppercase text-sm tracking-widest shadow-sm ${info.elapsed <= 120 ? 'bg-green-50 border-green-100 text-green-700' : 'bg-red-50 border-red-100 text-red-700'}`}>
              {info.performanceMsg}
          </div>

          <div className="mt-12 text-gray-300 font-bold text-[10px] uppercase tracking-[0.2em]">
            Loop Energia • Gestão de Experiência do Cliente
          </div>
      </div>
    );
  }

  const requiredFields = stage.requiredFields || [];
  const areAllFieldsFilled = requiredFields.every(f => (fieldValues[f] || client.stageData?.[f])?.trim());

  return (
    <div className="bg-white rounded-xl shadow-lg border border-gray-200 flex flex-col h-full overflow-hidden">
      <div className="bg-brand-600 p-6 shrink-0 flex items-center justify-between text-white">
        <div>
          <h2 className="text-xl font-black tracking-tight uppercase">Etapa {stage.stepNumber}: {stage.title}</h2>
          <p className="text-brand-100 text-xs font-medium">{stage.description}</p>
        </div>
        <div className="flex gap-2">
            <button onClick={() => setIsEditing(!isEditing)} className="p-2.5 hover:bg-white/10 rounded-xl transition-all">
                {isEditing ? <Save size={20} /> : <Edit2 size={20} />}
            </button>
        </div>
      </div>

      <div className="flex flex-col lg:flex-row flex-1 overflow-hidden">
        <div className="lg:w-80 p-6 overflow-y-auto border-r border-gray-100 bg-gray-50/50 flex flex-col gap-6 custom-scroll">

           <div className="bg-white p-5 rounded-2xl border border-brand-100 shadow-sm">
                <h3 className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-4 flex items-center gap-2">
                    <Zap size={14} className="text-gold-500" /> Status da Obra
                </h3>
                <div className="space-y-3">
                    <div className="flex justify-between text-xs font-medium">
                        <span className="text-gray-400">Início:</span>
                        <span className="text-brand-900">{info.start}</span>
                    </div>
                    <div className="flex justify-between text-xs font-medium">
                        <span className="text-gray-400">Prazo Final:</span>
                        <span className="text-brand-900">{info.deadline}</span>
                    </div>
                    <div className="flex justify-between text-xs font-medium">
                        <span className="text-gray-400">Dias:</span>
                        <span className="font-bold text-brand-900">{info.elapsed} / 120</span>
                    </div>
                    <div className="pt-2 border-t border-gray-50 mt-2">
                        <div className={`text-xs font-black uppercase text-center py-2 rounded-xl bg-gray-50 ${info.statusColor}`}>
                            {info.statusLabel}
                        </div>
                    </div>
                </div>
           </div>

           <div>
               <h3 className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-4 flex items-center gap-2">
                   <History size={14} /> Histórico
               </h3>
               <div className="space-y-4">
                   {STAGES.filter(s => client.stageHistory[s.id]).map((s, idx, arr) => {
                       const completionDate = new Date(client.stageHistory[s.id]);
                       const prevDate = idx > 0 ? new Date(client.stageHistory[arr[idx-1].id]) : new Date(client.createdAt);
                       const diff = Math.floor(Math.abs(completionDate.getTime() - prevDate.getTime()) / (1000 * 60 * 60 * 24));

                       return (
                           <div key={s.id} className="relative pl-6 border-l-2 border-brand-100 pb-2">
                               <div className="absolute -left-[9px] top-0 w-4 h-4 rounded-full bg-brand-500 border-2 border-white flex items-center justify-center">
                                   <CheckCircle2 size={10} className="text-white" />
                               </div>
                               <div className="flex flex-col">
                                   <span className="text-xs font-bold text-brand-900">{s.title}</span>
                                   <div className="flex justify-between items-center mt-1">
                                       <span className="text-[10px] text-gray-400 font-medium">{completionDate.toLocaleDateString('pt-BR')}</span>
                                       <span className="text-[9px] bg-brand-50 text-brand-600 px-1.5 py-0.5 rounded font-bold">
                                           {diff}d
                                       </span>
                                   </div>
                               </div>
                           </div>
                       );
                   })}
               </div>
           </div>

           {requiredFields.length > 0 && (
               <div className="space-y-4 pt-4 border-t border-gray-100">
                   <h3 className="text-[10px] font-black uppercase text-brand-700 tracking-widest">Preencher Variáveis</h3>
                   {requiredFields.map(field => (
                       <div key={field}>
                           <label className="text-xs font-bold text-gray-500 mb-1 block capitalize">{field}</label>
                           <input 
                             type="text"
                             className="w-full p-3 bg-white border border-gray-200 rounded-xl text-sm focus:ring-2 focus:ring-brand-500/20 outline-none transition-all"
                             value={fieldValues[field] || client.stageData?.[field] || ''}
                             onChange={e => handleFieldChange(field, e.target.value)}
                             placeholder={`Informe ${field}...`}
                           />
                       </div>
                   ))}
               </div>
           )}
        </div>

        <div className="flex-1 p-6 flex flex-col gap-4 bg-white">
            <div className="flex-1 bg-gray-50 border border-gray-100 rounded-3xl overflow-hidden flex flex-col shadow-inner">
                <div className="bg-white/50 px-6 py-3 border-b border-gray-100 flex justify-between items-center">
                    <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Template de Mensagem</span>
                    <button onClick={() => copyToClipboard(editableBody)} className="flex items-center gap-1.5 text-xs font-black text-brand-600 hover:text-brand-800 transition">
                        <Copy size={14} /> Copiar Texto
                    </button>
                </div>
                {isEditing ? (
                    <textarea 
                      className="flex-1 p-8 text-sm font-sans resize-none outline-none leading-relaxed bg-transparent"
                      value={editableBody}
                      onChange={e => setEditableBody(e.target.value)}
                    />
                ) : (
                    <div className="flex-1 p-8 text-sm whitespace-pre-wrap font-sans overflow-y-auto leading-relaxed text-slate-700">
                        {editableBody}
                    </div>
                )}
            </div>
            <button 
                onClick={handleWhatsAppClick}
                disabled={!areAllFieldsFilled}
                className={`w-full py-4 rounded-2xl font-black uppercase tracking-widest flex items-center justify-center gap-3 transition-all shadow-xl
                    ${areAllFieldsFilled ? 'bg-[#25D366] text-white hover:bg-[#1fb355] scale-[1.01] active:scale-100' : 'bg-gray-200 text-gray-400 cursor-not-allowed'}`}
            >
                <Phone size={20} />
                Enviar via WhatsApp
            </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Client, Stage } from '../types.ts';
import { Plus, Search, User, Zap, List, Kanban, X, Timer, ChevronRight, AlertCircle, Clock } from 'lucide-react';
import { STAGES } from '../constants.ts';
import { generateTemplateContent } from '../services/templateService.ts';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onUpdateClientStage }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'list' | 'pipeline'>('list');

  const [draggedClientId, setDraggedClientId] = useState<string | null>(null);
  const [transitionTargetStage, setTransitionTargetStage] = useState<Stage | null>(null);
  const [transitionClientId, setTransitionClientId] = useState<string | null>(null);
  const [transitionValues, setTransitionValues] = useState<Record<string, string>>({});

  const [initialStageId, setInitialStageId] = useState<string>(STAGES[0].id);
  const [initialStageValues, setInitialStageValues] = useState<Record<string, string>>({});

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '',
    clientNumber: '',
    prgd: '',
    phone: '',
    projectName: '',
  });

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const activeClients = clients.filter(c => c.currentStageId !== '7');
  const deliveredClients = clients.filter(c => c.currentStageId === '7');

  // Cálculos de Status para o Header
  const statusCounts = activeClients.reduce((acc, c) => {
    const days = calculateDaysElapsed(c.createdAt);
    if (days > 120) acc.urgente++;
    else if (days > 90) acc.atencao++;
    else acc.noPrazo++;
    return acc;
  }, { noPrazo: 0, atencao: 0, urgente: 0 });

  const formatPhoneNumber = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 11) {
       return numbers.replace(/(\d{2})(\d{5})(\d{4})/, '($1) $2-$3');
    }
    return value;
  };

  const formatDate = (isoString: string) => {
    if (!isoString) return '-';
    return new Date(isoString).toLocaleDateString('pt-BR');
  };

  const getStatusInfo = (days: number, isDelivered: boolean) => {
    if (isDelivered) return { label: '🟢 CONCLUÍDO', color: 'text-green-600', bg: 'bg-green-50' };
    if (days > 120) return { label: '🔴 CRÍTICO', color: 'text-red-600', bg: 'bg-red-50' };
    if (days > 90) return { label: '🟡 ATENÇÃO', color: 'text-orange-500', bg: 'bg-orange-50' };
    return { label: '🟢 NO PRAZO', color: 'text-green-600', bg: 'bg-green-50' };
  };

  const openWhatsApp = (client: Client, stage: Stage, values: Record<string, string> = {}) => {
      if (!client.phone || !stage.template) return;
      const mergedValues = { ...client.stageData, ...values };
      const content = generateTemplateContent(stage, client, mergedValues);
      const cleanPhone = client.phone.replace(/\D/g, '');
      const encodedText = encodeURIComponent(content.body);
      window.open(`https://api.whatsapp.com/send?phone=55${cleanPhone}&text=${encodedText}`, '_blank');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name?.trim() || !formData.clientNumber?.trim() || !formData.prgd?.trim() || !formData.phone?.trim()) {
      alert("⚠️ Atenção: Nome, Telefone, PRGD e Número do Cliente são obrigatórios.");
      return;
    }

    const selectedStage = STAGES.find(s => s.id === initialStageId);
    const now = new Date().toISOString();
    const newClient: Client = {
      id: Date.now().toString(),
      name: formData.name || '',
      clientNumber: formData.clientNumber || '',
      prgd: formData.prgd || '',
      phone: formData.phone || '',
      projectName: formData.projectName || `Projeto ${formData.name}`,
      additionalNotes: '',
      currentStageId: initialStageId,
      createdAt: now,
      stageHistory: { [initialStageId]: now },
      stageData: initialStageValues
    };
    if (selectedStage?.template) openWhatsApp(newClient, selectedStage, initialStageValues);
    setIsCreating(false);
    onCreateClient(newClient);
    setFormData({ name: '', clientNumber: '', prgd: '', phone: '' });
  };

  const handleDragStart = (e: React.DragEvent, client: Client) => {
    e.dataTransfer.setData('clientId', client.id);
    setDraggedClientId(client.id);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };

  const handleDrop = (e: React.DragEvent, stageId: string) => {
    e.preventDefault();
    const clientId = e.dataTransfer.getData('clientId');
    setDraggedClientId(null);
    if (!clientId) return;

    const client = clients.find(c => c.id === clientId);
    const targetStage = STAGES.find(s => s.id === stageId);

    if (client && targetStage && client.currentStageId !== stageId) {
      if (targetStage.requiredFields && targetStage.requiredFields.length > 0) {
        setTransitionClientId(clientId);
        setTransitionTargetStage(targetStage);
      } else {
        onUpdateClientStage(clientId, stageId);
        if (targetStage.template) setTimeout(() => openWhatsApp(client, targetStage), 100);
      }
    }
  };

  const handleTransitionSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (transitionClientId && transitionTargetStage) {
      const client = clients.find(c => c.id === transitionClientId);
      onUpdateClientStage(transitionClientId, transitionTargetStage.id, transitionValues);
      if (client && transitionTargetStage.template) openWhatsApp(client, transitionTargetStage, transitionValues);
      setTransitionTargetStage(null);
      setTransitionClientId(null);
      setTransitionValues({});
    }
  };

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.prgd.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-0 h-full flex flex-col relative overflow-hidden">
      {/* Modal de Criação Clean */}
      {isCreating && (
          <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
              <div className="bg-white rounded-3xl shadow-2xl w-full max-w-xl animate-scale-up border border-gray-100 overflow-hidden">
                  <div className="p-8 pb-4 flex justify-between items-center border-b border-gray-50">
                      <div>
                        <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">Novo Projeto</h2>
                        <p className="text-xs text-gray-400 font-bold uppercase tracking-widest">Os campos com * são obrigatórios</p>
                      </div>
                      <button onClick={() => setIsCreating(false)} className="p-2 hover:bg-gray-100 rounded-full transition text-gray-400 hover:text-brand-600"><X size={24} /></button>
                  </div>
                  <form onSubmit={handleSubmit} className="p-8 space-y-6 bg-white">
                      <div className="space-y-4">
                        <div className="group">
                          <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Nome do Titular *</label>
                          <input required placeholder="Ex: João Silva" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" onChange={e => setFormData({...formData, name: e.target.value})} />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Telefone *</label>
                            <input required placeholder="(00) 00000-0000" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" value={formData.phone} onChange={e => setFormData({...formData, phone: formatPhoneNumber(e.target.value)})} />
                          </div>
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Nº PRGD *</label>
                            <input required placeholder="Ex: GD-2024-00" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" onChange={e => setFormData({...formData, prgd: e.target.value})} />
                          </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Número Cliente *</label>
                            <input required placeholder="Ex: 100234" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" onChange={e => setFormData({...formData, clientNumber: e.target.value})} />
                          </div>
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Etapa Inicial</label>
                            <select value={initialStageId} onChange={e => setInitialStageId(e.target.value)} className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium">
                                {STAGES.map(s => <option key={s.id} value={s.id}>{s.stepNumber} - {s.title}</option>)}
                            </select>
                          </div>
                        </div>
                      </div>

                      <div className="pt-4">
                        <button type="submit" className="w-full bg-brand-500 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-sm hover:bg-brand-600 shadow-lg hover:shadow-brand-500/30 transition-all flex items-center justify-center gap-2">
                          <Zap size={18} className="text-gold-400" /> CADASTRAR PROJETO
                        </button>
                      </div>
                  </form>
              </div>
          </div>
      )}

      {/* Cabeçalho */}
      <div className="p-6 border-b flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-gray-50/30">
        <div>
          <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">Gestão de Carteira</h2>
          <div className="flex flex-wrap gap-2 mt-2">
              <span className="text-[9px] font-black bg-brand-50 text-brand-600 px-2.5 py-1 rounded-full uppercase tracking-widest border border-brand-100 shadow-sm">
                {activeClients.length} ATIVOS
              </span>
              <span className="text-[9px] font-black bg-green-50 text-green-600 px-2.5 py-1 rounded-full uppercase tracking-widest border border-green-100 shadow-sm">
                {deliveredClients.length} ENTREGUES
              </span>
              <div className="w-px h-4 bg-gray-200 mx-1 hidden sm:block self-center"></div>
              <span className="text-[9px] font-black bg-emerald-50 text-emerald-600 px-2.5 py-1 rounded-full uppercase tracking-widest border border-emerald-100 flex items-center gap-1 shadow-sm">
                <Clock size={10} /> {statusCounts.noPrazo} NO PRAZO
              </span>
              <span className="text-[9px] font-black bg-amber-50 text-amber-600 px-2.5 py-1 rounded-full uppercase tracking-widest border border-amber-100 flex items-center gap-1 shadow-sm">
                <AlertCircle size={10} /> {statusCounts.atencao} ATENÇÃO
              </span>
              <span className="text-[9px] font-black bg-red-50 text-red-600 px-2.5 py-1 rounded-full uppercase tracking-widest border border-red-100 flex items-center gap-1 shadow-sm">
                <AlertCircle size={10} /> {statusCounts.urgente} URGENTE
              </span>
          </div>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
             <div className="bg-white p-1.5 rounded-2xl flex border border-gray-100 shadow-sm flex-1 md:flex-none">
                <button onClick={() => setViewMode('list')} className={`flex-1 md:flex-none p-2.5 rounded-xl transition-all ${viewMode === 'list' ? 'bg-brand-600 text-white shadow-md' : 'text-gray-400 hover:bg-gray-50'}`} title="Visualização em Lista"><List size={18} className="mx-auto"/></button>
                <button onClick={() => setViewMode('pipeline')} className={`flex-1 md:flex-none p-2.5 rounded-xl transition-all ${viewMode === 'pipeline' ? 'bg-brand-600 text-white shadow-md' : 'text-gray-400 hover:bg-gray-50'}`} title="Visualização em Pipeline"><Kanban size={18} className="mx-auto"/></button>
             </div>
             <button onClick={() => setIsCreating(true)} className="flex-1 md:flex-none bg-brand-600 text-white px-6 py-3 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-brand-700 transition-all flex items-center justify-center gap-2">
                <Plus size={18} /> Criar Projeto
             </button>
        </div>
      </div>

      <div className="p-4 bg-white border-b">
         <div className="relative">
            <Search className="absolute left-4 top-3.5 text-gray-300" size={18} />
            <input placeholder="Buscar cliente ou PRGD..." className="w-full pl-12 p-3.5 rounded-2xl border-gray-100 border bg-gray-50 focus:bg-white outline-none transition" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
         </div>
      </div>

      {/* Área Principal com Scroll Horizontal Visível no Pipeline */}
      <div className={`flex-1 overflow-auto bg-gray-50/30 ${viewMode === 'pipeline' ? 'flex custom-scroll' : 'p-6'}`}>
        {viewMode === 'list' ? (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-8">
                {filteredClients.map(client => {
                    const isDelivered = client.currentStageId === '7';
                    const days = calculateDaysElapsed(client.createdAt, isDelivered ? client.stageHistory['7'] : undefined);
                    const deadlineDate = new Date(new Date(client.createdAt).getTime() + 120 * 24 * 60 * 60 * 1000);
                    const status = getStatusInfo(days, isDelivered);
                    const currentStage = STAGES.find(s => s.id === client.currentStageId);

                    return (
                        <div key={client.id} onClick={() => onSelectClient(client)} className="bg-white border border-gray-100 rounded-3xl p-6 hover:border-brand-400 cursor-pointer transition-all shadow-sm hover:shadow-2xl group flex flex-col gap-5">
                            <div className="flex justify-between items-start">
                                <div>
                                    <h3 className="font-black text-brand-600 uppercase text-sm group-hover:text-brand-500 transition tracking-tight">{client.name}</h3>
                                    <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest mt-0.5">{client.prgd} • #{client.clientNumber}</p>
                                </div>
                                <div className="p-2 bg-gray-50 rounded-xl group-hover:bg-brand-50 transition">
                                  <ChevronRight size={16} className="text-gray-300 group-hover:text-brand-500 transition" />
                                </div>
                            </div>

                            <div className={`p-5 rounded-2xl border border-gray-100 flex flex-col gap-3 ${status.bg} shadow-inner`}>
                                <h4 className="text-[10px] font-black text-brand-800 uppercase tracking-widest flex items-center gap-1.5 opacity-60">
                                    <Timer size={12} /> Dashboard do Projeto
                                </h4>
                                <div className="space-y-1.5">
                                    <div className="flex justify-between text-[10px] font-bold">
                                        <span className="text-gray-400 uppercase">Abertura:</span>
                                        <span className="text-brand-900">{formatDate(client.createdAt)}</span>
                                    </div>
                                    <div className="flex justify-between text-[10px] font-bold">
                                        <span className="text-gray-400 uppercase">Tempo de Obra:</span>
                                        <span className="text-brand-900 font-black">{days} / 120 dias</span>
                                    </div>
                                    <div className={`mt-3 py-2 rounded-xl text-center text-[10px] font-black tracking-widest bg-white shadow-sm border border-gray-50 ${status.color}`}>
                                        {status.label}
                                    </div>
                                </div>
                            </div>

                            <div className="flex flex-col gap-1.5 mt-auto">
                                <span className="text-[9px] font-black text-gray-300 uppercase tracking-widest">Etapa Atual</span>
                                <div className="flex items-center gap-2">
                                    <span className="bg-brand-600 text-gold-400 p-1.5 rounded-lg shadow-sm"><Zap size={12} /></span>
                                    <span className="text-xs font-black text-brand-900 uppercase tracking-tight">{currentStage?.title}</span>
                                </div>
                            </div>
                        </div>
                    );
                })}
             </div>
        ) : (
            <div className="flex gap-6 p-6 h-full min-w-max">
                {STAGES.map(stage => {
                    const stageClients = clients.filter(c => c.currentStageId === stage.id);
                    return (
                        <div key={stage.id} onDragOver={handleDragOver} onDrop={e => handleDrop(e, stage.id)} className="w-80 shrink-0 bg-gray-100/30 rounded-3xl border border-gray-200 flex flex-col max-h-full shadow-sm">
                            <div className="p-5 font-black text-[10px] uppercase tracking-widest text-brand-600 border-b border-gray-200 flex justify-between bg-white rounded-t-3xl items-center sticky top-0">
                                <span>{stage.title}</span>
                                <span className="bg-brand-600 text-white px-2.5 py-1 rounded-full shadow-sm">{stageClients.length}</span>
                            </div>
                            <div className="p-4 overflow-y-auto flex flex-col gap-4 custom-scroll">
                                {stageClients.map(c => (
                                    <div key={c.id} draggable onDragStart={e => handleDragStart(e, c)} onClick={() => onSelectClient(c)} className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm cursor-grab active:cursor-grabbing hover:border-brand-400 transition-all hover:shadow-lg group">
                                        <p className="font-black text-xs text-brand-600 group-hover:text-brand-500 transition uppercase tracking-tight">{c.name}</p>
                                        <p className="text-[9px] text-gray-400 font-black uppercase mt-1 tracking-widest">{c.prgd}</p>
                                        <div className="mt-4 flex justify-between items-center text-[9px] font-black pt-3 border-t border-gray-50">
                                            <span className={`px-2 py-0.5 rounded-full ${calculateDaysElapsed(c.createdAt) > 120 ? 'bg-red-50 text-red-600' : 'bg-green-50 text-green-600'}`}>
                                                {calculateDaysElapsed(c.createdAt)} DIAS
                                            </span>
                                            <span className="text-gray-300 font-medium">#{c.clientNumber}</span>
                                        </div>
                                    </div>
                                ))}
                                {stageClients.length === 0 && (
                                  <div className="border-2 border-dashed border-gray-100 rounded-2xl p-8 flex flex-col items-center justify-center opacity-30">
                                    <User className="text-gray-300 mb-2" size={20} />
                                    <p className="text-[9px] font-black uppercase text-gray-400">Sem clientes</p>
                                  </div>
                                )}
                            </div>
                        </div>
                    );
                })}
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Client, Stage } from '../types.ts';
import { Plus, Search, User, Zap, List, Kanban, X, Timer, ChevronRight, AlertCircle, Clock } from 'lucide-react';
import { STAGES } from '../constants.ts';
import { generateTemplateContent } from '../services/templateService.ts';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onUpdateClientStage }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'list' | 'pipeline'>('list');

  const [draggedClientId, setDraggedClientId] = useState<string | null>(null);
  const [transitionTargetStage, setTransitionTargetStage] = useState<Stage | null>(null);
  const [transitionClientId, setTransitionClientId] = useState<string | null>(null);
  const [transitionValues, setTransitionValues] = useState<Record<string, string>>({});

  const [initialStageId, setInitialStageId] = useState<string>(STAGES[0].id);
  const [initialStageValues, setInitialStageValues] = useState<Record<string, string>>({});

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '',
    clientNumber: '',
    prgd: '',
    phone: '',
    projectName: '',
  });

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    if (!startStr) return 0;
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const activeClients = clients.filter(c => c.currentStageId !== '7');
  const deliveredClients = clients.filter(c => c.currentStageId === '7');

  // Cálculos de Status para o Header
  const statusCounts = activeClients.reduce((acc, c) => {
    const days = calculateDaysElapsed(c.createdAt);
    if (days > 120) acc.urgente++;
    else if (days > 90) acc.atencao++;
    else acc.noPrazo++;
    return acc;
  }, { noPrazo: 0, atencao: 0, urgente: 0 });

  const formatPhoneNumber = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 11) {
       return numbers.replace(/(\d{2})(\d{5})(\d{4})/, '($1) $2-$3');
    }
    return value;
  };

  const formatDate = (isoString: string) => {
    if (!isoString) return '-';
    return new Date(isoString).toLocaleDateString('pt-BR');
  };

  const getStatusInfo = (days: number, isDelivered: boolean) => {
    if (isDelivered) return { label: '🟢 CONCLUÍDO', color: 'text-green-600', bg: 'bg-green-50' };
    if (days > 120) return { label: '🔴 CRÍTICO', color: 'text-red-600', bg: 'bg-red-50' };
    if (days > 90) return { label: '🟡 ATENÇÃO', color: 'text-orange-500', bg: 'bg-orange-50' };
    return { label: '🟢 NO PRAZO', color: 'text-green-600', bg: 'bg-green-50' };
  };

  const openWhatsApp = (client: Client, stage: Stage, values: Record<string, string> = {}) => {
      if (!client.phone || !stage.template) return;
      const mergedValues = { ...client.stageData, ...values };
      const content = generateTemplateContent(stage, client, mergedValues);
      const cleanPhone = client.phone.replace(/\D/g, '');
      const encodedText = encodeURIComponent(content.body);
      window.open(`https://api.whatsapp.com/send?phone=55${cleanPhone}&text=${encodedText}`, '_blank');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name?.trim() || !formData.clientNumber?.trim() || !formData.prgd?.trim() || !formData.phone?.trim()) {
      alert("⚠️ Atenção: Nome, Telefone, PRGD e Número do Cliente são obrigatórios.");
      return;
    }

    const selectedStage = STAGES.find(s => s.id === initialStageId);
    const now = new Date().toISOString();
    const newClient: Client = {
      id: Date.now().toString(),
      name: formData.name || '',
      clientNumber: formData.clientNumber || '',
      prgd: formData.prgd || '',
      phone: formData.phone || '',
      projectName: formData.projectName || `Projeto ${formData.name}`,
      additionalNotes: '',
      currentStageId: initialStageId,
      createdAt: now,
      stageHistory: { [initialStageId]: now },
      stageData: initialStageValues
    };
    if (selectedStage?.template) openWhatsApp(newClient, selectedStage, initialStageValues);
    setIsCreating(false);
    onCreateClient(newClient);
    setFormData({ name: '', clientNumber: '', prgd: '', phone: '' });
  };

  const handleDragStart = (e: React.DragEvent, client: Client) => {
    e.dataTransfer.setData('clientId', client.id);
    setDraggedClientId(client.id);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };

  const handleDrop = (e: React.DragEvent, stageId: string) => {
    e.preventDefault();
    const clientId = e.dataTransfer.getData('clientId');
    setDraggedClientId(null);
    if (!clientId) return;

    const client = clients.find(c => c.id === clientId);
    const targetStage = STAGES.find(s => s.id === stageId);

    if (client && targetStage && client.currentStageId !== stageId) {
      if (targetStage.requiredFields && targetStage.requiredFields.length > 0) {
        setTransitionClientId(clientId);
        setTransitionTargetStage(targetStage);
      } else {
        onUpdateClientStage(clientId, stageId);
        if (targetStage.template) setTimeout(() => openWhatsApp(client, targetStage), 100);
      }
    }
  };

  const handleTransitionSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (transitionClientId && transitionTargetStage) {
      const client = clients.find(c => c.id === transitionClientId);
      onUpdateClientStage(transitionClientId, transitionTargetStage.id, transitionValues);
      if (client && transitionTargetStage.template) openWhatsApp(client, transitionTargetStage, transitionValues);
      setTransitionTargetStage(null);
      setTransitionClientId(null);
      setTransitionValues({});
    }
  };

  const filteredClients = clients.filter(c => 
    c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
    c.prgd.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-0 h-full flex flex-col relative overflow-hidden">
      {/* Modal de Criação Clean */}
      {isCreating && (
          <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
              <div className="bg-white rounded-3xl shadow-2xl w-full max-w-xl animate-scale-up border border-gray-100 overflow-hidden">
                  <div className="p-8 pb-4 flex justify-between items-center border-b border-gray-50">
                      <div>
                        <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">Novo Projeto</h2>
                        <p className="text-xs text-gray-400 font-bold uppercase tracking-widest">Os campos com * são obrigatórios</p>
                      </div>
                      <button onClick={() => setIsCreating(false)} className="p-2 hover:bg-gray-100 rounded-full transition text-gray-400 hover:text-brand-600"><X size={24} /></button>
                  </div>
                  <form onSubmit={handleSubmit} className="p-8 space-y-6 bg-white">
                      <div className="space-y-4">
                        <div className="group">
                          <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Nome do Titular *</label>
                          <input required placeholder="Ex: João Silva" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" onChange={e => setFormData({...formData, name: e.target.value})} />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Telefone *</label>
                            <input required placeholder="(00) 00000-0000" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" value={formData.phone} onChange={e => setFormData({...formData, phone: formatPhoneNumber(e.target.value)})} />
                          </div>
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Nº PRGD *</label>
                            <input required placeholder="Ex: GD-2024-00" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" onChange={e => setFormData({...formData, prgd: e.target.value})} />
                          </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Número Cliente *</label>
                            <input required placeholder="Ex: 100234" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" onChange={e => setFormData({...formData, clientNumber: e.target.value})} />
                          </div>
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Etapa Inicial</label>
                            <select value={initialStageId} onChange={e => setInitialStageId(e.target.value)} className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium">
                                {STAGES.map(s => <option key={s.id} value={s.id}>{s.stepNumber} - {s.title}</option>)}
                            </select>
                          </div>
                        </div>
                      </div>

                      <div className="pt-4">
                        <button type="submit" className="w-full bg-brand-500 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-sm hover:bg-brand-600 shadow-lg hover:shadow-brand-500/30 transition-all flex items-center justify-center gap-2">
                          <Zap size={18} className="text-gold-400" /> CADASTRAR PROJETO
                        </button>
                      </div>
                  </form>
              </div>
          </div>
      )}

      {/* Cabeçalho */}
      <div className="p-6 border-b flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-gray-50/30">
        <div>
          <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">Gestão de Carteira</h2>
          <div className="flex flex-wrap gap-2 mt-2">
              <span className="text-[9px] font-black bg-brand-50 text-brand-600 px-2.5 py-1 rounded-full uppercase tracking-widest border border-brand-100 shadow-sm">
                {activeClients.length} ATIVOS
              </span>
              <span className="text-[9px] font-black bg-green-50 text-green-600 px-2.5 py-1 rounded-full uppercase tracking-widest border border-green-100 shadow-sm">
                {deliveredClients.length} ENTREGUES
              </span>
              <div className="w-px h-4 bg-gray-200 mx-1 hidden sm:block self-center"></div>
              <span className="text-[9px] font-black bg-emerald-50 text-emerald-600 px-2.5 py-1 rounded-full uppercase tracking-widest border border-emerald-100 flex items-center gap-1 shadow-sm">
                <Clock size={10} /> {statusCounts.noPrazo} NO PRAZO
              </span>
              <span className="text-[9px] font-black bg-amber-50 text-amber-600 px-2.5 py-1 rounded-full uppercase tracking-widest border border-amber-100 flex items-center gap-1 shadow-sm">
                <AlertCircle size={10} /> {statusCounts.atencao} ATENÇÃO
              </span>
              <span className="text-[9px] font-black bg-red-50 text-red-600 px-2.5 py-1 rounded-full uppercase tracking-widest border border-red-100 flex items-center gap-1 shadow-sm">
                <AlertCircle size={10} /> {statusCounts.urgente} URGENTE
              </span>
          </div>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
             <div className="bg-white p-1.5 rounded-2xl flex border border-gray-100 shadow-sm flex-1 md:flex-none">
                <button onClick={() => setViewMode('list')} className={`flex-1 md:flex-none p-2.5 rounded-xl transition-all ${viewMode === 'list' ? 'bg-brand-600 text-white shadow-md' : 'text-gray-400 hover:bg-gray-50'}`} title="Visualização em Lista"><List size={18} className="mx-auto"/></button>
                <button onClick={() => setViewMode('pipeline')} className={`flex-1 md:flex-none p-2.5 rounded-xl transition-all ${viewMode === 'pipeline' ? 'bg-brand-600 text-white shadow-md' : 'text-gray-400 hover:bg-gray-50'}`} title="Visualização em Pipeline"><Kanban size={18} className="mx-auto"/></button>
             </div>
             <button onClick={() => setIsCreating(true)} className="flex-1 md:flex-none bg-brand-600 text-white px-6 py-3 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-brand-700 transition-all flex items-center justify-center gap-2">
                <Plus size={18} /> Criar Projeto
             </button>
        </div>
      </div>

      <div className="p-4 bg-white border-b">
         <div className="relative">
            <Search className="absolute left-4 top-3.5 text-gray-300" size={18} />
            <input placeholder="Buscar cliente ou PRGD..." className="w-full pl-12 p-3.5 rounded-2xl border-gray-100 border bg-gray-50 focus:bg-white outline-none transition" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
         </div>
      </div>

      {/* Área Principal com Scroll Horizontal Visível no Pipeline */}
      <div className={`flex-1 overflow-auto bg-gray-50/30 ${viewMode === 'pipeline' ? 'flex custom-scroll' : 'p-6'}`}>
        {viewMode === 'list' ? (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-8">
                {filteredClients.map(client => {
                    const isDelivered = client.currentStageId === '7';
                    const days = calculateDaysElapsed(client.createdAt, isDelivered ? client.stageHistory['7'] : undefined);
                    const status = getStatusInfo(days, isDelivered);
                    const currentStage = STAGES.find(s => s.id === client.currentStageId);

                    return (
                        <div key={client.id} onClick={() => onSelectClient(client)} className="bg-white border border-gray-100 rounded-3xl p-6 hover:border-brand-400 cursor-pointer transition-all shadow-sm hover:shadow-2xl group flex flex-col gap-5">
                            <div className="flex justify-between items-start">
                                <div>
                                    <h3 className="font-black text-brand-600 uppercase text-sm group-hover:text-brand-500 transition tracking-tight">{client.name}</h3>
                                    <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest mt-0.5">{client.prgd} • #{client.clientNumber}</p>
                                </div>
                                <div className="p-2 bg-gray-50 rounded-xl group-hover:bg-brand-50 transition">
                                  <ChevronRight size={16} className="text-gray-300 group-hover:text-brand-500 transition" />
                                </div>
                            </div>

                            <div className={`p-5 rounded-2xl border border-gray-100 flex flex-col gap-3 ${status.bg} shadow-inner`}>
                                <h4 className="text-[10px] font-black text-brand-800 uppercase tracking-widest flex items-center gap-1.5 opacity-60">
                                    <Timer size={12} /> Dashboard do Projeto
