                <div className="space-y-3">
                    <div className="flex justify-between text-xs font-medium">
                        <span className="text-gray-400">Início:</span>
                        <span className="text-brand-900">{info.start}</span>
                    </div>
                    <div className="flex justify-between text-xs font-medium">
                        <span className="text-gray-400">Permanência Etapa:</span>
                        <span className="font-bold text-brand-600">{info.daysInStage} dias</span>
                    </div>
                    <div className="flex justify-between text-xs font-medium">
                        <span className="text-gray-400">Dias Totais:</span>
                        <span className="font-bold text-brand-900">{info.elapsed} / 120</span>
                    </div>
                    <div className="pt-2 border-t border-gray-50 mt-2">
                        <div className={`text-xs font-black uppercase text-center py-2 rounded-xl bg-gray-50 ${info.statusColor}`}>
                            {info.statusLabel}
                        </div>
                    </div>
                </div>
           </div>

           <div>
               <h3 className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-4 flex items-center gap-2">
                   <History size={14} /> Histórico
               </h3>
               <div className="space-y-4">
                   {STAGES.filter(s => client.stageHistory[s.id]).map((s, idx, arr) => {
                       const completionDate = new Date(client.stageHistory[s.id]);
                       const prevDate = idx > 0 ? new Date(client.stageHistory[arr[idx-1].id]) : new Date(client.createdAt);
                       const diff = Math.floor(Math.abs(completionDate.getTime() - prevDate.getTime()) / (1000 * 60 * 60 * 24));

                       return (
                           <div key={s.id} className="relative pl-6 border-l-2 border-brand-100 pb-2">
                               <div className="absolute -left-[9px] top-0 w-4 h-4 rounded-full bg-brand-500 border-2 border-white flex items-center justify-center">
                                   <CheckCircle2 size={10} className="text-white" />
                               </div>
                               <div className="flex flex-col">
                                   <span className="text-xs font-bold text-brand-900">{s.title}</span>
                                   <div className="flex justify-between items-center mt-1">
                                       <span className="text-[10px] text-gray-400 font-medium">{completionDate.toLocaleDateString('pt-BR')}</span>
                                       <span className="text-[9px] bg-brand-50 text-brand-600 px-1.5 py-0.5 rounded font-bold">
                                           {diff}d
                                       </span>
                                   </div>
                               </div>
                           </div>
                       );
                   })}
               </div>
           </div>

           {requiredFields.length > 0 && (
               <div className="space-y-4 pt-4 border-t border-gray-100">
                   <h3 className="text-[10px] font-black uppercase text-brand-700 tracking-widest">Preencher Variáveis</h3>
                   {requiredFields.map(field => (
                       <div key={field}>
                           <label className="text-xs font-bold text-gray-500 mb-1 block capitalize">{field}</label>
                           <input 
                             type="text"
                             className="w-full p-3 bg-white border border-gray-200 rounded-xl text-sm focus:ring-2 focus:ring-brand-500/20 outline-none transition-all"
                             value={fieldValues[field] || client.stageData?.[field] || ''}
                             onChange={e => handleFieldChange(field, e.target.value)}
                             placeholder={`Informe ${field}...`}
                           />
                       </div>
                   ))}
               </div>
           )}
        </div>

        <div className="flex-1 p-6 flex flex-col gap-4 bg-white">
            <div className="flex-1 bg-gray-50 border border-gray-100 rounded-3xl overflow-hidden flex flex-col shadow-inner">
                <div className="bg-white/50 px-6 py-3 border-b border-gray-100 flex justify-between items-center">
                    <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Template de Mensagem</span>
                    <button onClick={() => copyToClipboard(editableBody)} className="flex items-center gap-1.5 text-xs font-black text-brand-600 hover:text-brand-800 transition">
                        <Copy size={14} /> Copiar Texto
                    </button>
                </div>
                {isEditing ? (
                    <textarea 
                      className="flex-1 p-8 text-sm font-sans resize-none outline-none leading-relaxed bg-transparent"
                      value={editableBody}
                      onChange={e => setEditableBody(e.target.value)}
                    />
                ) : (
                    <div className="flex-1 p-8 text-sm whitespace-pre-wrap font-sans overflow-y-auto leading-relaxed text-slate-700">
                        {editableBody}
                    </div>
                )}
            </div>
            <button 
                onClick={handleWhatsAppClick}
                disabled={!areAllFieldsFilled}
                className={`w-full py-4 rounded-2xl font-black uppercase tracking-widest flex items-center justify-center gap-3 transition-all shadow-xl
                    ${areAllFieldsFilled ? 'bg-[#25D366] text-white hover:bg-[#1fb355] scale-[1.01] active:scale-100' : 'bg-gray-200 text-gray-400 cursor-not-allowed'}`}
            >
                <Phone size={20} />
                Enviar via WhatsApp
            </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Client, Stage } from '../types.ts';
import { Plus, Search, User, Zap, List, Kanban, X, Timer, ChevronRight, AlertCircle, Clock, FilterX } from 'lucide-react';
import { STAGES } from '../constants.ts';
import { generateTemplateContent } from '../services/templateService.ts';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

type FilterStatus = 'ativos' | 'entregues' | 'noprazo' | 'atencao' | 'urgente' | null;

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onUpdateClientStage }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'list' | 'pipeline'>('list');
  const [statusFilter, setStatusFilter] = useState<FilterStatus>(null);

  const [draggedClientId, setDraggedClientId] = useState<string | null>(null);
  const [transitionTargetStage, setTransitionTargetStage] = useState<Stage | null>(null);
  const [transitionClientId, setTransitionClientId] = useState<string | null>(null);
  const [transitionValues, setTransitionValues] = useState<Record<string, string>>({});

  const [initialStageId, setInitialStageId] = useState<string>(STAGES[0].id);
  const [initialStageValues, setInitialStageValues] = useState<Record<string, string>>({});

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '',
    clientNumber: '',
    prgd: '',
    phone: '',
    projectName: '',
  });

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    if (!startStr) return 0;
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const activeClients = clients.filter(c => c.currentStageId !== '7');
  const deliveredClients = clients.filter(c => c.currentStageId === '7');

  // Cálculos de Status para o Header
  const statusCounts = activeClients.reduce((acc, c) => {
    const days = calculateDaysElapsed(c.createdAt);
    if (days > 120) acc.urgente++;
    else if (days > 90) acc.atencao++;
    else acc.noPrazo++;
    return acc;
  }, { noPrazo: 0, atencao: 0, urgente: 0 });

  const formatPhoneNumber = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 11) {
       return numbers.replace(/(\d{2})(\d{5})(\d{4})/, '($1) $2-$3');
    }
    return value;
  };

  const formatDate = (isoString: string) => {
    if (!isoString) return '-';
    return new Date(isoString).toLocaleDateString('pt-BR');
  };

  const getStatusInfo = (days: number, isDelivered: boolean) => {
    if (isDelivered) return { label: '🟢 CONCLUÍDO', color: 'text-green-600', bg: 'bg-green-50', key: 'entregues' };
    if (days > 120) return { label: '🔴 CRÍTICO', color: 'text-red-600', bg: 'bg-red-50', key: 'urgente' };
    if (days > 90) return { label: '🟡 ATENÇÃO', color: 'text-orange-500', bg: 'bg-orange-50', key: 'atencao' };
    return { label: '🟢 NO PRAZO', color: 'text-green-600', bg: 'bg-green-50', key: 'noprazo' };
  };

  const handleFilterToggle = (filter: FilterStatus) => {
    setStatusFilter(prev => prev === filter ? null : filter);
  };

  const openWhatsApp = (client: Client, stage: Stage, values: Record<string, string> = {}) => {
      if (!client.phone || !stage.template) return;
      const mergedValues = { ...client.stageData, ...values };
      const content = generateTemplateContent(stage, client, mergedValues);
      const cleanPhone = client.phone.replace(/\D/g, '');
      const encodedText = encodeURIComponent(content.body);
      window.open(`https://api.whatsapp.com/send?phone=55${cleanPhone}&text=${encodedText}`, '_blank');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name?.trim() || !formData.clientNumber?.trim() || !formData.prgd?.trim() || !formData.phone?.trim()) {
      alert("⚠️ Atenção: Nome, Telefone, PRGD e Número do Cliente são obrigatórios.");
      return;
    }

    const selectedStage = STAGES.find(s => s.id === initialStageId);
    const now = new Date().toISOString();
    const newClient: Client = {
      id: Date.now().toString(),
      name: formData.name || '',
      clientNumber: formData.clientNumber || '',
      prgd: formData.prgd || '',
      phone: formData.phone || '',
      projectName: formData.projectName || `Projeto ${formData.name}`,
      additionalNotes: '',
      currentStageId: initialStageId,
      createdAt: now,
      stageHistory: { [initialStageId]: now },
      stageData: initialStageValues
    };
    if (selectedStage?.template) openWhatsApp(newClient, selectedStage, initialStageValues);
    setIsCreating(false);
    onCreateClient(newClient);
    setFormData({ name: '', clientNumber: '', prgd: '', phone: '' });
  };

  const handleDragStart = (e: React.DragEvent, client: Client) => {
    e.dataTransfer.setData('clientId', client.id);
    setDraggedClientId(client.id);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };

  const handleDrop = (e: React.DragEvent, stageId: string) => {
    e.preventDefault();
    const clientId = e.dataTransfer.getData('clientId');
    setDraggedClientId(null);
    if (!clientId) return;

    const client = clients.find(c => c.id === clientId);
    const targetStage = STAGES.find(s => s.id === stageId);

    if (client && targetStage && client.currentStageId !== stageId) {
      if (targetStage.requiredFields && targetStage.requiredFields.length > 0) {
        setTransitionClientId(clientId);
        setTransitionTargetStage(targetStage);
      } else {
        onUpdateClientStage(clientId, stageId);
        if (targetStage.template) setTimeout(() => openWhatsApp(client, targetStage), 100);
      }
    }
  };

  const filteredClients = clients.filter(c => {
    const matchesSearch = c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          c.prgd.toLowerCase().includes(searchTerm.toLowerCase());

    if (!matchesSearch) return false;
    if (!statusFilter) return true;

    const isDelivered = c.currentStageId === '7';
    const days = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);
    const statusKey = getStatusInfo(days, isDelivered).key;

    if (statusFilter === 'ativos') return !isDelivered;
    return statusKey === statusFilter;
  });

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-0 h-full flex flex-col relative overflow-hidden">
      {/* Modal de Criação Clean */}
      {isCreating && (
          <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
              <div className="bg-white rounded-3xl shadow-2xl w-full max-w-xl animate-scale-up border border-gray-100 overflow-hidden">
                  <div className="p-8 pb-4 flex justify-between items-center border-b border-gray-50">
                      <div>
                        <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">Novo Projeto</h2>
                        <p className="text-xs text-gray-400 font-bold uppercase tracking-widest">Os campos com * são obrigatórios</p>
                      </div>
                      <button onClick={() => setIsCreating(false)} className="p-2 hover:bg-gray-100 rounded-full transition text-gray-400 hover:text-brand-600"><X size={24} /></button>
                  </div>
                  <form onSubmit={handleSubmit} className="p-8 space-y-6 bg-white">
                      <div className="space-y-4">
                        <div className="group">
                          <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Nome do Titular *</label>
                          <input required placeholder="Ex: João Silva" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" onChange={e => setFormData({...formData, name: e.target.value})} />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Telefone *</label>
                            <input required placeholder="(00) 00000-0000" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" value={formData.phone} onChange={e => setFormData({...formData, phone: formatPhoneNumber(e.target.value)})} />
                          </div>
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Nº PRGD *</label>
                            <input required placeholder="Ex: GD-2024-00" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" onChange={e => setFormData({...formData, prgd: e.target.value})} />
                          </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Número Cliente *</label>
                            <input required placeholder="Ex: 100234" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" onChange={e => setFormData({...formData, clientNumber: e.target.value})} />
                          </div>
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Etapa Inicial</label>
                            <select value={initialStageId} onChange={e => setInitialStageId(e.target.value)} className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium">
                                {STAGES.map(s => <option key={s.id} value={s.id}>{s.stepNumber} - {s.title}</option>)}
                            </select>
                          </div>
                        </div>
                      </div>

                      <div className="pt-4">
                        <button type="submit" className="w-full bg-brand-500 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-sm hover:bg-brand-600 shadow-lg hover:shadow-brand-500/30 transition-all flex items-center justify-center gap-2">
                          <Zap size={18} className="text-gold-400" /> CADASTRAR PROJETO
                        </button>
                      </div>
                  </form>
              </div>
          </div>
      )}

      {/* Cabeçalho com Filtros Interativos */}
      <div className="p-6 border-b flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-gray-50/30">
        <div>
          <div className="flex items-center gap-3">
            <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">Gestão de Carteira</h2>
            {statusFilter && (
              <button 
                onClick={() => setStatusFilter(null)} 
                className="flex items-center gap-1 text-[9px] font-black text-gray-400 hover:text-brand-600 uppercase transition"
                title="Limpar Filtros"
              >
                <FilterX size={12} /> Limpar
              </button>
            )}
          </div>
          <div className="flex flex-wrap gap-2 mt-2">
              <button 
                onClick={() => handleFilterToggle('ativos')}
                className={`text-[9px] font-black px-2.5 py-1 rounded-full uppercase tracking-widest border transition-all shadow-sm ${statusFilter === 'ativos' ? 'bg-brand-600 text-white border-brand-700 ring-2 ring-brand-200' : 'bg-brand-50 text-brand-600 border-brand-100 hover:bg-brand-100'}`}
              >
                {activeClients.length} ATIVOS
              </button>
              <button 
                onClick={() => handleFilterToggle('entregues')}
                className={`text-[9px] font-black px-2.5 py-1 rounded-full uppercase tracking-widest border transition-all shadow-sm ${statusFilter === 'entregues' ? 'bg-green-600 text-white border-green-700 ring-2 ring-green-200' : 'bg-green-50 text-green-600 border-green-100 hover:bg-green-100'}`}
              >
                {deliveredClients.length} ENTREGUES
              </button>
              <div className="w-px h-4 bg-gray-200 mx-1 hidden sm:block self-center"></div>
              <button 
                onClick={() => handleFilterToggle('noprazo')}
                className={`text-[9px] font-black px-2.5 py-1 rounded-full uppercase tracking-widest border flex items-center gap-1 transition-all shadow-sm ${statusFilter === 'noprazo' ? 'bg-emerald-600 text-white border-emerald-700 ring-2 ring-emerald-200' : 'bg-emerald-50 text-emerald-600 border-emerald-100 hover:bg-emerald-100'}`}
              >
                <Clock size={10} /> {statusCounts.noPrazo} NO PRAZO
              </button>
              <button 
                onClick={() => handleFilterToggle('atencao')}
                className={`text-[9px] font-black px-2.5 py-1 rounded-full uppercase tracking-widest border flex items-center gap-1 transition-all shadow-sm ${statusFilter === 'atencao' ? 'bg-amber-600 text-white border-amber-700 ring-2 ring-amber-200' : 'bg-amber-50 text-amber-600 border-amber-100 hover:bg-amber-100'}`}
              >
                <AlertCircle size={10} /> {statusCounts.atencao} ATENÇÃO
              </button>
              <button 
                onClick={() => handleFilterToggle('urgente')}
                className={`text-[9px] font-black px-2.5 py-1 rounded-full uppercase tracking-widest border flex items-center gap-1 transition-all shadow-sm ${statusFilter === 'urgente' ? 'bg-red-600 text-white border-red-700 ring-2 ring-red-200' : 'bg-red-50 text-red-600 border-red-100 hover:bg-red-100'}`}
              >
                <AlertCircle size={10} /> {statusCounts.urgente} URGENTE
              </button>
          </div>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
             <div className="bg-white p-1.5 rounded-2xl flex border border-gray-100 shadow-sm flex-1 md:flex-none">
                <button onClick={() => setViewMode('list')} className={`flex-1 md:flex-none p-2.5 rounded-xl transition-all ${viewMode === 'list' ? 'bg-brand-600 text-white shadow-md' : 'text-gray-400 hover:bg-gray-50'}`} title="Visualização em Lista"><List size={18} className="mx-auto"/></button>
                <button onClick={() => setViewMode('pipeline')} className={`flex-1 md:flex-none p-2.5 rounded-xl transition-all ${viewMode === 'pipeline' ? 'bg-brand-600 text-white shadow-md' : 'text-gray-400 hover:bg-gray-50'}`} title="Visualização em Pipeline"><Kanban size={18} className="mx-auto"/></button>
             </div>
             <button onClick={() => setIsCreating(true)} className="flex-1 md:flex-none bg-brand-600 text-white px-6 py-3 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-brand-700 transition-all flex items-center justify-center gap-2">
                <Plus size={18} /> Criar Projeto
             </button>
        </div>
      </div>

      <div className="p-4 bg-white border-b">
         <div className="relative">
            <Search className="absolute left-4 top-3.5 text-gray-300" size={18} />
            <input placeholder="Buscar cliente ou PRGD..." className="w-full pl-12 p-3.5 rounded-2xl border-gray-100 border bg-gray-50 focus:bg-white outline-none transition" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
         </div>
      </div>

      {/* Área Principal com Filtros Aplicados */}
      <div className={`flex-1 overflow-auto bg-gray-50/30 ${viewMode === 'pipeline' ? 'flex custom-scroll' : 'p-6'}`}>
        {viewMode === 'list' ? (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-8">
                {filteredClients.map(client => {
                    const isDelivered = client.currentStageId === '7';
                    const days = calculateDaysElapsed(client.createdAt, isDelivered ? client.stageHistory['7'] : undefined);
                    const status = getStatusInfo(days, isDelivered);
                    const currentStage = STAGES.find(s => s.id === client.currentStageId);

                    return (
                        <div key={client.id} onClick={() => onSelectClient(client)} className="bg-white border border-gray-100 rounded-3xl p-6 hover:border-brand-400 cursor-pointer transition-all shadow-sm hover:shadow-2xl group flex flex-col gap-5">
                            <div className="flex justify-between items-start">
                                <div>
                                    <h3 className="font-black text-brand-600 uppercase text-sm group-hover:text-brand-500 transition tracking-tight">{client.name}</h3>
                                    <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest mt-0.5">{client.prgd} • #{client.clientNumber}</p>
                                </div>
                                <div className="p-2 bg-gray-50 rounded-xl group-hover:bg-brand-50 transition">
                                  <ChevronRight size={16} className="text-gray-300 group-hover:text-brand-500 transition" />
                                </div>
                            </div>

                            <div className={`p-5 rounded-2xl border border-gray-100 flex flex-col gap-3 ${status.bg} shadow-inner`}>
                                <h4 className="text-[10px] font-black text-brand-800 uppercase tracking-widest flex items-center gap-1.5 opacity-60">
                                    <Timer size={12} /> Dashboard do Projeto
                                </h4>
                                <div className="space-y-1.5">
                                    <div className="flex justify-between text-[10px] font-bold">
                                        <span className="text-gray-400 uppercase">Abertura:</span>
                                        <span className="text-brand-900">{formatDate(client.createdAt)}</span>
                                    </div>
                                    <div className="flex justify-between text-[10px] font-bold">
                                        <span className="text-gray-400 uppercase">Tempo de Obra:</span>
                                        <span className="text-brand-900 font-black">{days} / 120 dias</span>
                                    </div>
                                    <div className={`mt-3 py-2 rounded-xl text-center text-[10px] font-black tracking-widest bg-white shadow-sm border border-gray-50 ${status.color}`}>
                                        {status.label}
                                    </div>
                                </div>
                            </div>

                            <div className="flex flex-col gap-1.5 mt-auto">
                                <span className="text-[9px] font-black text-gray-300 uppercase tracking-widest">Etapa Atual</span>
                                <div className="flex items-center gap-2">
                                    <span className="bg-brand-600 text-gold-400 p-1.5 rounded-lg shadow-sm"><Zap size={12} /></span>
                                    <span className="text-xs font-black text-brand-900 uppercase tracking-tight">{currentStage?.title}</span>
                                </div>
                            </div>
                        </div>
                    );
                })}
                {filteredClients.length === 0 && (
                  <div className="col-span-full py-20 flex flex-col items-center justify-center opacity-30">
                    <Search size={64} className="text-gray-300 mb-4" />
                    <p className="text-xl font-black uppercase tracking-widest text-gray-400">Nenhum projeto encontrado</p>
                  </div>
                )}
             </div>
        ) : (
            <div className="flex gap-6 p-6 h-full min-w-max">
                {STAGES.map(stage => {
                    const stageClients = filteredClients.filter(c => c.currentStageId === stage.id);
                    return (
                        <div key={stage.id} onDragOver={handleDragOver} onDrop={e => handleDrop(e, stage.id)} className="w-80 shrink-0 bg-gray-100/30 rounded-3xl border border-gray-200 flex flex-col max-h-full shadow-sm">
                            <div className="p-5 font-black text-[10px] uppercase tracking-widest text-brand-600 border-b border-gray-200 flex justify-between bg-white rounded-t-3xl items-center sticky top-0">
                                <span>{stage.title}</span>
                                <span className="bg-brand-600 text-white px-2.5 py-1 rounded-full shadow-sm">{stageClients.length}</span>
                            </div>
                            <div className="p-4 overflow-y-auto flex flex-col gap-4 custom-scroll">
                                {stageClients.map(c => {
                                    const isDelivered = c.currentStageId === '7';
                                    const entryDate = c.stageHistory[c.currentStageId] || c.createdAt;
                                    const daysInStage = calculateDaysElapsed(entryDate, isDelivered ? c.stageHistory['7'] : undefined);
                                    const totalDays = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);

                                    return (
                                        <div key={c.id} draggable onDragStart={e => handleDragStart(e, c)} onClick={() => onSelectClient(c)} className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm cursor-grab active:cursor-grabbing hover:border-brand-400 transition-all hover:shadow-lg group">
                                            <p className="font-black text-xs text-brand-600 group-hover:text-brand-500 transition uppercase tracking-tight">{c.name}</p>
                                            <p className="text-[9px] text-gray-400 font-black uppercase mt-1 tracking-widest">{c.prgd}</p>

                                            <div className="mt-3 bg-brand-50/50 p-2 rounded-xl border border-brand-100/30">
                                                <p className="text-[8px] font-black text-brand-400 uppercase tracking-widest mb-0.5">Nesta Etapa</p>
                                                <p className="text-[10px] font-black text-brand-700">{daysInStage} dias</p>
                                            </div>

                                            <div className="mt-4 flex justify-between items-center text-[9px] font-black pt-3 border-t border-gray-50">
                                                <span className={`px-2 py-0.5 rounded-full ${totalDays > 120 ? 'bg-red-50 text-red-600' : 'bg-green-50 text-green-600'}`}>
                                                    TOTAL: {totalDays} DIAS
                                                </span>
                                                <span className="text-gray-300 font-medium">#{c.clientNumber}</span>
                                            </div>
                                        </div>
                                    );
                                })}
                                {stageClients.length === 0 && (
                                  <div className="border-2 border-dashed border-gray-100 rounded-2xl p-8 flex flex-col items-center justify-center opacity-30">
                                    <User className="text-gray-300 mb-2" size={20} />
                                    <p className="text-[9px] font-black uppercase text-gray-400">Sem resultados</p>
                                  </div>
                                )}
                            </div>
                        </div>
                    );
                })}
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Timeline } from './components/Timeline.tsx';
import { ContentGenerator } from './components/ContentGenerator.tsx';
import { ClientList } from './components/ClientList.tsx';
import { Dashboard } from './components/Dashboard.tsx';
import { STAGES } from './constants.ts';
import { Client, Stage } from './types.ts';
import { ArrowLeft, Settings, Zap, BarChart3, LayoutList } from 'lucide-react';

export default function App() {
  const [view, setView] = useState<'list' | 'detail' | 'dashboard'>('list');
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [currentStageId, setCurrentStageId] = useState<string>(STAGES[0].id);
  const [clients, setClients] = useState<Client[]>([]);

  const handleCreateClient = (newClient: Client) => {
    setClients(prev => [newClient, ...prev]);
    handleSelectClient(newClient);
  };

  const handleSelectClient = (client: Client) => {
    setSelectedClientId(client.id);
    setCurrentStageId(client.currentStageId || STAGES[0].id);
    setView('detail');
  };

  const handleUpdateNotes = (notes: string) => {
    if (!selectedClientId) return;
    setClients(prev => prev.map(c => 
      c.id === selectedClientId ? { ...c, additionalNotes: notes } : c
    ));
  };

  const handleUpdateClientStage = (clientId: string, newStageId: string, stageData?: Record<string, string>) => {
    const now = new Date().toISOString();
    setClients(prev => prev.map(c => {
      if (c.id === clientId) {
        return { 
          ...c, 
          currentStageId: newStageId, 
          stageData: { ...c.stageData, ...stageData },
          stageHistory: { ...c.stageHistory, [newStageId]: now }
        };
      }
      return c;
    }));
    if (selectedClientId === clientId) {
      setCurrentStageId(newStageId);
    }
  };

  const selectedClient = clients.find(c => c.id === selectedClientId);
  const currentStage = STAGES.find(s => s.id === currentStageId) || STAGES[0];

  return (
    <div className="h-screen bg-gray-100 flex flex-col overflow-hidden font-sans">
      <header className="bg-brand-900 h-16 sm:h-20 shrink-0 shadow-lg relative z-50 print:hidden">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 h-full flex items-center justify-between">
          <div className="flex items-center gap-4">
            {view === 'detail' && (
              <button onClick={() => setView('list')} className="p-2 hover:bg-white/10 rounded-full text-gold-400 transition">
                <ArrowLeft size={20} />
              </button>
            )}
            <div className="flex flex-col">
              <h1 className="text-xl sm:text-2xl font-black text-white uppercase tracking-tighter">
                LOOP <span className="text-gold-500">ENERGIA</span>
              </h1>
              <p className="text-[9px] text-brand-400 uppercase tracking-widest font-bold">Gestão de Experiência</p>
            </div>
          </div>

          <div className="flex items-center gap-2 sm:gap-4">
             {/* Navegação Global */}
             <nav className="flex bg-brand-800/50 p-1 rounded-xl border border-brand-700/50 mr-4">
                <button 
                  onClick={() => setView('list')}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${view !== 'dashboard' ? 'bg-brand-600 text-white shadow-lg' : 'text-brand-300 hover:text-white'}`}
                >
                  <LayoutList size={14} /> <span className="hidden sm:inline">Carteira</span>
                </button>
                <button 
                  onClick={() => setView('dashboard')}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${view === 'dashboard' ? 'bg-brand-600 text-white shadow-lg' : 'text-brand-300 hover:text-white'}`}
                >
                  <BarChart3 size={14} /> <span className="hidden sm:inline">Dashboard</span>
                </button>
             </nav>

             <Zap className="text-gold-500 hidden md:block" size={20} />
             <Settings className="text-brand-300 hover:text-white cursor-pointer transition" size={20} />
          </div>
        </div>
      </header>

      <main className={`flex-1 overflow-hidden max-w-7xl mx-auto w-full px-4 sm:px-6 py-4 ${view === 'dashboard' ? 'overflow-y-auto custom-scroll print:overflow-visible print:max-w-none print:px-0' : ''}`}>
        {view === 'list' ? (
          <ClientList 
            clients={clients} 
            onSelectClient={handleSelectClient} 
            onCreateClient={handleCreateClient}
            onUpdateClientStage={handleUpdateClientStage}
          />
        ) : view === 'dashboard' ? (
          <Dashboard clients={clients} />
        ) : (
          <div className="flex flex-col h-full gap-4">
            <Timeline 
              currentStageId={currentStageId} 
              onSelectStage={(s) => setCurrentStageId(s.id)} 
            />
            <div className="flex-1 min-h-0">
              {selectedClient && (
                <ContentGenerator 
                  stage={currentStage}
                  client={selectedClient}
                  onUpdateNotes={handleUpdateNotes}
                  onUpdateClientStage={handleUpdateClientStage}
                />
              )}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

import React from 'react';
import { Client } from '../types.ts';
import { STAGES } from '../constants.ts';
import { 
  Trophy, 
  Clock, 
  TrendingUp, 
  Users, 
  Star, 
  Download, 
  Calendar, 
  CheckCircle, 
  AlertTriangle, 
  XCircle,
  BarChart3
} from 'lucide-react';

interface DashboardProps {
  clients: Client[];
}

export const Dashboard: React.FC<DashboardProps> = ({ clients }) => {
  // Lógica de métricas
  const total = clients.length;
  const delivered = clients.filter(c => c.currentStageId === '7').length;
  const active = total - delivered;

  const calculateDays = (start: string, end?: string) => {
    const s = new Date(start);
    const e = end ? new Date(end) : new Date();
    return Math.floor(Math.abs(e.getTime() - s.getTime()) / (1000 * 60 * 60 * 24));
  };

  // Tempo médio de entrega (Ciclo)
  const deliveredClients = clients.filter(c => c.currentStageId === '7');
  const avgDeliveryTime = deliveredClients.length > 0 
    ? Math.round(deliveredClients.reduce((acc, c) => acc + calculateDays(c.createdAt, c.stageHistory['7']), 0) / deliveredClients.length)
    : 0;

  // SLA % (Dentro dos 120 dias)
  const onTimeDeliveries = deliveredClients.filter(c => calculateDays(c.createdAt, c.stageHistory['7']) <= 120).length;
  const slaPercentage = deliveredClients.length > 0 ? Math.round((onTimeDeliveries / deliveredClients.length) * 100) : 100;

  // Status da Carteira Ativa
  const activeStatus = clients.filter(c => c.currentStageId !== '7').reduce((acc, c) => {
    const days = calculateDays(c.createdAt);
    if (days > 120) acc.urgente++;
    else if (days > 90) acc.atencao++;
    else acc.noprazo++;
    return acc;
  }, { noprazo: 0, atencao: 0, urgente: 0 });

  // Score Médio
  const calculateInternalScore = (client: Client) => {
    let score = 5;
    const isCompleted = client.currentStageId === '7';
    const elapsed = calculateDays(client.createdAt, isCompleted ? client.stageHistory['7'] : undefined);
    const stageEntry = new Date(client.stageHistory[client.currentStageId] || client.createdAt);
    const daysInStage = Math.floor(Math.abs(new Date().getTime() - stageEntry.getTime()) / (1000 * 60 * 60 * 24));

    if (elapsed > 120) score -= 2;
    else if (elapsed > 90) score -= 1;
    if (!isCompleted) {
      if (daysInStage > 30) score -= 2;
      else if (daysInStage > 15) score -= 1;
    }
    return Math.max(1, score);
  };

  const avgScore = total > 0 
    ? (clients.reduce((acc, c) => acc + calculateInternalScore(c), 0) / total).toFixed(1)
    : "5.0";

  // Carga por Etapa
  const stageDistribution = STAGES.map(s => ({
    title: s.title,
    count: clients.filter(c => c.currentStageId === s.id).length
  }));

  const maxStageCount = Math.max(...stageDistribution.map(s => s.count), 1);

  const handlePrint = () => {
    window.print();
  };

  return (
    <div className="space-y-8 pb-12 animate-in fade-in duration-500">
      {/* Cabeçalho do Dashboard */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white p-6 rounded-3xl border border-gray-100 shadow-sm print:shadow-none print:border-none">
        <div>
          <h2 className="text-3xl font-black text-brand-600 uppercase tracking-tighter flex items-center gap-3">
            <BarChart3 className="text-gold-500" size={32} /> Central de Indicadores
          </h2>
          <p className="text-xs text-gray-400 font-bold uppercase tracking-[0.2em] mt-1">Visão Analítica da Jornada do Cliente • Loop Energia</p>
        </div>
        <button 
          onClick={handlePrint}
          className="bg-brand-600 hover:bg-brand-700 text-white px-6 py-3 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl transition-all flex items-center gap-2 print:hidden"
        >
          <Download size={18} /> Exportar Relatório PDF
        </button>
      </div>

      {/* Grid de KPIs (Big Numbers) */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <KPICard 
          title="Total de Projetos" 
          value={total} 
          subtitle="Registrados no GEV" 
          icon={<Users className="text-brand-500" />} 
          trend="+8% este mês"
        />
        <KPICard 
          title="Taxa de SLA" 
          value={`${slaPercentage}%`} 
          subtitle="Entregues no prazo" 
          icon={<CheckCircle className="text-emerald-500" />} 
          color="text-emerald-600"
        />
        <KPICard 
          title="Ciclo Médio" 
          value={`${avgDeliveryTime} d`} 
          subtitle="Tempo médio de entrega" 
          icon={<Clock className="text-amber-500" />} 
        />
        <KPICard 
          title="Saúde da Equipe" 
          value={avgScore} 
          subtitle="Score Médio de Projetos" 
          icon={<Star className="text-gold-500" />} 
          isScore
        />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Gráfico 1: Status da Carteira */}
        <div className="bg-white p-8 rounded-[2rem] border border-gray-100 shadow-sm flex flex-col h-full">
          <h3 className="text-sm font-black text-brand-900 uppercase tracking-widest mb-8 border-b border-gray-50 pb-4">Distribuição por Status</h3>
          <div className="flex flex-1 items-center justify-around gap-8 flex-col sm:flex-row">
            {/* SVG Donut Chart */}
            <div className="relative w-48 h-48">
              <svg viewBox="0 0 36 36" className="w-full h-full transform -rotate-90">
                <path d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" fill="none" stroke="#f3f4f6" strokeWidth="3" />
                {total > 0 && (
                  <>
                    <path 
                      d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" 
                      fill="none" stroke="#10b981" strokeWidth="3" 
                      strokeDasharray={`${(activeStatus.noprazo/active || 0) * 100}, 100`} 
                    />
                    <path 
                      d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" 
                      fill="none" stroke="#f59e0b" strokeWidth="3" 
                      strokeDasharray={`${(activeStatus.atencao/active || 0) * 100}, 100`}
                      strokeDashoffset={`-${(activeStatus.noprazo/active || 0) * 100}`}
                    />
                    <path 
                      d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" 
                      fill="none" stroke="#ef4444" strokeWidth="3" 
                      strokeDasharray={`${(activeStatus.urgente/active || 0) * 100}, 100`}
                      strokeDashoffset={`-${((activeStatus.noprazo + activeStatus.atencao)/active || 0) * 100}`}
                    />
                  </>
                )}
              </svg>
              <div className="absolute inset-0 flex flex-col items-center justify-center">
                <span className="text-3xl font-black text-brand-900">{active}</span>
                <span className="text-[8px] font-bold text-gray-400 uppercase">Ativos</span>
              </div>
            </div>
            {/* Legenda */}
            <div className="space-y-4 flex-1">
              <StatusLegend color="bg-emerald-500" label="No Prazo" count={activeStatus.noprazo} total={active} />
              <StatusLegend color="bg-amber-500" label="Atenção" count={activeStatus.atencao} total={active} />
              <StatusLegend color="bg-red-500" label="Urgente" count={activeStatus.urgente} total={active} />
            </div>
          </div>
        </div>

        {/* Gráfico 2: Carga por Etapa */}
        <div className="bg-white p-8 rounded-[2rem] border border-gray-100 shadow-sm">
          <h3 className="text-sm font-black text-brand-900 uppercase tracking-widest mb-8 border-b border-gray-50 pb-4">Carga de Trabalho por Etapa</h3>
          <div className="space-y-4">
            {stageDistribution.map((s, i) => (
              <div key={i} className="space-y-1">
                <div className="flex justify-between text-[10px] font-black uppercase tracking-tight text-gray-500">
                  <span>{s.title}</span>
                  <span>{s.count} projetos</span>
                </div>
                <div className="h-3 bg-gray-50 rounded-full overflow-hidden border border-gray-100">
                  <div 
                    className="h-full bg-brand-500 rounded-full transition-all duration-1000" 
                    style={{ width: `${(s.count / maxStageCount) * 100}%` }}
                  />
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Relatório Detalhado (Oculto em tela, visível no Print) */}
      <div className="hidden print:block mt-12 space-y-8">
        <h3 className="text-xl font-black text-brand-900 uppercase border-b-2 border-brand-900 pb-2">Resumo Executivo</h3>
        <table className="w-full text-left border-collapse">
          <thead>
            <tr className="bg-gray-50 text-[10px] font-black uppercase tracking-widest text-gray-500">
              <th className="p-4 border">Cliente / PRGD</th>
              <th className="p-4 border">Entrada</th>
              <th className="p-4 border">Etapa Atual</th>
              <th className="p-4 border">Status</th>
              <th className="p-4 border">Score</th>
            </tr>
          </thead>
          <tbody>
            {clients.map(c => (
              <tr key={c.id} className="text-xs border-b">
                <td className="p-4 font-bold">{c.name} <br/><span className="text-[10px] font-normal text-gray-400">{c.prgd}</span></td>
                <td className="p-4">{new Date(c.createdAt).toLocaleDateString('pt-BR')}</td>
                <td className="p-4">{STAGES.find(s => s.id === c.currentStageId)?.title}</td>
                <td className="p-4 uppercase font-bold text-[9px]">
                  {calculateDays(c.createdAt) > 120 ? 'Crítico' : calculateDays(c.createdAt) > 90 ? 'Atenção' : 'No Prazo'}
                </td>
                <td className="p-4 font-black">{calculateInternalScore(c)}⭐</td>
              </tr>
            ))}
          </tbody>
        </table>
        <div className="text-center pt-10 text-gray-300 text-[10px] font-bold uppercase tracking-widest">
           Relatório gerado em {new Date().toLocaleString('pt-BR')} • Loop Energia - Sistema GEV
        </div>
      </div>
    </div>
  );
};

const KPICard = ({ title, value, subtitle, icon, color = "text-brand-900", trend, isScore = false }: any) => (
  <div className="bg-white p-6 rounded-3xl border border-gray-100 shadow-sm hover:shadow-md transition-all flex flex-col gap-4 relative overflow-hidden group">
    <div className="absolute top-0 right-0 w-24 h-24 bg-brand-50 rounded-full -mr-12 -mt-12 transition-all group-hover:scale-110"></div>
    <div className="bg-white p-3 rounded-2xl shadow-sm border border-gray-50 w-fit relative z-10">
      {icon}
    </div>
    <div className="relative z-10">
      <p className="text-[10px] font-black text-gray-400 uppercase tracking-[0.15em]">{title}</p>
      <div className="flex items-baseline gap-2">
        <h4 className={`text-3xl font-black ${color} tracking-tighter`}>{value}</h4>
        {isScore && <Star size={18} fill="#dbb832" className="text-gold-400" />}
      </div>
      <p className="text-[10px] text-gray-400 font-bold mt-1 uppercase tracking-tight">{subtitle}</p>
    </div>
    {trend && <div className="text-[9px] font-black text-emerald-600 mt-2 bg-emerald-50 w-fit px-2 py-0.5 rounded-full">{trend}</div>}
  </div>
);

const StatusLegend = ({ color, label, count, total }: any) => {
  const percentage = total > 0 ? Math.round((count / total) * 100) : 0;
  return (
    <div className="flex items-center justify-between p-3 rounded-2xl bg-gray-50/50 border border-gray-50">
      <div className="flex items-center gap-3">
        <div className={`w-3 h-3 rounded-full ${color}`}></div>
        <span className="text-[10px] font-black uppercase text-gray-600 tracking-wider">{label}</span>
      </div>
      <div className="flex gap-4">
        <span className="text-[10px] font-black text-brand-900">{count}</span>
        <span className="text-[10px] font-bold text-gray-300">{percentage}%</span>
      </div>
    </div>
  );
};

