        <span className="text-[10px] font-black text-brand-900">{count}</span>
        <span className="text-[9px] font-bold text-gray-300">{percentage}%</span>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Timeline } from './components/Timeline.tsx';
import { ContentGenerator } from './components/ContentGenerator.tsx';
import { ClientList } from './components/ClientList.tsx';
import { Dashboard } from './components/Dashboard.tsx';
import { Login } from './components/Login.tsx';
import { STAGES } from './constants.ts';
import { Client, Stage } from './types.ts';
import { ArrowLeft, Settings, Zap, BarChart3, LayoutList, LogOut } from 'lucide-react';

export default function App() {
  const [auth, setAuth] = useState<{ isAuthenticated: boolean; isVisitor: boolean } | null>(null);
  const [view, setView] = useState<'list' | 'detail' | 'dashboard'>('list');
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [currentStageId, setCurrentStageId] = useState<string>(STAGES[0].id);
  const [clients, setClients] = useState<Client[]>([]);

  // Carregar dados se for Admin
  useEffect(() => {
    if (auth?.isAuthenticated && !auth.isVisitor) {
      const saved = localStorage.getItem('gev_loop_clients');
      if (saved) {
        try {
          setClients(JSON.parse(saved));
        } catch (e) {
          console.error("Erro ao carregar dados salvos", e);
        }
      }
    }
  }, [auth]);

  // Salvar dados se for Admin
  useEffect(() => {
    if (auth?.isAuthenticated && !auth.isVisitor) {
      localStorage.setItem('gev_loop_clients', JSON.stringify(clients));
    }
  }, [clients, auth]);

  const handleLogin = (mode: 'visitor' | 'admin') => {
    setAuth({
      isAuthenticated: true,
      isVisitor: mode === 'visitor'
    });
  };

  const handleLogout = () => {
    if (window.confirm("Deseja realmente sair do sistema?")) {
      setAuth(null);
      setClients([]);
      setView('list');
      setSelectedClientId(null);
    }
  };

  const handleCreateClient = (newClient: Client) => {
    setClients(prev => [newClient, ...prev]);
    handleSelectClient(newClient);
  };

  const handleEditClient = (updatedClient: Client) => {
    setClients(prev => prev.map(c => c.id === updatedClient.id ? updatedClient : c));
  };

  const handleDeleteClient = (clientId: string) => {
    if (window.confirm("Tem certeza que deseja excluir este projeto? Esta ação não pode ser desfeita.")) {
      setClients(prev => prev.filter(c => c.id !== clientId));
      if (selectedClientId === clientId) {
        setView('list');
        setSelectedClientId(null);
      }
    }
  };

  const handleSelectClient = (client: Client) => {
    setSelectedClientId(client.id);
    setCurrentStageId(client.currentStageId || STAGES[0].id);
    setView('detail');
  };

  const handleUpdateNotes = (notes: string) => {
    if (!selectedClientId) return;
    setClients(prev => prev.map(c => 
      c.id === selectedClientId ? { ...c, additionalNotes: notes } : c
    ));
  };

  const handleUpdateClientStage = (clientId: string, newStageId: string, stageData?: Record<string, string>) => {
    const now = new Date().toISOString();
    setClients(prev => prev.map(c => {
      if (c.id === clientId) {
        return { 
          ...c, 
          currentStageId: newStageId, 
          stageData: { ...c.stageData, ...stageData },
          stageHistory: { ...c.stageHistory, [newStageId]: now }
        };
      }
      return c;
    }));
    if (selectedClientId === clientId) {
      setCurrentStageId(newStageId);
    }
  };

  if (!auth?.isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  const selectedClient = clients.find(c => c.id === selectedClientId);
  const currentStage = STAGES.find(s => s.id === currentStageId) || STAGES[0];

  return (
    <div className="h-screen bg-gray-100 flex flex-col overflow-hidden font-sans">
      <header className="bg-brand-900 h-16 sm:h-20 shrink-0 shadow-lg relative z-50 print:hidden">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 h-full flex items-center justify-between">
          <div className="flex items-center gap-4">
            {view === 'detail' && (
              <button onClick={() => setView('list')} className="p-2 hover:bg-white/10 rounded-full text-gold-400 transition">
                <ArrowLeft size={20} />
              </button>
            )}
            <div className="flex flex-col">
              <h1 className="text-xl sm:text-2xl font-black text-white uppercase tracking-tighter leading-none">
                LOOP <span className="text-gold-500">ENERGIA</span>
              </h1>
              <div className="flex items-center gap-2">
                <p className="text-[8px] text-brand-400 uppercase tracking-widest font-bold">Gestão de Experiência</p>
                <span className={`text-[7px] px-1.5 py-0.5 rounded font-black uppercase ${auth.isVisitor ? 'bg-amber-500/20 text-amber-500' : 'bg-emerald-500/20 text-emerald-500'}`}>
                  {auth.isVisitor ? 'Visitante' : 'Admin'}
                </span>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-2 sm:gap-4">
             <nav className="flex bg-brand-800/50 p-1 rounded-xl border border-brand-700/50 mr-2 sm:mr-4">
                <button 
                  onClick={() => setView('list')}
                  className={`flex items-center gap-2 px-3 sm:px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${view !== 'dashboard' ? 'bg-brand-600 text-white shadow-lg' : 'text-brand-300 hover:text-white'}`}
                >
                  <LayoutList size={14} /> <span className="hidden sm:inline">Carteira</span>
                </button>
                <button 
                  onClick={() => setView('dashboard')}
                  className={`flex items-center gap-2 px-3 sm:px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${view === 'dashboard' ? 'bg-brand-600 text-white shadow-lg' : 'text-brand-300 hover:text-white'}`}
                >
                  <BarChart3 size={14} /> <span className="hidden sm:inline">Dashboard</span>
                </button>
             </nav>

             <div className="h-8 w-px bg-brand-800 hidden md:block"></div>

             <button 
               onClick={handleLogout}
               className="p-2 text-brand-300 hover:text-red-400 hover:bg-white/5 rounded-full transition flex items-center gap-2 group"
               title="Sair do Sistema"
             >
               <LogOut size={20} />
               <span className="hidden lg:inline text-[10px] font-black uppercase tracking-widest">Sair</span>
             </button>
          </div>
        </div>
      </header>

      <main className={`flex-1 overflow-hidden max-w-7xl mx-auto w-full px-4 sm:px-6 py-4 ${view === 'dashboard' ? 'overflow-y-auto custom-scroll print:overflow-visible print:max-w-none print:px-0' : ''}`}>
        {view === 'list' ? (
          <ClientList 
            clients={clients} 
            onSelectClient={handleSelectClient} 
            onCreateClient={handleCreateClient}
            onEditClient={handleEditClient}
            onDeleteClient={handleDeleteClient}
            onUpdateClientStage={handleUpdateClientStage}
          />
        ) : view === 'dashboard' ? (
          <Dashboard clients={clients} />
        ) : (
          <div className="flex flex-col h-full gap-4">
            <Timeline 
              currentStageId={currentStageId} 
              onSelectStage={(s) => setCurrentStageId(s.id)} 
            />
            <div className="flex-1 min-h-0">
              {selectedClient && (
                <ContentGenerator 
                  stage={currentStage}
                  client={selectedClient}
                  onUpdateNotes={handleUpdateNotes}
                  onUpdateClientStage={handleUpdateClientStage}
                />
              )}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

import React, { useState } from 'react';
import { Zap, User, Lock, ArrowRight, ShieldCheck, Eye, EyeOff } from 'lucide-react';

