    setTimeout(() => {
      if (username === 'Loop' && password === '1234') {
        onLogin('admin');
      } else {
        setError('Credenciais inválidas. Tente novamente.');
        setIsLoading(false);
      }
    }, 800);
  };

  return (
    <div className="h-screen w-full bg-brand-900 flex items-center justify-center p-4 relative overflow-hidden font-sans">
      {/* Background Decorativo */}
      <div className="absolute top-0 right-0 w-[500px] h-[500px] bg-brand-800 rounded-full blur-[100px] -mr-64 -mt-64 opacity-50"></div>
      <div className="absolute bottom-0 left-0 w-[400px] h-[400px] bg-gold-500 rounded-full blur-[120px] -ml-48 -mb-48 opacity-10"></div>

      <div className="w-full max-w-md relative z-10 animate-in fade-in zoom-in duration-500">
        <div className="bg-white rounded-[2.5rem] shadow-2xl overflow-hidden border border-brand-800/20">

          <div className="bg-brand-600 p-10 text-center flex flex-col items-center">
            <div className="bg-white p-4 rounded-3xl shadow-xl mb-6 scale-110">
              <Zap className="text-brand-600" size={32} />
            </div>
            <h1 className="text-3xl font-black text-white uppercase tracking-tighter leading-none">
              LOOP <span className="text-gold-400">ENERGIA</span>
            </h1>
            <p className="text-[10px] text-brand-200 uppercase tracking-[0.3em] font-bold mt-2">Gestão de Experiência do Cliente</p>
          </div>

          <div className="p-10">
            <form onSubmit={handleAdminLogin} className="space-y-6">
              <div>
                <label className="text-[10px] font-black uppercase text-brand-900 tracking-widest mb-2 block">Usuário</label>
                <div className="relative">
                  <User className="absolute left-4 top-3.5 text-gray-300" size={18} />
                  <input 
                    type="text" 
                    value={username}
                    onChange={(e) => setUsername(e.target.value)}
                    placeholder="Nome de usuário"
                    className="w-full pl-12 p-3.5 bg-gray-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium"
                  />
                </div>
              </div>

              <div>
                <label className="text-[10px] font-black uppercase text-brand-900 tracking-widest mb-2 block">Senha</label>
                <div className="relative">
                  <Lock className="absolute left-4 top-3.5 text-gray-300" size={18} />
                  <input 
                    type={showPassword ? "text" : "password"}
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    placeholder="••••••••"
                    className="w-full pl-12 pr-12 p-3.5 bg-gray-50 border border-gray-100 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium"
                  />
                  <button 
                    type="button"
                    onClick={() => setShowPassword(!showPassword)}
                    className="absolute right-4 top-3.5 text-gray-300 hover:text-brand-600 transition"
                  >
                    {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                  </button>
                </div>
              </div>

              {error && (
                <p className="text-red-500 text-[10px] font-bold uppercase text-center animate-bounce">{error}</p>
              )}

              <button 
                type="submit"
                disabled={isLoading}
                className="w-full bg-brand-600 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-brand-700 shadow-xl hover:shadow-brand-500/30 transition-all flex items-center justify-center gap-2 group"
              >
                {isLoading ? (
                  <div className="w-4 h-4 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                ) : (
                  <>Acessar Painel <ArrowRight size={16} className="group-hover:translate-x-1 transition-transform" /></>
                )}
              </button>
            </form>

            <div className="relative my-8">
              <div className="absolute inset-0 flex items-center"><div className="w-full border-t border-gray-100"></div></div>
              <div className="relative flex justify-center text-[10px] uppercase font-black tracking-widest text-gray-300">
                <span className="bg-white px-4">Ou se preferir</span>
              </div>
            </div>

            <button 
              onClick={() => onLogin('visitor')}
              className="w-full bg-gray-50 text-gray-500 py-4 rounded-2xl font-black uppercase tracking-widest text-[10px] hover:bg-gray-100 transition-all flex items-center justify-center gap-2"
            >
              Entrar como Visitante
            </button>
          </div>
        </div>

        <div className="mt-8 text-center">
          <p className="text-[10px] text-brand-400 font-bold uppercase tracking-widest opacity-60">© 2024 Loop Energia • Sistema de Gestão GEV</p>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Client, Stage } from '../types.ts';
import { Plus, Search, User, Zap, List, Kanban, X, Timer, ChevronRight, AlertCircle, Clock, FilterX, Trash2, Edit3 } from 'lucide-react';
import { STAGES } from '../constants.ts';
import { generateTemplateContent } from '../services/templateService.ts';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onEditClient: (client: Client) => void;
  onDeleteClient: (clientId: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

type FilterStatus = 'ativos' | 'entregues' | 'noprazo' | 'atencao' | 'urgente' | null;

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onEditClient, onDeleteClient, onUpdateClientStage }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'list' | 'pipeline'>('list');
  const [statusFilter, setStatusFilter] = useState<FilterStatus>(null);

  const [draggedClientId, setDraggedClientId] = useState<string | null>(null);
  const [transitionTargetStage, setTransitionTargetStage] = useState<Stage | null>(null);
  const [transitionClientId, setTransitionClientId] = useState<string | null>(null);
  const [transitionValues, setTransitionValues] = useState<Record<string, string>>({});

  const [initialStageId, setInitialStageId] = useState<string>(STAGES[0].id);

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '',
    clientNumber: '',
    prgd: '',
    phone: '',
    projectName: '',
  });

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    if (!startStr) return 0;
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const activeClients = clients.filter(c => c.currentStageId !== '7');
  const deliveredClients = clients.filter(c => c.currentStageId === '7');

  const statusCounts = activeClients.reduce((acc, c) => {
    const days = calculateDaysElapsed(c.createdAt);
    if (days > 120) acc.urgente++;
    else if (days > 90) acc.atencao++;
    else acc.noPrazo++;
    return acc;
  }, { noPrazo: 0, atencao: 0, urgente: 0 });

  const formatPhoneNumber = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 11) {
       return numbers.replace(/(\d{2})(\d{5})(\d{4})/, '($1) $2-$3');
    }
    return value;
  };

  const formatDate = (isoString: string) => {
    if (!isoString) return '-';
    return new Date(isoString).toLocaleDateString('pt-BR');
  };

  const getStatusInfo = (days: number, isDelivered: boolean) => {
    if (isDelivered) return { label: '🟢 CONCLUÍDO', color: 'text-green-600', bg: 'bg-green-50', key: 'entregues' };
    if (days > 120) return { label: '🔴 CRÍTICO', color: 'text-red-600', bg: 'bg-red-50', key: 'urgente' };
    if (days > 90) return { label: '🟡 ATENÇÃO', color: 'text-orange-500', bg: 'bg-orange-50', key: 'atencao' };
    return { label: '🟢 NO PRAZO', color: 'text-green-600', bg: 'bg-green-50', key: 'noprazo' };
  };

  const handleFilterToggle = (filter: FilterStatus) => {
    setStatusFilter(prev => prev === filter ? null : filter);
  };

  const openWhatsApp = (client: Client, stage: Stage, values: Record<string, string> = {}) => {
      if (!client.phone || !stage.template) return;
      const mergedValues = { ...client.stageData, ...values };
      const content = generateTemplateContent(stage, client, mergedValues);
      const cleanPhone = client.phone.replace(/\D/g, '');
      const encodedText = encodeURIComponent(content.body);
      window.open(`https://api.whatsapp.com/send?phone=55${cleanPhone}&text=${encodedText}`, '_blank');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name?.trim() || !formData.clientNumber?.trim() || !formData.prgd?.trim() || !formData.phone?.trim()) {
      alert("⚠️ Atenção: Nome, Telefone, PRGD e Número do Cliente são obrigatórios.");
      return;
    }

    if (editingClient) {
      const updatedClient: Client = {
        ...editingClient,
        name: formData.name || '',
        clientNumber: formData.clientNumber || '',
        prgd: formData.prgd || '',
        phone: formData.phone || '',
        projectName: formData.projectName || `Projeto ${formData.name}`,
        currentStageId: initialStageId
      };
      onEditClient(updatedClient);
    } else {
      const now = new Date().toISOString();
      const newClient: Client = {
        id: Date.now().toString(),
        name: formData.name || '',
        clientNumber: formData.clientNumber || '',
        prgd: formData.prgd || '',
        phone: formData.phone || '',
        projectName: formData.projectName || `Projeto ${formData.name}`,
        additionalNotes: '',
        currentStageId: initialStageId,
        createdAt: now,
        stageHistory: { [initialStageId]: now },
        stageData: {}
      };
      const selectedStage = STAGES.find(s => s.id === initialStageId);
      if (selectedStage?.template) openWhatsApp(newClient, selectedStage);
      onCreateClient(newClient);
    }

    closeModal();
  };

  const handleStartEdit = (client: Client, e: React.MouseEvent) => {
    e.stopPropagation();
    setEditingClient(client);
    setFormData({
      name: client.name,
      clientNumber: client.clientNumber,
      prgd: client.prgd,
      phone: client.phone,
      projectName: client.projectName
    });
    setInitialStageId(client.currentStageId);
    setIsCreating(true);
  };

  const handleDelete = (clientId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    onDeleteClient(clientId);
  };

  const closeModal = () => {
    setIsCreating(false);
    setEditingClient(null);
    setFormData({ name: '', clientNumber: '', prgd: '', phone: '', projectName: '' });
  };

  const handleDragStart = (e: React.DragEvent, client: Client) => {
    e.dataTransfer.setData('clientId', client.id);
    setDraggedClientId(client.id);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };

  const handleDrop = (e: React.DragEvent, stageId: string) => {
    e.preventDefault();
    const clientId = e.dataTransfer.getData('clientId');
    setDraggedClientId(null);
    if (!clientId) return;

    const client = clients.find(c => c.id === clientId);
    const targetStage = STAGES.find(s => s.id === stageId);

    if (client && targetStage && client.currentStageId !== stageId) {
      onUpdateClientStage(clientId, stageId);
      if (targetStage.template) setTimeout(() => openWhatsApp(client, targetStage), 100);
    }
  };

  const filteredClients = clients.filter(c => {
    const matchesSearch = c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          c.prgd.toLowerCase().includes(searchTerm.toLowerCase());

    if (!matchesSearch) return false;
    if (!statusFilter) return true;

    const isDelivered = c.currentStageId === '7';
    const days = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);
    const statusKey = getStatusInfo(days, isDelivered).key;

    if (statusFilter === 'ativos') return !isDelivered;
    return statusKey === statusFilter;
  });

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-0 h-full flex flex-col relative overflow-hidden">
      {/* Modal de Criação / Edição */}
      {isCreating && (
          <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
              <div className="bg-white rounded-3xl shadow-2xl w-full max-w-xl animate-scale-up border border-gray-100 overflow-hidden">
                  <div className="p-8 pb-4 flex justify-between items-center border-b border-gray-50">
                      <div>
                        <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">
                          {editingClient ? 'Editar Projeto' : 'Novo Projeto'}
                        </h2>
                        <p className="text-xs text-gray-400 font-bold uppercase tracking-widest">
                          {editingClient ? `Editando registro de ${editingClient.name}` : 'Os campos com * são obrigatórios'}
                        </p>
                      </div>
                      <button onClick={closeModal} className="p-2 hover:bg-gray-100 rounded-full transition text-gray-400 hover:text-brand-600"><X size={24} /></button>
                  </div>
                  <form onSubmit={handleSubmit} className="p-8 space-y-6 bg-white">
                      <div className="space-y-4">
                        <div className="group">
                          <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Nome do Titular *</label>
                          <input required value={formData.name} placeholder="Ex: João Silva" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" onChange={e => setFormData({...formData, name: e.target.value})} />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Telefone *</label>
                            <input required placeholder="(00) 00000-0000" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" value={formData.phone} onChange={e => setFormData({...formData, phone: formatPhoneNumber(e.target.value)})} />
                          </div>
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Nº PRGD *</label>
                            <input required value={formData.prgd} placeholder="Ex: GD-2024-00" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" onChange={e => setFormData({...formData, prgd: e.target.value})} />
                          </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Número Cliente *</label>
                            <input required value={formData.clientNumber} placeholder="Ex: 100234" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" onChange={e => setFormData({...formData, clientNumber: e.target.value})} />
                          </div>
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Etapa Atual</label>
                            <select value={initialStageId} onChange={e => setInitialStageId(e.target.value)} className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium">
                                {STAGES.map(s => <option key={s.id} value={s.id}>{s.stepNumber} - {s.title}</option>)}
                            </select>
                          </div>
                        </div>
                      </div>

                      <div className="pt-4">
                        <button type="submit" className="w-full bg-brand-500 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-sm hover:bg-brand-600 shadow-lg hover:shadow-brand-500/30 transition-all flex items-center justify-center gap-2">
                          <Zap size={18} className="text-gold-400" /> {editingClient ? 'SALVAR ALTERAÇÕES' : 'CADASTRAR PROJETO'}
                        </button>
                      </div>
                  </form>
              </div>
          </div>
      )}

      {/* Cabeçalho */}
      <div className="p-6 border-b flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-gray-50/30">
        <div>
          <div className="flex items-center gap-3">
            <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">Gestão de Carteira</h2>
            {statusFilter && (
              <button onClick={() => setStatusFilter(null)} className="flex items-center gap-1 text-[9px] font-black text-gray-400 hover:text-brand-600 uppercase transition"><FilterX size={12} /> Limpar</button>
            )}
          </div>
          <div className="flex flex-wrap gap-2 mt-2">
              <button onClick={() => handleFilterToggle('ativos')} className={`text-[9px] font-black px-2.5 py-1 rounded-full uppercase tracking-widest border transition-all shadow-sm ${statusFilter === 'ativos' ? 'bg-brand-600 text-white border-brand-700' : 'bg-brand-50 text-brand-600 border-brand-100'}`}>{activeClients.length} ATIVOS</button>
              <button onClick={() => handleFilterToggle('entregues')} className={`text-[9px] font-black px-2.5 py-1 rounded-full uppercase tracking-widest border transition-all shadow-sm ${statusFilter === 'entregues' ? 'bg-green-600 text-white border-green-700' : 'bg-green-50 text-green-600 border-green-100'}`}>{deliveredClients.length} ENTREGUES</button>
              <div className="w-px h-4 bg-gray-200 mx-1 hidden sm:block self-center"></div>
              <button onClick={() => handleFilterToggle('noprazo')} className={`text-[9px] font-black px-2.5 py-1 rounded-full uppercase tracking-widest border flex items-center gap-1 transition-all shadow-sm ${statusFilter === 'noprazo' ? 'bg-emerald-600 text-white' : 'bg-emerald-50 text-emerald-600'}`}>{statusCounts.noPrazo} NO PRAZO</button>
              <button onClick={() => handleFilterToggle('atencao')} className={`text-[9px] font-black px-2.5 py-1 rounded-full uppercase tracking-widest border flex items-center gap-1 transition-all shadow-sm ${statusFilter === 'atencao' ? 'bg-amber-600 text-white' : 'bg-amber-50 text-amber-600'}`}>{statusCounts.atencao} ATENÇÃO</button>
              <button onClick={() => handleFilterToggle('urgente')} className={`text-[9px] font-black px-2.5 py-1 rounded-full uppercase tracking-widest border flex items-center gap-1 transition-all shadow-sm ${statusFilter === 'urgente' ? 'bg-red-600 text-white' : 'bg-red-50 text-red-600'}`}>{statusCounts.urgente} URGENTE</button>
          </div>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
             <div className="bg-white p-1.5 rounded-2xl flex border border-gray-100 shadow-sm flex-1 md:flex-none">
                <button onClick={() => setViewMode('list')} className={`flex-1 md:flex-none p-2.5 rounded-xl transition-all ${viewMode === 'list' ? 'bg-brand-600 text-white shadow-md' : 'text-gray-400 hover:bg-gray-50'}`}><List size={18} className="mx-auto"/></button>
                <button onClick={() => setViewMode('pipeline')} className={`flex-1 md:flex-none p-2.5 rounded-xl transition-all ${viewMode === 'pipeline' ? 'bg-brand-600 text-white shadow-md' : 'text-gray-400 hover:bg-gray-50'}`}><Kanban size={18} className="mx-auto"/></button>
             </div>
             <button onClick={() => setIsCreating(true)} className="flex-1 md:flex-none bg-brand-600 text-white px-6 py-3 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-brand-700 transition-all flex items-center justify-center gap-2">
                <Plus size={18} /> Criar Projeto
             </button>
        </div>
      </div>

      <div className="p-4 bg-white border-b">
         <div className="relative">
            <Search className="absolute left-4 top-3.5 text-gray-300" size={18} />
            <input placeholder="Buscar cliente ou PRGD..." className="w-full pl-12 p-3.5 rounded-2xl border-gray-100 border bg-gray-50 focus:bg-white outline-none transition" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
         </div>
      </div>

      <div className={`flex-1 overflow-auto bg-gray-50/30 ${viewMode === 'pipeline' ? 'flex custom-scroll' : 'p-6'}`}>
        {viewMode === 'list' ? (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-8">
                {filteredClients.map(client => {
                    const isDelivered = client.currentStageId === '7';
                    const days = calculateDaysElapsed(client.createdAt, isDelivered ? client.stageHistory['7'] : undefined);
                    const status = getStatusInfo(days, isDelivered);
                    const currentStage = STAGES.find(s => s.id === client.currentStageId);

                    return (
                        <div key={client.id} onClick={() => onSelectClient(client)} className="bg-white border border-gray-100 rounded-3xl p-6 hover:border-brand-400 cursor-pointer transition-all shadow-sm hover:shadow-2xl group flex flex-col gap-4 relative overflow-hidden">
                            <div className="flex justify-between items-start">
                                <div>
                                    <h3 className="font-black text-brand-600 uppercase text-sm group-hover:text-brand-500 transition tracking-tight truncate max-w-[180px]">{client.name}</h3>
                                    <p className="text-[10px] text-gray-400 font-black uppercase tracking-widest mt-0.5">{client.prgd} • #{client.clientNumber}</p>
                                </div>
                                <div className="flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                                  <button onClick={(e) => handleStartEdit(client, e)} className="p-2 bg-gray-50 hover:bg-brand-50 text-gray-400 hover:text-brand-600 rounded-xl transition" title="Editar"><Edit3 size={14}/></button>
                                  <button onClick={(e) => handleDelete(client.id, e)} className="p-2 bg-gray-50 hover:bg-red-50 text-gray-400 hover:text-red-500 rounded-xl transition" title="Excluir"><Trash2 size={14}/></button>
                                </div>
                            </div>

                            <div className={`p-5 rounded-2xl border border-gray-100 flex flex-col gap-3 ${status.bg} shadow-inner`}>
                                <div className="flex justify-between text-[10px] font-bold">
                                    <span className="text-gray-400 uppercase">Tempo:</span>
                                    <span className="text-brand-900 font-black">{days} / 120 dias</span>
                                </div>
                                <div className={`py-1.5 rounded-xl text-center text-[9px] font-black tracking-widest bg-white shadow-sm border border-gray-50 ${status.color}`}>
                                    {status.label}
                                </div>
                            </div>

                            <div className="flex items-center gap-2 mt-2">
                                <span className="bg-brand-600 text-gold-400 p-1.5 rounded-lg"><Zap size={10} /></span>
                                <span className="text-[10px] font-black text-brand-900 uppercase tracking-tight truncate">{currentStage?.title}</span>
                            </div>
                        </div>
                    );
                })}
             </div>
        ) : (
            <div className="flex gap-6 p-6 h-full min-w-max">
                {STAGES.map(stage => {
                    const stageClients = filteredClients.filter(c => c.currentStageId === stage.id);
                    return (
                        <div key={stage.id} onDragOver={handleDragOver} onDrop={e => handleDrop(e, stage.id)} className="w-80 shrink-0 bg-gray-100/30 rounded-3xl border border-gray-200 flex flex-col max-h-full shadow-sm">
                            <div className="p-5 font-black text-[10px] uppercase tracking-widest text-brand-600 border-b border-gray-200 flex justify-between bg-white rounded-t-3xl items-center sticky top-0 z-10">
                                <span>{stage.title}</span>
                                <span className="bg-brand-600 text-white px-2.5 py-1 rounded-full shadow-sm">{stageClients.length}</span>
                            </div>
                            <div className="p-4 overflow-y-auto flex flex-col gap-4 custom-scroll">
                                {stageClients.map(c => {
                                    const totalDays = calculateDaysElapsed(c.createdAt, c.currentStageId === '7' ? c.stageHistory['7'] : undefined);
                                    return (
                                        <div key={c.id} draggable onDragStart={e => handleDragStart(e, c)} onClick={() => onSelectClient(c)} className="bg-white p-5 rounded-2xl border border-gray-100 shadow-sm cursor-grab active:cursor-grabbing hover:border-brand-400 transition-all hover:shadow-lg group">
                                            <div className="flex justify-between items-start mb-2">
                                              <p className="font-black text-[11px] text-brand-600 uppercase tracking-tight leading-tight truncate max-w-[120px]">{c.name}</p>
                                              <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                                <button onClick={(e) => handleStartEdit(c, e)} className="p-1.5 bg-gray-50 hover:bg-brand-50 text-gray-400 hover:text-brand-600 rounded-lg transition"><Edit3 size={10}/></button>
                                                <button onClick={(e) => handleDelete(c.id, e)} className="p-1.5 bg-gray-50 hover:bg-red-50 text-gray-400 hover:text-red-500 rounded-lg transition"><Trash2 size={10}/></button>
                                              </div>
                                            </div>
                                            <p className="text-[9px] text-gray-400 font-black uppercase tracking-widest">{c.prgd}</p>
                                            <div className="mt-4 flex justify-between items-center text-[9px] font-black pt-3 border-t border-gray-50">
                                                <span className={`${totalDays > 120 ? 'text-red-600' : 'text-emerald-600'}`}>{totalDays} DIAS</span>
                                                <span className="text-gray-300">#{c.clientNumber}</span>
                                            </div>
                                        </div>
                                    );
                                })}
                            </div>
                        </div>
                    );
                })}
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Timeline } from './components/Timeline.tsx';
import { ContentGenerator } from './components/ContentGenerator.tsx';
import { ClientList } from './components/ClientList.tsx';
import { Dashboard } from './components/Dashboard.tsx';
import { Login } from './components/Login.tsx';
import { STAGES } from './constants.ts';
import { Client, Stage } from './types.ts';
import { ArrowLeft, Settings, Zap, BarChart3, LayoutList, LogOut } from 'lucide-react';

export default function App() {
  const [auth, setAuth] = useState<{ isAuthenticated: boolean; isVisitor: boolean } | null>(null);
  const [view, setView] = useState<'list' | 'detail' | 'dashboard'>('list');
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [currentStageId, setCurrentStageId] = useState<string>(STAGES[0].id);
  const [clients, setClients] = useState<Client[]>([]);

  // Carregar dados se for Admin
  useEffect(() => {
    if (auth?.isAuthenticated && !auth.isVisitor) {
      const saved = localStorage.getItem('gev_loop_clients');
      if (saved) {
        try {
          setClients(JSON.parse(saved));
        } catch (e) {
          console.error("Erro ao carregar dados salvos", e);
        }
      }
    }
  }, [auth]);

  // Salvar dados APENAS se estiver logado como Admin e houver alterações válidas
  useEffect(() => {
    if (auth?.isAuthenticated && !auth.isVisitor) {
      // Evita salvar lista vazia se for apenas um reset de logout
      localStorage.setItem('gev_loop_clients', JSON.stringify(clients));
    }
  }, [clients, auth]);

  const handleLogin = (mode: 'visitor' | 'admin') => {
    setAuth({
      isAuthenticated: true,
      isVisitor: mode === 'visitor'
    });
  };

  const handleLogout = () => {
    if (window.confirm("Deseja realmente sair do sistema?")) {
      // Limpa estados primeiro para evitar que o useEffect de salvamento pegue a lista vazia
      const isVisitor = auth?.isVisitor;
      setAuth(null);
      setView('list');
      setSelectedClientId(null);
      setClients([]);
    }
  };

  const handleCreateClient = (newClient: Client) => {
    setClients(prev => [newClient, ...prev]);
    handleSelectClient(newClient);
  };

  const handleEditClient = (updatedClient: Client) => {
    setClients(prev => prev.map(c => c.id === updatedClient.id ? updatedClient : c));
  };

  const handleDeleteClient = (clientId: string) => {
    setClients(prev => prev.filter(c => c.id !== clientId));
    if (selectedClientId === clientId) {
      setView('list');
      setSelectedClientId(null);
    }
  };

  const handleSelectClient = (client: Client) => {
    setSelectedClientId(client.id);
    setCurrentStageId(client.currentStageId || STAGES[0].id);
    setView('detail');
  };

  const handleUpdateNotes = (notes: string) => {
    if (!selectedClientId) return;
    setClients(prev => prev.map(c => 
      c.id === selectedClientId ? { ...c, additionalNotes: notes } : c
    ));
  };

  const handleUpdateClientStage = (clientId: string, newStageId: string, stageData?: Record<string, string>) => {
    const now = new Date().toISOString();
    setClients(prev => prev.map(c => {
      if (c.id === clientId) {
        return { 
          ...c, 
          currentStageId: newStageId, 
          stageData: { ...c.stageData, ...stageData },
          stageHistory: { ...c.stageHistory, [newStageId]: now }
        };
      }
      return c;
    }));
    if (selectedClientId === clientId) {
      setCurrentStageId(newStageId);
    }
  };

  if (!auth?.isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  const selectedClient = clients.find(c => c.id === selectedClientId);
  const currentStage = STAGES.find(s => s.id === currentStageId) || STAGES[0];

  return (
    <div className="h-screen bg-gray-100 flex flex-col overflow-hidden font-sans">
      <header className="bg-brand-900 h-16 sm:h-20 shrink-0 shadow-lg relative z-50 print:hidden">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 h-full flex items-center justify-between">
          <div className="flex items-center gap-4">
            {view === 'detail' && (
              <button onClick={() => setView('list')} className="p-2 hover:bg-white/10 rounded-full text-gold-400 transition">
                <ArrowLeft size={20} />
              </button>
            )}
            <div className="flex flex-col">
              <h1 className="text-xl sm:text-2xl font-black text-white uppercase tracking-tighter leading-none">
                LOOP <span className="text-gold-500">ENERGIA</span>
              </h1>
              <div className="flex items-center gap-2">
                <p className="text-[8px] text-brand-400 uppercase tracking-widest font-bold">Gestão de Experiência</p>
                <span className={`text-[7px] px-1.5 py-0.5 rounded font-black uppercase ${auth.isVisitor ? 'bg-amber-500/20 text-amber-500' : 'bg-emerald-500/20 text-emerald-500'}`}>
                  {auth.isVisitor ? 'Visitante' : 'Admin'}
                </span>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-2 sm:gap-4">
             <nav className="flex bg-brand-800/50 p-1 rounded-xl border border-brand-700/50 mr-2 sm:mr-4">
                <button 
                  onClick={() => setView('list')}
                  className={`flex items-center gap-2 px-3 sm:px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${view !== 'dashboard' && view !== 'detail' ? 'bg-brand-600 text-white shadow-lg' : 'text-brand-300 hover:text-white'}`}
                >
                  <LayoutList size={14} /> <span className="hidden sm:inline">Carteira</span>
                </button>
                <button 
                  onClick={() => setView('dashboard')}
                  className={`flex items-center gap-2 px-3 sm:px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${view === 'dashboard' ? 'bg-brand-600 text-white shadow-lg' : 'text-brand-300 hover:text-white'}`}
                >
                  <BarChart3 size={14} /> <span className="hidden sm:inline">Dashboard</span>
                </button>
             </nav>

             <div className="h-8 w-px bg-brand-800 hidden md:block"></div>

             <button 
               onClick={handleLogout}
               className="p-2 text-brand-300 hover:text-red-400 hover:bg-white/5 rounded-full transition flex items-center gap-2 group"
               title="Sair do Sistema"
             >
               <LogOut size={20} />
               <span className="hidden lg:inline text-[10px] font-black uppercase tracking-widest">Sair</span>
             </button>
          </div>
        </div>
      </header>

      <main className={`flex-1 overflow-hidden max-w-7xl mx-auto w-full px-4 sm:px-6 py-4 ${view === 'dashboard' ? 'overflow-y-auto custom-scroll print:overflow-visible print:max-w-none print:px-0' : ''}`}>
        {view === 'list' ? (
          <ClientList 
            clients={clients} 
            onSelectClient={handleSelectClient} 
            onCreateClient={handleCreateClient}
            onEditClient={handleEditClient}
            onDeleteClient={handleDeleteClient}
            onUpdateClientStage={handleUpdateClientStage}
          />
        ) : view === 'dashboard' ? (
          <Dashboard clients={clients} />
        ) : (
          <div className="flex flex-col h-full gap-4">
            <Timeline 
              currentStageId={currentStageId} 
              onSelectStage={(s) => setCurrentStageId(s.id)} 
            />
            <div className="flex-1 min-h-0">
              {selectedClient && (
                <ContentGenerator 
                  stage={currentStage}
                  client={selectedClient}
                  onUpdateNotes={handleUpdateNotes}
                  onUpdateClientStage={handleUpdateClientStage}
                />
              )}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

import React, { useState } from 'react';
import { Client, Stage } from '../types.ts';
import { Plus, Search, User, Zap, List, Kanban, X, Timer, ChevronRight, AlertCircle, Clock, FilterX, Trash2, Edit3, Briefcase } from 'lucide-react';
import { STAGES, STEP_ICONS } from '../constants.ts';
import { generateTemplateContent } from '../services/templateService.ts';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onEditClient: (client: Client) => void;
  onDeleteClient: (clientId: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

type FilterStatus = 'ativos' | 'entregues' | 'noprazo' | 'atencao' | 'urgente' | null;

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onEditClient, onDeleteClient, onUpdateClientStage }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'list' | 'pipeline'>('list');
  const [statusFilter, setStatusFilter] = useState<FilterStatus>(null);

  const [draggedClientId, setDraggedClientId] = useState<string | null>(null);
  const [initialStageId, setInitialStageId] = useState<string>(STAGES[0].id);

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '',
    clientNumber: '',
    prgd: '',
    phone: '',
    projectName: '',
  });

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    if (!startStr) return 0;
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const activeClients = clients.filter(c => c.currentStageId !== '7');
  const deliveredClients = clients.filter(c => c.currentStageId === '7');

  const statusCounts = activeClients.reduce((acc, c) => {
    const days = calculateDaysElapsed(c.createdAt);
    if (days > 120) acc.urgente++;
    else if (days > 90) acc.atencao++;
    else acc.noPrazo++;
    return acc;
  }, { noPrazo: 0, atencao: 0, urgente: 0 });

  const formatPhoneNumber = (value: string) => {
    const numbers = value.replace(/\D/g, '');
    if (numbers.length <= 11) {
       return numbers.replace(/(\d{2})(\d{5})(\d{4})/, '($1) $2-$3');
    }
    return value;
  };

  const getStatusInfo = (days: number, isDelivered: boolean) => {
    if (isDelivered) return { label: '🟢 CONCLUÍDO', color: 'text-green-600', bg: 'bg-green-50', key: 'entregues' };
    if (days > 120) return { label: '🔴 CRÍTICO', color: 'text-red-600', bg: 'bg-red-50', key: 'urgente' };
    if (days > 90) return { label: '🟡 ATENÇÃO', color: 'text-orange-500', bg: 'bg-orange-50', key: 'atencao' };
    return { label: '🟢 NO PRAZO', color: 'text-green-600', bg: 'bg-green-50', key: 'noprazo' };
  };

  const handleFilterToggle = (filter: FilterStatus) => {
    setStatusFilter(prev => prev === filter ? null : filter);
  };

  const openWhatsApp = (client: Client, stage: Stage, values: Record<string, string> = {}) => {
      if (!client.phone || !stage.template) return;
      const mergedValues = { ...client.stageData, ...values };
      const content = generateTemplateContent(stage, client, mergedValues);
      const cleanPhone = client.phone.replace(/\D/g, '');
      const encodedText = encodeURIComponent(content.body);
      window.open(`https://api.whatsapp.com/send?phone=55${cleanPhone}&text=${encodedText}`, '_blank');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name?.trim() || !formData.clientNumber?.trim() || !formData.prgd?.trim() || !formData.phone?.trim()) {
      alert("⚠️ Atenção: Nome, Telefone, PRGD e Número do Cliente são obrigatórios.");
      return;
    }

    if (editingClient) {
      const updatedClient: Client = {
        ...editingClient,
        name: formData.name || '',
        clientNumber: formData.clientNumber || '',
        prgd: formData.prgd || '',
        phone: formData.phone || '',
        projectName: formData.projectName || `Projeto ${formData.name}`,
        currentStageId: initialStageId
      };
      onEditClient(updatedClient);
    } else {
      const now = new Date().toISOString();
      const newClient: Client = {
        id: Date.now().toString(),
        name: formData.name || '',
        clientNumber: formData.clientNumber || '',
        prgd: formData.prgd || '',
        phone: formData.phone || '',
        projectName: formData.projectName || `Projeto ${formData.name}`,
        additionalNotes: '',
        currentStageId: initialStageId,
        createdAt: now,
        stageHistory: { [initialStageId]: now },
        stageData: {}
      };
      const selectedStage = STAGES.find(s => s.id === initialStageId);
      if (selectedStage?.template) openWhatsApp(newClient, selectedStage);
      onCreateClient(newClient);
    }
    closeModal();
  };

  const handleStartEdit = (client: Client, e: React.MouseEvent) => {
    e.stopPropagation();
    setEditingClient(client);
    setFormData({
      name: client.name,
      clientNumber: client.clientNumber,
      prgd: client.prgd,
      phone: client.phone,
      projectName: client.projectName
    });
    setInitialStageId(client.currentStageId);
    setIsCreating(true);
  };

  const handleDelete = (clientId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (window.confirm("Tem certeza que deseja excluir este projeto definitivamente?")) {
      onDeleteClient(clientId);
    }
  };

  const closeModal = () => {
    setIsCreating(false);
    setEditingClient(null);
    setFormData({ name: '', clientNumber: '', prgd: '', phone: '', projectName: '' });
  };

  const handleDragStart = (e: React.DragEvent, client: Client) => {
    e.dataTransfer.setData('clientId', client.id);
    setDraggedClientId(client.id);
  };

  const handleDragOver = (e: React.DragOverEvent) => e.preventDefault();

  const handleDrop = (e: React.DragEvent, stageId: string) => {
    e.preventDefault();
    const clientId = e.dataTransfer.getData('clientId');
    setDraggedClientId(null);
    if (!clientId) return;

    const client = clients.find(c => c.id === clientId);
    const targetStage = STAGES.find(s => s.id === stageId);

    if (client && targetStage && client.currentStageId !== stageId) {
      onUpdateClientStage(clientId, stageId);
      if (targetStage.template) setTimeout(() => openWhatsApp(client, targetStage), 100);
    }
  };

  const filteredClients = clients.filter(c => {
    const matchesSearch = c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          c.prgd.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          c.projectName.toLowerCase().includes(searchTerm.toLowerCase());

    if (!matchesSearch) return false;
    if (!statusFilter) return true;

    const isDelivered = c.currentStageId === '7';
    const days = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);
    const statusKey = getStatusInfo(days, isDelivered).key;

    if (statusFilter === 'ativos') return !isDelivered;
    return statusKey === statusFilter;
  });

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-0 h-full flex flex-col relative overflow-hidden">
      {/* Modal de Criação / Edição */}
      {isCreating && (
          <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
              <div className="bg-white rounded-3xl shadow-2xl w-full max-w-xl animate-scale-up border border-gray-100 overflow-hidden">
                  <div className="p-8 pb-4 flex justify-between items-center border-b border-gray-50">
                      <div>
                        <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">
                          {editingClient ? 'Editar Projeto' : 'Novo Projeto'}
                        </h2>
                        <p className="text-xs text-gray-400 font-bold uppercase tracking-widest">
                          {editingClient ? `Editando registro de ${editingClient.name}` : 'Os campos com * são obrigatórios'}
                        </p>
                      </div>
                      <button onClick={closeModal} className="p-2 hover:bg-gray-100 rounded-full transition text-gray-400 hover:text-brand-600"><X size={24} /></button>
                  </div>
                  <form onSubmit={handleSubmit} className="p-8 space-y-6 bg-white">
                      <div className="space-y-4">
                        <div className="group">
                          <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Nome do Titular *</label>
                          <input required value={formData.name} placeholder="Ex: João Silva" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" onChange={e => setFormData({...formData, name: e.target.value})} />
                        </div>

                        <div className="group">
                          <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Nome do Projeto / Obra</label>
                          <input value={formData.projectName} placeholder="Ex: Residência Solar Centro" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" onChange={e => setFormData({...formData, projectName: e.target.value})} />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Telefone *</label>
                            <input required placeholder="(00) 00000-0000" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" value={formData.phone} onChange={e => setFormData({...formData, phone: formatPhoneNumber(e.target.value)})} />
                          </div>
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Nº PRGD *</label>
                            <input required value={formData.prgd} placeholder="Ex: GD-2024-00" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" onChange={e => setFormData({...formData, prgd: e.target.value})} />
                          </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Número Cliente *</label>
                            <input required value={formData.clientNumber} placeholder="Ex: 100234" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" onChange={e => setFormData({...formData, clientNumber: e.target.value})} />
                          </div>
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Etapa Inicial</label>
                            <select value={initialStageId} onChange={e => setInitialStageId(e.target.value)} className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium">
                                {STAGES.map(s => <option key={s.id} value={s.id}>{s.stepNumber} - {s.title}</option>)}
                            </select>
                          </div>
                        </div>
                      </div>

                      <div className="pt-4">
                        <button type="submit" className="w-full bg-brand-500 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-sm hover:bg-brand-600 shadow-lg hover:shadow-brand-500/30 transition-all flex items-center justify-center gap-2">
                          <Zap size={18} className="text-gold-400" /> {editingClient ? 'SALVAR ALTERAÇÕES' : 'CADASTRAR PROJETO'}
                        </button>
                      </div>
                  </form>
              </div>
          </div>
      )}

      {/* Filtros e Cabeçalho */}
      <div className="p-6 border-b flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-gray-50/30">
        <div>
          <div className="flex items-center gap-3">
            <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter leading-none">Gestão de Carteira</h2>
            {statusFilter && (
              <button onClick={() => setStatusFilter(null)} className="flex items-center gap-1 text-[9px] font-black text-gray-400 hover:text-brand-600 uppercase transition"><FilterX size={12} /> Limpar Filtro</button>
            )}
          </div>
          <div className="flex flex-wrap gap-2 mt-3">
              <button onClick={() => handleFilterToggle('ativos')} className={`text-[9px] font-black px-2.5 py-1 rounded-full uppercase tracking-widest border transition-all shadow-sm ${statusFilter === 'ativos' ? 'bg-brand-600 text-white border-brand-700' : 'bg-brand-50 text-brand-600 border-brand-100'}`}>{activeClients.length} ATIVOS</button>
              <button onClick={() => handleFilterToggle('entregues')} className={`text-[9px] font-black px-2.5 py-1 rounded-full uppercase tracking-widest border transition-all shadow-sm ${statusFilter === 'entregues' ? 'bg-green-600 text-white border-green-700' : 'bg-green-50 text-green-600 border-green-100'}`}>{deliveredClients.length} ENTREGUES</button>
              <div className="w-px h-4 bg-gray-200 mx-1 hidden sm:block self-center"></div>
              <button onClick={() => handleFilterToggle('noprazo')} className={`text-[9px] font-black px-2.5 py-1 rounded-full uppercase tracking-widest border flex items-center gap-1 transition-all shadow-sm ${statusFilter === 'noprazo' ? 'bg-emerald-600 text-white' : 'bg-emerald-50 text-emerald-600'}`}>{statusCounts.noPrazo} NO PRAZO</button>
              <button onClick={() => handleFilterToggle('atencao')} className={`text-[9px] font-black px-2.5 py-1 rounded-full uppercase tracking-widest border flex items-center gap-1 transition-all shadow-sm ${statusFilter === 'atencao' ? 'bg-amber-600 text-white' : 'bg-amber-50 text-amber-600'}`}>{statusCounts.atencao} ATENÇÃO</button>
              <button onClick={() => handleFilterToggle('urgente')} className={`text-[9px] font-black px-2.5 py-1 rounded-full uppercase tracking-widest border flex items-center gap-1 transition-all shadow-sm ${statusFilter === 'urgente' ? 'bg-red-600 text-white' : 'bg-red-50 text-red-600'}`}>{statusCounts.urgente} URGENTE</button>
          </div>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
             <div className="bg-white p-1.5 rounded-2xl flex border border-gray-100 shadow-sm flex-1 md:flex-none">
                <button onClick={() => setViewMode('list')} className={`flex-1 md:flex-none p-2.5 rounded-xl transition-all ${viewMode === 'list' ? 'bg-brand-600 text-white shadow-md' : 'text-gray-400 hover:bg-gray-50'}`}><List size={18} className="mx-auto"/></button>
                <button onClick={() => setViewMode('pipeline')} className={`flex-1 md:flex-none p-2.5 rounded-xl transition-all ${viewMode === 'pipeline' ? 'bg-brand-600 text-white shadow-md' : 'text-gray-400 hover:bg-gray-50'}`}><Kanban size={18} className="mx-auto"/></button>
             </div>
             <button onClick={() => setIsCreating(true)} className="flex-1 md:flex-none bg-brand-600 text-white px-6 py-3 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-brand-700 transition-all flex items-center justify-center gap-2">
                <Plus size={18} /> Novo Projeto
             </button>
        </div>
      </div>

      <div className="p-4 bg-white border-b">
         <div className="relative">
            <Search className="absolute left-4 top-3.5 text-gray-300" size={18} />
            <input placeholder="Buscar por Nome, Projeto ou PRGD..." className="w-full pl-12 p-3.5 rounded-2xl border-gray-100 border bg-gray-50 focus:bg-white outline-none transition" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
         </div>
