      <div className={`flex-1 overflow-auto bg-gray-50/30 ${viewMode === 'pipeline' ? 'flex custom-scroll' : 'p-6'}`}>
        {viewMode === 'list' ? (
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-8">
                {filteredClients.map(client => {
                    const isDelivered = client.currentStageId === '7';
                    const days = calculateDaysElapsed(client.createdAt, isDelivered ? client.stageHistory['7'] : undefined);
                    const status = getStatusInfo(days, isDelivered);
                    const currentStage = STAGES.find(s => s.id === client.currentStageId);
                    const Icon = STEP_ICONS[currentStage?.stepNumber || '1'];

                    return (
                        <div key={client.id} onClick={() => onSelectClient(client)} className="bg-white border border-gray-100 rounded-[2rem] p-6 hover:border-brand-400 cursor-pointer transition-all shadow-sm hover:shadow-2xl group flex flex-col gap-5 relative overflow-hidden">
                            <div className="flex justify-between items-start">
                                <div className="flex gap-4 items-center">
                                    <div className="bg-brand-50 p-3 rounded-2xl group-hover:bg-brand-600 group-hover:text-white transition-colors">
                                        <Briefcase size={20} />
                                    </div>
                                    <div>
                                        <h3 className="font-black text-brand-900 uppercase text-sm leading-tight group-hover:text-brand-600 transition tracking-tight truncate max-w-[180px]">{client.name}</h3>
                                        <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest mt-1">{client.projectName}</p>
                                    </div>
                                </div>
                                <div className="flex gap-1">
                                  <button onClick={(e) => handleStartEdit(client, e)} className="p-2 bg-gray-50 hover:bg-brand-600 text-gray-400 hover:text-white rounded-xl transition-all shadow-sm z-20" title="Editar"><Edit3 size={14}/></button>
                                  <button onClick={(e) => handleDelete(client.id, e)} className="p-2 bg-gray-50 hover:bg-red-600 text-gray-400 hover:text-white rounded-xl transition-all shadow-sm z-20" title="Excluir"><Trash2 size={14}/></button>
                                </div>
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div className="bg-gray-50/50 p-3 rounded-2xl border border-gray-100">
                                    <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest mb-1">PRGD</p>
                                    <p className="text-[10px] font-black text-brand-900">{client.prgd}</p>
                                </div>
                                <div className="bg-gray-50/50 p-3 rounded-2xl border border-gray-100">
                                    <p className="text-[9px] font-black text-gray-400 uppercase tracking-widest mb-1">Nº Cliente</p>
                                    <p className="text-[10px] font-black text-brand-900">#{client.clientNumber}</p>
                                </div>
                            </div>

                            <div className={`p-5 rounded-3xl border border-gray-100 flex flex-col gap-3 ${status.bg} shadow-sm relative overflow-hidden`}>
                                <div className="flex justify-between items-center text-[10px] font-black">
                                    <span className="text-gray-400 uppercase flex items-center gap-1"><Clock size={12}/> Jornada Total:</span>
                                    <span className="text-brand-900">{days} / 120 dias</span>
                                </div>
                                <div className="h-1.5 w-full bg-white/50 rounded-full overflow-hidden">
                                    <div className={`h-full transition-all duration-1000 rounded-full ${days > 120 ? 'bg-red-500' : days > 90 ? 'bg-amber-500' : 'bg-emerald-500'}`} style={{width: `${Math.min((days/120)*100, 100)}%`}} />
                                </div>
                                <div className={`py-2 rounded-xl text-center text-[9px] font-black tracking-widest bg-white shadow-sm border border-gray-50/50 ${status.color}`}>
                                    {status.label}
