                            <div className="flex items-center justify-between pt-4 border-t border-gray-50">
                                <div className="flex items-center gap-2">
                                    <div className="bg-brand-900 text-gold-400 p-2 rounded-xl">
                                        <Icon size={14} />
                                    </div>
                                    <div className="flex flex-col">
                                        <span className="text-[8px] font-black text-gray-400 uppercase tracking-widest">Etapa Atual</span>
                                        <span className="text-[10px] font-black text-brand-900 uppercase tracking-tight truncate max-w-[150px]">{currentStage?.title}</span>
                                    </div>
                                </div>
                                <ChevronRight className="text-gray-200 group-hover:translate-x-1 group-hover:text-brand-400 transition-all" size={20} />
                            </div>
                        </div>
                    );
                })}
             </div>
        ) : (
            <div className="flex gap-6 p-6 h-full min-w-max">
                {STAGES.map(stage => {
                    const stageClients = filteredClients.filter(c => c.currentStageId === stage.id);
                    return (
                        <div key={stage.id} onDragOver={handleDragOver} onDrop={e => handleDrop(e, stage.id)} className="w-80 shrink-0 bg-gray-100/30 rounded-[2.5rem] border border-gray-200 flex flex-col max-h-full shadow-sm overflow-hidden">
                            <div className="p-6 font-black text-[10px] uppercase tracking-widest text-brand-600 border-b border-gray-200 flex justify-between bg-white items-center sticky top-0 z-10">
                                <span>{stage.title}</span>
                                <span className="bg-brand-600 text-white px-3 py-1 rounded-full shadow-md">{stageClients.length}</span>
                            </div>
                            <div className="p-4 overflow-y-auto flex flex-col gap-4 custom-scroll">
                                {stageClients.map(c => {
                                    const totalDays = calculateDaysElapsed(c.createdAt, c.currentStageId === '7' ? c.stageHistory['7'] : undefined);
                                    return (
                                        <div key={c.id} draggable onDragStart={e => handleDragStart(e, c)} onClick={() => onSelectClient(c)} className="bg-white p-5 rounded-3xl border border-gray-100 shadow-sm cursor-grab active:cursor-grabbing hover:border-brand-400 transition-all hover:shadow-lg group flex flex-col gap-3">
                                            <div className="flex justify-between items-start">
