                                                <button onClick={(e) => handleDelete(c.id, e)} className="p-1.5 bg-gray-50 hover:bg-red-600 text-gray-400 hover:text-white rounded-lg transition-all z-20"><Trash2 size={10}/></button>
                                              </div>
                                            </div>
                                            <div className="flex justify-between items-center text-[9px] font-black pt-3 border-t border-gray-50">
                                                <span className={`${totalDays > 120 ? 'text-red-600' : 'text-emerald-600'} flex items-center gap-1`}><Clock size={10}/> {totalDays} DIAS</span>
                                                <span className="text-gray-300">#{c.clientNumber}</span>
                                            </div>
                                        </div>
                                    );
                                })}
                            </div>
                        </div>
                    );
                })}
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Timeline } from './components/Timeline.tsx';
import { ContentGenerator } from './components/ContentGenerator.tsx';
import { ClientList } from './components/ClientList.tsx';
import { Dashboard } from './components/Dashboard.tsx';
import { Login } from './components/Login.tsx';
import { STAGES } from './constants.ts';
import { Client, Stage } from './types.ts';
import { ArrowLeft, Settings, Zap, BarChart3, LayoutList, LogOut } from 'lucide-react';

export default function App() {
  const [auth, setAuth] = useState<{ isAuthenticated: boolean; isVisitor: boolean } | null>(null);
  const [view, setView] = useState<'list' | 'detail' | 'dashboard'>('list');
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [currentStageId, setCurrentStageId] = useState<string>(STAGES[0].id);
  const [clients, setClients] = useState<Client[]>([]);

  // Carregar dados se for Admin
  useEffect(() => {
    if (auth?.isAuthenticated && !auth.isVisitor) {
      const saved = localStorage.getItem('gev_loop_clients');
      if (saved) {
        try {
          setClients(JSON.parse(saved));
        } catch (e) {
          console.error("Erro ao carregar dados salvos", e);
        }
      }
    }
  }, [auth]);

  // Salvar dados APENAS se estiver logado como Admin
  useEffect(() => {
    if (auth?.isAuthenticated && !auth.isVisitor && clients.length >= 0) {
      localStorage.setItem('gev_loop_clients', JSON.stringify(clients));
    }
  }, [clients, auth]);

  const handleLogin = (mode: 'visitor' | 'admin') => {
    setAuth({
      isAuthenticated: true,
      isVisitor: mode === 'visitor'
    });
  };

  const handleLogout = () => {
    if (window.confirm("Deseja realmente sair e trocar de usuário?")) {
      // Limpa estados para forçar re-render do Login
      setAuth(null);
      setClients([]);
      setView('list');
      setSelectedClientId(null);
    }
  };

  const handleCreateClient = (newClient: Client) => {
    setClients(prev => [newClient, ...prev]);
    handleSelectClient(newClient);
  };

  const handleEditClient = (updatedClient: Client) => {
    setClients(prev => prev.map(c => c.id === updatedClient.id ? updatedClient : c));
  };

  const handleDeleteClient = (clientId: string) => {
    setClients(prev => prev.filter(c => c.id !== clientId));
    if (selectedClientId === clientId) {
      setView('list');
      setSelectedClientId(null);
    }
  };

  const handleSelectClient = (client: Client) => {
    setSelectedClientId(client.id);
    setCurrentStageId(client.currentStageId || STAGES[0].id);
    setView('detail');
  };

  const handleUpdateNotes = (notes: string) => {
    if (!selectedClientId) return;
    setClients(prev => prev.map(c => 
      c.id === selectedClientId ? { ...c, additionalNotes: notes } : c
    ));
  };

  const handleUpdateClientStage = (clientId: string, newStageId: string, stageData?: Record<string, string>) => {
    const now = new Date().toISOString();
    setClients(prev => prev.map(c => {
      if (c.id === clientId) {
        return { 
          ...c, 
          currentStageId: newStageId, 
          stageData: { ...c.stageData, ...stageData },
          stageHistory: { ...c.stageHistory, [newStageId]: now }
        };
      }
      return c;
    }));
    if (selectedClientId === clientId) {
      setCurrentStageId(newStageId);
    }
  };

  if (!auth?.isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  const selectedClient = clients.find(c => c.id === selectedClientId);
  const currentStage = STAGES.find(s => s.id === currentStageId) || STAGES[0];

  return (
    <div className="h-screen bg-gray-100 flex flex-col overflow-hidden font-sans">
      <header className="bg-brand-900 h-16 sm:h-20 shrink-0 shadow-lg relative z-50 print:hidden">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 h-full flex items-center justify-between">
          <div className="flex items-center gap-4">
            {view === 'detail' && (
              <button onClick={() => setView('list')} className="p-2 hover:bg-white/10 rounded-full text-gold-400 transition">
                <ArrowLeft size={20} />
              </button>
            )}
            <div className="flex flex-col">
              <h1 className="text-xl sm:text-2xl font-black text-white uppercase tracking-tighter leading-none">
                LOOP <span className="text-gold-500">ENERGIA</span>
              </h1>
              <div className="flex items-center gap-2">
                <p className="text-[8px] text-brand-400 uppercase tracking-widest font-bold">Gestão de Experiência</p>
                <span className={`text-[7px] px-1.5 py-0.5 rounded font-black uppercase ${auth.isVisitor ? 'bg-amber-500/20 text-amber-500' : 'bg-emerald-500/20 text-emerald-500'}`}>
                  {auth.isVisitor ? 'Visitante' : 'Admin'}
                </span>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-2 sm:gap-4">
             <nav className="flex bg-brand-800/50 p-1 rounded-xl border border-brand-700/50 mr-2 sm:mr-4">
                <button 
                  onClick={() => setView('list')}
                  className={`flex items-center gap-2 px-3 sm:px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${view !== 'dashboard' && view !== 'detail' ? 'bg-brand-600 text-white shadow-lg' : 'text-brand-300 hover:text-white'}`}
                >
                  <LayoutList size={14} /> <span className="hidden sm:inline">Carteira</span>
                </button>
                <button 
                  onClick={() => setView('dashboard')}
                  className={`flex items-center gap-2 px-3 sm:px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${view === 'dashboard' ? 'bg-brand-600 text-white shadow-lg' : 'text-brand-300 hover:text-white'}`}
                >
                  <BarChart3 size={14} /> <span className="hidden sm:inline">Dashboard</span>
                </button>
             </nav>

             <div className="h-8 w-px bg-brand-800 hidden md:block"></div>

             <button 
               onClick={handleLogout}
               className="p-2 text-brand-300 hover:text-red-400 hover:bg-white/5 rounded-full transition flex items-center gap-2 group"
               title="Sair do Sistema"
             >
               <LogOut size={20} />
               <span className="hidden lg:inline text-[10px] font-black uppercase tracking-widest">Sair</span>
             </button>
          </div>
        </div>
      </header>

      <main className={`flex-1 overflow-hidden max-w-7xl mx-auto w-full px-4 sm:px-6 py-4 ${view === 'dashboard' ? 'overflow-y-auto custom-scroll print:overflow-visible print:max-w-none print:px-0' : ''}`}>
        {view === 'list' ? (
          <ClientList 
            clients={clients} 
            onSelectClient={handleSelectClient} 
            onCreateClient={handleCreateClient}
            onEditClient={handleEditClient}
            onDeleteClient={handleDeleteClient}
            onUpdateClientStage={handleUpdateClientStage}
          />
        ) : view === 'dashboard' ? (
          <Dashboard clients={clients} />
        ) : (
          <div className="flex flex-col h-full gap-4">
            <Timeline 
              currentStageId={currentStageId} 
              onSelectStage={(s) => setCurrentStageId(s.id)} 
            />
            <div className="flex-1 min-h-0">
              {selectedClient && (
                <ContentGenerator 
                  stage={currentStage}
                  client={selectedClient}
                  onUpdateNotes={handleUpdateNotes}
                  onUpdateClientStage={handleUpdateClientStage}
                />
              )}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

import React, { useState } from 'react';
import { Client, Stage } from '../types.ts';
import { Plus, Search, User, Zap, List, Kanban, X, Timer, ChevronRight, AlertCircle, Clock, FilterX, Trash2, Edit3, Briefcase, CalendarDays } from 'lucide-react';
import { STAGES, STEP_ICONS } from '../constants.ts';
import { generateTemplateContent } from '../services/templateService.ts';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onEditClient: (client: Client) => void;
  onDeleteClient: (clientId: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

type FilterStatus = 'ativos' | 'entregues' | 'noprazo' | 'atencao' | 'urgente' | null;

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onEditClient, onDeleteClient, onUpdateClientStage }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'list' | 'pipeline'>('list');
  const [statusFilter, setStatusFilter] = useState<FilterStatus>(null);

  const [draggedClientId, setDraggedClientId] = useState<string | null>(null);
  const [initialStageId, setInitialStageId] = useState<string>(STAGES[0].id);

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '',
    clientNumber: '',
    prgd: '',
    phone: '',
    projectName: '',
  });

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    if (!startStr) return 0;
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const getStatusInfo = (days: number, isDelivered: boolean) => {
    if (isDelivered) return { label: '🟢 CONCLUÍDO', color: 'text-green-600', bg: 'bg-green-50', key: 'entregues' };
    if (days > 120) return { label: '🔴 CRÍTICO', color: 'text-red-600', bg: 'bg-red-50', key: 'urgente' };
    if (days > 90) return { label: '🟡 ATENÇÃO', color: 'text-orange-500', bg: 'bg-orange-50', key: 'atencao' };
    return { label: '🟢 NO PRAZO', color: 'text-green-600', bg: 'bg-green-50', key: 'noprazo' };
  };

  const handleFilterToggle = (filter: FilterStatus) => {
    setStatusFilter(prev => prev === filter ? null : filter);
  };

  const openWhatsApp = (client: Client, stage: Stage, values: Record<string, string> = {}) => {
      if (!client.phone || !stage.template) return;
      const mergedValues = { ...client.stageData, ...values };
      const content = generateTemplateContent(stage, client, mergedValues);
      const cleanPhone = client.phone.replace(/\D/g, '');
      const encodedText = encodeURIComponent(content.body);
      window.open(`https://api.whatsapp.com/send?phone=55${cleanPhone}&text=${encodedText}`, '_blank');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name?.trim() || !formData.clientNumber?.trim() || !formData.prgd?.trim() || !formData.phone?.trim()) {
      alert("⚠️ Atenção: Nome, Telefone, PRGD e Número do Cliente são obrigatórios.");
      return;
    }

    if (editingClient) {
      const updatedClient: Client = {
        ...editingClient,
        name: formData.name || '',
        clientNumber: formData.clientNumber || '',
        prgd: formData.prgd || '',
        phone: formData.phone || '',
        projectName: formData.projectName || `Projeto ${formData.name}`,
        currentStageId: initialStageId
      };
      onEditClient(updatedClient);
    } else {
      const now = new Date().toISOString();
      const newClient: Client = {
        id: Date.now().toString(),
        name: formData.name || '',
        clientNumber: formData.clientNumber || '',
        prgd: formData.prgd || '',
        phone: formData.phone || '',
        projectName: formData.projectName || `Projeto ${formData.name}`,
        additionalNotes: '',
        currentStageId: initialStageId,
        createdAt: now,
        stageHistory: { [initialStageId]: now },
        stageData: {}
      };
      const selectedStage = STAGES.find(s => s.id === initialStageId);
      if (selectedStage?.template) openWhatsApp(newClient, selectedStage);
      onCreateClient(newClient);
    }
    closeModal();
  };

  const handleStartEdit = (client: Client, e: React.MouseEvent) => {
    e.stopPropagation(); // IMPORTANTE: Impede que abra o detalhe do cliente
    setEditingClient(client);
    setFormData({
      name: client.name,
      clientNumber: client.clientNumber,
      prgd: client.prgd,
      phone: client.phone,
      projectName: client.projectName
    });
    setInitialStageId(client.currentStageId);
    setIsCreating(true);
  };

  const handleDelete = (clientId: string, e: React.MouseEvent) => {
    e.stopPropagation(); // IMPORTANTE: Impede que abra o detalhe do cliente
    if (window.confirm("Tem certeza que deseja apagar este cliente permanentemente?")) {
      onDeleteClient(clientId);
    }
  };

  const closeModal = () => {
    setIsCreating(false);
    setEditingClient(null);
    setFormData({ name: '', clientNumber: '', prgd: '', phone: '', projectName: '' });
  };

  const filteredClients = clients.filter(c => {
    const matchesSearch = c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          c.prgd.toLowerCase().includes(searchTerm.toLowerCase());

    if (!matchesSearch) return false;
    if (!statusFilter) return true;

    const isDelivered = c.currentStageId === '7';
    const days = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);
    const statusKey = getStatusInfo(days, isDelivered).key;

    if (statusFilter === 'ativos') return !isDelivered;
    return statusKey === statusFilter;
  });

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-0 h-full flex flex-col relative overflow-hidden">
      {/* Modal de Criação / Edição */}
      {isCreating && (
          <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
              <div className="bg-white rounded-3xl shadow-2xl w-full max-w-xl animate-scale-up border border-gray-100 overflow-hidden">
                  <div className="p-8 pb-4 flex justify-between items-center border-b border-gray-50">
                      <div>
                        <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">
                          {editingClient ? 'Editar Cliente' : 'Novo Cliente'}
                        </h2>
                        <p className="text-xs text-gray-400 font-bold uppercase tracking-widest">
                          Preencha os dados do titular da conta
                        </p>
                      </div>
                      <button onClick={closeModal} className="p-2 hover:bg-gray-100 rounded-full transition text-gray-400 hover:text-brand-600"><X size={24} /></button>
                  </div>
                  <form onSubmit={handleSubmit} className="p-8 space-y-6 bg-white">
                      <div className="space-y-4">
                        <div className="group">
                          <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Nome do Titular *</label>
                          <input required value={formData.name} placeholder="Ex: João Silva" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" onChange={e => setFormData({...formData, name: e.target.value})} />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Telefone *</label>
                            <input required placeholder="(00) 00000-0000" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} />
                          </div>
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Nº PRGD *</label>
                            <input required value={formData.prgd} placeholder="Ex: GD-2024-00" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" onChange={e => setFormData({...formData, prgd: e.target.value})} />
                          </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Número Cliente *</label>
                            <input required value={formData.clientNumber} placeholder="Ex: 100234" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" onChange={e => setFormData({...formData, clientNumber: e.target.value})} />
                          </div>
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Etapa</label>
                            <select value={initialStageId} onChange={e => setInitialStageId(e.target.value)} className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium">
                                {STAGES.map(s => <option key={s.id} value={s.id}>{s.stepNumber} - {s.title}</option>)}
                            </select>
                          </div>
                        </div>
                      </div>

                      <div className="pt-4">
                        <button type="submit" className="w-full bg-brand-500 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-sm hover:bg-brand-600 shadow-lg transition-all flex items-center justify-center gap-2">
                          <Zap size={18} className="text-gold-400" /> {editingClient ? 'SALVAR ALTERAÇÕES' : 'CADASTRAR CLIENTE'}
                        </button>
                      </div>
                  </form>
              </div>
          </div>
      )}

      {/* Cabeçalho de Gestão */}
      <div className="p-6 border-b flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-gray-50/30">
        <div>
          <div className="flex items-center gap-3">
            <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter leading-none">Gestão de Carteira</h2>
            {statusFilter && (
              <button onClick={() => setStatusFilter(null)} className="flex items-center gap-1 text-[9px] font-black text-gray-400 hover:text-brand-600 uppercase transition"><FilterX size={12} /> Limpar Filtro</button>
            )}
          </div>
          <div className="flex flex-wrap gap-2 mt-3">
              <button onClick={() => handleFilterToggle('ativos')} className={`text-[9px] font-black px-2.5 py-1 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'ativos' ? 'bg-brand-600 text-white border-brand-700' : 'bg-brand-50 text-brand-600 border-brand-100'}`}>ATIVOS</button>
              <button onClick={() => handleFilterToggle('entregues')} className={`text-[9px] font-black px-2.5 py-1 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'entregues' ? 'bg-green-600 text-white border-green-700' : 'bg-green-50 text-green-600 border-green-100'}`}>ENTREGUES</button>
          </div>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
             <div className="bg-white p-1.5 rounded-2xl flex border border-gray-100 shadow-sm">
                <button onClick={() => setViewMode('list')} className={`p-2.5 rounded-xl transition-all ${viewMode === 'list' ? 'bg-brand-600 text-white shadow-md' : 'text-gray-400 hover:bg-gray-50'}`}><List size={18}/></button>
                <button onClick={() => setViewMode('pipeline')} className={`p-2.5 rounded-xl transition-all ${viewMode === 'pipeline' ? 'bg-brand-600 text-white shadow-md' : 'text-gray-400 hover:bg-gray-50'}`}><Kanban size={18}/></button>
             </div>
             <button onClick={() => setIsCreating(true)} className="bg-brand-600 text-white px-6 py-3 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-brand-700 transition-all flex items-center justify-center gap-2">
                <Plus size={18} /> Novo Cliente
             </button>
        </div>
      </div>

      <div className="p-4 bg-white border-b">
         <div className="relative">
            <Search className="absolute left-4 top-3.5 text-gray-300" size={18} />
            <input placeholder="Buscar por Nome ou PRGD..." className="w-full pl-12 p-3.5 rounded-2xl border-gray-100 border bg-gray-50 focus:bg-white outline-none transition font-medium" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
         </div>
      </div>

      <div className={`flex-1 overflow-auto bg-gray-50/30 p-6`}>
             <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-8">
                {filteredClients.map(client => {
                    const isDelivered = client.currentStageId === '7';
                    const totalDays = calculateDaysElapsed(client.createdAt, isDelivered ? client.stageHistory['7'] : undefined);

                    // Dias na etapa atual
                    const stageEntryStr = client.stageHistory[client.currentStageId] || client.createdAt;
                    const stageDays = calculateDaysElapsed(stageEntryStr);

                    const status = getStatusInfo(totalDays, isDelivered);
                    const currentStage = STAGES.find(s => s.id === client.currentStageId);
                    const Icon = STEP_ICONS[currentStage?.stepNumber || '1'];

                    return (
                        <div key={client.id} onClick={() => onSelectClient(client)} className="bg-white border border-gray-100 rounded-[2.5rem] p-6 hover:border-brand-400 cursor-pointer transition-all shadow-sm hover:shadow-2xl group flex flex-col gap-5 relative overflow-hidden">
                            <div className="flex justify-between items-start">
                                <div className="flex gap-4 items-center">
                                    <div className="bg-brand-50 p-4 rounded-3xl group-hover:bg-brand-600 group-hover:text-white transition-colors">
                                        <User size={24} />
                                    </div>
                                    <div>
                                        <h3 className="font-black text-brand-900 uppercase text-lg leading-tight group-hover:text-brand-600 transition tracking-tighter truncate max-w-[180px]">{client.name}</h3>
                                        <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest mt-1">PRGD: {client.prgd}</p>
                                    </div>
                                </div>
                                <div className="flex gap-1 relative z-50">
                                  <button onClick={(e) => handleStartEdit(client, e)} className="p-2.5 bg-gray-50 hover:bg-brand-600 text-gray-400 hover:text-white rounded-xl transition-all shadow-sm" title="Editar"><Edit3 size={16}/></button>
                                  <button onClick={(e) => handleDelete(client.id, e)} className="p-2.5 bg-gray-50 hover:bg-red-600 text-gray-400 hover:text-white rounded-xl transition-all shadow-sm" title="Apagar"><Trash2 size={16}/></button>
                                </div>
                            </div>

                            <div className={`p-6 rounded-[2rem] border border-gray-100 flex flex-col gap-4 ${status.bg} shadow-inner`}>
                                <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest">
                                    <span className="text-gray-400 flex items-center gap-1.5"><Clock size={12}/> Jornada Total:</span>
                                    <span className="text-brand-900">{totalDays} dias</span>
                                </div>

                                <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest pt-2 border-t border-gray-200/50">
                                    <span className="text-gray-400 flex items-center gap-1.5"><CalendarDays size={12}/> Dias nesta etapa:</span>
                                    <span className="text-brand-600">{stageDays} dias</span>
                                </div>

                                <div className={`py-2.5 rounded-2xl text-center text-[9px] font-black tracking-[0.2em] bg-white shadow-sm border border-gray-50/50 mt-2 ${status.color}`}>
                                    {status.label}
                                </div>
                            </div>

                            <div className="flex items-center justify-between pt-4 border-t border-gray-50">
                                <div className="flex items-center gap-3">
                                    <div className="bg-brand-900 text-gold-400 p-2.5 rounded-xl shadow-lg shadow-brand-900/20">
                                        <Icon size={16} />
                                    </div>
                                    <div className="flex flex-col">
                                        <span className="text-[8px] font-black text-gray-400 uppercase tracking-widest">Etapa Atual</span>
                                        <span className="text-xs font-black text-brand-900 uppercase tracking-tight truncate max-w-[160px]">{currentStage?.title}</span>
                                    </div>
                                </div>
                                <ChevronRight className="text-gray-200 group-hover:translate-x-1 group-hover:text-brand-400 transition-all" size={20} />
                            </div>
                        </div>
                    );
                })}
             </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Timeline } from './components/Timeline.tsx';
import { ContentGenerator } from './components/ContentGenerator.tsx';
import { ClientList } from './components/ClientList.tsx';
import { Dashboard } from './components/Dashboard.tsx';
import { Login } from './components/Login.tsx';
import { STAGES } from './constants.ts';
import { Client, Stage } from './types.ts';
import { ArrowLeft, Settings, Zap, BarChart3, LayoutList, LogOut } from 'lucide-react';

export default function App() {
  const [auth, setAuth] = useState<{ isAuthenticated: boolean; isVisitor: boolean } | null>(null);
  const [view, setView] = useState<'list' | 'detail' | 'dashboard'>('list');
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [currentStageId, setCurrentStageId] = useState<string>(STAGES[0].id);
  const [clients, setClients] = useState<Client[]>([]);

  // Carregar dados se for Admin
  useEffect(() => {
    if (auth?.isAuthenticated && !auth.isVisitor) {
      const saved = localStorage.getItem('gev_loop_clients');
      if (saved) {
        try {
          setClients(JSON.parse(saved));
        } catch (e) {
          console.error("Erro ao carregar dados salvos", e);
        }
      }
    }
  }, [auth]);

  // Salvar dados se for Admin
  useEffect(() => {
    if (auth?.isAuthenticated && !auth.isVisitor) {
      localStorage.setItem('gev_loop_clients', JSON.stringify(clients));
    }
  }, [clients, auth]);

  const handleLogin = (mode: 'visitor' | 'admin') => {
    setAuth({
      isAuthenticated: true,
      isVisitor: mode === 'visitor'
    });
  };

  const handleLogout = () => {
    if (window.confirm("Deseja realmente sair do sistema?")) {
      // Limpeza total de estados para forçar re-render do Login
      setAuth(null);
      setClients([]);
      setView('list');
      setSelectedClientId(null);
      setCurrentStageId(STAGES[0].id);
    }
  };

  const handleCreateClient = (newClient: Client) => {
    setClients(prev => [newClient, ...prev]);
    handleSelectClient(newClient);
  };

  const handleEditClient = (updatedClient: Client) => {
    setClients(prev => prev.map(c => c.id === updatedClient.id ? updatedClient : c));
  };

  const handleDeleteClient = (clientId: string) => {
    setClients(prev => prev.filter(c => c.id !== clientId));
    if (selectedClientId === clientId) {
      setView('list');
      setSelectedClientId(null);
    }
  };

  const handleSelectClient = (client: Client) => {
    setSelectedClientId(client.id);
    setCurrentStageId(client.currentStageId || STAGES[0].id);
    setView('detail');
  };

  const handleUpdateNotes = (notes: string) => {
    if (!selectedClientId) return;
    setClients(prev => prev.map(c => 
      c.id === selectedClientId ? { ...c, additionalNotes: notes } : c
    ));
  };

  const handleUpdateClientStage = (clientId: string, newStageId: string, stageData?: Record<string, string>) => {
    const now = new Date().toISOString();
    setClients(prev => prev.map(c => {
      if (c.id === clientId) {
        return { 
          ...c, 
          currentStageId: newStageId, 
          stageData: { ...c.stageData, ...stageData },
          stageHistory: { ...c.stageHistory, [newStageId]: now }
        };
      }
      return c;
    }));
    if (selectedClientId === clientId) {
      setCurrentStageId(newStageId);
    }
  };

  if (!auth?.isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  const selectedClient = clients.find(c => c.id === selectedClientId);
  const currentStage = STAGES.find(s => s.id === currentStageId) || STAGES[0];

  return (
    <div className="h-screen bg-gray-100 flex flex-col overflow-hidden font-sans">
      <header className="bg-brand-900 h-16 sm:h-20 shrink-0 shadow-lg relative z-50 print:hidden">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 h-full flex items-center justify-between">
          <div className="flex items-center gap-4">
            {view === 'detail' && (
              <button onClick={() => setView('list')} className="p-2 hover:bg-white/10 rounded-full text-gold-400 transition">
                <ArrowLeft size={20} />
              </button>
            )}
            <div className="flex flex-col">
              <h1 className="text-xl sm:text-2xl font-black text-white uppercase tracking-tighter leading-none">
                LOOP <span className="text-gold-500">ENERGIA</span>
              </h1>
              <div className="flex items-center gap-2">
                <p className="text-[8px] text-brand-400 uppercase tracking-widest font-bold">Gestão de Experiência</p>
                <span className={`text-[7px] px-1.5 py-0.5 rounded font-black uppercase ${auth.isVisitor ? 'bg-amber-500/20 text-amber-500' : 'bg-emerald-500/20 text-emerald-500'}`}>
                  {auth.isVisitor ? 'Visitante' : 'Admin'}
                </span>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-2 sm:gap-4">
             <nav className="flex bg-brand-800/50 p-1 rounded-xl border border-brand-700/50 mr-2 sm:mr-4">
                <button 
                  onClick={() => setView('list')}
                  className={`flex items-center gap-2 px-3 sm:px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${view !== 'dashboard' && view !== 'detail' ? 'bg-brand-600 text-white shadow-lg' : 'text-brand-300 hover:text-white'}`}
                >
                  <LayoutList size={14} /> <span className="hidden sm:inline">Carteira</span>
                </button>
                <button 
                  onClick={() => setView('dashboard')}
                  className={`flex items-center gap-2 px-3 sm:px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${view === 'dashboard' ? 'bg-brand-600 text-white shadow-lg' : 'text-brand-300 hover:text-white'}`}
                >
                  <BarChart3 size={14} /> <span className="hidden sm:inline">Dashboard</span>
                </button>
             </nav>

             <div className="h-8 w-px bg-brand-800 hidden md:block"></div>

             <button 
               onClick={handleLogout}
               className="p-2 text-brand-300 hover:text-red-400 hover:bg-white/5 rounded-full transition flex items-center gap-2 group"
               title="Sair do Sistema"
             >
               <LogOut size={20} />
               <span className="hidden lg:inline text-[10px] font-black uppercase tracking-widest">Sair</span>
             </button>
          </div>
        </div>
      </header>

      <main className={`flex-1 overflow-hidden max-w-7xl mx-auto w-full px-4 sm:px-6 py-4 ${view === 'dashboard' ? 'overflow-y-auto custom-scroll print:overflow-visible print:max-w-none print:px-0' : ''}`}>
        {view === 'list' ? (
          <ClientList 
            clients={clients} 
            onSelectClient={handleSelectClient} 
            onCreateClient={handleCreateClient}
            onEditClient={handleEditClient}
            onDeleteClient={handleDeleteClient}
            onUpdateClientStage={handleUpdateClientStage}
          />
        ) : view === 'dashboard' ? (
          <Dashboard clients={clients} />
        ) : (
          <div className="flex flex-col h-full gap-4">
            <Timeline 
              currentStageId={currentStageId} 
              onSelectStage={(s) => setCurrentStageId(s.id)} 
            />
            <div className="flex-1 min-h-0">
              {selectedClient && (
                <ContentGenerator 
                  stage={currentStage}
                  client={selectedClient}
                  onUpdateNotes={handleUpdateNotes}
                  onUpdateClientStage={handleUpdateClientStage}
                />
              )}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

import React, { useState } from 'react';
import { Client, Stage } from '../types.ts';
import { Plus, Search, User, Zap, List, Kanban, X, Timer, ChevronRight, AlertCircle, Clock, FilterX, Trash2, Edit3, CalendarDays } from 'lucide-react';
import { STAGES, STEP_ICONS } from '../constants.ts';
import { generateTemplateContent } from '../services/templateService.ts';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onEditClient: (client: Client) => void;
  onDeleteClient: (clientId: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

type FilterStatus = 'ativos' | 'entregues' | 'noprazo' | 'atencao' | 'urgente' | null;

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onEditClient, onDeleteClient, onUpdateClientStage }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'list' | 'pipeline'>('list');
  const [statusFilter, setStatusFilter] = useState<FilterStatus>(null);

  const [draggedClientId, setDraggedClientId] = useState<string | null>(null);
  const [initialStageId, setInitialStageId] = useState<string>(STAGES[0].id);

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '',
    clientNumber: '',
    prgd: '',
    phone: '',
    projectName: '',
  });

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    if (!startStr) return 0;
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const getStatusInfo = (days: number, isDelivered: boolean) => {
    if (isDelivered) return { label: '🟢 CONCLUÍDO', color: 'text-green-600', bg: 'bg-green-50', key: 'entregues' };
    if (days > 120) return { label: '🔴 CRÍTICO', color: 'text-red-600', bg: 'bg-red-50', key: 'urgente' };
    if (days > 90) return { label: '🟡 ATENÇÃO', color: 'text-orange-500', bg: 'bg-orange-50', key: 'atencao' };
    return { label: '🟢 NO PRAZO', color: 'text-green-600', bg: 'bg-green-50', key: 'noprazo' };
  };

  const handleFilterToggle = (filter: FilterStatus) => {
    setStatusFilter(prev => prev === filter ? null : filter);
  };

  const openWhatsApp = (client: Client, stage: Stage, values: Record<string, string> = {}) => {
      if (!client.phone || !stage.template) return;
      const mergedValues = { ...client.stageData, ...values };
      const content = generateTemplateContent(stage, client, mergedValues);
      const cleanPhone = client.phone.replace(/\D/g, '');
      const encodedText = encodeURIComponent(content.body);
      window.open(`https://api.whatsapp.com/send?phone=55${cleanPhone}&text=${encodedText}`, '_blank');
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name?.trim() || !formData.clientNumber?.trim() || !formData.prgd?.trim() || !formData.phone?.trim()) {
      alert("⚠️ Atenção: Nome, Telefone, PRGD e Número do Cliente são obrigatórios.");
      return;
    }

    if (editingClient) {
      const updatedClient: Client = {
        ...editingClient,
        name: formData.name || '',
        clientNumber: formData.clientNumber || '',
        prgd: formData.prgd || '',
        phone: formData.phone || '',
        projectName: formData.projectName || `Projeto ${formData.name}`,
        currentStageId: initialStageId
      };
      onEditClient(updatedClient);
    } else {
      const now = new Date().toISOString();
      const newClient: Client = {
        id: Date.now().toString(),
        name: formData.name || '',
        clientNumber: formData.clientNumber || '',
        prgd: formData.prgd || '',
        phone: formData.phone || '',
        projectName: formData.projectName || `Projeto ${formData.name}`,
        additionalNotes: '',
        currentStageId: initialStageId,
        createdAt: now,
        stageHistory: { [initialStageId]: now },
        stageData: {}
      };
      const selectedStage = STAGES.find(s => s.id === initialStageId);
      if (selectedStage?.template) openWhatsApp(newClient, selectedStage);
      onCreateClient(newClient);
    }
    closeModal();
  };

  const handleStartEdit = (client: Client, e: React.MouseEvent) => {
    e.stopPropagation();
    setEditingClient(client);
    setFormData({
      name: client.name,
      clientNumber: client.clientNumber,
      prgd: client.prgd,
      phone: client.phone,
      projectName: client.projectName
    });
    setInitialStageId(client.currentStageId);
    setIsCreating(true);
  };

  const handleDelete = (clientId: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (window.confirm("Deseja realmente apagar este cliente? Esta ação é definitiva.")) {
      onDeleteClient(clientId);
    }
  };

  const closeModal = () => {
    setIsCreating(false);
    setEditingClient(null);
    setFormData({ name: '', clientNumber: '', prgd: '', phone: '', projectName: '' });
  };

  const filteredClients = clients.filter(c => {
    const matchesSearch = c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          c.prgd.toLowerCase().includes(searchTerm.toLowerCase());

    if (!matchesSearch) return false;
    if (!statusFilter) return true;

    const isDelivered = c.currentStageId === '7';
    const days = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);
    const statusKey = getStatusInfo(days, isDelivered).key;

    if (statusFilter === 'ativos') return !isDelivered;
    return statusKey === statusFilter;
  });

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-0 h-full flex flex-col relative overflow-hidden">
      {/* Modal de Criação / Edição */}
      {isCreating && (
          <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
              <div className="bg-white rounded-3xl shadow-2xl w-full max-w-xl animate-scale-up border border-gray-100 overflow-hidden">
                  <div className="p-8 pb-4 flex justify-between items-center border-b border-gray-50">
                      <div>
                        <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">
                          {editingClient ? 'Editar Cadastro' : 'Novo Cliente'}
                        </h2>
                        <p className="text-xs text-gray-400 font-bold uppercase tracking-widest">
                          Preencha as informações do titular
                        </p>
                      </div>
                      <button onClick={closeModal} className="p-2 hover:bg-gray-100 rounded-full transition text-gray-400 hover:text-brand-600"><X size={24} /></button>
                  </div>
                  <form onSubmit={handleSubmit} className="p-8 space-y-6 bg-white">
                      <div className="space-y-4">
                        <div className="group">
                          <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Nome do Titular *</label>
                          <input required value={formData.name} placeholder="Ex: João Silva" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" onChange={e => setFormData({...formData, name: e.target.value})} />
                        </div>

                        <div className="grid grid-cols-2 gap-4">
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Telefone *</label>
                            <input required placeholder="(00) 00000-0000" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} />
                          </div>
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-700 tracking-widest mb-1.5 block">Nº PRGD *</label>
                            <input required value={formData.prgd} placeholder="Ex: GD-2024-00" className="w-full p-3.5 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white focus:border-brand-500 transition text-sm font-medium" onChange={e => setFormData({...formData, prgd: e.target.value})} />
                          </div>
