            <Search className="absolute left-4 top-3.5 text-gray-300" size={18} />
            <input placeholder="Buscar titular ou PRGD..." className="w-full pl-12 p-3.5 rounded-2xl border-gray-100 border bg-gray-50 focus:bg-white outline-none transition font-medium" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
