import React, { useState } from 'react';
import { Client, Stage } from '../types.ts';
import { Plus, Search, User, Zap, List, Kanban, X, ChevronRight, Clock, Trash2, Edit3, CalendarDays, ArrowRightLeft } from 'lucide-react';
import { STAGES, STEP_ICONS } from '../constants.ts';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onEditClient: (client: Client) => void;
  onDeleteClient: (clientId: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

type ViewMode = 'list' | 'pipeline';
type FilterStatus = 'ativos' | 'entregues' | 'noprazo' | 'atencao' | 'urgente' | null;

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onEditClient, onDeleteClient, onUpdateClientStage }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<ViewMode>('pipeline'); // Padrão agora é Pipeline como solicitado
  const [statusFilter, setStatusFilter] = useState<FilterStatus>(null);
  const [initialStageId, setInitialStageId] = useState<string>(STAGES[0].id);

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '',
    clientNumber: '',
    prgd: '',
    phone: '',
  });

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    if (!startStr) return 0;
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const getStatusInfo = (days: number, isDelivered: boolean) => {
    if (isDelivered) return { label: '🟢 CONCLUÍDO', color: 'text-green-600', bg: 'bg-green-50', key: 'entregues' };
    if (days > 120) return { label: '🔴 CRÍTICO', color: 'text-red-600', bg: 'bg-red-50', key: 'urgente' };
    if (days > 90) return { label: '🟡 ATENÇÃO', color: 'text-orange-500', bg: 'bg-orange-50', key: 'atencao' };
    return { label: '🟢 NO PRAZO', color: 'text-green-600', bg: 'bg-green-50', key: 'noprazo' };
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name?.trim() || !formData.clientNumber?.trim() || !formData.prgd?.trim() || !formData.phone?.trim()) {
      alert("Preencha os campos obrigatórios.");
      return;
    }

    if (editingClient) {
      onEditClient({
        ...editingClient,
        name: formData.name || '',
        clientNumber: formData.clientNumber || '',
        prgd: formData.prgd || '',
        phone: formData.phone || '',
      });
    } else {
      const now = new Date().toISOString();
      onCreateClient({
        id: Date.now().toString(),
        name: formData.name || '',
        clientNumber: formData.clientNumber || '',
        prgd: formData.prgd || '',
        phone: formData.phone || '',
        projectName: `Projeto ${formData.name}`,
        additionalNotes: '',
        currentStageId: initialStageId,
        createdAt: now,
        stageHistory: { [initialStageId]: now },
        stageData: {}
      });
    }
    closeModal();
  };

  const closeModal = () => {
    setIsCreating(false);
    setEditingClient(null);
    setFormData({ name: '', clientNumber: '', prgd: '', phone: '' });
  };

  const filteredClients = clients.filter(c => {
    const matchesSearch = c.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
                          c.prgd.toLowerCase().includes(searchTerm.toLowerCase());
    if (!matchesSearch) return false;
    if (!statusFilter) return true;
    const isDelivered = c.currentStageId === '7';
    const days = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);
    const statusKey = getStatusInfo(days, isDelivered).key;
    if (statusFilter === 'ativos') return !isDelivered;
    return statusKey === statusFilter;
  });

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-0 h-full flex flex-col relative overflow-hidden">
      {/* Modal Cadastro/Edição */}
      {isCreating && (
          <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
              <div className="bg-white rounded-3xl shadow-2xl w-full max-w-xl animate-scale-up border border-gray-100 overflow-hidden">
                  <div className="p-8 pb-4 flex justify-between items-center border-b border-gray-50">
                      <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">{editingClient ? 'Editar Cadastro' : 'Novo Cliente'}</h2>
                      <button onClick={closeModal} className="p-2 hover:bg-gray-100 rounded-full transition text-gray-400"><X size={24} /></button>
                  </div>
                  <form onSubmit={handleSubmit} className="p-8 space-y-6">
                      <div className="space-y-4">
                        <input required value={formData.name} placeholder="Nome do Titular" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20" onChange={e => setFormData({...formData, name: e.target.value})} />
                        <div className="grid grid-cols-2 gap-4">
                          <input required placeholder="Telefone" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} />
                          <input required value={formData.prgd} placeholder="Nº PRGD" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none" onChange={e => setFormData({...formData, prgd: e.target.value})} />
                        </div>
                        <input required value={formData.clientNumber} placeholder="Número do Cliente" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none" onChange={e => setFormData({...formData, clientNumber: e.target.value})} />
                      </div>
                      <button type="submit" className="w-full bg-brand-600 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-sm hover:bg-brand-700 shadow-lg transition-all">
                        {editingClient ? 'SALVAR ALTERAÇÕES' : 'CADASTRAR CLIENTE'}
                      </button>
                  </form>
              </div>
          </div>
      )}

      {/* Cabeçalho de Navegação e Filtros */}
      <div className="p-6 border-b flex flex-col gap-6 bg-gray-50/30">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <div>
                <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">Gestão de Carteira</h2>
                <div className="flex flex-wrap gap-2 mt-2">
                    {['ativos', 'entregues', 'noprazo', 'atencao', 'urgente'].map((f) => (
                        <button 
                            key={f}
                            onClick={() => setStatusFilter(statusFilter === f ? null : f as FilterStatus)}
                            className={`text-[9px] font-black px-3 py-1 rounded-full uppercase tracking-widest border transition-all ${statusFilter === f ? 'bg-brand-600 text-white' : 'bg-white text-brand-600 border-gray-200'}`}
                        >
                            {f}
                        </button>
                    ))}
                </div>
            </div>

            <div className="flex bg-white p-1.5 rounded-2xl border border-gray-200 shadow-sm">
                <button onClick={() => setViewMode('list')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'list' ? 'bg-brand-600 text-white shadow-md' : 'text-gray-400 hover:text-brand-600'}`}>
                    <List size={14} /> Lista
                </button>
                <button onClick={() => setViewMode('pipeline')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'pipeline' ? 'bg-brand-600 text-white shadow-md' : 'text-gray-400 hover:text-brand-600'}`}>
                    <Kanban size={14} /> Pipeline
                </button>
            </div>
        </div>

        <div className="flex flex-col md:flex-row gap-4">
            <div className="relative flex-1">
                <Search className="absolute left-4 top-3.5 text-gray-300" size={18} />
                <input 
                    placeholder="Buscar titular ou PRGD..." 
                    className="w-full pl-12 p-3.5 rounded-2xl border-gray-200 border bg-white outline-none transition font-medium" 
                    value={searchTerm} 
                    onChange={e => setSearchTerm(e.target.value)} 
                />
            </div>
            <button onClick={() => setIsCreating(true)} className="bg-brand-600 text-white px-8 py-3.5 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-brand-700 transition-all flex items-center justify-center gap-2">
                <Plus size={18} /> Novo Cadastro
            </button>
        </div>
      </div>

      <div className="flex-1 overflow-hidden bg-gray-50/50">
        {viewMode === 'list' ? (
          <div className="p-6 overflow-auto h-full">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-8">
                {filteredClients.map(client => (
                    <ClientCard 
                        key={client.id} 
                        client={client} 
                        onSelect={onSelectClient} 
                        onEdit={(e) => {
                            e.stopPropagation();
                            setEditingClient(client);
                            setFormData({ name: client.name, clientNumber: client.clientNumber, prgd: client.prgd, phone: client.phone });
                            setIsCreating(true);
                        }}
                        onDelete={(e) => {
                            e.stopPropagation();
                            if(window.confirm("Excluir cliente?")) onDeleteClient(client.id);
                        }}
                        calculateDays={calculateDaysElapsed}
                        getStatus={getStatusInfo}
                    />
                ))}
            </div>
          </div>
        ) : (
          /* VISÃO PIPELINE / KANBAN - ONDE SE PODE MOVER OS CLIENTES */
          <div className="flex overflow-x-auto h-full p-6 gap-6 snap-x custom-scroll">
            {STAGES.map(stage => {
              const stageClients = filteredClients.filter(c => c.currentStageId === stage.id);
              return (
                <div key={stage.id} className="min-w-[320px] max-w-[320px] flex flex-col h-full snap-start">
                  <div className="flex items-center justify-between mb-4 px-2">
                    <div className="flex items-center gap-2">
                        <span className="bg-brand-600 text-white w-6 h-6 rounded-lg flex items-center justify-center text-[10px] font-black">{stage.stepNumber}</span>
                        <h3 className="text-xs font-black uppercase text-brand-900 tracking-tight">{stage.title}</h3>
                    </div>
                    <span className="text-[10px] font-black text-gray-300 bg-gray-100 px-2 py-0.5 rounded-full">{stageClients.length}</span>
                  </div>

                  <div className="flex-1 overflow-y-auto space-y-4 pr-2 custom-scroll">
                    {stageClients.map(client => (
                        <div 
                            key={client.id} 
                            onClick={() => onSelectClient(client)}
                            className="bg-white p-5 rounded-3xl border border-gray-100 shadow-sm hover:shadow-xl hover:border-brand-300 transition-all cursor-pointer group"
                        >
                            <div className="flex justify-between items-start mb-3">
                                <h4 className="font-black text-brand-900 uppercase text-xs truncate max-w-[180px] group-hover:text-brand-600">{client.name}</h4>
                                <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                                    <button onClick={(e) => { e.stopPropagation(); if(window.confirm("Excluir?")) onDeleteClient(client.id); }} className="p-1.5 text-gray-300 hover:text-red-500 hover:bg-red-50 rounded-lg"><Trash2 size={12} /></button>
                                </div>
                            </div>

                            <div className="bg-gray-50 rounded-2xl p-3 mb-3">
                                <div className="flex justify-between items-center text-[9px] font-black uppercase tracking-widest mb-1.5">
                                    <span className="text-gray-400">Permanência:</span>
                                    <span className="text-brand-600">{calculateDaysElapsed(client.stageHistory[client.currentStageId] || client.createdAt)} dias</span>
                                </div>
                                <div className="w-full bg-gray-200 h-1 rounded-full overflow-hidden">
                                    <div className="bg-brand-500 h-full" style={{ width: `${Math.min(100, (calculateDaysElapsed(client.stageHistory[client.currentStageId] || client.createdAt) / 15) * 100)}%` }}></div>
                                </div>
                            </div>

                            <div className="flex items-center justify-between">
                                <span className="text-[8px] font-black text-gray-400 uppercase tracking-widest">PRGD: {client.prgd}</span>
                                <button 
                                    onClick={(e) => {
                                        e.stopPropagation();
                                        const nextIdx = STAGES.findIndex(s => s.id === client.currentStageId) + 1;
                                        if (nextIdx < STAGES.length) onUpdateClientStage(client.id, STAGES[nextIdx].id);
                                    }}
                                    className="p-1.5 bg-brand-50 text-brand-600 rounded-xl hover:bg-brand-600 hover:text-white transition-all shadow-sm flex items-center gap-1 text-[9px] font-black uppercase"
                                >
                                    Avançar <ArrowRightLeft size={10} />
                                </button>
                            </div>
                        </div>
                    ))}
                    {stageClients.length === 0 && (
                        <div className="border-2 border-dashed border-gray-100 rounded-3xl p-8 flex flex-col items-center justify-center text-gray-200">
                            <Zap size={24} className="mb-2 opacity-20" />
                            <span className="text-[8px] font-black uppercase tracking-[0.2em]">Sem Clientes</span>
                        </div>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

const ClientCard = ({ client, onSelect, onEdit, onDelete, calculateDays, getStatus }: any) => {
    const isDelivered = client.currentStageId === '7';
    const totalDays = calculateDays(client.createdAt, isDelivered ? client.stageHistory['7'] : undefined);
    const stageDays = calculateDays(client.stageHistory[client.currentStageId] || client.createdAt);
    const status = getStatus(totalDays, isDelivered);
    const currentStage = STAGES.find(s => s.id === client.currentStageId);
    const Icon = STEP_ICONS[currentStage?.stepNumber || '1'];

    return (
        <div onClick={() => onSelect(client)} className="bg-white border border-gray-100 rounded-[2.5rem] p-6 hover:border-brand-400 cursor-pointer transition-all shadow-sm hover:shadow-2xl group relative overflow-hidden flex flex-col gap-5">
            <div className="flex justify-between items-start">
                <div className="flex gap-4 items-center">
                    <div className="bg-brand-50 p-4 rounded-3xl group-hover:bg-brand-600 group-hover:text-white transition-colors">
                        <User size={24} />
                    </div>
                    <div>
                        <h3 className="font-black text-brand-900 uppercase text-lg leading-tight group-hover:text-brand-600 transition tracking-tighter truncate max-w-[160px]">{client.name}</h3>
                        <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest mt-1">PRGD: {client.prgd}</p>
                    </div>
                </div>
                <div className="flex gap-1 relative z-30">
                  <button onClick={onEdit} className="p-2.5 bg-gray-50 hover:bg-brand-600 text-gray-400 hover:text-white rounded-xl transition-all"><Edit3 size={16}/></button>
                  <button onClick={onDelete} className="p-2.5 bg-gray-50 hover:bg-red-600 text-gray-400 hover:text-white rounded-xl transition-all"><Trash2 size={16}/></button>
                </div>
            </div>

            <div className={`p-6 rounded-[2rem] border border-gray-100 flex flex-col gap-4 ${status.bg} shadow-inner`}>
                <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest">
                    <span className="text-gray-400 flex items-center gap-1.5"><Clock size={12}/> Jornada Total:</span>
                    <span className="text-brand-900 font-bold">{totalDays} dias</span>
                </div>
                <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest pt-2 border-t border-gray-200/50">
                    <span className="text-gray-400 flex items-center gap-1.5"><CalendarDays size={12}/> Estágio Atual:</span>
                    <span className="text-brand-600 font-bold">{stageDays} dias</span>
                </div>
                <div className={`py-2.5 rounded-2xl text-center text-[9px] font-black tracking-[0.2em] bg-white shadow-sm border border-gray-50/50 mt-2 ${status.color}`}>
                    {status.label}
                </div>
            </div>

            <div className="flex items-center justify-between pt-4 border-t border-gray-50">
                <div className="flex items-center gap-3">
                    <div className="bg-brand-900 text-gold-400 p-2.5 rounded-xl shadow-lg">
                        <Icon size={16} />
                    </div>
                    <div className="flex flex-col">
                        <span className="text-[8px] font-black text-gray-400 uppercase tracking-widest">Etapa</span>
                        <span className="text-xs font-black text-brand-900 uppercase tracking-tight truncate max-w-[160px]">{currentStage?.title}</span>
                    </div>
                </div>
                <ChevronRight className="text-gray-200 group-hover:translate-x-1 group-hover:text-brand-400 transition-all" size={20} />
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { Timeline } from './components/Timeline.tsx';
import { ContentGenerator } from './components/ContentGenerator.tsx';
import { ClientList } from './components/ClientList.tsx';
import { Dashboard } from './components/Dashboard.tsx';
import { STAGES } from './constants.ts';
import { Client, Stage } from './types.ts';
import { ArrowLeft, BarChart3, LayoutList, Zap } from 'lucide-react';

export default function App() {
  const [view, setView] = useState<'list' | 'detail' | 'dashboard'>('list');
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [currentStageId, setCurrentStageId] = useState<string>(STAGES[0].id);
  const [clients, setClients] = useState<Client[]>([]);

  // Carregar dados salvos automaticamente
  useEffect(() => {
    const saved = localStorage.getItem('gev_loop_clients');
    if (saved) {
      try {
        setClients(JSON.parse(saved));
      } catch (e) {
        console.error("Erro ao carregar dados", e);
      }
    }
  }, []);

  // Salvar dados automaticamente
  useEffect(() => {
    localStorage.setItem('gev_loop_clients', JSON.stringify(clients));
  }, [clients]);

  const handleCreateClient = (newClient: Client) => {
    setClients(prev => [newClient, ...prev]);
    handleSelectClient(newClient);
  };

  const handleEditClient = (updatedClient: Client) => {
    setClients(prev => prev.map(c => c.id === updatedClient.id ? updatedClient : c));
  };

  const handleDeleteClient = (clientId: string) => {
    if (window.confirm("Deseja realmente excluir este cliente?")) {
      setClients(prev => prev.filter(c => c.id !== clientId));
      if (selectedClientId === clientId) {
        setView('list');
        setSelectedClientId(null);
      }
    }
  };

  const handleSelectClient = (client: Client) => {
    setSelectedClientId(client.id);
    setCurrentStageId(client.currentStageId || STAGES[0].id);
    setView('detail');
  };

  const handleUpdateNotes = (notes: string) => {
    if (!selectedClientId) return;
    setClients(prev => prev.map(c => 
      c.id === selectedClientId ? { ...c, additionalNotes: notes } : c
    ));
  };

  const handleUpdateClientStage = (clientId: string, newStageId: string, stageData?: Record<string, string>) => {
    const now = new Date().toISOString();
    setClients(prev => prev.map(c => {
      if (c.id === clientId) {
        return { 
          ...c, 
          currentStageId: newStageId, 
          stageData: { ...c.stageData, ...stageData },
          stageHistory: { ...c.stageHistory, [newStageId]: now }
        };
      }
      return c;
    }));
    if (selectedClientId === clientId) {
      setCurrentStageId(newStageId);
    }
  };

  const selectedClient = clients.find(c => c.id === selectedClientId);
  const currentStage = STAGES.find(s => s.id === currentStageId) || STAGES[0];

  return (
    <div className="h-screen bg-gray-50 flex flex-col overflow-hidden font-sans">
      <header className="bg-brand-900 h-16 sm:h-20 shrink-0 shadow-lg relative z-50 print:hidden border-b border-brand-800">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 h-full flex items-center justify-between">
          <div className="flex items-center gap-4">
            {view === 'detail' && (
              <button onClick={() => setView('list')} className="p-2 hover:bg-white/10 rounded-full text-gold-400 transition">
                <ArrowLeft size={20} />
              </button>
            )}
            <div className="flex flex-col">
              <h1 className="text-xl sm:text-2xl font-black text-white uppercase tracking-tighter leading-none">
                LOOP <span className="text-gold-500">ENERGIA</span>
              </h1>
              <p className="text-[8px] text-brand-400 uppercase tracking-widest font-bold mt-1">Gestão de Experiência do Cliente</p>
            </div>
          </div>

          <div className="flex items-center gap-4">
             <nav className="flex bg-brand-800/40 p-1 rounded-xl border border-brand-700/50">
                <button 
                  onClick={() => setView('list')}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${view !== 'dashboard' && view !== 'detail' ? 'bg-brand-600 text-white shadow-lg' : 'text-brand-300 hover:text-white'}`}
                >
                  <LayoutList size={14} /> <span className="hidden sm:inline">Carteira</span>
                </button>
                <button 
                  onClick={() => setView('dashboard')}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${view === 'dashboard' ? 'bg-brand-600 text-white shadow-lg' : 'text-brand-300 hover:text-white'}`}
                >
                  <BarChart3 size={14} /> <span className="hidden sm:inline">Dashboard</span>
                </button>
             </nav>
             <div className="bg-brand-800 p-2 rounded-full text-gold-400">
               <Zap size={18} fill="currentColor" />
             </div>
          </div>
        </div>
      </header>

      <main className={`flex-1 overflow-hidden max-w-7xl mx-auto w-full px-4 sm:px-6 py-4 ${view === 'dashboard' ? 'overflow-y-auto custom-scroll' : ''}`}>
        {view === 'list' ? (
          <ClientList 
            clients={clients} 
            onSelectClient={handleSelectClient} 
            onCreateClient={handleCreateClient}
            onEditClient={handleEditClient}
            onDeleteClient={handleDeleteClient}
            onUpdateClientStage={handleUpdateClientStage}
          />
        ) : view === 'dashboard' ? (
          <Dashboard clients={clients} />
        ) : (
          <div className="flex flex-col h-full gap-4">
            <Timeline 
              currentStageId={currentStageId} 
              onSelectStage={(s) => setCurrentStageId(s.id)} 
            />
            <div className="flex-1 min-h-0">
              {selectedClient && (
                <ContentGenerator 
                  stage={currentStage}
                  client={selectedClient}
                  onUpdateNotes={handleUpdateNotes}
                  onUpdateClientStage={handleUpdateClientStage}
                />
              )}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

import React, { useState } from 'react';
import { Client, Stage } from '../types.ts';
import { Plus, Search, User, Zap, List, Kanban, X, ChevronRight, Clock, Trash2, Edit3, CalendarDays, ArrowRightLeft } from 'lucide-react';
import { STAGES, STEP_ICONS } from '../constants.ts';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onEditClient: (client: Client) => void;
  onDeleteClient: (clientId: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

type ViewMode = 'list' | 'pipeline';
type FilterStatus = 'ativos' | 'entregues' | 'noprazo' | 'atencao' | 'urgente' | null;

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onEditClient, onDeleteClient, onUpdateClientStage }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<ViewMode>('pipeline');
  const [statusFilter, setStatusFilter] = useState<FilterStatus>(null);
  const [initialStageId, setInitialStageId] = useState<string>(STAGES[0].id);

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '',
    clientNumber: '',
    prgd: '',
    phone: '',
  });

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    if (!startStr) return 0;
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const getStatusInfo = (days: number, isDelivered: boolean) => {
    if (isDelivered) return { label: '🟢 CONCLUÍDO', color: 'text-green-600', bg: 'bg-green-50', key: 'entregues', btn: 'bg-green-100 text-green-700' };
    if (days > 120) return { label: '🔴 CRÍTICO', color: 'text-red-600', bg: 'bg-red-50', key: 'urgente', btn: 'bg-red-100 text-red-700' };
    if (days > 90) return { label: '🟡 ATENÇÃO', color: 'text-orange-500', bg: 'bg-orange-50', key: 'atencao', btn: 'bg-amber-100 text-amber-700' };
    return { label: '🟢 NO PRAZO', color: 'text-green-600', bg: 'bg-green-50', key: 'noprazo', btn: 'bg-emerald-100 text-emerald-700' };
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingClient) {
      onEditClient({ ...editingClient, name: formData.name || '', clientNumber: formData.clientNumber || '', prgd: formData.prgd || '', phone: formData.phone || '' });
    } else {
      const now = new Date().toISOString();
      onCreateClient({
        id: Date.now().toString(),
        name: formData.name || '',
        clientNumber: formData.clientNumber || '',
        prgd: formData.prgd || '',
        phone: formData.phone || '',
        projectName: `Projeto ${formData.name}`,
        additionalNotes: '',
        currentStageId: initialStageId,
        createdAt: now,
        stageHistory: { [initialStageId]: now },
        stageData: {}
      });
    }
    closeModal();
  };

  const closeModal = () => {
    setIsCreating(false);
    setEditingClient(null);
    setFormData({ name: '', clientNumber: '', prgd: '', phone: '' });
  };

  const filteredClients = clients.filter(c => {
    const matchesSearch = c.name.toLowerCase().includes(searchTerm.toLowerCase()) || c.prgd.toLowerCase().includes(searchTerm.toLowerCase());
    if (!matchesSearch) return false;
    if (!statusFilter) return true;
    const isDelivered = c.currentStageId === '7';
    const days = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);
    const info = getStatusInfo(days, isDelivered);
    if (statusFilter === 'ativos') return !isDelivered;
    return info.key === statusFilter;
  });

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-gray-200 p-0 h-full flex flex-col relative overflow-hidden font-sans">
      {/* Modal de Cadastro */}
      {isCreating && (
          <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
              <div className="bg-white rounded-3xl shadow-2xl w-full max-w-xl animate-scale-up border border-gray-100 overflow-hidden">
                  <div className="p-8 pb-4 flex justify-between items-center border-b border-gray-50">
                      <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">{editingClient ? 'Editar Cadastro' : 'Novo Cliente'}</h2>
                      <button onClick={closeModal} className="p-2 hover:bg-gray-100 rounded-full transition text-gray-400"><X size={24} /></button>
                  </div>
                  <form onSubmit={handleSubmit} className="p-8 space-y-6">
                      <div className="space-y-4">
                        <input required value={formData.name} placeholder="Nome do Titular" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20" onChange={e => setFormData({...formData, name: e.target.value})} />
                        <div className="grid grid-cols-2 gap-4">
                          <input required placeholder="Telefone" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} />
                          <input required value={formData.prgd} placeholder="Nº PRGD" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none" onChange={e => setFormData({...formData, prgd: e.target.value})} />
                        </div>
                        <input required value={formData.clientNumber} placeholder="Número do Cliente" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none" onChange={e => setFormData({...formData, clientNumber: e.target.value})} />
                      </div>
                      <button type="submit" className="w-full bg-brand-600 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-sm hover:bg-brand-700 shadow-lg transition-all">
                        {editingClient ? 'SALVAR ALTERAÇÕES' : 'CADASTRAR CLIENTE'}
                      </button>
                  </form>
              </div>
          </div>
      )}

      {/* CABEÇALHO RESTAURADO COM CORES E DIVISOR */}
      <div className="p-6 border-b flex flex-col gap-6 bg-gray-50/30">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <div>
                <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">Carteira de Projetos</h2>
                <div className="flex flex-wrap items-center gap-2 mt-2">
                    {/* Grupo de Status */}
                    <button onClick={() => setStatusFilter(statusFilter === 'ativos' ? null : 'ativos')} className={`text-[9px] font-black px-3 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'ativos' ? 'bg-brand-600 text-white border-brand-700' : 'bg-white text-brand-600 border-gray-200 hover:border-brand-300'}`}>Ativos</button>
                    <button onClick={() => setStatusFilter(statusFilter === 'entregues' ? null : 'entregues')} className={`text-[9px] font-black px-3 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'entregues' ? 'bg-green-600 text-white border-green-700' : 'bg-white text-green-600 border-gray-200 hover:border-green-300'}`}>Entregues</button>

                    {/* Linha Divisora Vertical */}
                    <div className="h-4 w-px bg-gray-300 mx-1"></div>

                    {/* Grupo de Prazos */}
                    <button onClick={() => setStatusFilter(statusFilter === 'noprazo' ? null : 'noprazo')} className={`text-[9px] font-black px-3 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'noprazo' ? 'bg-emerald-600 text-white border-emerald-700' : 'bg-emerald-50 text-emerald-700 border-emerald-100 hover:bg-emerald-100'}`}>No Prazo</button>
                    <button onClick={() => setStatusFilter(statusFilter === 'atencao' ? null : 'atencao')} className={`text-[9px] font-black px-3 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'atencao' ? 'bg-amber-500 text-white border-amber-600' : 'bg-amber-50 text-amber-700 border-amber-100 hover:bg-amber-100'}`}>Atenção</button>
                    <button onClick={() => setStatusFilter(statusFilter === 'urgente' ? null : 'urgente')} className={`text-[9px] font-black px-3 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'urgente' ? 'bg-red-600 text-white border-red-700' : 'bg-red-50 text-red-700 border-red-100 hover:bg-red-100'}`}>Urgente</button>
                </div>
            </div>

            <div className="flex bg-white p-1 rounded-2xl border border-gray-200 shadow-sm">
                <button onClick={() => setViewMode('list')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'list' ? 'bg-brand-600 text-white shadow-md' : 'text-gray-400 hover:text-brand-600'}`}>
                    <List size={14} /> Lista
                </button>
                <button onClick={() => setViewMode('pipeline')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'pipeline' ? 'bg-brand-600 text-white shadow-md' : 'text-gray-400 hover:text-brand-600'}`}>
                    <Kanban size={14} /> Pipeline
                </button>
            </div>
        </div>

        <div className="flex flex-col md:flex-row gap-4">
            <div className="relative flex-1">
                <Search className="absolute left-4 top-3.5 text-gray-300" size={18} />
                <input placeholder="Buscar por nome ou PRGD..." className="w-full pl-12 p-3.5 rounded-2xl border-gray-200 border bg-white outline-none transition font-medium" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
            </div>
            <button onClick={() => setIsCreating(true)} className="bg-brand-600 text-white px-8 py-3.5 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-brand-700 transition-all flex items-center justify-center gap-2">
                <Plus size={18} /> Novo Cliente
            </button>
        </div>
      </div>

      <div className="flex-1 overflow-hidden bg-gray-50/50">
        {viewMode === 'list' ? (
          <div className="p-6 overflow-auto h-full">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-8">
                {filteredClients.map(client => (
                    <ClientCard 
                        key={client.id} 
                        client={client} 
                        onSelect={onSelectClient} 
                        onEdit={(e) => {
                            e.stopPropagation();
                            setEditingClient(client);
                            setFormData({ name: client.name, clientNumber: client.clientNumber, prgd: client.prgd, phone: client.phone });
                            setIsCreating(true);
                        }}
                        onDelete={(e) => {
                            e.stopPropagation();
                            onDeleteClient(client.id);
                        }}
                        calculateDays={calculateDaysElapsed}
                        getStatus={getStatusInfo}
                    />
                ))}
            </div>
          </div>
        ) : (
          /* PIPELINE KANBAN RESTAURADO */
          <div className="flex overflow-x-auto h-full p-6 gap-6 snap-x custom-scroll">
            {STAGES.map(stage => {
              const stageClients = filteredClients.filter(c => c.currentStageId === stage.id);
              const Icon = STEP_ICONS[stage.stepNumber] || Zap;
              return (
                <div key={stage.id} className="min-w-[300px] max-w-[300px] flex flex-col h-full snap-start">
                  <div className="flex items-center justify-between mb-4 px-2">
                    <div className="flex items-center gap-3">
                        <div className="bg-brand-900 text-gold-400 p-2 rounded-lg shadow-sm">
                            <Icon size={14} />
                        </div>
                        <h3 className="text-xs font-black uppercase text-brand-900 tracking-tight">{stage.title}</h3>
                    </div>
                    <span className="text-[10px] font-black text-gray-400 bg-gray-200/50 px-2 py-0.5 rounded-full">{stageClients.length}</span>
                  </div>

                  <div className="flex-1 overflow-y-auto space-y-4 pr-2 custom-scroll">
                    {stageClients.map(client => {
                        const totalDays = calculateDaysElapsed(client.createdAt);
                        const stageDays = calculateDaysElapsed(client.stageHistory[client.currentStageId] || client.createdAt);
                        const status = getStatusInfo(totalDays, client.currentStageId === '7');

                        return (
                            <div key={client.id} onClick={() => onSelectClient(client)} className="bg-white p-5 rounded-3xl border border-gray-100 shadow-sm hover:shadow-xl hover:border-brand-400 transition-all cursor-pointer group relative overflow-hidden">
                                <div className={`absolute top-0 left-0 w-1 h-full ${status.bg.replace('bg-', 'bg-')}`}></div>
                                <div className="flex justify-between items-start mb-3">
                                    <h4 className="font-black text-brand-900 uppercase text-xs truncate max-w-[150px] group-hover:text-brand-600">{client.name}</h4>
                                    <button onClick={(e) => { e.stopPropagation(); onDeleteClient(client.id); }} className="p-1.5 text-gray-200 hover:text-red-500 rounded-lg transition-colors"><Trash2 size={12} /></button>
                                </div>

                                <div className="space-y-2 mb-3">
                                    <div className="flex justify-between text-[8px] font-black uppercase text-gray-400">
                                        <span>PRGD: {client.prgd}</span>
                                        <span className={status.color}>{stageDays} dias</span>
                                    </div>
                                    <div className="h-1 bg-gray-100 rounded-full overflow-hidden">
                                        <div className={`h-full transition-all duration-500 ${status.color.replace('text-', 'bg-')}`} style={{ width: `${Math.min(100, (stageDays / 15) * 100)}%` }}></div>
                                    </div>
                                </div>

                                <div className="flex items-center justify-between pt-2 border-t border-gray-50">
                                    <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-full ${status.btn}`}>{status.label.split(' ')[1]}</span>
                                    <button onClick={(e) => { e.stopPropagation(); const nextIdx = STAGES.findIndex(s => s.id === client.currentStageId) + 1; if (nextIdx < STAGES.length) onUpdateClientStage(client.id, STAGES[nextIdx].id); }} className="p-1.5 bg-brand-50 text-brand-600 rounded-lg hover:bg-brand-600 hover:text-white transition-all shadow-sm">
                                        <ArrowRightLeft size={10} />
                                    </button>
                                </div>
                            </div>
                        );
                    })}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

const ClientCard = ({ client, onSelect, onEdit, onDelete, calculateDays, getStatus }: any) => {
    const isDelivered = client.currentStageId === '7';
    const totalDays = calculateDays(client.createdAt, isDelivered ? client.stageHistory['7'] : undefined);
    const stageDays = calculateDays(client.stageHistory[client.currentStageId] || client.createdAt);
    const status = getStatus(totalDays, isDelivered);
    const currentStage = STAGES.find(s => s.id === client.currentStageId);
    const Icon = STEP_ICONS[currentStage?.stepNumber || '1'];

    return (
        <div onClick={() => onSelect(client)} className="bg-white border border-gray-100 rounded-[2.5rem] p-6 hover:border-brand-400 cursor-pointer transition-all shadow-sm hover:shadow-2xl group relative overflow-hidden flex flex-col gap-5">
            <div className="flex justify-between items-start">
                <div className="flex gap-4 items-center">
                    <div className="bg-brand-50 p-4 rounded-3xl group-hover:bg-brand-600 group-hover:text-white transition-colors">
                        <User size={24} />
                    </div>
                    <div>
                        <h3 className="font-black text-brand-900 uppercase text-lg leading-tight group-hover:text-brand-600 transition tracking-tighter truncate max-w-[160px]">{client.name}</h3>
                        <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest mt-1">PRGD: {client.prgd}</p>
                    </div>
                </div>
                <div className="flex gap-1 relative z-30">
                  <button onClick={onEdit} className="p-2.5 bg-gray-50 hover:bg-brand-600 text-gray-400 hover:text-white rounded-xl transition-all shadow-sm"><Edit3 size={16}/></button>
                  <button onClick={onDelete} className="p-2.5 bg-gray-50 hover:bg-red-600 text-gray-400 hover:text-white rounded-xl transition-all shadow-sm"><Trash2 size={16}/></button>
                </div>
            </div>

            <div className={`p-6 rounded-[2rem] border border-gray-100 flex flex-col gap-4 ${status.bg} shadow-inner`}>
                <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest">
                    <span className="text-gray-400 flex items-center gap-1.5"><Clock size={12}/> Jornada Total:</span>
                    <span className="text-brand-900 font-bold">{totalDays} dias</span>
                </div>
                <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest pt-2 border-t border-gray-200/50">
                    <span className="text-gray-400 flex items-center gap-1.5"><CalendarDays size={12}/> Tempo na Etapa:</span>
                    <span className="text-brand-600 font-bold">{stageDays} dias</span>
                </div>
                <div className={`py-2.5 rounded-2xl text-center text-[9px] font-black tracking-[0.2em] bg-white shadow-sm border border-gray-50/50 mt-2 ${status.color}`}>
                    {status.label}
                </div>
            </div>

            <div className="flex items-center justify-between pt-4 border-t border-gray-50">
                <div className="flex items-center gap-3">
                    <div className="bg-brand-900 text-gold-400 p-2.5 rounded-xl shadow-lg shadow-brand-900/20">
                        <Icon size={16} />
                    </div>
                    <div className="flex flex-col">
                        <span className="text-[8px] font-black text-gray-400 uppercase tracking-widest">Etapa Atual</span>
                        <span className="text-xs font-black text-brand-900 uppercase tracking-tight truncate max-w-[160px]">{currentStage?.title}</span>
                    </div>
                </div>
                <ChevronRight className="text-gray-200 group-hover:translate-x-1 group-hover:text-brand-400 transition-all" size={20} />
            </div>
        </div>
    );
};

import React, { useEffect, useRef } from 'react';
import { STAGES, STEP_ICONS } from '../constants.ts';
import { Stage } from '../types.ts';
import { Check } from 'lucide-react';

interface TimelineProps {
  currentStageId: string;
  onSelectStage: (stage: Stage) => void;
}

export const Timeline: React.FC<TimelineProps> = ({ currentStageId, onSelectStage }) => {
  const currentStageIndex = STAGES.findIndex(s => s.id === currentStageId);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      const activeElement = scrollRef.current.querySelector('[data-active="true"]');
      if (activeElement) {
        activeElement.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
      }
    }
  }, [currentStageId]);

  return (
    <div className="bg-white rounded-3xl shadow-sm border border-gray-200 w-full relative overflow-hidden shrink-0">
      <div className="absolute top-0 left-0 right-0 h-1 bg-gradient-to-r from-brand-900 via-brand-600 to-gold-500"></div>

      <div 
        ref={scrollRef}
        className="flex overflow-x-auto gap-4 p-5 scrollbar-hide snap-x"
        style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
      >
        {STAGES.map((stage, index) => {
          const Icon = STEP_ICONS[stage.stepNumber] || STEP_ICONS['1'];
          const isActive = stage.id === currentStageId;
          const isCompleted = index < currentStageIndex;

          return (
            <div 
              key={stage.id}
              data-active={isActive}
              onClick={() => onSelectStage(stage)}
              className={`
                shrink-0 snap-center cursor-pointer transition-all duration-300
                flex flex-col items-center gap-3 p-4 rounded-2xl min-w-[140px] border
                ${isActive 
                  ? 'bg-brand-50 border-brand-200 shadow-xl scale-105 z-10' 
                  : isCompleted
                    ? 'bg-gray-50 border-gold-100 opacity-80'
                    : 'bg-transparent border-transparent opacity-40 hover:opacity-100'
                }
              `}
            >
              <div 
                className={`
                  flex items-center justify-center w-12 h-12 rounded-2xl border-2 transition-all shadow-sm
                  ${isActive 
                    ? 'border-brand-900 bg-brand-900 text-gold-400' 
                    : isCompleted 
                      ? 'border-gold-500 bg-gold-50 text-gold-600' 
                      : 'border-gray-200 bg-white text-gray-300'
                  }
                `}
              >
                {isCompleted ? <Check size={20} strokeWidth={3} /> : <Icon size={20} />}
              </div>

              <div className="flex flex-col items-center text-center">
                <span className="text-[8px] uppercase font-black text-gray-400 tracking-[0.2em]">Passo {stage.stepNumber}</span>
                <h3 className={`text-[10px] font-black uppercase leading-tight mt-1 ${isActive ? 'text-brand-900' : 'text-gray-500'}`}>
                  {stage.title}
                </h3>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Timeline } from './components/Timeline.tsx';
import { ContentGenerator } from './components/ContentGenerator.tsx';
import { ClientList } from './components/ClientList.tsx';
import { Dashboard } from './components/Dashboard.tsx';
import { STAGES } from './constants.ts';
import { Client, Stage } from './types.ts';
import { ArrowLeft, BarChart3, LayoutList, Zap } from 'lucide-react';

export default function App() {
  const [view, setView] = useState<'list' | 'detail' | 'dashboard'>('list');
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [currentStageId, setCurrentStageId] = useState<string>(STAGES[0].id);
  const [clients, setClients] = useState<Client[]>([]);

  useEffect(() => {
    const saved = localStorage.getItem('gev_loop_clients');
    if (saved) {
      try {
        setClients(JSON.parse(saved));
      } catch (e) {
        console.error("Erro ao carregar dados", e);
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('gev_loop_clients', JSON.stringify(clients));
  }, [clients]);

  const handleCreateClient = (newClient: Client) => {
    setClients(prev => [newClient, ...prev]);
    handleSelectClient(newClient);
  };

  const handleEditClient = (updatedClient: Client) => {
    setClients(prev => prev.map(c => c.id === updatedClient.id ? updatedClient : c));
  };

  const handleDeleteClient = (clientId: string) => {
    setClients(prev => prev.filter(c => c.id !== clientId));
    if (selectedClientId === clientId) {
      setView('list');
      setSelectedClientId(null);
    }
  };

  const handleSelectClient = (client: Client) => {
    setSelectedClientId(client.id);
    setCurrentStageId(client.currentStageId || STAGES[0].id);
    setView('detail');
  };

  const handleUpdateNotes = (notes: string) => {
    if (!selectedClientId) return;
    setClients(prev => prev.map(c => 
      c.id === selectedClientId ? { ...c, additionalNotes: notes } : c
    ));
  };

  const handleUpdateClientStage = (clientId: string, newStageId: string, stageData?: Record<string, string>) => {
    const now = new Date().toISOString();
    setClients(prev => prev.map(c => {
      if (c.id === clientId) {
        return { 
          ...c, 
          currentStageId: newStageId, 
          stageData: { ...c.stageData, ...stageData },
          stageHistory: { ...c.stageHistory, [newStageId]: now }
        };
      }
      return c;
    }));
    if (selectedClientId === clientId) {
      setCurrentStageId(newStageId);
    }
  };

  const selectedClient = clients.find(c => c.id === selectedClientId);
  const currentStage = STAGES.find(s => s.id === currentStageId) || STAGES[0];

  return (
    <div className="h-screen bg-gray-50 flex flex-col overflow-hidden font-sans">
      <header className="bg-brand-900 h-16 sm:h-20 shrink-0 shadow-lg relative z-50 border-b border-brand-800">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 h-full flex items-center justify-between">
          <div className="flex items-center gap-4">
            {view === 'detail' && (
              <button onClick={() => setView('list')} className="p-2 hover:bg-white/10 rounded-full text-gold-400 transition">
                <ArrowLeft size={20} />
              </button>
            )}
            <div className="flex flex-col">
              <h1 className="text-xl sm:text-2xl font-black text-white uppercase tracking-tighter leading-none">
                LOOP <span className="text-gold-500">ENERGIA</span>
              </h1>
              <p className="text-[8px] text-brand-400 uppercase tracking-widest font-bold mt-1">Gestão de Experiência do Cliente</p>
            </div>
          </div>

          <div className="flex items-center gap-4">
             <nav className="flex bg-brand-800/40 p-1 rounded-xl border border-brand-700/50">
                <button 
                  onClick={() => setView('list')}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${view !== 'dashboard' && view !== 'detail' ? 'bg-brand-600 text-white shadow-lg' : 'text-brand-300 hover:text-white'}`}
                >
                  <LayoutList size={14} /> <span className="hidden sm:inline">Carteira</span>
                </button>
                <button 
                  onClick={() => setView('dashboard')}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${view === 'dashboard' ? 'bg-brand-600 text-white shadow-lg' : 'text-brand-300 hover:text-white'}`}
                >
                  <BarChart3 size={14} /> <span className="hidden sm:inline">Dashboard</span>
                </button>
             </nav>
             <div className="bg-brand-800 p-2.5 rounded-full text-gold-400 border border-brand-700">
               <Zap size={18} fill="currentColor" />
             </div>
          </div>
        </div>
      </header>

      <main className="flex-1 overflow-hidden max-w-7xl mx-auto w-full px-4 sm:px-6 py-4">
        {view === 'list' ? (
          <ClientList 
            clients={clients} 
            onSelectClient={handleSelectClient} 
            onCreateClient={handleCreateClient}
            onEditClient={handleEditClient}
            onDeleteClient={handleDeleteClient}
            onUpdateClientStage={handleUpdateClientStage}
          />
        ) : view === 'dashboard' ? (
          <Dashboard clients={clients} />
        ) : (
          <div className="flex flex-col h-full gap-4">
            <Timeline 
              currentStageId={currentStageId} 
              onSelectStage={(s) => setCurrentStageId(s.id)} 
            />
            <div className="flex-1 min-h-0">
              {selectedClient && (
                <ContentGenerator 
                  stage={currentStage}
                  client={selectedClient}
                  onUpdateNotes={handleUpdateNotes}
                  onUpdateClientStage={handleUpdateClientStage}
                />
              )}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

import React, { useState } from 'react';
import { Client, Stage } from '../types.ts';
import { Plus, Search, User, Zap, List, Kanban, X, ChevronRight, Clock, Trash2, Edit3, CalendarDays, ArrowRightLeft } from 'lucide-react';
import { STAGES, STEP_ICONS } from '../constants.ts';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onEditClient: (client: Client) => void;
  onDeleteClient: (clientId: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

type ViewMode = 'list' | 'pipeline';
type FilterStatus = 'ativos' | 'entregues' | 'noprazo' | 'atencao' | 'urgente' | null;

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onEditClient, onDeleteClient, onUpdateClientStage }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<ViewMode>('pipeline');
  const [statusFilter, setStatusFilter] = useState<FilterStatus>(null);

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '', clientNumber: '', prgd: '', phone: '',
  });

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    if (!startStr) return 0;
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const getStatusInfo = (days: number, isDelivered: boolean) => {
    if (isDelivered) return { label: '🟢 ENTREGUE', color: 'text-green-600', bg: 'bg-green-50', key: 'entregues', btn: 'bg-green-100 text-green-700' };
    if (days > 120) return { label: '🔴 URGENTE', color: 'text-red-600', bg: 'bg-red-50', key: 'urgente', btn: 'bg-red-100 text-red-700' };
    if (days > 90) return { label: '🟡 ATENÇÃO', color: 'text-amber-500', bg: 'bg-amber-50', key: 'atencao', btn: 'bg-amber-100 text-amber-700' };
    return { label: '🟢 NO PRAZO', color: 'text-emerald-600', bg: 'bg-emerald-50', key: 'noprazo', btn: 'bg-emerald-100 text-emerald-700' };
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingClient) {
      onEditClient({ ...editingClient, name: formData.name || '', clientNumber: formData.clientNumber || '', prgd: formData.prgd || '', phone: formData.phone || '' });
    } else {
      const now = new Date().toISOString();
      onCreateClient({
        id: Date.now().toString(),
        name: formData.name || '',
        clientNumber: formData.clientNumber || '',
        prgd: formData.prgd || '',
        phone: formData.phone || '',
        projectName: `Projeto ${formData.name}`,
        additionalNotes: '',
        currentStageId: STAGES[0].id,
        createdAt: now,
        stageHistory: { [STAGES[0].id]: now },
        stageData: {}
      });
    }
    closeModal();
  };

  const closeModal = () => {
    setIsCreating(false);
    setEditingClient(null);
    setFormData({ name: '', clientNumber: '', prgd: '', phone: '' });
  };

  const filteredClients = clients.filter(c => {
    const matchesSearch = c.name.toLowerCase().includes(searchTerm.toLowerCase()) || c.prgd.toLowerCase().includes(searchTerm.toLowerCase());
    if (!matchesSearch) return false;
    if (!statusFilter) return true;
    const isDelivered = c.currentStageId === '7';
    const days = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);
    const info = getStatusInfo(days, isDelivered);
    if (statusFilter === 'ativos') return !isDelivered;
    return info.key === statusFilter;
  });

  return (
    <div className="bg-white rounded-3xl shadow-sm border border-gray-200 h-full flex flex-col relative overflow-hidden">
      {/* MODAL CADASTRO */}
      {isCreating && (
          <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-4">
              <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-xl animate-scale-up border border-white/20 overflow-hidden">
                  <div className="p-8 pb-4 flex justify-between items-center border-b border-gray-50 bg-gray-50/50">
                      <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">{editingClient ? 'Editar Cadastro' : 'Novo Cliente'}</h2>
                      <button onClick={closeModal} className="p-2 hover:bg-white rounded-full transition text-gray-400"><X size={24} /></button>
                  </div>
                  <form onSubmit={handleSubmit} className="p-8 space-y-6">
                      <div className="space-y-4">
                        <div className="group">
                          <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1.5 block ml-1">Titular do Projeto</label>
                          <input required value={formData.name} placeholder="Nome Completo" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white transition-all" onChange={e => setFormData({...formData, name: e.target.value})} />
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1.5 block ml-1">Telefone</label>
                            <input required placeholder="(00) 00000-0000" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white transition-all" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} />
                          </div>
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1.5 block ml-1">Nº PRGD</label>
                            <input required value={formData.prgd} placeholder="GD-0000" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white transition-all" onChange={e => setFormData({...formData, prgd: e.target.value})} />
                          </div>
                        </div>
                        <div className="group">
                            <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1.5 block ml-1">Número do Cliente</label>
                            <input required value={formData.clientNumber} placeholder="Ex: 100200300" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white transition-all" onChange={e => setFormData({...formData, clientNumber: e.target.value})} />
                        </div>
                      </div>
                      <button type="submit" className="w-full bg-brand-600 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-sm hover:bg-brand-700 shadow-xl transition-all">
                        {editingClient ? 'SALVAR ALTERAÇÕES' : 'CADASTRAR CLIENTE'}
                      </button>
                  </form>
              </div>
          </div>
      )}

      {/* HEADER DA CARTEIRA COM FILTROS RESTAURADOS */}
      <div className="p-6 border-b flex flex-col gap-6 bg-gray-50/50">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <div>
                <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter leading-tight">Gestão de Carteira</h2>
                <div className="flex flex-wrap items-center gap-2 mt-2">
                    {/* Status Ativos/Entregues */}
                    <button onClick={() => setStatusFilter(statusFilter === 'ativos' ? null : 'ativos')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'ativos' ? 'bg-brand-600 text-white border-brand-700' : 'bg-white text-brand-600 border-gray-200'}`}>Ativos</button>
                    <button onClick={() => setStatusFilter(statusFilter === 'entregues' ? null : 'entregues')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'entregues' ? 'bg-green-600 text-white border-green-700' : 'bg-white text-green-600 border-gray-200'}`}>Entregues</button>

                    {/* Divisor Vertical */}
                    <div className="h-4 w-px bg-gray-300/60 mx-1"></div>

                    {/* Filtros de Prazos com Ortografia Correta */}
                    <button onClick={() => setStatusFilter(statusFilter === 'noprazo' ? null : 'noprazo')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'noprazo' ? 'bg-emerald-600 text-white border-emerald-700 shadow-sm' : 'bg-emerald-50 text-emerald-700 border-emerald-100 hover:bg-emerald-100'}`}>No Prazo</button>
                    <button onClick={() => setStatusFilter(statusFilter === 'atencao' ? null : 'atencao')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'atencao' ? 'bg-amber-500 text-white border-amber-600 shadow-sm' : 'bg-amber-50 text-amber-700 border-amber-100 hover:bg-amber-100'}`}>Atenção</button>
                    <button onClick={() => setStatusFilter(statusFilter === 'urgente' ? null : 'urgente')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'urgente' ? 'bg-red-600 text-white border-red-700 shadow-sm' : 'bg-red-50 text-red-700 border-red-100 hover:bg-red-100'}`}>Urgente</button>
                </div>
            </div>

            <div className="flex bg-gray-100 p-1 rounded-2xl border border-gray-200">
                <button onClick={() => setViewMode('list')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'list' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-400 hover:text-brand-600'}`}>
                    <List size={14} /> Lista
                </button>
                <button onClick={() => setViewMode('pipeline')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'pipeline' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-400 hover:text-brand-600'}`}>
                    <Kanban size={14} /> Pipeline
                </button>
            </div>
        </div>

        <div className="flex flex-col md:flex-row gap-4">
            <div className="relative flex-1">
                <Search className="absolute left-4 top-3.5 text-gray-300" size={18} />
                <input placeholder="Filtrar por nome do titular ou PRGD..." className="w-full pl-12 p-3.5 rounded-2xl border-gray-200 border bg-white outline-none transition-all focus:border-brand-300 font-medium text-sm" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
            </div>
            <button onClick={() => setIsCreating(true)} className="bg-brand-600 text-white px-8 py-3.5 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-brand-700 hover:scale-[1.02] active:scale-95 transition-all flex items-center justify-center gap-2">
                <Plus size={18} /> Novo Cliente
            </button>
        </div>
      </div>

      <div className="flex-1 overflow-hidden bg-gray-100/30">
        {viewMode === 'list' ? (
          <div className="p-6 overflow-auto h-full scrollbar-hide">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-8">
                {filteredClients.map(client => (
                    <ClientCard 
                        key={client.id} 
                        client={client} 
                        onSelect={onSelectClient} 
                        onEdit={(e) => {
                            e.stopPropagation();
                            setEditingClient(client);
                            setFormData({ name: client.name, clientNumber: client.clientNumber, prgd: client.prgd, phone: client.phone });
                            setIsCreating(true);
                        }}
                        onDelete={(e) => {
                            e.stopPropagation();
                            if(window.confirm(`Excluir ${client.name}?`)) onDeleteClient(client.id);
                        }}
                        calculateDays={calculateDaysElapsed}
                        getStatus={getStatusInfo}
                    />
                ))}
            </div>
          </div>
        ) : (
          /* PIPELINE KANBAN COM SEPARAÇÃO DE ABAS MELHORADA */
          <div className="flex overflow-x-auto h-full p-6 gap-6 snap-x custom-scroll">
            {STAGES.map(stage => {
              const stageClients = filteredClients.filter(c => c.currentStageId === stage.id);
              const Icon = STEP_ICONS[stage.stepNumber] || Zap;
              return (
                <div key={stage.id} className="min-w-[320px] max-w-[320px] flex flex-col h-full snap-start group/column">
                  {/* Cabeçalho da Coluna do Pipeline */}
                  <div className="flex items-center justify-between mb-4 px-2">
                    <div className="flex items-center gap-3">
                        <div className="bg-brand-900 text-gold-400 p-2.5 rounded-xl shadow-lg border border-brand-800">
                            <Icon size={16} />
                        </div>
                        <h3 className="text-[11px] font-black uppercase text-brand-900 tracking-tight leading-none">{stage.title}</h3>
                    </div>
                    <span className="text-[10px] font-black text-brand-600 bg-brand-50 border border-brand-100 px-2.5 py-1 rounded-full">{stageClients.length}</span>
                  </div>

                  {/* Container da Coluna (Separação Visual) */}
                  <div className="flex-1 overflow-y-auto space-y-4 p-3 rounded-3xl bg-gray-100/60 border border-gray-200/50 shadow-inner custom-scroll">
                    {stageClients.map(client => {
                        const totalDays = calculateDaysElapsed(client.createdAt);
                        const stageDays = calculateDaysElapsed(client.stageHistory[client.currentStageId] || client.createdAt);
                        const status = getStatusInfo(totalDays, client.currentStageId === '7');

                        return (
                            <div key={client.id} onClick={() => onSelectClient(client)} className="bg-white p-5 rounded-[2rem] border border-gray-100 shadow-sm hover:shadow-xl hover:border-brand-400 transition-all cursor-pointer group relative overflow-hidden">
                                <div className="flex justify-between items-start mb-3">
                                    <div>
                                        <h4 className="font-black text-brand-900 uppercase text-xs truncate max-w-[150px] group-hover:text-brand-600">{client.name}</h4>
                                        <p className="text-[9px] text-gray-400 font-bold uppercase mt-0.5 tracking-tighter">PRGD: {client.prgd}</p>
                                    </div>
                                    <button onClick={(e) => { e.stopPropagation(); if(window.confirm("Excluir?")) onDeleteClient(client.id); }} className="p-1.5 text-gray-200 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"><Trash2 size={12} /></button>
                                </div>

                                <div className="space-y-2 mb-4 bg-gray-50/50 p-3 rounded-2xl border border-gray-50">
                                    <div className="flex justify-between text-[8px] font-black uppercase tracking-widest">
                                        <span className="text-gray-400">Tempo na Etapa</span>
                                        <span className={status.color}>{stageDays} dias</span>
                                    </div>
                                    <div className="h-1.5 bg-gray-100 rounded-full overflow-hidden shadow-inner">
                                        <div className={`h-full transition-all duration-700 ${status.color.replace('text-', 'bg-')}`} style={{ width: `${Math.min(100, (stageDays / 15) * 100)}%` }}></div>
                                    </div>
                                </div>

                                <div className="flex items-center justify-between">
                                    <span className={`text-[8px] font-black uppercase px-2.5 py-1 rounded-full ${status.btn} border border-current opacity-70`}>{status.label.split(' ')[1]}</span>
                                    <button 
                                      onClick={(e) => { e.stopPropagation(); const nextIdx = STAGES.findIndex(s => s.id === client.currentStageId) + 1; if (nextIdx < STAGES.length) onUpdateClientStage(client.id, STAGES[nextIdx].id); }} 
                                      className="p-2 bg-brand-50 text-brand-600 rounded-xl hover:bg-brand-600 hover:text-white transition-all shadow-sm border border-brand-100 hover:border-brand-600"
                                      title="Avançar Etapa"
                                    >
                                        <ArrowRightLeft size={12} />
                                    </button>
                                </div>
                            </div>
                        );
                    })}
                    {stageClients.length === 0 && (
                        <div className="h-32 border-2 border-dashed border-gray-200 rounded-[2rem] flex flex-col items-center justify-center text-gray-300/60 opacity-50">
                            <Zap size={20} className="mb-2" />
                            <span className="text-[8px] font-black uppercase tracking-[0.2em]">Sem Projetos</span>
                        </div>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

const ClientCard = ({ client, onSelect, onEdit, onDelete, calculateDays, getStatus }: any) => {
    const isDelivered = client.currentStageId === '7';
    const totalDays = calculateDays(client.createdAt, isDelivered ? client.stageHistory['7'] : undefined);
    const stageDays = calculateDays(client.stageHistory[client.currentStageId] || client.createdAt);
    const status = getStatus(totalDays, isDelivered);
    const currentStage = STAGES.find(s => s.id === client.currentStageId);
    const Icon = STEP_ICONS[currentStage?.stepNumber || '1'];

    return (
        <div onClick={() => onSelect(client)} className="bg-white border border-gray-100 rounded-[2.5rem] p-6 hover:border-brand-400 cursor-pointer transition-all shadow-sm hover:shadow-2xl group relative overflow-hidden flex flex-col gap-5">
            <div className="flex justify-between items-start">
                <div className="flex gap-4 items-center">
                    <div className="bg-brand-50 p-4 rounded-3xl group-hover:bg-brand-600 group-hover:text-white transition-all shadow-inner">
                        <User size={24} />
                    </div>
                    <div>
                        <h3 className="font-black text-brand-900 uppercase text-lg leading-tight group-hover:text-brand-600 transition tracking-tighter truncate max-w-[160px]">{client.name}</h3>
                        <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest mt-1">PRGD: {client.prgd}</p>
                    </div>
                </div>
                <div className="flex gap-1.5">
                  <button onClick={onEdit} className="p-2.5 bg-gray-50 hover:bg-brand-600 text-gray-400 hover:text-white rounded-2xl transition-all shadow-sm"><Edit3 size={16}/></button>
                  <button onClick={onDelete} className="p-2.5 bg-gray-50 hover:bg-red-600 text-gray-400 hover:text-white rounded-2xl transition-all shadow-sm"><Trash2 size={16}/></button>
                </div>
            </div>

            <div className={`p-6 rounded-[2rem] border border-gray-100 flex flex-col gap-4 ${status.bg} shadow-inner`}>
                <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest">
                    <span className="text-gray-400 flex items-center gap-1.5"><Clock size={12}/> Jornada Total:</span>
                    <span className="text-brand-900 font-bold">{totalDays} dias</span>
                </div>
                <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest pt-2 border-t border-gray-200/50">
                    <span className="text-gray-400 flex items-center gap-1.5"><CalendarDays size={12}/> Tempo na Etapa:</span>
                    <span className="text-brand-600 font-bold">{stageDays} dias</span>
                </div>
                <div className={`py-2.5 rounded-2xl text-center text-[9px] font-black tracking-[0.2em] bg-white shadow-sm border border-gray-50/50 mt-2 ${status.color}`}>
                    {status.label}
                </div>
            </div>

            <div className="flex items-center justify-between pt-4 border-t border-gray-50">
                <div className="flex items-center gap-3">
                    <div className="bg-brand-900 text-gold-400 p-2.5 rounded-xl shadow-lg border border-brand-800">
                        <Icon size={16} />
                    </div>
                    <div className="flex flex-col">
                        <span className="text-[8px] font-black text-gray-400 uppercase tracking-widest">Estágio Atual</span>
                        <span className="text-xs font-black text-brand-900 uppercase tracking-tight truncate max-w-[160px]">{currentStage?.title}</span>
                    </div>
                </div>
                <ChevronRight className="text-gray-200 group-hover:translate-x-1 group-hover:text-brand-400 transition-all" size={20} />
            </div>
        </div>
    );
};

import React, { useEffect, useRef } from 'react';
import { STAGES, STEP_ICONS } from '../constants.ts';
import { Stage } from '../types.ts';
import { Check } from 'lucide-react';

interface TimelineProps {
  currentStageId: string;
  onSelectStage: (stage: Stage) => void;
}

export const Timeline: React.FC<TimelineProps> = ({ currentStageId, onSelectStage }) => {
  const currentStageIndex = STAGES.findIndex(s => s.id === currentStageId);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      const activeElement = scrollRef.current.querySelector('[data-active="true"]');
      if (activeElement) {
        activeElement.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
      }
    }
  }, [currentStageId]);

  return (
    <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-200 w-full relative overflow-hidden shrink-0">
      <div className="absolute top-0 left-0 right-0 h-1 bg-gradient-to-r from-brand-900 via-brand-600 to-gold-500"></div>

      <div 
        ref={scrollRef}
        className="flex overflow-x-auto gap-4 p-6 scrollbar-hide snap-x"
        style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
      >
        {STAGES.map((stage, index) => {
          const Icon = STEP_ICONS[stage.stepNumber] || STEP_ICONS['1'];
          const isActive = stage.id === currentStageId;
          const isCompleted = index < currentStageIndex;

          return (
            <div 
              key={stage.id}
              data-active={isActive}
              onClick={() => onSelectStage(stage)}
              className={`
                shrink-0 snap-center cursor-pointer transition-all duration-500
                flex flex-col items-center gap-3 p-5 rounded-3xl min-w-[160px] border
                ${isActive 
                  ? 'bg-brand-50 border-brand-200 shadow-xl scale-105 z-10' 
                  : isCompleted
                    ? 'bg-gray-50 border-gold-100 opacity-80'
                    : 'bg-transparent border-transparent opacity-40 hover:opacity-100'
                }
              `}
            >
              <div 
                className={`
                  flex items-center justify-center w-14 h-14 rounded-2xl border-2 transition-all shadow-md
                  ${isActive 
                    ? 'border-brand-900 bg-brand-900 text-gold-400' 
                    : isCompleted 
                      ? 'border-gold-500 bg-gold-50 text-gold-600' 
                      : 'border-gray-200 bg-white text-gray-300'
                  }
                `}
              >
                {isCompleted ? <Check size={24} strokeWidth={3} /> : <Icon size={24} />}
              </div>

              <div className="flex flex-col items-center text-center">
                <span className={`text-[8px] uppercase font-black tracking-[0.2em] ${isActive ? 'text-brand-600' : 'text-gray-400'}`}>Etapa {stage.stepNumber}</span>
                <h3 className={`text-[11px] font-black uppercase leading-tight mt-1.5 ${isActive ? 'text-brand-900' : 'text-gray-500'}`}>
                  {stage.title}
                </h3>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Client, Stage } from '../types.ts';
import { Plus, Search, User, Zap, List, Kanban, X, ChevronRight, Clock, Trash2, Edit3, CalendarDays, ArrowRightLeft, GripVertical } from 'lucide-react';
import { STAGES, STEP_ICONS } from '../constants.ts';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onEditClient: (client: Client) => void;
  onDeleteClient: (clientId: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

type ViewMode = 'list' | 'pipeline';
type FilterStatus = 'ativos' | 'entregues' | 'noprazo' | 'atencao' | 'urgente' | null;

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onEditClient, onDeleteClient, onUpdateClientStage }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<ViewMode>('pipeline');
  const [statusFilter, setStatusFilter] = useState<FilterStatus>(null);
  const [draggedClientId, setDraggedClientId] = useState<string | null>(null);

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '', clientNumber: '', prgd: '', phone: '',
  });

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    if (!startStr) return 0;
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const getStatusInfo = (days: number, isDelivered: boolean) => {
    if (isDelivered) return { label: '🟢 ENTREGUE', color: 'text-green-600', bg: 'bg-green-50', key: 'entregues', btn: 'bg-green-100 text-green-700' };
    if (days > 120) return { label: '🔴 URGENTE', color: 'text-red-600', bg: 'bg-red-50', key: 'urgente', btn: 'bg-red-100 text-red-700' };
    if (days > 90) return { label: '🟡 ATENÇÃO', color: 'text-amber-500', bg: 'bg-amber-50', key: 'atencao', btn: 'bg-amber-100 text-amber-700' };
    return { label: '🟢 NO PRAZO', color: 'text-emerald-600', bg: 'bg-emerald-50', key: 'noprazo', btn: 'bg-emerald-100 text-emerald-700' };
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingClient) {
      onEditClient({ ...editingClient, name: formData.name || '', clientNumber: formData.clientNumber || '', prgd: formData.prgd || '', phone: formData.phone || '' });
    } else {
      const now = new Date().toISOString();
      onCreateClient({
        id: Date.now().toString(),
        name: formData.name || '',
        clientNumber: formData.clientNumber || '',
        prgd: formData.prgd || '',
        phone: formData.phone || '',
        projectName: `Projeto ${formData.name}`,
        additionalNotes: '',
        currentStageId: STAGES[0].id,
        createdAt: now,
        stageHistory: { [STAGES[0].id]: now },
        stageData: {}
      });
    }
    closeModal();
  };

  const closeModal = () => {
    setIsCreating(false);
    setEditingClient(null);
    setFormData({ name: '', clientNumber: '', prgd: '', phone: '' });
  };

  const filteredClients = clients.filter(c => {
    const matchesSearch = c.name.toLowerCase().includes(searchTerm.toLowerCase()) || c.prgd.toLowerCase().includes(searchTerm.toLowerCase());
    if (!matchesSearch) return false;
    if (!statusFilter) return true;
    const isDelivered = c.currentStageId === '7';
    const days = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);
    const info = getStatusInfo(days, isDelivered);
    if (statusFilter === 'ativos') return !isDelivered;
    return info.key === statusFilter;
  });

  // Drag and Drop Handlers
  const handleDragStart = (clientId: string) => {
    setDraggedClientId(clientId);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };

  const handleDrop = (stageId: string) => {
    if (draggedClientId) {
      onUpdateClientStage(draggedClientId, stageId);
      setDraggedClientId(null);
    }
  };

  return (
    <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-200 h-full flex flex-col relative overflow-hidden">
      {/* MODAL DE CADASTRO */}
      {isCreating && (
          <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-4">
              <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-xl animate-scale-up border border-white/20 overflow-hidden">
                  <div className="p-8 pb-4 flex justify-between items-center border-b border-gray-50 bg-gray-50/50">
                      <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">{editingClient ? 'Editar Cadastro' : 'Novo Cliente'}</h2>
                      <button onClick={closeModal} className="p-2 hover:bg-white rounded-full transition text-gray-400"><X size={24} /></button>
                  </div>
                  <form onSubmit={handleSubmit} className="p-8 space-y-6">
                      <div className="space-y-4">
                        <div className="group">
                          <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1.5 block ml-1">Titular do Projeto</label>
                          <input required value={formData.name} placeholder="Nome Completo" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:ring-2 focus:ring-brand-500/20 focus:bg-white transition-all" onChange={e => setFormData({...formData, name: e.target.value})} />
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1.5 block ml-1">Telefone</label>
                            <input required placeholder="(00) 00000-0000" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white transition-all" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} />
                          </div>
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1.5 block ml-1">Nº PRGD</label>
                            <input required value={formData.prgd} placeholder="GD-0000" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white transition-all" onChange={e => setFormData({...formData, prgd: e.target.value})} />
                          </div>
                        </div>
                      </div>
                      <button type="submit" className="w-full bg-brand-600 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-sm hover:bg-brand-700 shadow-xl transition-all">
                        {editingClient ? 'SALVAR ALTERAÇÕES' : 'CADASTRAR CLIENTE'}
                      </button>
                  </form>
              </div>
          </div>
      )}

      {/* HEADER COM FILTROS E SEPARADOR */}
      <div className="p-6 border-b flex flex-col gap-6 bg-gray-50/50">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <div>
                <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter leading-tight">Gestão de Carteira</h2>
                <div className="flex flex-wrap items-center gap-2 mt-2">
                    <button onClick={() => setStatusFilter(statusFilter === 'ativos' ? null : 'ativos')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'ativos' ? 'bg-brand-600 text-white border-brand-700 shadow-sm' : 'bg-white text-brand-600 border-gray-200 hover:border-brand-300'}`}>Ativos</button>
                    <button onClick={() => setStatusFilter(statusFilter === 'entregues' ? null : 'entregues')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'entregues' ? 'bg-green-600 text-white border-green-700 shadow-sm' : 'bg-white text-green-600 border-gray-200 hover:border-green-300'}`}>Entregues</button>

                    {/* LINHA VERTICAL SEPARADORA */}
                    <div className="h-5 w-px bg-gray-300 mx-2"></div>

                    <button onClick={() => setStatusFilter(statusFilter === 'noprazo' ? null : 'noprazo')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'noprazo' ? 'bg-emerald-600 text-white border-emerald-700 shadow-sm' : 'bg-emerald-50 text-emerald-700 border-emerald-100 hover:bg-emerald-200'}`}>No Prazo</button>
                    <button onClick={() => setStatusFilter(statusFilter === 'atencao' ? null : 'atencao')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'atencao' ? 'bg-amber-500 text-white border-amber-600 shadow-sm' : 'bg-amber-50 text-amber-700 border-amber-100 hover:bg-amber-200'}`}>Atenção</button>
                    <button onClick={() => setStatusFilter(statusFilter === 'urgente' ? null : 'urgente')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'urgente' ? 'bg-red-600 text-white border-red-700 shadow-sm' : 'bg-red-50 text-red-700 border-red-100 hover:bg-red-200'}`}>Urgente</button>
                </div>
            </div>

            <div className="flex bg-gray-100 p-1 rounded-2xl border border-gray-200">
                <button onClick={() => setViewMode('list')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'list' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-400 hover:text-brand-600'}`}>
                    <List size={14} /> Lista
                </button>
                <button onClick={() => setViewMode('pipeline')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'pipeline' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-400 hover:text-brand-600'}`}>
                    <Kanban size={14} /> Pipeline
                </button>
            </div>
        </div>

        <div className="flex flex-col md:flex-row gap-4">
            <div className="relative flex-1">
                <Search className="absolute left-4 top-3.5 text-gray-300" size={18} />
                <input placeholder="Filtrar por titular ou PRGD..." className="w-full pl-12 p-3.5 rounded-2xl border-gray-200 border bg-white outline-none focus:border-brand-300 transition-all font-medium text-sm" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
            </div>
            <button onClick={() => setIsCreating(true)} className="bg-brand-600 text-white px-8 py-3.5 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-brand-700 transition-all flex items-center justify-center gap-2">
                <Plus size={18} /> Novo Cliente
            </button>
        </div>
      </div>

      <div className="flex-1 overflow-hidden bg-gray-100/30">
        {viewMode === 'list' ? (
          <div className="p-6 overflow-auto h-full scrollbar-hide">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-8">
                {filteredClients.map(client => (
                    <div key={client.id} onClick={() => onSelectClient(client)}>
                       <ClientCardItem 
                          client={client} 
                          onEdit={(e) => { e.stopPropagation(); setEditingClient(client); setFormData({name: client.name, prgd: client.prgd, phone: client.phone}); setIsCreating(true); }}
                          onDelete={(e) => { e.stopPropagation(); if(confirm("Excluir?")) onDeleteClient(client.id); }}
                          calculateDays={calculateDaysElapsed}
                          getStatus={getStatusInfo}
                       />
                    </div>
                ))}
            </div>
          </div>
        ) : (
          /* PIPELINE COM DRAG AND DROP E SEPARAÇÃO DE ABAS */
          <div className="flex overflow-x-auto h-full p-6 gap-6 snap-x custom-scroll">
            {STAGES.map(stage => {
              const stageClients = filteredClients.filter(c => c.currentStageId === stage.id);
              const Icon = STEP_ICONS[stage.stepNumber] || Zap;
              return (
                <div 
                  key={stage.id} 
                  className="min-w-[320px] max-w-[320px] flex flex-col h-full snap-start group/column"
                  onDragOver={handleDragOver}
                  onDrop={() => handleDrop(stage.id)}
                >
                  <div className="flex items-center justify-between mb-4 px-2">
                    <div className="flex items-center gap-3">
                        <div className="bg-brand-900 text-gold-400 p-2.5 rounded-xl shadow-lg border border-brand-800">
                            <Icon size={16} />
                        </div>
                        <h3 className="text-[11px] font-black uppercase text-brand-900 tracking-tight leading-none">{stage.title}</h3>
                    </div>
                    <span className="text-[10px] font-black text-brand-600 bg-brand-50 border border-brand-100 px-2.5 py-1 rounded-full">{stageClients.length}</span>
                  </div>

                  <div className={`flex-1 overflow-y-auto space-y-4 p-3 rounded-3xl bg-gray-100/60 border border-gray-200/50 shadow-inner transition-all ${draggedClientId ? 'ring-2 ring-brand-400 ring-dashed' : ''} custom-scroll`}>
                    {stageClients.map(client => {
                        const totalDays = calculateDaysElapsed(client.createdAt);
                        const stageDays = calculateDaysElapsed(client.stageHistory[client.currentStageId] || client.createdAt);
                        const status = getStatusInfo(totalDays, client.currentStageId === '7');

                        return (
                            <div 
                                key={client.id} 
                                draggable 
                                onDragStart={() => handleDragStart(client.id)}
                                onClick={() => onSelectClient(client)} 
                                className="bg-white p-5 rounded-[2rem] border border-gray-100 shadow-sm hover:shadow-xl hover:border-brand-400 transition-all cursor-grab active:cursor-grabbing group relative overflow-hidden"
                            >
                                <div className="flex justify-between items-start mb-3">
                                    <div className="flex items-center gap-2">
                                        <GripVertical className="text-gray-200 group-hover:text-gray-400 transition-colors" size={14} />
                                        <div>
                                            <h4 className="font-black text-brand-900 uppercase text-[11px] truncate max-w-[150px] group-hover:text-brand-600">{client.name}</h4>
                                            <p className="text-[8px] text-gray-400 font-bold uppercase mt-0.5">PRGD: {client.prgd}</p>
                                        </div>
                                    </div>
                                    <button onClick={(e) => { e.stopPropagation(); if(confirm("Excluir?")) onDeleteClient(client.id); }} className="p-1.5 text-gray-200 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"><Trash2 size={12} /></button>
                                </div>

                                <div className="space-y-2 mb-4 bg-gray-50/50 p-3 rounded-2xl border border-gray-100">
                                    <div className="flex justify-between text-[8px] font-black uppercase tracking-widest">
                                        <span className="text-gray-400">Tempo na Etapa</span>
                                        <span className={status.color}>{stageDays} dias</span>
                                    </div>
                                    <div className="h-1.5 bg-gray-200 rounded-full overflow-hidden shadow-inner">
                                        <div className={`h-full transition-all duration-700 ${status.color.replace('text-', 'bg-')}`} style={{ width: `${Math.min(100, (stageDays / 15) * 100)}%` }}></div>
                                    </div>
                                </div>

                                <div className="flex items-center justify-between">
                                    <span className={`text-[8px] font-black uppercase px-2.5 py-1 rounded-full ${status.btn} border border-current opacity-70`}>{status.label.split(' ')[1]}</span>
                                    <button 
                                      onClick={(e) => { e.stopPropagation(); const nextIdx = STAGES.findIndex(s => s.id === client.currentStageId) + 1; if (nextIdx < STAGES.length) onUpdateClientStage(client.id, STAGES[nextIdx].id); }} 
                                      className="p-2 bg-brand-50 text-brand-600 rounded-xl hover:bg-brand-600 hover:text-white transition-all shadow-sm border border-brand-100 hover:border-brand-600"
                                    >
                                        <ArrowRightLeft size={12} />
                                    </button>
                                </div>
                            </div>
                        );
                    })}
                    {stageClients.length === 0 && (
                        <div className="h-32 border-2 border-dashed border-gray-200 rounded-[2rem] flex flex-col items-center justify-center text-gray-300 opacity-50">
                            <Zap size={20} className="mb-2" />
                            <span className="text-[8px] font-black uppercase tracking-[0.2em]">Vazio</span>
                        </div>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

const ClientCardItem = ({ client, onEdit, onDelete, calculateDays, getStatus }: any) => {
    const isDelivered = client.currentStageId === '7';
    const totalDays = calculateDays(client.createdAt, isDelivered ? client.stageHistory['7'] : undefined);
    const stageDays = calculateDays(client.stageHistory[client.currentStageId] || client.createdAt);
    const status = getStatus(totalDays, isDelivered);
    const currentStage = STAGES.find(s => s.id === client.currentStageId);
    const Icon = STEP_ICONS[currentStage?.stepNumber || '1'];

    return (
        <div className="bg-white border border-gray-100 rounded-[2.5rem] p-6 hover:border-brand-400 cursor-pointer transition-all shadow-sm hover:shadow-2xl group relative overflow-hidden flex flex-col gap-5">
            <div className="flex justify-between items-start">
                <div className="flex gap-4 items-center">
                    <div className="bg-brand-50 p-4 rounded-3xl group-hover:bg-brand-600 group-hover:text-white transition-all shadow-inner">
                        <User size={24} />
                    </div>
                    <div>
                        <h3 className="font-black text-brand-900 uppercase text-lg leading-tight group-hover:text-brand-600 transition tracking-tighter truncate max-w-[160px]">{client.name}</h3>
                        <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest mt-1">PRGD: {client.prgd}</p>
                    </div>
                </div>
                <div className="flex gap-1.5">
                  <button onClick={onEdit} className="p-2.5 bg-gray-50 hover:bg-brand-600 text-gray-400 hover:text-white rounded-2xl transition-all"><Edit3 size={16}/></button>
                  <button onClick={onDelete} className="p-2.5 bg-gray-50 hover:bg-red-600 text-gray-400 hover:text-white rounded-2xl transition-all"><Trash2 size={16}/></button>
                </div>
            </div>

            <div className={`p-6 rounded-[2rem] border border-gray-100 flex flex-col gap-4 ${status.bg} shadow-inner`}>
