import React, { useState, useEffect } from 'react';
import { Stage, Client, GeneratedContent } from '../types.ts';
import { generateTemplateContent } from '../services/templateService.ts';
import { Copy, Phone, Zap, Edit2, Save, Star, History, CheckCircle2, Trophy } from 'lucide-react';
import { STAGES } from '../constants.ts';

interface ContentGeneratorProps {
  stage: Stage;
  client: Client;
  onUpdateNotes: (notes: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

export const ContentGenerator: React.FC<ContentGeneratorProps> = ({ stage, client, onUpdateNotes, onUpdateClientStage }) => {
  const [fieldValues, setFieldValues] = useState<Record<string, string>>({});
  const [isEditing, setIsEditing] = useState(false);
  const [editableBody, setEditableBody] = useState('');

  useEffect(() => {
    setFieldValues(client.stageData || {});
    setIsEditing(false);
  }, [stage.id, client.id]);

  useEffect(() => {
    if (!isEditing) {
      const generated = generateTemplateContent(stage, client, { ...client.stageData, ...fieldValues });
      setEditableBody(generated.body);
    }
  }, [fieldValues, stage, client, isEditing]);

  const handleFieldChange = (variable: string, value: string) => {
    setFieldValues(prev => ({ ...prev, [variable]: value }));
  };

  const openWhatsApp = (text: string) => {
    const cleanPhone = client.phone.replace(/\D/g, '');
    const phoneWithCountry = cleanPhone.startsWith('55') ? cleanPhone : `55${cleanPhone}`;
    const encodedText = encodeURIComponent(text);
    window.open(`https://api.whatsapp.com/send?phone=${phoneWithCountry}&text=${encodedText}`, '_blank');
  };

  const handleWhatsAppClick = () => {
    if (!client.phone) {
      alert("⚠️ Erro: Cliente sem telefone cadastrado!");
      return;
    }
    if (stage.id === '3' && !fieldValues['data prevista'] && !client.stageData?.['data prevista']) {
      alert("⚠️ Atenção: Você precisa informar a DATA PREVISTA para esta etapa!");
      return;
    }
    openWhatsApp(editableBody);
    onUpdateClientStage(client.id, client.currentStageId, fieldValues);
  };

  const handleSaveAndAdvance = () => {
    onUpdateClientStage(client.id, stage.id, fieldValues);
    if (stage.template) {
        openWhatsApp(editableBody);
    }
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(editableBody);
    alert("Copiado! ✅");
  };

  const calculateInfo = () => {
    const start = new Date(client.createdAt);
    const now = client.currentStageId === '7' ? new Date(client.stageHistory['7']) : new Date();
    const elapsed = Math.floor(Math.abs(now.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));

    let statusLabel = '🟢 NO PRAZO';
    let statusColor = 'text-emerald-600';
    if (elapsed > 120) { statusLabel = '🔴 URGENTE'; statusColor = 'text-red-600'; }
    else if (elapsed > 90) { statusLabel = '🟡 ATENÇÃO'; statusColor = 'text-amber-500'; }

    return { elapsed, statusLabel, statusColor, start: start.toLocaleDateString('pt-BR') };
  };

  const info = calculateInfo();

  if (stage.id === '7') {
    return (
      <div className="bg-white rounded-[2.5rem] shadow-xl border border-gray-100 p-12 flex flex-col items-center justify-center text-center h-full animate-in fade-in zoom-in">
          <div className="bg-green-100 p-8 rounded-full text-green-600 mb-8 shadow-inner"><Trophy size={80} /></div>
          <h2 className="text-4xl font-black text-brand-900 uppercase tracking-tighter">Projeto Entregue!</h2>
          <p className="text-gray-400 font-bold uppercase text-xs tracking-[0.3em] mt-2 mb-10">Loop Energia • Excelência</p>
          <div className="grid grid-cols-2 gap-4 w-full max-w-md">
            <div className="bg-gray-50 p-6 rounded-3xl border border-gray-100">
              <span className="text-[10px] font-black text-gray-400 uppercase block mb-1">Início</span>
              <span className="font-black text-brand-900 text-lg">{info.start}</span>
            </div>
            <div className="bg-gray-50 p-6 rounded-3xl border border-gray-100">
              <span className="text-[10px] font-black text-gray-400 uppercase block mb-1">Total de Dias</span>
              <span className="font-black text-brand-900 text-lg">{info.elapsed} d</span>
            </div>
          </div>
      </div>
    );
  }

  const requiredFields = stage.requiredFields || [];
  const allFieldsFilled = requiredFields.every(f => (fieldValues[f] || client.stageData?.[f])?.trim());

  return (
    <div className="bg-white rounded-[2.5rem] shadow-lg border border-gray-200 flex flex-col h-full overflow-hidden">
      <div className="bg-brand-600 p-6 flex justify-between items-center text-white shrink-0">
        <div>
          <h2 className="text-xl font-black uppercase tracking-tight">Etapa {stage.stepNumber}: {stage.title}</h2>
          <p className="text-brand-100 text-xs font-bold uppercase tracking-wider">{stage.description}</p>
        </div>
        <button onClick={() => setIsEditing(!isEditing)} className="p-3 bg-white/10 hover:bg-white/20 rounded-2xl transition">
          {isEditing ? <Save size={20} /> : <Edit2 size={20} />}
        </button>
      </div>

      <div className="flex flex-col lg:flex-row flex-1 min-h-0">
        <div className="lg:w-80 p-6 border-r border-gray-100 bg-gray-50/50 flex flex-col gap-6 overflow-y-auto custom-scroll">
           <div className="bg-white p-5 rounded-3xl border border-brand-100 shadow-sm">
             <h3 className="text-[10px] font-black text-brand-600 uppercase mb-4 tracking-widest flex items-center gap-2">
               <Zap size={14} className="text-gold-500" /> Saúde do Projeto
             </h3>
             <div className="space-y-3">
               <div className="flex justify-between text-xs font-bold">
                 <span className="text-gray-400 uppercase text-[9px]">Início:</span>
                 <span className="text-brand-900">{info.start}</span>
               </div>
               <div className="flex justify-between text-xs font-bold">
                 <span className="text-gray-400 uppercase text-[9px]">Tempo:</span>
                 <span className="text-brand-900">{info.elapsed} dias</span>
               </div>
               <div className={`mt-2 py-2 rounded-xl text-[9px] font-black text-center bg-gray-50 border border-gray-100 ${info.statusColor}`}>
                 {info.statusLabel}
               </div>
             </div>
           </div>

           {requiredFields.length > 0 && (
             <div className="space-y-4">
               <h3 className="text-[10px] font-black text-amber-600 uppercase tracking-widest flex items-center gap-2">
                 ⚠️ Preencher Variáveis
               </h3>
               {requiredFields.map(field => (
                 <div key={field}>
                   <label className="text-[9px] font-black uppercase text-gray-500 mb-1.5 block tracking-widest ml-1">{field}</label>
                   <input 
                     className={`w-full p-4 bg-white border rounded-2xl text-sm focus:ring-4 outline-none transition-all ${!fieldValues[field] && !client.stageData?.[field] ? 'border-amber-200 focus:ring-amber-100' : 'border-gray-200 focus:ring-brand-100'}`}
                     value={fieldValues[field] || client.stageData?.[field] || ''}
                     onChange={e => handleFieldChange(field, e.target.value)}
                     placeholder={`Ex: ${field === 'data prevista' ? '15/10/2024' : '...'}`}
                   />
                 </div>
               ))}
             </div>
           )}
        </div>

        <div className="flex-1 p-6 flex flex-col gap-4 bg-white">
          <div className="flex-1 bg-gray-50 rounded-[2rem] border border-gray-100 overflow-hidden flex flex-col shadow-inner">
            <div className="px-6 py-3 border-b border-gray-100 bg-white/50 flex justify-between items-center">
              <span className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em]">Visualização da Mensagem</span>
              <button onClick={copyToClipboard} className="text-[10px] font-black text-brand-600 uppercase hover:underline">Copiar Texto</button>
            </div>

            {isEditing ? (
              <textarea 
                className="flex-1 p-8 text-sm font-sans leading-relaxed bg-transparent outline-none resize-none"
                value={editableBody}
                onChange={e => setEditableBody(e.target.value)}
              />
            ) : (
              <div className="flex-1 p-8 text-sm font-sans leading-relaxed whitespace-pre-wrap text-slate-700 overflow-y-auto custom-scroll">
                {editableBody}
              </div>
            )}
          </div>

          <div className="space-y-3">
            <button 
              onClick={handleWhatsAppClick}
              className={`w-full py-5 rounded-2xl font-black uppercase tracking-[0.2em] flex items-center justify-center gap-3 transition-all shadow-xl
                ${allFieldsFilled 
                  ? 'bg-[#25D366] text-white hover:bg-[#1fb355] hover:scale-[1.01]' 
                  : 'bg-gray-200 text-gray-400 cursor-not-allowed opacity-60'}`}
            >
              <Phone size={22} fill="currentColor" /> Enviar Mensagem via WhatsApp
            </button>

            {allFieldsFilled && stage.id !== client.currentStageId && (
              <button 
                onClick={handleSaveAndAdvance}
                className="w-full py-3 bg-brand-50 text-brand-600 rounded-2xl font-black uppercase text-[10px] tracking-widest border border-brand-100 hover:bg-brand-600 hover:text-white transition-all"
              >
                Salvar Dados e Avançar Etapa
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Timeline } from './components/Timeline.tsx';
import { ContentGenerator } from './components/ContentGenerator.tsx';
import { ClientList } from './components/ClientList.tsx';
import { Dashboard } from './components/Dashboard.tsx';
import { STAGES } from './constants.ts';
import { Client, Stage } from './types.ts';
import { ArrowLeft, BarChart3, LayoutList, Zap } from 'lucide-react';
import { generateTemplateContent } from './services/templateService.ts';

export default function App() {
  const [view, setView] = useState<'list' | 'detail' | 'dashboard'>('list');
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [currentStageId, setCurrentStageId] = useState<string>(STAGES[0].id);
  const [clients, setClients] = useState<Client[]>([]);

  useEffect(() => {
    const saved = localStorage.getItem('gev_loop_clients');
    if (saved) {
      try {
        setClients(JSON.parse(saved));
      } catch (e) {
        console.error("Erro ao carregar dados", e);
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('gev_loop_clients', JSON.stringify(clients));
  }, [clients]);

  const handleCreateClient = (newClient: Client) => {
    // 1. Salva o cliente e seleciona
    setClients(prev => [newClient, ...prev]);
    handleSelectClient(newClient);

    // 2. Disparo automático de Boas-Vindas (Etapa 1)
    const firstStage = STAGES[0];
    if (firstStage && firstStage.template && newClient.phone) {
      const generated = generateTemplateContent(firstStage, newClient, {});
      const cleanPhone = newClient.phone.replace(/\D/g, '');
      const phoneWithCountry = cleanPhone.startsWith('55') ? cleanPhone : `55${cleanPhone}`;
      const encodedText = encodeURIComponent(generated.body);

      // Abre o WhatsApp imediatamente
      window.open(`https://api.whatsapp.com/send?phone=${phoneWithCountry}&text=${encodedText}`, '_blank');
    }
  };

  const handleEditClient = (updatedClient: Client) => {
    setClients(prev => prev.map(c => c.id === updatedClient.id ? updatedClient : c));
  };

  const handleDeleteClient = (clientId: string) => {
    setClients(prev => prev.filter(c => c.id !== clientId));
    if (selectedClientId === clientId) {
      setView('list');
      setSelectedClientId(null);
    }
  };

  const handleSelectClient = (client: Client) => {
    setSelectedClientId(client.id);
    setCurrentStageId(client.currentStageId || STAGES[0].id);
    setView('detail');
  };

  const handleUpdateNotes = (notes: string) => {
    if (!selectedClientId) return;
    setClients(prev => prev.map(c => 
      c.id === selectedClientId ? { ...c, additionalNotes: notes } : c
    ));
  };

  const handleUpdateClientStage = (clientId: string, newStageId: string, stageData?: Record<string, string>) => {
    const now = new Date().toISOString();
    setClients(prev => prev.map(c => {
      if (c.id === clientId) {
        return { 
          ...c, 
          currentStageId: newStageId, 
          stageData: { ...c.stageData, ...stageData },
          stageHistory: { ...c.stageHistory, [newStageId]: now }
        };
      }
      return c;
    }));
    if (selectedClientId === clientId) {
      setCurrentStageId(newStageId);
    }
  };

  const selectedClient = clients.find(c => c.id === selectedClientId);
  const currentStage = STAGES.find(s => s.id === currentStageId) || STAGES[0];

  return (
    <div className="h-screen bg-gray-50 flex flex-col overflow-hidden font-sans">
      <header className="bg-brand-900 h-16 sm:h-20 shrink-0 shadow-lg relative z-50 border-b border-brand-800">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 h-full flex items-center justify-between">
          <div className="flex items-center gap-4">
            {view === 'detail' && (
              <button onClick={() => setView('list')} className="p-2 hover:bg-white/10 rounded-full text-gold-400 transition">
                <ArrowLeft size={20} />
              </button>
            )}
            <div className="flex flex-col">
              <h1 className="text-xl sm:text-2xl font-black text-white uppercase tracking-tighter leading-none">
                LOOP <span className="text-gold-500">ENERGIA</span>
              </h1>
