import React, { useState } from 'react';
import { Client, Stage } from '../types.ts';
import { Plus, Search, User, Zap, List, Kanban, X, ChevronRight, Clock, Trash2, Edit3, CalendarDays, ArrowRightLeft, GripVertical } from 'lucide-react';
import { STAGES, STEP_ICONS } from '../constants.ts';
import { generateTemplateContent } from '../services/templateService.ts';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onEditClient: (client: Client) => void;
  onDeleteClient: (clientId: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

type ViewMode = 'list' | 'pipeline';
type FilterStatus = 'ativos' | 'entregues' | 'noprazo' | 'atencao' | 'urgente' | null;

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onEditClient, onDeleteClient, onUpdateClientStage }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<ViewMode>('pipeline');
  const [statusFilter, setStatusFilter] = useState<FilterStatus>(null);
  const [draggedClientId, setDraggedClientId] = useState<string | null>(null);

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '', clientNumber: '', prgd: '', phone: '',
  });

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    if (!startStr) return 0;
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const getStatusInfo = (days: number, isDelivered: boolean) => {
    if (isDelivered) return { label: '🟢 ENTREGUE', color: 'text-green-600', bg: 'bg-green-50', key: 'entregues', btn: 'bg-green-100 text-green-700' };
    if (days > 120) return { label: '🔴 URGENTE', color: 'text-red-600', bg: 'bg-red-50', key: 'urgente', btn: 'bg-red-100 text-red-700' };
    if (days > 90) return { label: '🟡 ATENÇÃO', color: 'text-amber-500', bg: 'bg-amber-50', key: 'atencao', btn: 'bg-amber-100 text-amber-700' };
    return { label: '🟢 NO PRAZO', color: 'text-emerald-600', bg: 'bg-emerald-50', key: 'noprazo', btn: 'bg-emerald-100 text-emerald-700' };
  };

  const filteredClients = clients.filter(c => {
    const matchesSearch = c.name.toLowerCase().includes(searchTerm.toLowerCase()) || c.prgd.toLowerCase().includes(searchTerm.toLowerCase());
    if (!matchesSearch) return false;
    if (!statusFilter) return true;
    const isDelivered = c.currentStageId === '7';
    const days = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);
    const info = getStatusInfo(days, isDelivered);
    if (statusFilter === 'ativos') return !isDelivered;
    return info.key === statusFilter;
  });

  const triggerWhatsApp = (client: Client, stage: Stage) => {
    if (!client.phone) return;
    const generated = generateTemplateContent(stage, client, client.stageData || {});
    if (!generated.body) return;

    const cleanPhone = client.phone.replace(/\D/g, '');
    const phoneWithCountry = cleanPhone.startsWith('55') ? cleanPhone : `55${cleanPhone}`;
    const encodedText = encodeURIComponent(generated.body);
    window.open(`https://api.whatsapp.com/send?phone=${phoneWithCountry}&text=${encodedText}`, '_blank');
  };

  const onDragStart = (id: string) => setDraggedClientId(id);
  const onDragOver = (e: React.DragEvent) => e.preventDefault();

  const onDrop = (stageId: string) => {
    if (draggedClientId) {
      const client = clients.find(c => c.id === draggedClientId);
      const targetStage = STAGES.find(s => s.id === stageId);

      if (client && targetStage) {
        // Validação de pré-requisitos (Independente de onde venha o arraste)
        const requiredFields = targetStage.requiredFields || [];
        const missingFields = requiredFields.filter(field => !client.stageData?.[field]?.trim());

        if (missingFields.length > 0) {
          alert(`⚠️ PRÉ-REQUISITO OBRIGATÓRIO: Para avançar para a etapa "${targetStage.title}", você deve primeiro preencher o(s) campo(s): ${missingFields.join(', ')} na ficha do cliente.`);
          onSelectClient(client); // Abre a ficha para o usuário preencher
        } else {
          onUpdateClientStage(draggedClientId, stageId);
          if (targetStage.template) {
            triggerWhatsApp(client, targetStage);
          }
        }
      }
      setDraggedClientId(null);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingClient) {
      onEditClient({ ...editingClient, name: formData.name || '', clientNumber: formData.clientNumber || '', prgd: formData.prgd || '', phone: formData.phone || '' });
    } else {
      const now = new Date().toISOString();
      onCreateClient({
        id: Date.now().toString(),
        name: formData.name || '',
        clientNumber: formData.clientNumber || '',
        prgd: formData.prgd || '',
        phone: formData.phone || '',
        projectName: `Projeto ${formData.name}`,
        additionalNotes: '',
        currentStageId: STAGES[0].id,
        createdAt: now,
        stageHistory: { [STAGES[0].id]: now },
        stageData: {}
      });
    }
    closeModal();
  };

  const closeModal = () => {
    setIsCreating(false);
    setEditingClient(null);
    setFormData({ name: '', clientNumber: '', prgd: '', phone: '' });
  };

  return (
    <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-200 h-full flex flex-col relative overflow-hidden">
      {isCreating && (
          <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-4">
              <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-xl animate-scale-up border border-white/20 overflow-hidden">
                  <div className="p-8 pb-4 flex justify-between items-center border-b border-gray-50 bg-gray-50/50">
                      <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">{editingClient ? 'Editar Cadastro' : 'Novo Cliente'}</h2>
                      <button onClick={closeModal} className="p-2 hover:bg-white rounded-full transition text-gray-400"><X size={24} /></button>
                  </div>
                  <form onSubmit={handleSubmit} className="p-8 space-y-6">
                      <div className="space-y-4">
                        <div className="group">
                          <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1.5 block ml-1">Titular do Projeto</label>
                          <input required value={formData.name} placeholder="Nome Completo" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white transition-all" onChange={e => setFormData({...formData, name: e.target.value})} />
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1.5 block ml-1">Telefone</label>
                            <input required placeholder="(00) 00000-0000" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white transition-all" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} />
                          </div>
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1.5 block ml-1">Nº PRGD</label>
                            <input required value={formData.prgd} placeholder="GD-0000" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white transition-all" onChange={e => setFormData({...formData, prgd: e.target.value})} />
                          </div>
                        </div>
                      </div>
                      <button type="submit" className="w-full bg-brand-600 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-sm hover:bg-brand-700 shadow-xl transition-all">
                        {editingClient ? 'SALVAR ALTERAÇÕES' : 'CADASTRAR CLIENTE'}
                      </button>
                  </form>
              </div>
          </div>
      )}

      <div className="p-6 border-b flex flex-col gap-6 bg-gray-50/50">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <div>
                <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter leading-tight">Gestão de Carteira</h2>
                <div className="flex flex-wrap items-center gap-2 mt-2">
                    <button onClick={() => setStatusFilter(statusFilter === 'ativos' ? null : 'ativos')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'ativos' ? 'bg-brand-600 text-white shadow-sm' : 'bg-white text-brand-600 hover:border-brand-300'}`}>Ativos</button>
                    <button onClick={() => setStatusFilter(statusFilter === 'entregues' ? null : 'entregues')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'entregues' ? 'bg-green-600 text-white shadow-sm' : 'bg-white text-green-600 hover:border-green-300'}`}>Entregues</button>
                    <div className="h-4 w-px bg-gray-300 mx-2"></div>
                    <button onClick={() => setStatusFilter(statusFilter === 'noprazo' ? null : 'noprazo')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'noprazo' ? 'bg-emerald-600 text-white shadow-sm' : 'bg-emerald-50 text-emerald-700'}`}>No Prazo</button>
                    <button onClick={() => setStatusFilter(statusFilter === 'atencao' ? null : 'atencao')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'atencao' ? 'bg-amber-500 text-white shadow-sm' : 'bg-amber-50 text-amber-700'}`}>Atenção</button>
                    <button onClick={() => setStatusFilter(statusFilter === 'urgente' ? null : 'urgente')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'urgente' ? 'bg-red-600 text-white shadow-sm' : 'bg-red-50 text-red-700'}`}>Urgente</button>
                </div>
            </div>

            <div className="flex bg-gray-100 p-1 rounded-2xl border border-gray-200">
                <button onClick={() => setViewMode('list')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'list' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-400'}`}>
                    <List size={14} /> Lista
                </button>
                <button onClick={() => setViewMode('pipeline')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'pipeline' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-400'}`}>
                    <Kanban size={14} /> Pipeline
                </button>
            </div>
        </div>

        <div className="flex flex-col md:flex-row gap-4">
            <div className="relative flex-1">
                <Search className="absolute left-4 top-3.5 text-gray-300" size={18} />
                <input placeholder="Filtrar por nome ou PRGD..." className="w-full pl-12 p-3.5 rounded-2xl border bg-white outline-none focus:border-brand-300 font-medium text-sm" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
            </div>
            <button onClick={() => setIsCreating(true)} className="bg-brand-600 text-white px-8 py-3.5 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-brand-700 transition-all flex items-center justify-center gap-2">
                <Plus size={18} /> Novo Cliente
            </button>
        </div>
      </div>

      <div className="flex-1 overflow-hidden bg-gray-100/30">
        {viewMode === 'list' ? (
          <div className="p-6 overflow-auto h-full scrollbar-hide">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-8">
                {filteredClients.map(client => (
                    <div key={client.id} onClick={() => onSelectClient(client)}>
                       <ClientCardItem 
                          client={client} 
                          onEdit={(e) => { e.stopPropagation(); setEditingClient(client); setFormData({name: client.name, prgd: client.prgd, phone: client.phone}); setIsCreating(true); }}
                          onDelete={(e) => { e.stopPropagation(); if(confirm("Excluir?")) onDeleteClient(client.id); }}
                          calculateDays={calculateDaysElapsed}
                          getStatus={getStatusInfo}
                       />
                    </div>
                ))}
            </div>
          </div>
        ) : (
          <div className="flex overflow-x-auto h-full p-6 gap-6 snap-x custom-scroll">
            {STAGES.map(stage => {
              const stageClients = filteredClients.filter(c => c.currentStageId === stage.id);
              const Icon = STEP_ICONS[stage.stepNumber] || Zap;
              return (
                <div 
                  key={stage.id} 
                  className="min-w-[320px] flex flex-col h-full snap-start"
                  onDragOver={onDragOver}
                  onDrop={() => onDrop(stage.id)}
                >
                  <div className="flex items-center justify-between mb-4 px-2">
                    <div className="flex items-center gap-3">
                        <div className="bg-brand-900 text-gold-400 p-2.5 rounded-xl shadow-lg border border-brand-800"><Icon size={16} /></div>
                        <h3 className="text-[11px] font-black uppercase text-brand-900 tracking-tight">{stage.title}</h3>
                    </div>
                    <span className="text-[10px] font-black text-brand-600 bg-brand-50 px-2.5 py-1 rounded-full">{stageClients.length}</span>
                  </div>

                  <div className={`flex-1 overflow-y-auto space-y-4 p-3 rounded-3xl bg-gray-100/60 border-2 border-transparent transition-all ${draggedClientId ? 'border-dashed border-brand-300' : ''} custom-scroll`}>
                    {stageClients.map(client => {
                        const totalDays = calculateDaysElapsed(client.createdAt);
                        const status = getStatusInfo(totalDays, client.currentStageId === '7');
                        return (
                            <div 
                                key={client.id} 
                                draggable 
                                onDragStart={() => onDragStart(client.id)}
                                onClick={() => onSelectClient(client)} 
                                className="bg-white p-5 rounded-[2rem] border border-gray-100 shadow-sm hover:shadow-xl hover:border-brand-400 transition-all cursor-grab active:cursor-grabbing group"
                            >
                                <div className="flex justify-between items-start mb-3">
                                    <div className="flex items-center gap-2">
                                        <GripVertical size={14} className="text-gray-200 group-hover:text-gray-400" />
                                        <div>
                                            <h4 className="font-black text-brand-900 uppercase text-[11px] group-hover:text-brand-600">{client.name}</h4>
                                            <p className="text-[8px] text-gray-400 font-bold uppercase">PRGD: {client.prgd}</p>
                                        </div>
                                    </div>
                                    <button onClick={(e) => { e.stopPropagation(); if(confirm("Excluir?")) onDeleteClient(client.id); }} className="text-gray-200 hover:text-red-500 transition"><Trash2 size={12} /></button>
                                </div>

                                <div className="flex items-center justify-between mt-4">
                                    <span className={`text-[8px] font-black uppercase px-2.5 py-1 rounded-full ${status.btn} border border-current opacity-70`}>{status.label.split(' ')[1]}</span>
                                    <div className="text-[10px] font-black text-brand-900 bg-gray-50 px-3 py-1 rounded-lg">{totalDays} d</div>
                                </div>
                            </div>
                        );
                    })}
                    {stageClients.length === 0 && (
                        <div className="h-32 border-2 border-dashed border-gray-200 rounded-[2rem] flex items-center justify-center text-gray-300 opacity-50"><Zap size={20} /></div>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

const ClientCardItem = ({ client, onEdit, onDelete, calculateDays, getStatus }: any) => {
    const isDelivered = client.currentStageId === '7';
    const totalDays = calculateDays(client.createdAt, isDelivered ? client.stageHistory['7'] : undefined);
    const status = getStatus(totalDays, isDelivered);
    const currentStage = STAGES.find(s => s.id === client.currentStageId);
    const Icon = STEP_ICONS[currentStage?.stepNumber || '1'];

    return (
        <div className="bg-white border border-gray-100 rounded-[2.5rem] p-6 hover:border-brand-400 cursor-pointer transition-all shadow-sm hover:shadow-2xl group relative overflow-hidden flex flex-col gap-5">
            <div className="flex justify-between items-start">
                <div className="flex gap-4 items-center">
                    <div className="bg-brand-50 p-4 rounded-3xl group-hover:bg-brand-600 group-hover:text-white transition-all"><User size={24} /></div>
                    <div>
                        <h3 className="font-black text-brand-900 uppercase text-lg truncate max-w-[160px]">{client.name}</h3>
                        <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest mt-1">PRGD: {client.prgd}</p>
                    </div>
                </div>
                <div className="flex gap-1.5">
                  <button onClick={onEdit} className="p-2.5 bg-gray-50 hover:bg-brand-600 text-gray-400 hover:text-white rounded-2xl transition-all"><Edit3 size={16}/></button>
                  <button onClick={onDelete} className="p-2.5 bg-gray-50 hover:bg-red-600 text-gray-400 hover:text-white rounded-2xl transition-all"><Trash2 size={16}/></button>
                </div>
            </div>

            <div className={`p-6 rounded-[2rem] border border-gray-100 flex flex-col gap-3 ${status.bg}`}>
                <div className="flex justify-between text-[10px] font-black uppercase tracking-widest">
                    <span className="text-gray-400">Jornada:</span>
                    <span className="text-brand-900 font-bold">{totalDays} dias</span>
                </div>
                <div className={`py-2 rounded-2xl text-center text-[9px] font-black tracking-widest bg-white shadow-sm ${status.color}`}>
                    {status.label}
                </div>
            </div>

            <div className="flex items-center justify-between pt-4 border-t border-gray-50">
                <div className="flex items-center gap-3">
                    <div className="bg-brand-900 text-gold-400 p-2.5 rounded-xl"><Icon size={16} /></div>
                    <div className="flex flex-col">
                        <span className="text-[8px] font-black text-gray-400 uppercase tracking-widest">Status Atual</span>
                        <span className="text-xs font-black text-brand-900 uppercase">{currentStage?.title}</span>
                    </div>
                </div>
                <ChevronRight className="text-gray-200 group-hover:translate-x-1 group-hover:text-brand-400 transition-all" size={20} />
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { Stage, Client, GeneratedContent } from '../types.ts';
import { generateTemplateContent } from '../services/templateService.ts';
import { Copy, Phone, Zap, Edit2, Save, Star, History, CheckCircle2, Trophy } from 'lucide-react';
import { STAGES } from '../constants.ts';

interface ContentGeneratorProps {
  stage: Stage;
  client: Client;
  onUpdateNotes: (notes: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

export const ContentGenerator: React.FC<ContentGeneratorProps> = ({ stage, client, onUpdateNotes, onUpdateClientStage }) => {
  const [fieldValues, setFieldValues] = useState<Record<string, string>>({});
  const [isEditing, setIsEditing] = useState(false);
  const [editableBody, setEditableBody] = useState('');

  useEffect(() => {
    setFieldValues(client.stageData || {});
    setIsEditing(false);
  }, [stage.id, client.id]);

  useEffect(() => {
    if (!isEditing) {
      const generated = generateTemplateContent(stage, client, { ...client.stageData, ...fieldValues });
      setEditableBody(generated.body);
    }
  }, [fieldValues, stage, client, isEditing]);

  const handleFieldChange = (variable: string, value: string) => {
    setFieldValues(prev => ({ ...prev, [variable]: value }));
  };

  const openWhatsApp = (text: string) => {
    const cleanPhone = client.phone.replace(/\D/g, '');
    const phoneWithCountry = cleanPhone.startsWith('55') ? cleanPhone : `55${cleanPhone}`;
    const encodedText = encodeURIComponent(text);
    window.open(`https://api.whatsapp.com/send?phone=${phoneWithCountry}&text=${encodedText}`, '_blank');
  };

  const requiredFields = stage.requiredFields || [];
  const allFieldsFilled = requiredFields.every(f => (fieldValues[f] || client.stageData?.[f])?.trim());

  const handleWhatsAppClick = () => {
    if (!client.phone) {
      alert("⚠️ Erro: Cliente sem telefone cadastrado!");
      return;
    }

    // Validação redundante e explícita para pré-requisitos antes do WhatsApp
    if (!allFieldsFilled) {
      alert(`⚠️ Atenção: Você deve preencher os campos obrigatórios (${requiredFields.join(', ')}) para esta etapa antes de enviar a mensagem.`);
      return;
    }

    openWhatsApp(editableBody);
    // Salva os dados mas mantém a etapa se estiver apenas enviando mensagem da etapa atual
    onUpdateClientStage(client.id, client.currentStageId, fieldValues);
  };

  const handleSaveAndAdvance = () => {
    if (!allFieldsFilled) {
      alert(`⚠️ Bloqueado: Preencha os campos obrigatórios antes de avançar.`);
      return;
    }
    onUpdateClientStage(client.id, stage.id, fieldValues);
    if (stage.template) {
        openWhatsApp(editableBody);
    }
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(editableBody);
    alert("Copiado! ✅");
  };

  const calculateInfo = () => {
    const start = new Date(client.createdAt);
    const now = client.currentStageId === '7' ? new Date(client.stageHistory['7']) : new Date();
    const elapsed = Math.floor(Math.abs(now.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));

    let statusLabel = '🟢 NO PRAZO';
    let statusColor = 'text-emerald-600';
    if (elapsed > 120) { statusLabel = '🔴 URGENTE'; statusColor = 'text-red-600'; }
    else if (elapsed > 90) { statusLabel = '🟡 ATENÇÃO'; statusColor = 'text-amber-500'; }

    return { elapsed, statusLabel, statusColor, start: start.toLocaleDateString('pt-BR') };
  };

  const info = calculateInfo();

  if (stage.id === '7') {
    return (
      <div className="bg-white rounded-[2.5rem] shadow-xl border border-gray-100 p-12 flex flex-col items-center justify-center text-center h-full animate-in fade-in zoom-in">
          <div className="bg-green-100 p-8 rounded-full text-green-600 mb-8 shadow-inner"><Trophy size={80} /></div>
          <h2 className="text-4xl font-black text-brand-900 uppercase tracking-tighter">Projeto Entregue!</h2>
          <p className="text-gray-400 font-bold uppercase text-xs tracking-[0.3em] mt-2 mb-10">Loop Energia • Excelência</p>
          <div className="grid grid-cols-2 gap-4 w-full max-w-md">
            <div className="bg-gray-50 p-6 rounded-3xl border border-gray-100">
              <span className="text-[10px] font-black text-gray-400 uppercase block mb-1">Início</span>
              <span className="font-black text-brand-900 text-lg">{info.start}</span>
            </div>
            <div className="bg-gray-50 p-6 rounded-3xl border border-gray-100">
              <span className="text-[10px] font-black text-gray-400 uppercase block mb-1">Total de Dias</span>
              <span className="font-black text-brand-900 text-lg">{info.elapsed} d</span>
            </div>
          </div>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-[2.5rem] shadow-lg border border-gray-200 flex flex-col h-full overflow-hidden">
      <div className="bg-brand-600 p-6 flex justify-between items-center text-white shrink-0">
        <div>
          <h2 className="text-xl font-black uppercase tracking-tight">Etapa {stage.stepNumber}: {stage.title}</h2>
          <p className="text-brand-100 text-xs font-bold uppercase tracking-wider">{stage.description}</p>
        </div>
        <button onClick={() => setIsEditing(!isEditing)} className="p-3 bg-white/10 hover:bg-white/20 rounded-2xl transition">
          {isEditing ? <Save size={20} /> : <Edit2 size={20} />}
        </button>
      </div>

      <div className="flex flex-col lg:flex-row flex-1 min-h-0">
        <div className="lg:w-80 p-6 border-r border-gray-100 bg-gray-50/50 flex flex-col gap-6 overflow-y-auto custom-scroll">
           <div className="bg-white p-5 rounded-3xl border border-brand-100 shadow-sm">
             <h3 className="text-[10px] font-black text-brand-600 uppercase mb-4 tracking-widest flex items-center gap-2">
               <Zap size={14} className="text-gold-500" /> Saúde do Projeto
             </h3>
             <div className="space-y-3">
               <div className="flex justify-between text-xs font-bold">
                 <span className="text-gray-400 uppercase text-[9px]">Início:</span>
                 <span className="text-brand-900">{info.start}</span>
               </div>
               <div className="flex justify-between text-xs font-bold">
                 <span className="text-gray-400 uppercase text-[9px]">Tempo:</span>
                 <span className="text-brand-900">{info.elapsed} dias</span>
               </div>
               <div className={`mt-2 py-2 rounded-xl text-[9px] font-black text-center bg-gray-50 border border-gray-100 ${info.statusColor}`}>
                 {info.statusLabel}
               </div>
             </div>
           </div>

           {requiredFields.length > 0 && (
             <div className="space-y-4">
               <h3 className="text-[10px] font-black text-amber-600 uppercase tracking-widest flex items-center gap-2">
                 ⚠️ Preencher Variáveis
               </h3>
               {requiredFields.map(field => (
                 <div key={field}>
                   <label className="text-[9px] font-black uppercase text-gray-500 mb-1.5 block tracking-widest ml-1">{field}</label>
                   <input 
                     className={`w-full p-4 bg-white border rounded-2xl text-sm focus:ring-4 outline-none transition-all ${!fieldValues[field] && !client.stageData?.[field] ? 'border-amber-200 focus:ring-amber-100' : 'border-gray-200 focus:ring-brand-100'}`}
                     value={fieldValues[field] || client.stageData?.[field] || ''}
                     onChange={e => handleFieldChange(field, e.target.value)}
                     placeholder={`Ex: ${field === 'data prevista' ? '15/10/2024' : '...'}`}
                   />
                 </div>
               ))}
             </div>
           )}
        </div>

        <div className="flex-1 p-6 flex flex-col gap-4 bg-white">
          <div className="flex-1 bg-gray-50 rounded-[2rem] border border-gray-100 overflow-hidden flex flex-col shadow-inner">
            <div className="px-6 py-3 border-b border-gray-100 bg-white/50 flex justify-between items-center">
              <span className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em]">Visualização da Mensagem</span>
              <button onClick={copyToClipboard} className="text-[10px] font-black text-brand-600 uppercase hover:underline">Copiar Texto</button>
            </div>

            {isEditing ? (
              <textarea 
                className="flex-1 p-8 text-sm font-sans leading-relaxed bg-transparent outline-none resize-none"
                value={editableBody}
                onChange={e => setEditableBody(e.target.value)}
              />
            ) : (
              <div className="flex-1 p-8 text-sm font-sans leading-relaxed whitespace-pre-wrap text-slate-700 overflow-y-auto custom-scroll">
                {editableBody}
              </div>
            )}
          </div>

          <div className="space-y-3">
            <button 
              onClick={handleWhatsAppClick}
              disabled={!allFieldsFilled}
              className={`w-full py-5 rounded-2xl font-black uppercase tracking-[0.2em] flex items-center justify-center gap-3 transition-all shadow-xl
                ${allFieldsFilled 
                  ? 'bg-[#25D366] text-white hover:bg-[#1fb355] hover:scale-[1.01]' 
                  : 'bg-gray-200 text-gray-400 cursor-not-allowed opacity-60'}`}
            >
              <Phone size={22} fill="currentColor" /> Enviar Mensagem via WhatsApp
            </button>

            {allFieldsFilled && stage.id !== client.currentStageId && (
              <button 
                onClick={handleSaveAndAdvance}
                className="w-full py-3 bg-brand-50 text-brand-600 rounded-2xl font-black uppercase text-[10px] tracking-widest border border-brand-100 hover:bg-brand-600 hover:text-white transition-all"
              >
                Salvar Dados e Avançar Etapa
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Client, Stage } from '../types.ts';
import { Plus, Search, User, Zap, List, Kanban, X, ChevronRight, Clock, Trash2, Edit3, CalendarDays, ArrowRightLeft, GripVertical, CheckCircle2 } from 'lucide-react';
import { STAGES, STEP_ICONS } from '../constants.ts';
import { generateTemplateContent } from '../services/templateService.ts';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onEditClient: (client: Client) => void;
  onDeleteClient: (clientId: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

type ViewMode = 'list' | 'pipeline';
type FilterStatus = 'ativos' | 'entregues' | 'noprazo' | 'atencao' | 'urgente' | null;

interface PendingTransition {
  client: Client;
  targetStage: Stage;
  fieldValues: Record<string, string>;
}

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onEditClient, onDeleteClient, onUpdateClientStage }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<ViewMode>('pipeline');
  const [statusFilter, setStatusFilter] = useState<FilterStatus>(null);
  const [draggedClientId, setDraggedClientId] = useState<string | null>(null);

  // Novo estado para gerenciar a transição pendente (modal de preenchimento rápido)
  const [pendingTransition, setPendingTransition] = useState<PendingTransition | null>(null);

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '', clientNumber: '', prgd: '', phone: '',
  });

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    if (!startStr) return 0;
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const getStatusInfo = (days: number, isDelivered: boolean) => {
    if (isDelivered) return { label: '🟢 ENTREGUE', color: 'text-green-600', bg: 'bg-green-50', key: 'entregues', btn: 'bg-green-100 text-green-700' };
    if (days > 120) return { label: '🔴 URGENTE', color: 'text-red-600', bg: 'bg-red-50', key: 'urgente', btn: 'bg-red-100 text-red-700' };
    if (days > 90) return { label: '🟡 ATENÇÃO', color: 'text-amber-500', bg: 'bg-amber-50', key: 'atencao', btn: 'bg-amber-100 text-amber-700' };
    return { label: '🟢 NO PRAZO', color: 'text-emerald-600', bg: 'bg-emerald-50', key: 'noprazo', btn: 'bg-emerald-100 text-emerald-700' };
  };

  const filteredClients = clients.filter(c => {
    const matchesSearch = c.name.toLowerCase().includes(searchTerm.toLowerCase()) || c.prgd.toLowerCase().includes(searchTerm.toLowerCase());
    if (!matchesSearch) return false;
    if (!statusFilter) return true;
    const isDelivered = c.currentStageId === '7';
    const days = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);
    const info = getStatusInfo(days, isDelivered);
    if (statusFilter === 'ativos') return !isDelivered;
    return info.key === statusFilter;
  });

  const triggerWhatsApp = (client: Client, stage: Stage, additionalData: Record<string, string> = {}) => {
    if (!client.phone) return;
    const combinedData = { ...(client.stageData || {}), ...additionalData };
    const generated = generateTemplateContent(stage, client, combinedData);
    if (!generated.body) return;

    const cleanPhone = client.phone.replace(/\D/g, '');
    const phoneWithCountry = cleanPhone.startsWith('55') ? cleanPhone : `55${cleanPhone}`;
    const encodedText = encodeURIComponent(generated.body);
    window.open(`https://api.whatsapp.com/send?phone=${phoneWithCountry}&text=${encodedText}`, '_blank');
  };

  const onDragStart = (id: string) => setDraggedClientId(id);
  const onDragOver = (e: React.DragEvent) => e.preventDefault();

  const onDrop = (stageId: string) => {
    if (draggedClientId) {
      const client = clients.find(c => c.id === draggedClientId);
      const targetStage = STAGES.find(s => s.id === stageId);

      if (client && targetStage) {
        const requiredFields = targetStage.requiredFields || [];
        const missingFields = requiredFields.filter(field => !client.stageData?.[field]?.trim());

        if (missingFields.length > 0) {
          // Em vez de abrir a ficha completa, abre o modal de preenchimento rápido
          setPendingTransition({
            client,
            targetStage,
            fieldValues: missingFields.reduce((acc, field) => ({ ...acc, [field]: '' }), {})
          });
        } else {
          onUpdateClientStage(draggedClientId, stageId);
          if (targetStage.template) {
            triggerWhatsApp(client, targetStage);
          }
        }
      }
      setDraggedClientId(null);
    }
  };

  const handleConfirmPendingTransition = () => {
    if (!pendingTransition) return;
    const { client, targetStage, fieldValues } = pendingTransition;

    // Verifica se todos os campos foram preenchidos no modal
    const missing = Object.values(fieldValues).some(v => !v.trim());
    if (missing) {
      alert("Por favor, preencha todos os campos obrigatórios.");
      return;
    }

    // Move e atualiza dados
    onUpdateClientStage(client.id, targetStage.id, fieldValues);

    // Dispara WhatsApp
    if (targetStage.template) {
      triggerWhatsApp(client, targetStage, fieldValues);
    }

    setPendingTransition(null);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingClient) {
      onEditClient({ ...editingClient, name: formData.name || '', clientNumber: formData.clientNumber || '', prgd: formData.prgd || '', phone: formData.phone || '' });
    } else {
      const now = new Date().toISOString();
      onCreateClient({
        id: Date.now().toString(),
        name: formData.name || '',
        clientNumber: formData.clientNumber || '',
        prgd: formData.prgd || '',
        phone: formData.phone || '',
        projectName: `Projeto ${formData.name}`,
        additionalNotes: '',
        currentStageId: STAGES[0].id,
        createdAt: now,
        stageHistory: { [STAGES[0].id]: now },
        stageData: {}
      });
    }
    closeModal();
  };

  const closeModal = () => {
    setIsCreating(false);
    setEditingClient(null);
    setFormData({ name: '', clientNumber: '', prgd: '', phone: '' });
  };

  return (
    <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-200 h-full flex flex-col relative overflow-hidden">

      {/* Modal de Transição Rápida (Preenchimento de Campos Obrigatórios) */}
      {pendingTransition && (
        <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-md z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-md animate-scale-up border border-white/20 overflow-hidden">
            <div className="p-8 pb-4 flex justify-between items-center border-b border-gray-50 bg-amber-50/50">
              <div className="flex items-center gap-3">
                <div className="bg-amber-100 text-amber-600 p-2 rounded-xl"><CalendarDays size={20} /></div>
                <h2 className="text-xl font-black text-brand-900 uppercase tracking-tighter">Informação Necessária</h2>
              </div>
              <button onClick={() => setPendingTransition(null)} className="p-2 hover:bg-white rounded-full transition text-gray-400"><X size={20} /></button>
            </div>
            <div className="p-8 space-y-6">
              <p className="text-xs font-bold text-gray-400 uppercase tracking-widest leading-relaxed">
                Para mover <span className="text-brand-600 font-black">{pendingTransition.client.name}</span> para a etapa de <span className="text-brand-600 font-black">{pendingTransition.targetStage.title}</span>, informe:
              </p>

              <div className="space-y-4">
                {Object.keys(pendingTransition.fieldValues).map(field => (
                  <div key={field} className="group">
                    <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1.5 block ml-1">{field}</label>
                    <input 
                      autoFocus
                      required
                      placeholder={field === 'data prevista' ? 'Ex: 15/10/2024' : 'Preencha aqui...'}
                      className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white focus:border-brand-300 transition-all text-sm font-bold"
                      value={pendingTransition.fieldValues[field]}
                      onChange={e => setPendingTransition({
                        ...pendingTransition,
                        fieldValues: { ...pendingTransition.fieldValues, [field]: e.target.value }
                      })}
                    />
                  </div>
                ))}
              </div>

              <button 
                onClick={handleConfirmPendingTransition}
                className="w-full bg-brand-600 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-brand-700 shadow-xl transition-all flex items-center justify-center gap-2"
              >
                Confirmar e Abrir WhatsApp <ArrowRightLeft size={16} />
              </button>
            </div>
          </div>
        </div>
      )}

      {isCreating && (
          <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-4">
              <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-xl animate-scale-up border border-white/20 overflow-hidden">
                  <div className="p-8 pb-4 flex justify-between items-center border-b border-gray-50 bg-gray-50/50">
                      <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">{editingClient ? 'Editar Cadastro' : 'Novo Cliente'}</h2>
                      <button onClick={closeModal} className="p-2 hover:bg-white rounded-full transition text-gray-400"><X size={24} /></button>
                  </div>
                  <form onSubmit={handleSubmit} className="p-8 space-y-6">
                      <div className="space-y-4">
                        <div className="group">
                          <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1.5 block ml-1">Titular do Projeto</label>
                          <input required value={formData.name} placeholder="Nome Completo" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white transition-all" onChange={e => setFormData({...formData, name: e.target.value})} />
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1.5 block ml-1">Telefone</label>
                            <input required placeholder="(00) 00000-0000" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white transition-all" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} />
                          </div>
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1.5 block ml-1">Nº PRGD</label>
                            <input required value={formData.prgd} placeholder="GD-0000" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white transition-all" onChange={e => setFormData({...formData, prgd: e.target.value})} />
                          </div>
                        </div>
                      </div>
                      <button type="submit" className="w-full bg-brand-600 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-sm hover:bg-brand-700 shadow-xl transition-all">
                        {editingClient ? 'SALVAR ALTERAÇÕES' : 'CADASTRAR CLIENTE'}
                      </button>
                  </form>
              </div>
          </div>
      )}

      <div className="p-6 border-b flex flex-col gap-6 bg-gray-50/50">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <div>
                <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter leading-tight">Gestão de Carteira</h2>
                <div className="flex flex-wrap items-center gap-2 mt-2">
                    <button onClick={() => setStatusFilter(statusFilter === 'ativos' ? null : 'ativos')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'ativos' ? 'bg-brand-600 text-white shadow-sm' : 'bg-white text-brand-600 hover:border-brand-300'}`}>Ativos</button>
                    <button onClick={() => setStatusFilter(statusFilter === 'entregues' ? null : 'entregues')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'entregues' ? 'bg-green-600 text-white shadow-sm' : 'bg-white text-green-600 hover:border-green-300'}`}>Entregues</button>
                    <div className="h-4 w-px bg-gray-300 mx-2"></div>
                    <button onClick={() => setStatusFilter(statusFilter === 'noprazo' ? null : 'noprazo')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'noprazo' ? 'bg-emerald-600 text-white shadow-sm' : 'bg-emerald-50 text-emerald-700'}`}>No Prazo</button>
                    <button onClick={() => setStatusFilter(statusFilter === 'atencao' ? null : 'atencao')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'atencao' ? 'bg-amber-500 text-white shadow-sm' : 'bg-amber-50 text-amber-700'}`}>Atenção</button>
                    <button onClick={() => setStatusFilter(statusFilter === 'urgente' ? null : 'urgente')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'urgente' ? 'bg-red-600 text-white shadow-sm' : 'bg-red-50 text-red-700'}`}>Urgente</button>
                </div>
            </div>

            <div className="flex bg-gray-100 p-1 rounded-2xl border border-gray-200">
                <button onClick={() => setViewMode('list')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'list' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-400'}`}>
                    <List size={14} /> Lista
                </button>
                <button onClick={() => setViewMode('pipeline')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'pipeline' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-400'}`}>
                    <Kanban size={14} /> Pipeline
                </button>
            </div>
        </div>

        <div className="flex flex-col md:flex-row gap-4">
            <div className="relative flex-1">
                <Search className="absolute left-4 top-3.5 text-gray-300" size={18} />
                <input placeholder="Filtrar por nome ou PRGD..." className="w-full pl-12 p-3.5 rounded-2xl border bg-white outline-none focus:border-brand-300 font-medium text-sm" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
            </div>
            <button onClick={() => setIsCreating(true)} className="bg-brand-600 text-white px-8 py-3.5 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-brand-700 transition-all flex items-center justify-center gap-2">
                <Plus size={18} /> Novo Cliente
            </button>
        </div>
      </div>

      <div className="flex-1 overflow-hidden bg-gray-100/30">
        {viewMode === 'list' ? (
          <div className="p-6 overflow-auto h-full scrollbar-hide">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-8">
                {filteredClients.map(client => (
                    <div key={client.id} onClick={() => onSelectClient(client)}>
                       <ClientCardItem 
                          client={client} 
                          onEdit={(e) => { e.stopPropagation(); setEditingClient(client); setFormData({name: client.name, prgd: client.prgd, phone: client.phone}); setIsCreating(true); }}
                          onDelete={(e) => { e.stopPropagation(); if(confirm("Excluir?")) onDeleteClient(client.id); }}
                          calculateDays={calculateDaysElapsed}
                          getStatus={getStatusInfo}
                       />
                    </div>
                ))}
            </div>
          </div>
        ) : (
          <div className="flex overflow-x-auto h-full p-6 gap-6 snap-x custom-scroll">
            {STAGES.map(stage => {
              const stageClients = filteredClients.filter(c => c.currentStageId === stage.id);
              const Icon = STEP_ICONS[stage.stepNumber] || Zap;
              return (
                <div 
                  key={stage.id} 
                  className="min-w-[320px] flex flex-col h-full snap-start"
                  onDragOver={onDragOver}
                  onDrop={() => onDrop(stage.id)}
                >
                  <div className="flex items-center justify-between mb-4 px-2">
                    <div className="flex items-center gap-3">
                        <div className="bg-brand-900 text-gold-400 p-2.5 rounded-xl shadow-lg border border-brand-800"><Icon size={16} /></div>
                        <h3 className="text-[11px] font-black uppercase text-brand-900 tracking-tight">{stage.title}</h3>
                    </div>
                    <span className="text-[10px] font-black text-brand-600 bg-brand-50 px-2.5 py-1 rounded-full">{stageClients.length}</span>
                  </div>

                  <div className={`flex-1 overflow-y-auto space-y-4 p-3 rounded-3xl bg-gray-100/60 border-2 border-transparent transition-all ${draggedClientId ? 'border-dashed border-brand-300' : ''} custom-scroll`}>
                    {stageClients.map(client => {
                        const totalDays = calculateDaysElapsed(client.createdAt);
                        const status = getStatusInfo(totalDays, client.currentStageId === '7');
                        return (
                            <div 
                                key={client.id} 
                                draggable 
                                onDragStart={() => onDragStart(client.id)}
                                onClick={() => onSelectClient(client)} 
                                className="bg-white p-5 rounded-[2rem] border border-gray-100 shadow-sm hover:shadow-xl hover:border-brand-400 transition-all cursor-grab active:cursor-grabbing group"
                            >
                                <div className="flex justify-between items-start mb-3">
                                    <div className="flex items-center gap-2">
                                        <GripVertical size={14} className="text-gray-200 group-hover:text-gray-400" />
                                        <div>
                                            <h4 className="font-black text-brand-900 uppercase text-[11px] group-hover:text-brand-600">{client.name}</h4>
                                            <p className="text-[8px] text-gray-400 font-bold uppercase">PRGD: {client.prgd}</p>
                                        </div>
                                    </div>
                                    <button onClick={(e) => { e.stopPropagation(); if(confirm("Excluir?")) onDeleteClient(client.id); }} className="text-gray-200 hover:text-red-500 transition"><Trash2 size={12} /></button>
                                </div>

                                <div className="flex items-center justify-between mt-4">
                                    <span className={`text-[8px] font-black uppercase px-2.5 py-1 rounded-full ${status.btn} border border-current opacity-70`}>{status.label.split(' ')[1]}</span>
                                    <div className="text-[10px] font-black text-brand-900 bg-gray-50 px-3 py-1 rounded-lg">{totalDays} d</div>
                                </div>
                            </div>
                        );
                    })}
                    {stageClients.length === 0 && (
                        <div className="h-32 border-2 border-dashed border-gray-200 rounded-[2rem] flex items-center justify-center text-gray-300 opacity-50"><Zap size={20} /></div>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

const ClientCardItem = ({ client, onEdit, onDelete, calculateDays, getStatus }: any) => {
    const isDelivered = client.currentStageId === '7';
    const totalDays = calculateDays(client.createdAt, isDelivered ? client.stageHistory['7'] : undefined);
    const status = getStatus(totalDays, isDelivered);
    const currentStage = STAGES.find(s => s.id === client.currentStageId);
    const Icon = STEP_ICONS[currentStage?.stepNumber || '1'];

    return (
        <div className="bg-white border border-gray-100 rounded-[2.5rem] p-6 hover:border-brand-400 cursor-pointer transition-all shadow-sm hover:shadow-2xl group relative overflow-hidden flex flex-col gap-5">
            <div className="flex justify-between items-start">
                <div className="flex gap-4 items-center">
                    <div className="bg-brand-50 p-4 rounded-3xl group-hover:bg-brand-600 group-hover:text-white transition-all"><User size={24} /></div>
                    <div>
                        <h3 className="font-black text-brand-900 uppercase text-lg truncate max-w-[160px]">{client.name}</h3>
                        <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest mt-1">PRGD: {client.prgd}</p>
                    </div>
                </div>
                <div className="flex gap-1.5">
                  <button onClick={onEdit} className="p-2.5 bg-gray-50 hover:bg-brand-600 text-gray-400 hover:text-white rounded-2xl transition-all"><Edit3 size={16}/></button>
                  <button onClick={onDelete} className="p-2.5 bg-gray-50 hover:bg-red-600 text-gray-400 hover:text-white rounded-2xl transition-all"><Trash2 size={16}/></button>
                </div>
            </div>

            <div className={`p-6 rounded-[2rem] border border-gray-100 flex flex-col gap-3 ${status.bg}`}>
                <div className="flex justify-between text-[10px] font-black uppercase tracking-widest">
                    <span className="text-gray-400">Jornada:</span>
                    <span className="text-brand-900 font-bold">{totalDays} dias</span>
                </div>
                <div className={`py-2 rounded-2xl text-center text-[9px] font-black tracking-widest bg-white shadow-sm ${status.color}`}>
                    {status.label}
                </div>
            </div>

            <div className="flex items-center justify-between pt-4 border-t border-gray-50">
                <div className="flex items-center gap-3">
                    <div className="bg-brand-900 text-gold-400 p-2.5 rounded-xl"><Icon size={16} /></div>
                    <div className="flex flex-col">
                        <span className="text-[8px] font-black text-gray-400 uppercase tracking-widest">Status Atual</span>
                        <span className="text-xs font-black text-brand-900 uppercase">{currentStage?.title}</span>
                    </div>
                </div>
                <ChevronRight className="text-gray-200 group-hover:translate-x-1 group-hover:text-brand-400 transition-all" size={20} />
            </div>
        </div>
    );
};

import React, { useState } from 'react';
import { Client, Stage } from '../types.ts';
import { Plus, Search, User, Zap, List, Kanban, X, ChevronRight, Clock, Trash2, Edit3, CalendarDays, ArrowRightLeft, GripVertical, CheckCircle2 } from 'lucide-react';
import { STAGES, STEP_ICONS } from '../constants.ts';
import { generateTemplateContent } from '../services/templateService.ts';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onEditClient: (client: Client) => void;
  onDeleteClient: (clientId: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

type ViewMode = 'list' | 'pipeline';
type FilterStatus = 'ativos' | 'entregues' | 'noprazo' | 'atencao' | 'urgente' | null;

interface PendingTransition {
  client: Client;
  targetStage: Stage;
  fieldValues: Record<string, string>;
}

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onEditClient, onDeleteClient, onUpdateClientStage }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<ViewMode>('pipeline');
  const [statusFilter, setStatusFilter] = useState<FilterStatus>(null);
  const [draggedClientId, setDraggedClientId] = useState<string | null>(null);

  // Novo estado para gerenciar a transição pendente (modal de preenchimento rápido)
  const [pendingTransition, setPendingTransition] = useState<PendingTransition | null>(null);

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '', clientNumber: '', prgd: '', phone: '',
  });

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    if (!startStr) return 0;
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const getStatusInfo = (days: number, isDelivered: boolean) => {
    if (isDelivered) return { label: '🟢 ENTREGUE', color: 'text-green-600', bg: 'bg-green-50', key: 'entregues', btn: 'bg-green-100 text-green-700' };
    if (days > 120) return { label: '🔴 URGENTE', color: 'text-red-600', bg: 'bg-red-50', key: 'urgente', btn: 'bg-red-100 text-red-700' };
    if (days > 90) return { label: '🟡 ATENÇÃO', color: 'text-amber-500', bg: 'bg-amber-50', key: 'atencao', btn: 'bg-amber-100 text-amber-700' };
    return { label: '🟢 NO PRAZO', color: 'text-emerald-600', bg: 'bg-emerald-50', key: 'noprazo', btn: 'bg-emerald-100 text-emerald-700' };
  };

  const filteredClients = clients.filter(c => {
    const matchesSearch = c.name.toLowerCase().includes(searchTerm.toLowerCase()) || c.prgd.toLowerCase().includes(searchTerm.toLowerCase());
    if (!matchesSearch) return false;
    if (!statusFilter) return true;
    const isDelivered = c.currentStageId === '7';
    const days = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);
    const info = getStatusInfo(days, isDelivered);
    if (statusFilter === 'ativos') return !isDelivered;
    return info.key === statusFilter;
  });

  const triggerWhatsApp = (client: Client, stage: Stage, additionalData: Record<string, string> = {}) => {
    if (!client.phone) return;
    const combinedData = { ...(client.stageData || {}), ...additionalData };
    const generated = generateTemplateContent(stage, client, combinedData);
    if (!generated.body) return;

    const cleanPhone = client.phone.replace(/\D/g, '');
    const phoneWithCountry = cleanPhone.startsWith('55') ? cleanPhone : `55${cleanPhone}`;
    const encodedText = encodeURIComponent(generated.body);
    window.open(`https://api.whatsapp.com/send?phone=${phoneWithCountry}&text=${encodedText}`, '_blank');
  };

  const onDragStart = (id: string) => setDraggedClientId(id);
  const onDragOver = (e: React.DragEvent) => e.preventDefault();

  const onDrop = (stageId: string) => {
    if (draggedClientId) {
      const client = clients.find(c => c.id === draggedClientId);
      const targetStage = STAGES.find(s => s.id === stageId);

      if (client && targetStage) {
        const requiredFields = targetStage.requiredFields || [];
        // Fix: added explicit casting to string for the stageData field access to resolve 'unknown' type error on .trim()
        const missingFields = requiredFields.filter(field => !((client.stageData?.[field] as string | undefined)?.trim()));

        if (missingFields.length > 0) {
          // Em vez de abrir a ficha completa, abre o modal de preenchimento rápido
          setPendingTransition({
            client,
            targetStage,
            fieldValues: missingFields.reduce((acc, field) => ({ ...acc, [field]: '' }), {})
          });
        } else {
          onUpdateClientStage(draggedClientId, stageId);
          if (targetStage.template) {
            triggerWhatsApp(client, targetStage);
          }
        }
      }
      setDraggedClientId(null);
    }
  };

  const handleConfirmPendingTransition = () => {
    if (!pendingTransition) return;
    const { client, targetStage, fieldValues } = pendingTransition;

    // Verifica se todos os campos foram preenchidos no modal
    const missing = Object.values(fieldValues).some(v => !v.trim());
    if (missing) {
      alert("Por favor, preencha todos os campos obrigatórios.");
      return;
    }

    // Move e atualiza dados
    onUpdateClientStage(client.id, targetStage.id, fieldValues);

    // Dispara WhatsApp
    if (targetStage.template) {
      triggerWhatsApp(client, targetStage, fieldValues);
    }

    setPendingTransition(null);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingClient) {
      onEditClient({ ...editingClient, name: formData.name || '', clientNumber: formData.clientNumber || '', prgd: formData.prgd || '', phone: formData.phone || '' });
    } else {
      const now = new Date().toISOString();
      onCreateClient({
        id: Date.now().toString(),
        name: formData.name || '',
        clientNumber: formData.clientNumber || '',
        prgd: formData.prgd || '',
        phone: formData.phone || '',
        projectName: `Projeto ${formData.name}`,
        additionalNotes: '',
        currentStageId: STAGES[0].id,
        createdAt: now,
        stageHistory: { [STAGES[0].id]: now },
        stageData: {}
      });
    }
    closeModal();
  };

  const closeModal = () => {
    setIsCreating(false);
    setEditingClient(null);
    setFormData({ name: '', clientNumber: '', prgd: '', phone: '' });
  };

  return (
    <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-200 h-full flex flex-col relative overflow-hidden">

      {/* Modal de Transição Rápida (Preenchimento de Campos Obrigatórios) */}
      {pendingTransition && (
        <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-md z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-md animate-scale-up border border-white/20 overflow-hidden">
            <div className="p-8 pb-4 flex justify-between items-center border-b border-gray-50 bg-amber-50/50">
              <div className="flex items-center gap-3">
                <div className="bg-amber-100 text-amber-600 p-2 rounded-xl"><CalendarDays size={20} /></div>
                <h2 className="text-xl font-black text-brand-900 uppercase tracking-tighter">Informação Necessária</h2>
              </div>
              <button onClick={() => setPendingTransition(null)} className="p-2 hover:bg-white rounded-full transition text-gray-400"><X size={20} /></button>
            </div>
            <div className="p-8 space-y-6">
              <p className="text-xs font-bold text-gray-400 uppercase tracking-widest leading-relaxed">
                Para mover <span className="text-brand-600 font-black">{pendingTransition.client.name}</span> para a etapa de <span className="text-brand-600 font-black">{pendingTransition.targetStage.title}</span>, informe:
              </p>

              <div className="space-y-4">
                {Object.keys(pendingTransition.fieldValues).map(field => (
                  <div key={field} className="group">
                    <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1.5 block ml-1">{field}</label>
                    <input 
                      autoFocus
                      required
                      placeholder={field === 'data prevista' ? 'Ex: 15/10/2024' : 'Preencha aqui...'}
                      className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white focus:border-brand-300 transition-all text-sm font-bold"
                      value={pendingTransition.fieldValues[field]}
                      onChange={e => setPendingTransition({
                        ...pendingTransition,
                        fieldValues: { ...pendingTransition.fieldValues, [field]: e.target.value }
                      })}
                    />
                  </div>
                ))}
              </div>

              <button 
                onClick={handleConfirmPendingTransition}
                className="w-full bg-brand-600 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-brand-700 shadow-xl transition-all flex items-center justify-center gap-2"
              >
                Confirmar e Abrir WhatsApp <ArrowRightLeft size={16} />
              </button>
            </div>
          </div>
        </div>
      )}

      {isCreating && (
          <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-4">
              <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-xl animate-scale-up border border-white/20 overflow-hidden">
                  <div className="p-8 pb-4 flex justify-between items-center border-b border-gray-50 bg-gray-50/50">
                      <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">{editingClient ? 'Editar Cadastro' : 'Novo Cliente'}</h2>
                      <button onClick={closeModal} className="p-2 hover:bg-white rounded-full transition text-gray-400"><X size={24} /></button>
                  </div>
                  <form onSubmit={handleSubmit} className="p-8 space-y-6">
                      <div className="space-y-4">
                        <div className="group">
                          <label className="text-[10px] font-black uppercase text-brand-900 tracking-widest mb-2 block">Titular do Projeto</label>
                          <input required value={formData.name} placeholder="Nome Completo" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white transition-all" onChange={e => setFormData({...formData, name: e.target.value})} />
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-900 tracking-widest mb-2 block">Telefone</label>
                            <input required placeholder="(00) 00000-0000" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white transition-all" value={formData.phone} onChange={e => setFormData({...formData, phone: e.target.value})} />
                          </div>
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-900 tracking-widest mb-2 block">Nº PRGD</label>
                            <input required value={formData.prgd} placeholder="GD-0000" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white transition-all" onChange={e => setFormData({...formData, prgd: e.target.value})} />
                          </div>
                        </div>
                      </div>
                      <button type="submit" className="w-full bg-brand-600 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-sm hover:bg-brand-700 shadow-xl transition-all">
                        {editingClient ? 'SALVAR ALTERAÇÕES' : 'CADASTRAR CLIENTE'}
                      </button>
                  </form>
              </div>
          </div>
      )}

      <div className="p-6 border-b flex flex-col gap-6 bg-gray-50/50">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <div>
                <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter leading-tight">Gestão de Carteira</h2>
                <div className="flex flex-wrap items-center gap-2 mt-2">
                    <button onClick={() => setStatusFilter(statusFilter === 'ativos' ? null : 'ativos')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'ativos' ? 'bg-brand-600 text-white shadow-sm' : 'bg-white text-brand-600 hover:border-brand-300'}`}>Ativos</button>
                    <button onClick={() => setStatusFilter(statusFilter === 'entregues' ? null : 'entregues')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'entregues' ? 'bg-green-600 text-white shadow-sm' : 'bg-white text-green-600 hover:border-green-300'}`}>Entregues</button>
                    <div className="h-4 w-px bg-gray-300 mx-2"></div>
                    <button onClick={() => setStatusFilter(statusFilter === 'noprazo' ? null : 'noprazo')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'noprazo' ? 'bg-emerald-600 text-white shadow-sm' : 'bg-emerald-50 text-emerald-700'}`}>No Prazo</button>
                    <button onClick={() => setStatusFilter(statusFilter === 'atencao' ? null : 'atencao')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'atencao' ? 'bg-amber-500 text-white shadow-sm' : 'bg-amber-50 text-amber-700'}`}>Atenção</button>
                    <button onClick={() => setStatusFilter(statusFilter === 'urgente' ? null : 'urgente')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'urgente' ? 'bg-red-600 text-white shadow-sm' : 'bg-red-50 text-red-700'}`}>Urgente</button>
                </div>
            </div>

            <div className="flex bg-gray-100 p-1 rounded-2xl border border-gray-200">
                <button onClick={() => setViewMode('list')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'list' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-400'}`}>
                    <List size={14} /> Lista
                </button>
                <button onClick={() => setViewMode('pipeline')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'pipeline' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-400'}`}>
                    <Kanban size={14} /> Pipeline
                </button>
            </div>
        </div>

        <div className="flex flex-col md:flex-row gap-4">
            <div className="relative flex-1">
                <Search className="absolute left-4 top-3.5 text-gray-300" size={18} />
                <input placeholder="Filtrar por nome ou PRGD..." className="w-full pl-12 p-3.5 rounded-2xl border bg-white outline-none focus:border-brand-300 font-medium text-sm" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
            </div>
            <button onClick={() => setIsCreating(true)} className="bg-brand-600 text-white px-8 py-3.5 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-brand-700 transition-all flex items-center justify-center gap-2">
                <Plus size={18} /> Novo Cliente
            </button>
        </div>
      </div>

      <div className="flex-1 overflow-hidden bg-gray-100/30">
        {viewMode === 'list' ? (
          <div className="p-6 overflow-auto h-full scrollbar-hide">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-8">
                {filteredClients.map(client => (
                    <div key={client.id} onClick={() => onSelectClient(client)}>
                       <ClientCardItem 
                          client={client} 
                          onEdit={(e: React.MouseEvent) => { e.stopPropagation(); setEditingClient(client); setFormData({name: client.name, prgd: client.prgd, phone: client.phone}); setIsCreating(true); }}
                          onDelete={(e: React.MouseEvent) => { e.stopPropagation(); if(confirm("Excluir?")) onDeleteClient(client.id); }}
                          calculateDays={calculateDaysElapsed}
                          getStatus={getStatusInfo}
                       />
                    </div>
                ))}
            </div>
          </div>
        ) : (
          <div className="flex overflow-x-auto h-full p-6 gap-6 snap-x custom-scroll">
            {STAGES.map(stage => {
              const stageClients = filteredClients.filter(c => c.currentStageId === stage.id);
              const Icon = STEP_ICONS[stage.stepNumber] || Zap;
              return (
                <div 
                  key={stage.id} 
                  className="min-w-[320px] flex flex-col h-full snap-start"
                  onDragOver={onDragOver}
                  onDrop={() => onDrop(stage.id)}
                >
                  <div className="flex items-center justify-between mb-4 px-2">
                    <div className="flex items-center gap-3">
                        <div className="bg-brand-900 text-gold-400 p-2.5 rounded-xl shadow-lg border border-brand-800"><Icon size={16} /></div>
                        <h3 className="text-[11px] font-black uppercase text-brand-900 tracking-tight">{stage.title}</h3>
                    </div>
                    <span className="text-[10px] font-black text-brand-600 bg-brand-50 px-2.5 py-1 rounded-full">{stageClients.length}</span>
                  </div>

                  <div className={`flex-1 overflow-y-auto space-y-4 p-3 rounded-3xl bg-gray-100/60 border-2 border-transparent transition-all ${draggedClientId ? 'border-dashed border-brand-300' : ''} custom-scroll`}>
                    {stageClients.map(client => {
                        const totalDays = calculateDaysElapsed(client.createdAt);
                        const status = getStatusInfo(totalDays, client.currentStageId === '7');
                        return (
                            <div 
                                key={client.id} 
                                draggable 
                                onDragStart={() => onDragStart(client.id)}
                                onClick={() => onSelectClient(client)} 
                                className="bg-white p-5 rounded-[2rem] border border-gray-100 shadow-sm hover:shadow-xl hover:border-brand-400 transition-all cursor-grab active:cursor-grabbing group"
                            >
                                <div className="flex justify-between items-start mb-3">
                                    <div className="flex items-center gap-2">
                                        <GripVertical size={14} className="text-gray-200 group-hover:text-gray-400" />
                                        <div>
                                            <h4 className="font-black text-brand-900 uppercase text-[11px] group-hover:text-brand-600">{client.name}</h4>
                                            <p className="text-[8px] text-gray-400 font-bold uppercase">PRGD: {client.prgd}</p>
                                        </div>
                                    </div>
                                    <button onClick={(e) => { e.stopPropagation(); if(confirm("Excluir?")) onDeleteClient(client.id); }} className="text-gray-200 hover:text-red-500 transition"><Trash2 size={12} /></button>
                                </div>

                                <div className="flex items-center justify-between mt-4">
                                    <span className={`text-[8px] font-black uppercase px-2.5 py-1 rounded-full ${status.btn} border border-current opacity-70`}>{status.label.split(' ')[1]}</span>
                                    <div className="text-[10px] font-black text-brand-900 bg-gray-50 px-3 py-1 rounded-lg">{totalDays} d</div>
                                </div>
                            </div>
                        );
                    })}
                    {stageClients.length === 0 && (
                        <div className="h-32 border-2 border-dashed border-gray-200 rounded-[2rem] flex items-center justify-center text-gray-300 opacity-50"><Zap size={20} /></div>
                    )}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

const ClientCardItem = ({ client, onEdit, onDelete, calculateDays, getStatus }: any) => {
    const isDelivered = client.currentStageId === '7';
    const totalDays = calculateDays(client.createdAt, isDelivered ? client.stageHistory['7'] : undefined);
    const status = getStatus(totalDays, isDelivered);
    const currentStage = STAGES.find(s => s.id === client.currentStageId);
    const Icon = STEP_ICONS[currentStage?.stepNumber || '1'];

    return (
        <div className="bg-white border border-gray-100 rounded-[2.5rem] p-6 hover:border-brand-400 cursor-pointer transition-all shadow-sm hover:shadow-2xl group relative overflow-hidden flex flex-col gap-5">
            <div className="flex justify-between items-start">
                <div className="flex gap-4 items-center">
                    <div className="bg-brand-50 p-4 rounded-3xl group-hover:bg-brand-600 group-hover:text-white transition-all"><User size={24} /></div>
                    <div>
                        <h3 className="font-black text-brand-900 uppercase text-lg truncate max-w-[160px]">{client.name}</h3>
                        <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest mt-1">PRGD: {client.prgd}</p>
                    </div>
                </div>
                <div className="flex gap-1.5">
                  <button onClick={onEdit} className="p-2.5 bg-gray-50 hover:bg-brand-600 text-gray-400 hover:text-white rounded-2xl transition-all"><Edit3 size={16}/></button>
                  <button onClick={onDelete} className="p-2.5 bg-gray-50 hover:bg-red-600 text-gray-400 hover:text-white rounded-2xl transition-all"><Trash2 size={16}/></button>
                </div>
            </div>

            <div className={`p-6 rounded-[2rem] border border-gray-100 flex flex-col gap-3 ${status.bg}`}>
                <div className="flex justify-between text-[10px] font-black uppercase tracking-widest">
                    <span className="text-gray-400">Jornada:</span>
                    <span className="text-brand-900 font-bold">{totalDays} dias</span>
                </div>
                <div className={`py-2 rounded-2xl text-center text-[9px] font-black tracking-widest bg-white shadow-sm ${status.color}`}>
                    {status.label}
                </div>
            </div>

            <div className="flex items-center justify-between pt-4 border-t border-gray-50">
                <div className="flex items-center gap-3">
                    <div className="bg-brand-900 text-gold-400 p-2.5 rounded-xl"><Icon size={16} /></div>
                    <div className="flex flex-col">
                        <span className="text-[8px] font-black text-gray-400 uppercase tracking-widest">Status Atual</span>
                        <span className="text-xs font-black text-brand-900 uppercase">{currentStage?.title}</span>
                    </div>
                </div>
                <ChevronRight className="text-gray-200 group-hover:translate-x-1 group-hover:text-brand-400 transition-all" size={20} />
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { Stage, Client, GeneratedContent } from '../types.ts';
import { generateTemplateContent } from '../services/templateService.ts';
import { 
  Copy, 
  Phone, 
  Zap, 
  Edit2, 
  Save, 
  Star, 
  History, 
  CheckCircle2, 
  Trophy, 
  Clock, 
  Calendar,
  AlertCircle,
  TrendingUp,
  ArrowRight
} from 'lucide-react';
import { STAGES } from '../constants.ts';

interface ContentGeneratorProps {
  stage: Stage;
  client: Client;
  onUpdateNotes: (notes: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

export const ContentGenerator: React.FC<ContentGeneratorProps> = ({ stage, client, onUpdateNotes, onUpdateClientStage }) => {
  const [fieldValues, setFieldValues] = useState<Record<string, string>>({});
  const [isEditing, setIsEditing] = useState(false);
  const [editableBody, setEditableBody] = useState('');

  useEffect(() => {
    setFieldValues(client.stageData || {});
    setIsEditing(false);
  }, [stage.id, client.id]);

  useEffect(() => {
    if (!isEditing) {
      const generated = generateTemplateContent(stage, client, { ...client.stageData, ...fieldValues });
      setEditableBody(generated.body);
    }
  }, [fieldValues, stage, client, isEditing]);

  const handleFieldChange = (variable: string, value: string) => {
    setFieldValues(prev => ({ ...prev, [variable]: value }));
  };

  const openWhatsApp = (text: string) => {
    const cleanPhone = client.phone.replace(/\D/g, '');
    const phoneWithCountry = cleanPhone.startsWith('55') ? cleanPhone : `55${cleanPhone}`;
    const encodedText = encodeURIComponent(text);
    window.open(`https://api.whatsapp.com/send?phone=${phoneWithCountry}&text=${encodedText}`, '_blank');
  };

  const requiredFields = stage.requiredFields || [];
  const allFieldsFilled = requiredFields.every(f => (fieldValues[f] || client.stageData?.[f])?.trim());

  const handleWhatsAppClick = () => {
    if (!client.phone) {
      alert("⚠️ Erro: Cliente sem telefone cadastrado!");
      return;
    }
    if (!allFieldsFilled) {
      alert(`⚠️ Atenção: Preencha os campos obrigatórios (${requiredFields.join(', ')}) antes de enviar.`);
      return;
    }
    openWhatsApp(editableBody);
    onUpdateClientStage(client.id, client.currentStageId, fieldValues);
  };

  const handleSaveAndAdvance = () => {
    if (!allFieldsFilled) {
      alert(`⚠️ Bloqueado: Preencha os campos obrigatórios.`);
      return;
    }
    onUpdateClientStage(client.id, stage.id, fieldValues);
    if (stage.template) openWhatsApp(editableBody);
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(editableBody);
    alert("Copiado! ✅");
  };

  // Lógica Avançada de Métricas e Saúde
  const calculateMetrics = () => {
    const start = new Date(client.createdAt);
    const isCompleted = client.currentStageId === '7';
    const now = isCompleted ? new Date(client.stageHistory['7']) : new Date();

    // Total de dias do projeto
    const totalDays = Math.floor(Math.abs(now.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));

    // Dias na etapa ATUAL
    const stageEntry = new Date(client.stageHistory[client.currentStageId] || client.createdAt);
    const daysInCurrentStage = Math.floor(Math.abs(new Date().getTime() - stageEntry.getTime()) / (1000 * 60 * 60 * 24));

    // Cálculo do Score (Estrelas)
    let score = 5;
    if (totalDays > 120) score -= 2;
    else if (totalDays > 90) score -= 1;

    if (!isCompleted) {
      if (daysInCurrentStage > 30) score -= 2;
      else if (daysInCurrentStage > 15) score -= 1;
    }
    score = Math.max(1, score);

    // Cor baseada no SLA de 120 dias
    const slaPercent = Math.min(100, (totalDays / 120) * 100);
    let slaColor = 'bg-emerald-500';
    if (totalDays > 120) slaColor = 'bg-red-600';
    else if (totalDays > 90) slaColor = 'bg-amber-500';

    return { totalDays, daysInCurrentStage, score, slaPercent, slaColor, start: start.toLocaleDateString('pt-BR') };
  };

  const metrics = calculateMetrics();

  const renderHistory = () => {
    const historyEntries = Object.entries(client.stageHistory)
      .map(([id, date]) => ({
        stage: STAGES.find(s => s.id === id),
        date: new Date(date)
      }))
      .filter(e => e.stage)
      .sort((a, b) => b.date.getTime() - a.date.getTime()); // Mais recentes primeiro

    return (
      <div className="mt-8">
        <h3 className="text-[10px] font-black text-brand-900 uppercase tracking-widest flex items-center gap-2 mb-4">
          <History size={14} className="text-brand-600" /> Histórico de Movimentação
        </h3>
        <div className="space-y-3">
          {historyEntries.map((entry, idx) => (
            <div key={idx} className="flex items-center gap-4 bg-gray-50 p-3 rounded-2xl border border-gray-100 group">
              <div className="bg-white p-2 rounded-xl shadow-sm border border-gray-100 group-hover:border-brand-300 transition-all">
                <CheckCircle2 size={14} className="text-emerald-500" />
              </div>
              <div className="flex-1">
                <p className="text-[10px] font-black text-brand-900 uppercase">{entry.stage?.title}</p>
                <p className="text-[9px] text-gray-400 font-bold">{entry.date.toLocaleDateString('pt-BR')} às {entry.date.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })}</p>
              </div>
              {idx === 0 && <span className="text-[8px] font-black bg-brand-600 text-white px-2 py-0.5 rounded-full uppercase tracking-tighter">Atual</span>}
            </div>
          ))}
        </div>
      </div>
    );
  };

  if (stage.id === '7') {
    return (
      <div className="bg-white rounded-[2.5rem] shadow-xl border border-gray-100 p-12 flex flex-col items-center justify-center text-center h-full animate-in fade-in zoom-in">
          <div className="bg-green-100 p-8 rounded-full text-green-600 mb-8 shadow-inner"><Trophy size={80} /></div>
          <h2 className="text-4xl font-black text-brand-900 uppercase tracking-tighter">Projeto Entregue!</h2>
          <p className="text-gray-400 font-bold uppercase text-xs tracking-[0.3em] mt-2 mb-10">Loop Energia • Excelência</p>
          <div className="grid grid-cols-2 gap-4 w-full max-w-md mb-8">
            <div className="bg-gray-50 p-6 rounded-3xl border border-gray-100">
              <span className="text-[10px] font-black text-gray-400 uppercase block mb-1">Início</span>
              <span className="font-black text-brand-900 text-lg">{metrics.start}</span>
            </div>
            <div className="bg-gray-50 p-6 rounded-3xl border border-gray-100">
              <span className="text-[10px] font-black text-gray-400 uppercase block mb-1">Total de Dias</span>
              <span className="font-black text-brand-900 text-lg">{metrics.totalDays} d</span>
            </div>
          </div>
          <div className="w-full max-w-md bg-white border border-gray-100 rounded-3xl p-6">
            {renderHistory()}
          </div>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-[2.5rem] shadow-lg border border-gray-200 flex flex-col h-full overflow-hidden">
      <div className="bg-brand-600 p-6 flex justify-between items-center text-white shrink-0">
        <div className="flex items-center gap-4">
           <div className="bg-white/20 p-3 rounded-2xl backdrop-blur-sm">
             <Zap size={24} className="text-gold-400 fill-current" />
           </div>
           <div>
            <h2 className="text-xl font-black uppercase tracking-tight">Etapa {stage.stepNumber}: {stage.title}</h2>
            <p className="text-brand-100 text-xs font-bold uppercase tracking-wider">{stage.description}</p>
          </div>
        </div>
        <button onClick={() => setIsEditing(!isEditing)} className="p-3 bg-white/10 hover:bg-white/20 rounded-2xl transition group">
          {isEditing ? <Save size={20} /> : <Edit2 size={20} className="group-hover:rotate-12 transition-transform" />}
        </button>
      </div>

      <div className="flex flex-col lg:flex-row flex-1 min-h-0">
        <div className="lg:w-80 p-6 border-r border-gray-100 bg-gray-50/50 flex flex-col gap-6 overflow-y-auto custom-scroll">

           {/* Card de Saúde do Cliente (Estrelas) */}
           <div className="bg-white p-5 rounded-3xl border border-brand-100 shadow-sm">
             <div className="flex justify-between items-center mb-4">
               <h3 className="text-[10px] font-black text-brand-600 uppercase tracking-widest">Saúde do Projeto</h3>
               <div className="flex gap-0.5">
                  {[1,2,3,4,5].map(s => (
                    <Star key={s} size={12} fill={s <= metrics.score ? "#dbb832" : "transparent"} className={s <= metrics.score ? "text-gold-500" : "text-gray-200"} />
                  ))}
               </div>
             </div>

             <div className="space-y-4">
               <div>
                 <div className="flex justify-between text-[9px] font-black uppercase text-gray-400 mb-1">
                    <span>Prazo Total (SLA 120d)</span>
                    <span className={metrics.totalDays > 120 ? 'text-red-600' : 'text-brand-900'}>{metrics.totalDays} dias</span>
                 </div>
                 <div className="h-1.5 w-full bg-gray-100 rounded-full overflow-hidden">
                   <div className={`h-full transition-all duration-1000 ${metrics.slaColor}`} style={{ width: `${metrics.slaPercent}%` }}></div>
                 </div>
               </div>

               <div className="flex items-center gap-3 bg-brand-50/50 p-3 rounded-2xl border border-brand-100">
                 <Clock size={16} className="text-brand-600" />
                 <div>
                   <p className="text-[8px] font-black text-gray-400 uppercase leading-none">Dias nesta etapa</p>
                   <p className="text-sm font-black text-brand-900 mt-1">{metrics.daysInCurrentStage} dias</p>
                 </div>
               </div>
             </div>
           </div>

           {requiredFields.length > 0 && (
             <div className="space-y-4">
               <h3 className="text-[10px] font-black text-amber-600 uppercase tracking-widest flex items-center gap-2">
                 <AlertCircle size={14} /> Dados Necessários
               </h3>
               {requiredFields.map(field => (
                 <div key={field}>
                   <label className="text-[9px] font-black uppercase text-gray-500 mb-1.5 block tracking-widest ml-1">{field}</label>
                   <input 
                     className={`w-full p-4 bg-white border rounded-2xl text-sm font-bold focus:ring-4 outline-none transition-all ${!fieldValues[field] && !client.stageData?.[field] ? 'border-amber-200 focus:ring-amber-100' : 'border-gray-200 focus:ring-brand-100'}`}
                     value={fieldValues[field] || client.stageData?.[field] || ''}
                     onChange={e => handleFieldChange(field, e.target.value)}
                     placeholder={`Ex: ${field === 'data prevista' ? '15/10/2024' : '...'}`}
                   />
                 </div>
               ))}
             </div>
           )}

           {/* Histórico na Sidebar */}
           {renderHistory()}
        </div>

        <div className="flex-1 p-6 flex flex-col gap-4 bg-white overflow-hidden">
          <div className="flex-1 bg-gray-50 rounded-[2rem] border border-gray-100 overflow-hidden flex flex-col shadow-inner">
            <div className="px-6 py-3 border-b border-gray-100 bg-white/50 flex justify-between items-center">
              <span className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em]">Visualização da Mensagem</span>
              <button onClick={copyToClipboard} className="text-[10px] font-black text-brand-600 uppercase hover:underline flex items-center gap-1">
                <Copy size={12} /> Copiar Texto
              </button>
            </div>

            {isEditing ? (
              <textarea 
                className="flex-1 p-8 text-sm font-sans font-medium leading-relaxed bg-transparent outline-none resize-none text-slate-700"
                value={editableBody}
                onChange={e => setEditableBody(e.target.value)}
              />
            ) : (
              <div className="flex-1 p-8 text-sm font-sans font-medium leading-relaxed whitespace-pre-wrap text-slate-700 overflow-y-auto custom-scroll">
                {editableBody}
              </div>
            )}
          </div>

          <div className="space-y-3">
            <button 
              onClick={handleWhatsAppClick}
              disabled={!allFieldsFilled}
              className={`w-full py-5 rounded-2xl font-black uppercase tracking-[0.2em] flex items-center justify-center gap-3 transition-all shadow-xl
                ${allFieldsFilled 
                  ? 'bg-[#25D366] text-white hover:bg-[#1fb355] hover:scale-[1.01]' 
                  : 'bg-gray-200 text-gray-400 cursor-not-allowed opacity-60'}`}
            >
              <Phone size={22} fill="currentColor" /> Enviar para WhatsApp
            </button>

            {allFieldsFilled && stage.id !== client.currentStageId && (
              <button 
                onClick={handleSaveAndAdvance}
                className="w-full py-4 bg-brand-900 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest border border-brand-800 hover:bg-black transition-all flex items-center justify-center gap-2 group"
              >
                Confirmar Dados e Avançar para {stage.title} <ArrowRight size={14} className="group-hover:translate-x-1 transition-transform" />
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Client, Stage } from '../types.ts';
import { Plus, Search, User, Zap, List, Kanban, X, ChevronRight, Clock, Trash2, Edit3, CalendarDays, ArrowRightLeft, GripVertical, CheckCircle2, Star } from 'lucide-react';
import { STAGES, STEP_ICONS } from '../constants.ts';
import { generateTemplateContent } from '../services/templateService.ts';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onEditClient: (client: Client) => void;
  onDeleteClient: (clientId: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

type ViewMode = 'list' | 'pipeline';
type FilterStatus = 'ativos' | 'entregues' | 'noprazo' | 'atencao' | 'urgente' | null;

interface PendingTransition {
  client: Client;
  targetStage: Stage;
  fieldValues: Record<string, string>;
}

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onEditClient, onDeleteClient, onUpdateClientStage }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<ViewMode>('pipeline');
  const [statusFilter, setStatusFilter] = useState<FilterStatus>(null);
  const [draggedClientId, setDraggedClientId] = useState<string | null>(null);
  const [pendingTransition, setPendingTransition] = useState<PendingTransition | null>(null);

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '', clientNumber: '', prgd: '', phone: '',
  });

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    if (!startStr) return 0;
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const getStatusInfo = (days: number, isDelivered: boolean) => {
    if (isDelivered) return { label: '🟢 ENTREGUE', color: 'text-green-600', bg: 'bg-green-50', key: 'entregues', btn: 'bg-green-100 text-green-700' };
    if (days > 120) return { label: '🔴 URGENTE', color: 'text-red-600', bg: 'bg-red-50', key: 'urgente', btn: 'bg-red-100 text-red-700' };
    if (days > 90) return { label: '🟡 ATENÇÃO', color: 'text-amber-500', bg: 'bg-amber-50', key: 'atencao', btn: 'bg-amber-100 text-amber-700' };
    return { label: '🟢 NO PRAZO', color: 'text-emerald-600', bg: 'bg-emerald-50', key: 'noprazo', btn: 'bg-emerald-100 text-emerald-700' };
  };

  const filteredClients = clients.filter(c => {
    const matchesSearch = c.name.toLowerCase().includes(searchTerm.toLowerCase()) || c.prgd.toLowerCase().includes(searchTerm.toLowerCase());
    if (!matchesSearch) return false;
    if (!statusFilter) return true;
    const isDelivered = c.currentStageId === '7';
    const days = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);
    const info = getStatusInfo(days, isDelivered);
    if (statusFilter === 'ativos') return !isDelivered;
    return info.key === statusFilter;
  });

  const triggerWhatsApp = (client: Client, stage: Stage, additionalData: Record<string, string> = {}) => {
    if (!client.phone) return;
    const combinedData = { ...(client.stageData || {}), ...additionalData };
    const generated = generateTemplateContent(stage, client, combinedData);
    if (!generated.body) return;

    const cleanPhone = client.phone.replace(/\D/g, '');
    const phoneWithCountry = cleanPhone.startsWith('55') ? cleanPhone : `55${cleanPhone}`;
    const encodedText = encodeURIComponent(generated.body);
    window.open(`https://api.whatsapp.com/send?phone=${phoneWithCountry}&text=${encodedText}`, '_blank');
  };

  const onDragStart = (id: string) => setDraggedClientId(id);
  const onDragOver = (e: React.DragEvent) => e.preventDefault();

  const onDrop = (stageId: string) => {
    if (draggedClientId) {
      const client = clients.find(c => c.id === draggedClientId);
      const targetStage = STAGES.find(s => s.id === stageId);

      if (client && targetStage) {
        const requiredFields = targetStage.requiredFields || [];
        const missingFields = requiredFields.filter(field => !((client.stageData?.[field] as string | undefined)?.trim()));

        if (missingFields.length > 0) {
          setPendingTransition({
            client,
            targetStage,
            fieldValues: missingFields.reduce((acc, field) => ({ ...acc, [field]: '' }), {})
          });
        } else {
          onUpdateClientStage(draggedClientId, stageId);
          if (targetStage.template) triggerWhatsApp(client, targetStage);
        }
      }
      setDraggedClientId(null);
    }
  };

  const handleConfirmPendingTransition = () => {
    if (!pendingTransition) return;
    const { client, targetStage, fieldValues } = pendingTransition;
    if (Object.values(fieldValues).some(v => !v.trim())) {
      alert("Por favor, preencha todos os campos.");
      return;
    }
    onUpdateClientStage(client.id, targetStage.id, fieldValues);
    if (targetStage.template) triggerWhatsApp(client, targetStage, fieldValues);
    setPendingTransition(null);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingClient) {
      onEditClient({ ...editingClient, name: formData.name || '', clientNumber: formData.clientNumber || '', prgd: formData.prgd || '', phone: formData.phone || '' });
    } else {
      const now = new Date().toISOString();
      onCreateClient({
        id: Date.now().toString(),
        name: formData.name || '',
        clientNumber: formData.clientNumber || '',
        prgd: formData.prgd || '',
        phone: formData.phone || '',
        projectName: `Projeto ${formData.name}`,
        additionalNotes: '',
        currentStageId: STAGES[0].id,
        createdAt: now,
        stageHistory: { [STAGES[0].id]: now },
        stageData: {}
      });
    }
    closeModal();
  };

  const closeModal = () => {
    setIsCreating(false);
    setEditingClient(null);
    setFormData({ name: '', clientNumber: '', prgd: '', phone: '' });
  };

  return (
    <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-200 h-full flex flex-col relative overflow-hidden">

      {pendingTransition && (
        <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-md z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-md animate-scale-up border border-white/20 overflow-hidden">
            <div className="p-8 pb-4 flex justify-between items-center border-b border-gray-50 bg-amber-50/50">
              <div className="flex items-center gap-3">
                <div className="bg-amber-100 text-amber-600 p-2 rounded-xl"><CalendarDays size={20} /></div>
                <h2 className="text-xl font-black text-brand-900 uppercase tracking-tighter">Informação Necessária</h2>
              </div>
              <button onClick={() => setPendingTransition(null)} className="p-2 hover:bg-white rounded-full transition text-gray-400"><X size={20} /></button>
            </div>
            <div className="p-8 space-y-6">
              <p className="text-xs font-bold text-gray-400 uppercase tracking-widest leading-relaxed">
                Para mover <span className="text-brand-600 font-black">{pendingTransition.client.name}</span> para a etapa de <span className="text-brand-600 font-black">{pendingTransition.targetStage.title}</span>, informe:
              </p>
              <div className="space-y-4">
                {Object.keys(pendingTransition.fieldValues).map(field => (
                  <div key={field} className="group">
                    <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1.5 block ml-1">{field}</label>
                    <input autoFocus required placeholder={field === 'data prevista' ? 'Ex: 15/10/2024' : 'Preencha aqui...'}
                      className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white focus:border-brand-300 transition-all text-sm font-bold"
                      value={pendingTransition.fieldValues[field]}
                      onChange={e => setPendingTransition({...pendingTransition, fieldValues: { ...pendingTransition.fieldValues, [field]: e.target.value }})}
                    />
                  </div>
                ))}
              </div>
              <button onClick={handleConfirmPendingTransition} className="w-full bg-brand-600 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-brand-700 shadow-xl transition-all flex items-center justify-center gap-2">
                Confirmar e Abrir WhatsApp <ArrowRightLeft size={16} />
              </button>
            </div>
          </div>
        </div>
      )}

      {isCreating && (
          <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-4">
              <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-xl animate-scale-up border border-white/20 overflow-hidden">
                  <div className="p-8 pb-4 flex justify-between items-center border-b border-gray-50 bg-gray-50/50">
                      <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">{editingClient ? 'Editar Cadastro' : 'Novo Cliente'}</h2>
                      <button onClick={closeModal} className="p-2 hover:bg-white rounded-full transition text-gray-400"><X size={24} /></button>
                  </div>
                  <form onSubmit={handleSubmit} className="p-8 space-y-6">
                      <div className="space-y-4">
                        <div className="group">
                          <label className="text-[10px] font-black uppercase text-brand-900 tracking-widest mb-2 block">Titular do Projeto</label>
