                <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter leading-tight">Gestão de Carteira</h2>
                <div className="flex flex-wrap items-center gap-2 mt-2">
                    <button onClick={() => setStatusFilter(statusFilter === 'ativos' ? null : 'ativos')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'ativos' ? 'bg-brand-600 text-white shadow-sm' : 'bg-white text-brand-600 hover:border-brand-300'}`}>Ativos</button>
                    <button onClick={() => setStatusFilter(statusFilter === 'entregues' ? null : 'entregues')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'entregues' ? 'bg-green-600 text-white shadow-sm' : 'bg-white text-green-600 hover:border-green-300'}`}>Entregues</button>
                    <div className="h-4 w-px bg-gray-300 mx-2"></div>
                    <button onClick={() => setStatusFilter(statusFilter === 'noprazo' ? null : 'noprazo')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'noprazo' ? 'bg-emerald-600 text-white shadow-sm' : 'bg-emerald-50 text-emerald-700'}`}>No Prazo</button>
                    <button onClick={() => setStatusFilter(statusFilter === 'atencao' ? null : 'atencao')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'atencao' ? 'bg-amber-500 text-white shadow-sm' : 'bg-amber-50 text-amber-700'}`}>Atenção</button>
                    <button onClick={() => setStatusFilter(statusFilter === 'urgente' ? null : 'urgente')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'urgente' ? 'bg-red-600 text-white shadow-sm' : 'bg-red-50 text-red-700'}`}>Urgente</button>
                </div>
            </div>

            <div className="flex bg-gray-100 p-1 rounded-2xl border border-gray-200">
                <button onClick={() => setViewMode('list')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'list' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-400'}`}>
                    <List size={14} /> Lista
                </button>
                <button onClick={() => setViewMode('pipeline')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'pipeline' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-400'}`}>
                    <Kanban size={14} /> Pipeline
                </button>
            </div>
        </div>

        <div className="flex flex-col md:flex-row gap-4">
            <div className="relative flex-1">
                <Search className="absolute left-4 top-3.5 text-gray-300" size={18} />
                <input placeholder="Filtrar por nome ou PRGD..." className="w-full pl-12 p-3.5 rounded-2xl border bg-white outline-none focus:border-brand-300 font-medium text-sm" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
            </div>
            <button onClick={() => setIsCreating(true)} className="bg-brand-600 text-white px-8 py-3.5 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-brand-700 transition-all flex items-center justify-center gap-2">
                <Plus size={18} /> Novo Cliente
            </button>
        </div>
      </div>

      <div className="flex-1 overflow-hidden bg-gray-100/30">
        {viewMode === 'list' ? (
          <div className="p-6 overflow-auto h-full scrollbar-hide">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-8">
                {filteredClients.map(client => (
                    <div key={client.id} onClick={() => onSelectClient(client)}>
                       <ClientCardItem 
                          client={client} 
                          onEdit={(e: React.MouseEvent) => { e.stopPropagation(); setEditingClient(client); setFormData({name: client.name, prgd: client.prgd, phone: client.phone}); setIsCreating(true); }}
                          onDelete={(e: React.MouseEvent) => { e.stopPropagation(); if(confirm("Excluir?")) onDeleteClient(client.id); }}
                          calculateDays={calculateDaysElapsed}
                          getStatus={getStatusInfo}
                       />
                    </div>
                ))}
            </div>
          </div>
        ) : (
          <div className="flex overflow-x-auto h-full p-6 gap-6 snap-x custom-scroll">
            {STAGES.map(stage => {
              const stageClients = filteredClients.filter(c => c.currentStageId === stage.id);
              const Icon = STEP_ICONS[stage.stepNumber] || Zap;
              return (
                <div 
                  key={stage.id} 
                  className="min-w-[320px] flex flex-col h-full snap-start"
                  onDragOver={onDragOver}
                  onDrop={() => onDrop(stage.id)}
                >
                  <div className="flex items-center justify-between mb-4 px-2">
                    <div className="flex items-center gap-3">
                        <div className="bg-brand-900 text-gold-400 p-2.5 rounded-xl shadow-lg border border-brand-800"><Icon size={16} /></div>
                        <h3 className="text-[11px] font-black uppercase text-brand-900 tracking-tight">{stage.title}</h3>
                    </div>
                    <span className="text-[10px] font-black text-brand-600 bg-brand-50 px-2.5 py-1 rounded-full">{stageClients.length}</span>
                  </div>

                  <div className={`flex-1 overflow-y-auto space-y-4 p-3 rounded-3xl bg-gray-100/60 border-2 border-transparent transition-all ${draggedClientId ? 'border-dashed border-brand-300' : ''} custom-scroll`}>
                    {stageClients.map(client => {
                        const totalDays = calculateDaysElapsed(client.createdAt);
                        const status = getStatusInfo(totalDays, client.currentStageId === '7');

                        const stageEntryStr = (client.stageHistory[client.currentStageId] as any) || client.createdAt;
                        const stageEntry = new Date(stageEntryStr);
                        const daysInStage = Math.floor(Math.abs(new Date().getTime() - stageEntry.getTime()) / (1000 * 60 * 60 * 24));

                        let score = 5;
                        if (totalDays > 120) score -= 2; else if (totalDays > 90) score -= 1;
                        if (daysInStage > 30) score -= 2; else if (daysInStage > 15) score -= 1;
                        score = Math.max(1, score);

                        const startD = new Date(client.createdAt);
                        const deadlineD = new Date(startD);
                        deadlineD.setDate(deadlineD.getDate() + 120);

                        return (
                            <div 
                                key={client.id} 
                                draggable 
                                onDragStart={() => onDragStart(client.id)}
                                onClick={() => onSelectClient(client)} 
                                className="bg-white p-5 rounded-[2rem] border border-gray-100 shadow-sm hover:shadow-xl hover:border-brand-400 transition-all cursor-grab active:cursor-grabbing group"
                            >
                                <div className="flex justify-between items-start mb-3">
                                    <div className="flex items-center gap-2">
                                        <GripVertical size={14} className="text-gray-200 group-hover:text-gray-400" />
                                        <div>
                                            <h4 className="font-black text-brand-900 uppercase text-[11px] group-hover:text-brand-600">{client.name}</h4>
                                            <div className="flex gap-0.5 mt-0.5">
                                              {[1,2,3,4,5].map(s => <Star key={s} size={8} fill={s <= score ? "#dbb832" : "transparent"} className={s <= score ? "text-gold-500" : "text-gray-100"} />)}
                                            </div>
                                        </div>
                                    </div>
                                    <button onClick={(e) => { e.stopPropagation(); if(confirm("Excluir?")) onDeleteClient(client.id); }} className="text-gray-200 hover:text-red-500 transition"><Trash2 size={12} /></button>
                                </div>

                                <div className="mt-3 flex items-center justify-between border-t border-gray-50 pt-3">
                                  <div className="flex flex-col">
                                    <span className="text-[7px] font-black text-gray-400 uppercase">Prazo Final</span>
                                    <span className="text-[9px] font-black text-brand-900">{deadlineD.toLocaleDateString('pt-BR', {day: '2-digit', month: '2-digit'})}</span>
                                  </div>
                                  <div className={`text-[9px] font-black px-3 py-1 rounded-lg ${totalDays > 120 ? 'bg-red-50 text-red-600' : 'bg-gray-50 text-brand-900'}`}>
                                    {totalDays}d
                                  </div>
                                </div>
                            </div>
                        );
                    })}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

const ClientCardItem = ({ client, onEdit, onDelete, calculateDays, getStatus }: any) => {
    const isDelivered = client.currentStageId === '7';
    const totalDays = calculateDays(client.createdAt, isDelivered ? client.stageHistory['7'] : undefined);
    const status = getStatus(totalDays, isDelivered);
    const currentStage = STAGES.find(s => s.id === client.currentStageId);
    const Icon = STEP_ICONS[currentStage?.stepNumber || '1'];

    const stageEntryStr = (client.stageHistory[client.currentStageId] as any) || client.createdAt;
    const stageEntry = new Date(stageEntryStr);
    const daysInStage = Math.floor(Math.abs(new Date().getTime() - stageEntry.getTime()) / (1000 * 60 * 60 * 24));
    let score = 5;
    if (totalDays > 120) score -= 2; else if (totalDays > 90) score -= 1;
    if (daysInStage > 30) score -= 2; else if (daysInStage > 15) score -= 1;
    score = Math.max(1, score);

    const startD = new Date(client.createdAt);
    const deadlineD = new Date(startD);
    deadlineD.setDate(deadlineD.getDate() + 120);

    return (
        <div className="bg-white border border-gray-100 rounded-[2.5rem] p-6 hover:border-brand-400 cursor-pointer transition-all shadow-sm hover:shadow-2xl group relative overflow-hidden flex flex-col gap-5">
            <div className="flex justify-between items-start">
                <div className="flex gap-4 items-center">
                    <div className="bg-brand-50 p-4 rounded-3xl group-hover:bg-brand-600 group-hover:text-white transition-all"><User size={24} /></div>
                    <div>
                        <h3 className="font-black text-brand-900 uppercase text-lg truncate max-w-[160px]">{client.name}</h3>
                        <div className="flex gap-0.5 mt-1">
                          {[1,2,3,4,5].map(s => <Star key={s} size={10} fill={s <= score ? "#dbb832" : "transparent"} className={s <= score ? "text-gold-500" : "text-gray-100"} />)}
                        </div>
                    </div>
                </div>
                <div className="flex gap-1.5">
                  <button onClick={onEdit} className="p-2.5 bg-gray-50 hover:bg-brand-600 text-gray-400 hover:text-white rounded-2xl transition-all"><Edit3 size={16}/></button>
                  <button onClick={onDelete} className="p-2.5 bg-gray-50 hover:bg-red-600 text-gray-400 hover:text-white rounded-2xl transition-all"><Trash2 size={16}/></button>
                </div>
            </div>

            <div className={`p-5 rounded-[2rem] border border-gray-100 flex flex-col gap-3 ${status.bg}`}>
                <div className="grid grid-cols-2 gap-2 mb-1">
                  <div className="flex flex-col">
                    <span className="text-[7px] font-black text-gray-400 uppercase">Iniciado</span>
                    <span className="text-[10px] font-black text-brand-900">{startD.toLocaleDateString('pt-BR')}</span>
                  </div>
                  <div className="flex flex-col text-right">
                    <span className="text-[7px] font-black text-gray-400 uppercase">Entrega Loop</span>
                    <span className="text-[10px] font-black text-brand-900">{deadlineD.toLocaleDateString('pt-BR')}</span>
                  </div>
                </div>
                <div className={`py-2 rounded-2xl text-center text-[9px] font-black tracking-widest bg-white shadow-sm ${status.color}`}>
                    {status.label} • {totalDays} DIAS
                </div>
            </div>

            <div className="flex items-center justify-between pt-4 border-t border-gray-50">
                <div className="flex items-center gap-3">
                    <div className="bg-brand-900 text-gold-400 p-2.5 rounded-xl"><Icon size={16} /></div>
                    <div className="flex flex-col">
                        <span className="text-[8px] font-black text-gray-400 uppercase tracking-widest">Etapa Atual ({daysInStage}d)</span>
                        <span className="text-xs font-black text-brand-900 uppercase">{currentStage?.title}</span>
                    </div>
                </div>
                <ChevronRight className="text-gray-200 group-hover:translate-x-1 group-hover:text-brand-400 transition-all" size={20} />
            </div>
        </div>
    );
};

import React, { useState, useRef } from 'react';
import { Client } from '../types.ts';
import { STAGES } from '../constants.ts';
import { 
  Trophy, 
  Clock, 
  TrendingUp, 
  Users, 
  Star, 
  Download, 
  Calendar, 
  CheckCircle, 
  AlertTriangle, 
  XCircle,
  BarChart3,
  Info,
  Loader2,
  FileText,
  Flag
} from 'lucide-react';

interface DashboardProps {
  clients: Client[];
}

declare var html2pdf: any;

export const Dashboard: React.FC<DashboardProps> = ({ clients }) => {
  const [isGenerating, setIsGenerating] = useState(false);
  const dashboardRef = useRef<HTMLDivElement>(null);

  const total = clients.length;
  const delivered = clients.filter(c => c.currentStageId === '7').length;
  const active = total - delivered;

  const calculateDays = (start: string, end?: string) => {
    const s = new Date(start);
    const e = end ? new Date(end) : new Date();
    return Math.floor(Math.abs(e.getTime() - s.getTime()) / (1000 * 60 * 60 * 24));
  };

  const deliveredClients = clients.filter(c => c.currentStageId === '7');
  const avgDeliveryTime = deliveredClients.length > 0 
    ? Math.round(deliveredClients.reduce((acc, c) => acc + calculateDays(c.createdAt, c.stageHistory['7']), 0) / deliveredClients.length)
    : 0;

  const onTimeDeliveries = deliveredClients.filter(c => calculateDays(c.createdAt, c.stageHistory['7']) <= 120).length;
  const slaPercentage = deliveredClients.length > 0 ? Math.round((onTimeDeliveries / deliveredClients.length) * 100) : 100;

  const activeStatus = clients.filter(c => c.currentStageId !== '7').reduce((acc, c) => {
    const days = calculateDays(c.createdAt);
    if (days > 120) acc.urgente++;
    else if (days > 90) acc.atencao++;
    else acc.noprazo++;
    return acc;
  }, { noprazo: 0, atencao: 0, urgente: 0 });

  const calculateInternalScore = (client: Client) => {
    let score = 5;
    const isCompleted = client.currentStageId === '7';
    const elapsed = calculateDays(client.createdAt, isCompleted ? client.stageHistory['7'] : undefined);
    const stageEntry = new Date((client.stageHistory[client.currentStageId] as any) || client.createdAt);
    const daysInStage = Math.floor(Math.abs(new Date().getTime() - stageEntry.getTime()) / (1000 * 60 * 60 * 24));

    if (elapsed > 120) score -= 2;
    else if (elapsed > 90) score -= 1;
    if (!isCompleted) {
      if (daysInStage > 30) score -= 2;
      else if (daysInStage > 15) score -= 1;
    }
    return Math.max(1, score);
  };

  const avgScore = total > 0 
    ? (clients.reduce((acc, c) => acc + calculateInternalScore(c), 0) / total).toFixed(1)
    : "5.0";

  const stageDistribution = STAGES.map(s => ({
    title: s.title,
    count: clients.filter(c => c.currentStageId === s.id).length
  }));

  const maxStageCount = Math.max(...stageDistribution.map(s => s.count), 1);

  const handleDownloadPDF = async () => {
    if (!dashboardRef.current) return;
    setIsGenerating(true);
    const element = dashboardRef.current;
    const dateStr = new Date().toLocaleDateString('pt-BR').replace(/\//g, '-');
    const filename = `Relatorio_Loop_Energia_${dateStr}.pdf`;

    const opt = {
      margin: [10, 10, 10, 10],
      filename: filename,
      image: { type: 'jpeg', quality: 0.98 },
      html2canvas: { scale: 2, useCORS: true, letterRendering: true, backgroundColor: '#f9fafb' },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
      pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
    };

    try {
      await html2pdf().set(opt).from(element).save();
    } catch (error) {
      console.error(error);
      alert("Erro ao gerar PDF.");
    } finally {
      setIsGenerating(false);
    }
  };

  return (
    <div className="space-y-8 pb-12 animate-in fade-in duration-500">
      <div className="bg-emerald-50 border border-emerald-100 p-4 rounded-2xl flex items-center gap-3 shadow-sm">
        <div className="bg-emerald-600 p-2 rounded-xl text-white"><CheckCircle size={18} /></div>
        <p className="text-xs font-bold text-emerald-900 leading-relaxed">
          EXPORTAÇÃO ATIVA: <span className="font-normal">Relatório pronto para download.</span>
        </p>
      </div>

      <div ref={dashboardRef} className="space-y-8 bg-gray-50/50 p-2 rounded-[2.5rem]">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white p-6 rounded-3xl border border-gray-100 shadow-sm">
          <div>
            <h2 className="text-3xl font-black text-brand-600 uppercase tracking-tighter flex items-center gap-3">
              <BarChart3 className="text-gold-500" size={32} /> Central Loop Energia
            </h2>
            <p className="text-xs text-gray-400 font-bold uppercase tracking-[0.2em] mt-1">Status de Gestão GEV</p>
          </div>

          <button onClick={handleDownloadPDF} disabled={isGenerating} data-html2canvas-ignore="true" 
            className={`px-6 py-3 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl transition-all flex items-center gap-2
              ${isGenerating ? 'bg-gray-400' : 'bg-brand-600 hover:bg-brand-700 text-white'}`}
          >
            {isGenerating ? <Loader2 size={18} className="animate-spin" /> : <FileText size={18} />}
            Baixar PDF
          </button>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
          <KPICard title="Projetos" value={total} subtitle="Base Total" icon={<Users className="text-brand-500" />} />
          <KPICard title="Meta SLA" value={`${slaPercentage}%`} subtitle="Dentro de 120 dias" icon={<CheckCircle className="text-emerald-500" />} color="text-emerald-600" />
          <KPICard title="Prazo Médio" value={`${avgDeliveryTime} d`} subtitle="Média Entrega" icon={<Clock className="text-amber-500" />} />
          <KPICard title="Score Loop" value={avgScore} subtitle="Média Estrelas" icon={<Star className="text-gold-500" />} isScore />
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
          <div className="bg-white p-8 rounded-[2rem] border border-gray-100 shadow-sm flex flex-col h-full">
            <h3 className="text-sm font-black text-brand-900 uppercase tracking-widest mb-8 border-b border-gray-50 pb-4">Status da Carteira Ativa</h3>
            <div className="flex flex-1 items-center justify-around gap-8 flex-col sm:flex-row">
              <div className="relative w-40 h-40">
                <svg viewBox="0 0 36 36" className="w-full h-full transform -rotate-90">
                  <path d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" fill="none" stroke="#f3f4f6" strokeWidth="4" />
                  {active > 0 && (
                    <>
                      <path d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" fill="none" stroke="#10b981" strokeWidth="4" strokeDasharray={`${(activeStatus.noprazo/active)*100}, 100`} />
                      <path d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" fill="none" stroke="#f59e0b" strokeWidth="4" strokeDasharray={`${(activeStatus.atencao/active)*100}, 100`} strokeDashoffset={`-${(activeStatus.noprazo/active)*100}`} />
                      <path d="M18 2.0845 a 15.9155 15.9155 0 0 1 0 31.831 a 15.9155 15.9155 0 0 1 0 -31.831" fill="none" stroke="#ef4444" strokeWidth="4" strokeDasharray={`${(activeStatus.urgente/active)*100}, 100`} strokeDashoffset={`-${((activeStatus.noprazo+activeStatus.atencao)/active)*100}`} />
                    </>
                  )}
                </svg>
                <div className="absolute inset-0 flex flex-col items-center justify-center">
                  <span className="text-2xl font-black text-brand-900">{active}</span>
                  <span className="text-[8px] font-bold text-gray-400 uppercase">Ativos</span>
                </div>
              </div>
              <div className="space-y-3 flex-1">
                <StatusLegend color="bg-emerald-500" label="No Prazo" count={activeStatus.noprazo} total={active} />
                <StatusLegend color="bg-amber-500" label="Atenção" count={activeStatus.atencao} total={active} />
                <StatusLegend color="bg-red-500" label="Urgente" count={activeStatus.urgente} total={active} />
              </div>
            </div>
          </div>

          <div className="bg-white p-8 rounded-[2rem] border border-gray-100 shadow-sm">
            <h3 className="text-sm font-black text-brand-900 uppercase tracking-widest mb-8 border-b border-gray-50 pb-4">Volume por Etapa</h3>
            <div className="space-y-3">
              {stageDistribution.map((s, i) => (
                <div key={i} className="space-y-1">
                  <div className="flex justify-between text-[9px] font-black uppercase text-gray-500">
                    <span>{s.title}</span>
                    <span>{s.count}</span>
                  </div>
                  <div className="h-2.5 bg-gray-50 rounded-full overflow-hidden border border-gray-100">
                    <div className="h-full bg-brand-500 rounded-full transition-all duration-1000" style={{ width: `${(s.count / maxStageCount) * 100}%` }} />
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="bg-white p-8 rounded-[2rem] border border-gray-100 shadow-sm col-span-full">
