import React, { useState } from 'react';
import { Client, Stage } from '../types.ts';
import { Plus, Search, User, Zap, List, Kanban, X, ChevronRight, Clock, Trash2, Edit3, CalendarDays, ArrowRightLeft, GripVertical, CheckCircle2, Star, Calendar, Flag, Phone, Timer, AlertCircle } from 'lucide-react';
import { STAGES, STEP_ICONS } from '../constants.ts';
import { generateTemplateContent } from '../services/templateService.ts';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onEditClient: (client: Client) => void;
  onDeleteClient: (clientId: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

type ViewMode = 'list' | 'pipeline';
type FilterStatus = 'ativos' | 'entregues' | 'noprazo' | 'atencao' | 'urgente' | null;

interface PendingTransition {
  client: Client;
  targetStage: Stage;
  fieldValues: Record<string, string>;
}

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onEditClient, onDeleteClient, onUpdateClientStage }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'list' | 'pipeline'>('list'); // DEFINIDO COMO LISTA POR PADRÃO
  const [statusFilter, setStatusFilter] = useState<FilterStatus>(null);
  const [draggedClientId, setDraggedClientId] = useState<string | null>(null);
  const [pendingTransition, setPendingTransition] = useState<PendingTransition | null>(null);

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '', clientNumber: '', prgd: '', phone: '',
  });

  const formatPhone = (value: string) => {
    if (!value) return "";
    value = value.replace(/\D/g, "");
    value = value.substring(0, 11);
    if (value.length > 10) {
      return value.replace(/^(\d{2})(\d{5})(\d{4}).*/, "($1) $2-$3");
    } else if (value.length > 5) {
      return value.replace(/^(\d{2})(\d{4})(\d{0,4}).*/, "($1) $2-$3");
    } else if (value.length > 2) {
      return value.replace(/^(\d{2})(\d{0,5})/, "($1) $2");
    } else {
      return value.replace(/^(\d*)/, "($1");
    }
  };

  const formatPRGD = (value: string) => {
    if (!value) return "";
    value = value.replace(/\D/g, "");
    value = value.substring(0, 5);
    if (value.length > 3) {
      return value.replace(/^(\d{3})(\d{0,2})/, "$1-$2");
    }
    return value;
  };

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    if (!startStr) return 0;
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const getStatusInfo = (days: number, isDelivered: boolean) => {
    if (isDelivered) return { label: '🟢 ENTREGUE', color: 'text-green-600', bg: 'bg-green-50', dot: 'bg-green-500', key: 'entregues', btn: 'bg-green-100 text-green-700' };
    if (days > 120) return { label: '🔴 URGENTE', color: 'text-red-600', bg: 'bg-red-50', dot: 'bg-red-500', key: 'urgente', btn: 'bg-red-100 text-red-700' };
    if (days > 90) return { label: '🟡 ATENÇÃO', color: 'text-amber-500', bg: 'bg-amber-50', dot: 'bg-amber-500', key: 'atencao', btn: 'bg-amber-100 text-amber-700' };
    return { label: '🟢 NO PRAZO', color: 'text-emerald-600', bg: 'bg-emerald-50', dot: 'bg-emerald-500', key: 'noprazo', btn: 'bg-emerald-100 text-emerald-700' };
  };

  const filteredClients = clients.filter(c => {
    const matchesSearch = c.name.toLowerCase().includes(searchTerm.toLowerCase()) || c.prgd.toLowerCase().includes(searchTerm.toLowerCase());
    if (!matchesSearch) return false;
    if (!statusFilter) return true;
    const isDelivered = c.currentStageId === '7';
    const days = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);
    const info = getStatusInfo(days, isDelivered);
    if (statusFilter === 'ativos') return !isDelivered;
    return info.key === statusFilter;
  });

  const triggerWhatsApp = (client: Client, stage: Stage, additionalData: Record<string, string> = {}) => {
    if (!client.phone) return;
    const combinedData = { ...(client.stageData || {}), ...additionalData };
    const generated = generateTemplateContent(stage, client, combinedData);
    if (!generated.body) return;

    const cleanPhone = client.phone.replace(/\D/g, '');
    const phoneWithCountry = cleanPhone.startsWith('55') ? cleanPhone : `55${cleanPhone}`;
    const encodedText = encodeURIComponent(generated.body);
    window.open(`https://api.whatsapp.com/send?phone=${phoneWithCountry}&text=${encodedText}`, '_blank');
  };

  const onDragStart = (id: string) => setDraggedClientId(id);
  const onDragOver = (e: React.DragEvent) => e.preventDefault();

  const onDrop = (stageId: string) => {
    if (draggedClientId) {
      const client = clients.find(c => c.id === draggedClientId);
      const targetStage = STAGES.find(s => s.id === stageId);

      if (client && targetStage) {
        const requiredFields = targetStage.requiredFields || [];
        const missingFields = requiredFields.filter(field => {
          const value = client.stageData ? (client.stageData[field] as any) : undefined;
          return !value || typeof value !== 'string' || value.trim() === '';
        });

        if (missingFields.length > 0) {
          setPendingTransition({
            client,
            targetStage,
            fieldValues: missingFields.reduce((acc, field) => ({ ...acc, [field]: '' }), {})
          });
        } else {
          onUpdateClientStage(draggedClientId, stageId);
          if (targetStage.template) triggerWhatsApp(client, targetStage);
        }
      }
      setDraggedClientId(null);
    }
  };

  const handleConfirmPendingTransition = () => {
    if (!pendingTransition) return;
    const { client, targetStage, fieldValues } = pendingTransition;
    if (Object.values(fieldValues).some((v: unknown) => !(v as string).trim())) {
      alert("Por favor, preencha todos os campos.");
      return;
    }
    onUpdateClientStage(client.id, targetStage.id, fieldValues);
    if (targetStage.template) triggerWhatsApp(client, targetStage, fieldValues);
    setPendingTransition(null);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingClient) {
      onEditClient({ ...editingClient, name: formData.name || '', clientNumber: formData.clientNumber || '', prgd: formData.prgd || '', phone: formData.phone || '' });
    } else {
      const now = new Date().toISOString();
      onCreateClient({
        id: Date.now().toString(),
        name: formData.name || '',
        clientNumber: formData.clientNumber || '',
        prgd: formData.prgd || '',
        phone: formData.phone || '',
        projectName: `Projeto ${formData.name}`,
        additionalNotes: '',
        currentStageId: STAGES[0].id,
        createdAt: now,
        stageHistory: { [STAGES[0].id]: now },
        stageData: {}
      });
    }
    closeModal();
  };

  const closeModal = () => {
    setIsCreating(false);
    setEditingClient(null);
    setFormData({ name: '', clientNumber: '', prgd: '', phone: '' });
  };

  return (
    <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-200 h-full flex flex-col relative overflow-hidden">

      {pendingTransition && (
        <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-md z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-md animate-scale-up border border-white/20 overflow-hidden">
            <div className="p-8 pb-4 flex justify-between items-center border-b border-gray-50 bg-amber-50/50">
              <div className="flex items-center gap-3">
                <div className="bg-amber-100 text-amber-600 p-2 rounded-xl"><CalendarDays size={20} /></div>
                <h2 className="text-xl font-black text-brand-900 uppercase tracking-tighter">Informação Necessária</h2>
              </div>
              <button onClick={() => setPendingTransition(null)} className="p-2 hover:bg-white rounded-full transition text-gray-400"><X size={20} /></button>
            </div>
            <div className="p-8 space-y-6">
              <p className="text-xs font-bold text-gray-400 uppercase tracking-widest leading-relaxed">
                Para mover <span className="text-brand-600 font-black">{pendingTransition.client.name}</span> para a etapa de <span className="text-brand-600 font-black">{pendingTransition.targetStage.title}</span>, informe:
              </p>
              <div className="space-y-4">
                {Object.keys(pendingTransition.fieldValues).map(field => (
                  <div key={field} className="group">
                    <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1.5 block ml-1">{field}</label>
                    <input autoFocus required placeholder={field === 'data prevista' ? 'Ex: 15/10/2024' : 'Preencha aqui...'}
                      className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white focus:border-brand-300 transition-all text-sm font-bold"
                      value={pendingTransition.fieldValues[field]}
                      onChange={e => setPendingTransition({...pendingTransition, fieldValues: { ...pendingTransition.fieldValues, [field]: e.target.value }})}
                    />
                  </div>
                ))}
              </div>
              <button onClick={handleConfirmPendingTransition} className="w-full bg-brand-600 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-brand-700 shadow-xl transition-all flex items-center justify-center gap-2">
                Confirmar e Abrir WhatsApp <ArrowRightLeft size={16} />
              </button>
            </div>
          </div>
        </div>
      )}

      {isCreating && (
          <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-4">
              <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-xl animate-scale-up border border-white/20 overflow-hidden">
                  <div className="p-8 pb-4 flex justify-between items-center border-b border-gray-50 bg-gray-50/50">
                      <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">{editingClient ? 'Editar Cadastro' : 'Novo Cliente'}</h2>
                      <button onClick={closeModal} className="p-2 hover:bg-white rounded-full transition text-gray-400"><X size={24} /></button>
                  </div>
                  <form onSubmit={handleSubmit} className="p-8 space-y-6">
                      <div className="space-y-4">
                        <div className="group">
                          <label className="text-[10px] font-black uppercase text-brand-900 tracking-widest mb-2 block">Titular do Projeto</label>
                          <input required value={formData.name} placeholder="Nome Completo" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white transition-all" onChange={e => setFormData({...formData, name: e.target.value})} />
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-900 tracking-widest mb-2 block">Telefone</label>
                            <input 
                              required 
                              placeholder="(00) 00000-0000" 
                              className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white transition-all" 
                              value={formData.phone} 
                              onChange={e => setFormData({...formData, phone: formatPhone(e.target.value)})} 
                            />
                          </div>
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-900 tracking-widest mb-2 block">Nº PRGD</label>
                            <input 
                              required 
                              value={formData.prgd} 
                              placeholder="000-00" 
                              className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white transition-all" 
                              onChange={e => setFormData({...formData, prgd: formatPRGD(e.target.value)})} 
                            />
                          </div>
                        </div>
                      </div>
                      <button type="submit" className="w-full bg-brand-600 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-sm hover:bg-brand-700 shadow-xl transition-all">
                        {editingClient ? 'SALVAR ALTERAÇÕES' : 'CADASTRAR CLIENTE'}
                      </button>
                  </form>
              </div>
          </div>
      )}

      <div className="p-6 border-b flex flex-col gap-6 bg-gray-50/50">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <div>
                <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter leading-tight">Gestão de Carteira</h2>
                <div className="flex flex-wrap items-center gap-2 mt-2">
                    <button onClick={() => setStatusFilter(statusFilter === 'ativos' ? null : 'ativos')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'ativos' ? 'bg-brand-600 text-white shadow-sm' : 'bg-white text-brand-600 hover:border-brand-300'}`}>Ativos</button>
                    <button onClick={() => setStatusFilter(statusFilter === 'entregues' ? null : 'entregues')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'entregues' ? 'bg-green-600 text-white shadow-sm' : 'bg-white text-green-600 hover:border-green-300'}`}>Entregues</button>
                    <div className="h-4 w-px bg-gray-300 mx-2"></div>
                    <button onClick={() => setStatusFilter(statusFilter === 'noprazo' ? null : 'noprazo')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'noprazo' ? 'bg-emerald-600 text-white shadow-sm' : 'bg-emerald-50 text-emerald-700'}`}>No Prazo</button>
                    <button onClick={() => setStatusFilter(statusFilter === 'atencao' ? null : 'atencao')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'atencao' ? 'bg-amber-500 text-white shadow-sm' : 'bg-amber-50 text-amber-700'}`}>Atenção</button>
                    <button onClick={() => setStatusFilter(statusFilter === 'urgente' ? null : 'urgente')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'urgente' ? 'bg-red-600 text-white shadow-sm' : 'bg-red-50 text-red-700'}`}>Urgente</button>
                </div>
            </div>

            <div className="flex bg-gray-100 p-1 rounded-2xl border border-gray-200">
                <button onClick={() => setViewMode('list')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'list' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-400'}`}>
                    <List size={14} /> Lista
                </button>
                <button onClick={() => setViewMode('pipeline')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'pipeline' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-400'}`}>
                    <Kanban size={14} /> Pipeline
                </button>
            </div>
        </div>

        <div className="flex flex-col md:flex-row gap-4">
            <div className="relative flex-1">
                <Search className="absolute left-4 top-3.5 text-gray-300" size={18} />
                <input placeholder="Filtrar por nome ou PRGD..." className="w-full pl-12 p-3.5 rounded-2xl border bg-white outline-none focus:border-brand-300 font-medium text-sm" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
            </div>
            <button onClick={() => setIsCreating(true)} className="bg-brand-600 text-white px-8 py-3.5 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-brand-700 transition-all flex items-center justify-center gap-2">
                <Plus size={18} /> Novo Cliente
            </button>
        </div>
      </div>

      <div className="flex-1 overflow-hidden bg-gray-100/30">
        {viewMode === 'list' ? (
          <div className="p-6 overflow-auto h-full scrollbar-hide">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-8">
                {filteredClients.map(client => (
                    <div key={client.id} onClick={() => onSelectClient(client)}>
                       <ClientCardItem 
                          client={client} 
                          onEdit={(e: React.MouseEvent) => { e.stopPropagation(); setEditingClient(client); setFormData({name: client.name, prgd: client.prgd, phone: client.phone}); setIsCreating(true); }}
                          onDelete={(e: React.MouseEvent) => { e.stopPropagation(); if(confirm("Excluir?")) onDeleteClient(client.id); }}
                          calculateDays={calculateDaysElapsed}
                          getStatus={getStatusInfo}
                       />
                    </div>
                ))}
            </div>
          </div>
        ) : (
          <div className="flex overflow-x-auto h-full p-6 gap-6 snap-x custom-scroll">
            {STAGES.map(stage => {
              const stageClients = filteredClients.filter(c => c.currentStageId === stage.id);
              const Icon = STEP_ICONS[stage.stepNumber] || Zap;
              return (
                <div 
                  key={stage.id} 
                  className="min-w-[320px] flex flex-col h-full snap-start"
                  onDragOver={onDragOver}
                  onDrop={() => onDrop(stage.id)}
                >
                  <div className="flex items-center justify-between mb-4 px-2">
                    <div className="flex items-center gap-3">
                        <div className="bg-brand-900 text-gold-400 p-2.5 rounded-xl shadow-lg border border-brand-800"><Icon size={16} /></div>
                        <h3 className="text-[11px] font-black uppercase text-brand-900 tracking-tight">{stage.title}</h3>
                    </div>
                    <span className="text-[10px] font-black text-brand-600 bg-brand-50 px-2.5 py-1 rounded-full">{stageClients.length}</span>
                  </div>

                  <div className={`flex-1 overflow-y-auto space-y-4 p-3 rounded-3xl bg-gray-100/60 border-2 border-transparent transition-all ${draggedClientId ? 'border-dashed border-brand-300' : ''} custom-scroll`}>
                    {stageClients.map(client => {
                        const totalDays = calculateDaysElapsed(client.createdAt);
                        const isDelivered = client.currentStageId === '7';
                        const status = getStatusInfo(totalDays, isDelivered);

                        const stageEntryStr = (client.stageHistory[client.currentStageId] as any) || client.createdAt;
                        const stageEntry = new Date(stageEntryStr);
                        const daysInStage = Math.floor(Math.abs(new Date().getTime() - stageEntry.getTime()) / (1000 * 60 * 60 * 24));

                        // Score Logic
                        let score = 5;
                        if (totalDays > 120) score -= 2; else if (totalDays > 90) score -= 1;
                        if (daysInStage > 30) score -= 2; else if (daysInStage > 15) score -= 1;
                        score = Math.max(1, score);

                        // Days to lose next star logic
                        const triggers = [];
                        if (totalDays <= 90) triggers.push(91 - totalDays);
                        else if (totalDays <= 120) triggers.push(121 - totalDays);

                        if (daysInStage <= 15) triggers.push(16 - daysInStage);
                        else if (daysInStage <= 30) triggers.push(31 - daysInStage);

                        const daysToLoseStar = triggers.length > 0 ? Math.min(...triggers) : null;

                        const startD = new Date(client.createdAt);
                        const deadlineD = new Date(startD);
                        deadlineD.setDate(deadlineD.getDate() + 120);

                        return (
                            <div 
                                key={client.id} 
                                draggable 
                                onDragStart={() => onDragStart(client.id)}
                                onClick={() => onSelectClient(client)} 
                                className={`bg-white p-5 rounded-[2.2rem] border-2 shadow-sm hover:shadow-xl transition-all cursor-grab active:cursor-grabbing group relative overflow-hidden flex flex-col min-h-[160px] ${totalDays > 120 ? 'border-red-100' : totalDays > 90 ? 'border-amber-100' : 'border-white'}`}
                            >
                                {/* Header: Pulse + Name + Stars */}
                                <div className="flex justify-between items-start mb-4">
                                    <div className="flex items-center gap-3">
                                        <div className="relative flex h-3 w-3">
                                          <span className={`animate-ping absolute inline-flex h-full w-full rounded-full opacity-75 ${status.dot}`}></span>
                                          <span className={`relative inline-flex rounded-full h-3 w-3 ${status.dot}`}></span>
                                        </div>
                                        <div>
                                            <h4 className="font-black text-brand-900 uppercase text-[11px] group-hover:text-brand-600 leading-none truncate max-w-[150px]">{client.name}</h4>
                                            <div className="flex gap-0.5 mt-2">
                                              {[1,2,3,4,5].map(s => <Star key={s} size={9} fill={s <= score ? "#dbb832" : "transparent"} className={s <= score ? "text-gold-500" : "text-gray-100"} />)}
                                            </div>
                                        </div>
                                    </div>
                                    <button onClick={(e) => { e.stopPropagation(); if(confirm("Excluir?")) onDeleteClient(client.id); }} className="text-gray-200 hover:text-red-500 transition opacity-0 group-hover:opacity-100"><Trash2 size={12} /></button>
                                </div>

                                {/* Lean Data Grid */}
                                <div className="grid grid-cols-2 gap-y-3 mb-4">
                                  <div className="flex flex-col">
                                    <span className="text-[7px] font-black text-gray-400 uppercase tracking-widest">Prazo Final</span>
                                    <span className="text-[10px] font-black text-brand-900">{deadlineD.toLocaleDateString('pt-BR', {day: '2-digit', month: '2-digit', year: '2-digit'})}</span>
                                  </div>
                                  <div className="flex flex-col text-right">
                                    <span className="text-[7px] font-black text-gray-400 uppercase tracking-widest">Na Etapa</span>
                                    <span className="text-[10px] font-black text-brand-900">{daysInStage} dias</span>
                                  </div>
                                </div>

                                {/* Star Alert & Status Footer - FIXED CUTOFF HERE */}
                                <div className="mt-auto flex items-center justify-between border-t border-gray-50 pt-3">
                                  <div className="flex items-center gap-1.5 overflow-hidden">
                                    <Timer size={10} className="text-gray-300 shrink-0" />
                                    <span className="text-[8px] font-black text-gray-400 uppercase truncate">
                                      {daysToLoseStar !== null ? `Estrela: ${daysToLoseStar}d` : 'Score Máx.'}
                                    </span>
                                  </div>
                                  <div className={`text-[8px] font-black px-2.5 py-1 rounded-full border whitespace-nowrap ${status.color} ${status.bg} border-current uppercase tracking-tight`}>
                                    {status.label.replace(/🟢|🟡|🔴/g, '').trim()}
                                  </div>
                                </div>
                            </div>
                        );
                    })}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

const ClientCardItem = ({ client, onEdit, onDelete, calculateDays, getStatus }: any) => {
    const isDelivered = client.currentStageId === '7';
