                        <span className="text-[8px] font-black text-gray-400 uppercase tracking-widest mb-0.5">Etapa Atual ({daysInStage}d)</span>
                        <span className="text-[11px] font-black text-brand-900 uppercase truncate max-w-[140px] tracking-tight">{currentStage?.title}</span>
                    </div>
