            </div>

            {/* Footer */}
            <div className="pt-3 border-t border-gray-100 flex items-center justify-between">
              <span className="text-[8px] font-black text-emerald-600 uppercase tracking-widest">Projeto Concluído</span>
              <div className="bg-emerald-100 p-1.5 rounded-lg text-emerald-600"><ChevronRight size={14} /></div>
            </div>
