            {/* Timeline Histórico - CORREÇÃO DO CORTE (SCROLL INTERNO) */}
            <div className="flex-1 flex flex-col min-h-0 bg-gray-50/30 p-3.5 rounded-[1.8rem] border border-gray-100">
