import React, { useState } from 'react';
import { Client, Stage } from '../types.ts';
import { Plus, Search, User, Zap, List, Kanban, X, ChevronRight, Clock, Trash2, Edit3, CalendarDays, ArrowRightLeft, GripVertical, CheckCircle2, Star, Calendar, Flag, Phone, Timer, AlertCircle, CheckCircle, Trophy } from 'lucide-react';
import { STAGES, STEP_ICONS } from '../constants.ts';
import { generateTemplateContent } from '../services/templateService.ts';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onEditClient: (client: Client) => void;
  onDeleteClient: (clientId: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

type ViewMode = 'list' | 'pipeline';
type FilterStatus = 'ativos' | 'entregues' | 'noprazo' | 'atencao' | 'urgente' | null;

interface PendingTransition {
  client: Client;
  targetStage: Stage;
  fieldValues: Record<string, string>;
}

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onEditClient, onDeleteClient, onUpdateClientStage }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'list' | 'pipeline'>('list'); 
  const [statusFilter, setStatusFilter] = useState<FilterStatus>(null);
  const [draggedClientId, setDraggedClientId] = useState<string | null>(null);
  const [pendingTransition, setPendingTransition] = useState<PendingTransition | null>(null);

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '', clientNumber: '', prgd: '', phone: '',
  });

  const formatPhone = (value: string) => {
    if (!value) return "";
    value = value.replace(/\D/g, "");
    value = value.substring(0, 11);
    if (value.length > 10) {
      return value.replace(/^(\d{2})(\d{5})(\d{4}).*/, "($1) $2-$3");
    } else if (value.length > 5) {
      return value.replace(/^(\d{2})(\d{4})(\d{0,4}).*/, "($1) $2-$3");
    } else if (value.length > 2) {
      return value.replace(/^(\d{2})(\d{0,5})/, "($1) $2");
    } else {
      return value.replace(/^(\d*)/, "($1");
    }
  };

  const formatPRGD = (value: string) => {
    if (!value) return "";
    value = value.replace(/\D/g, "");
    value = value.substring(0, 5);
    if (value.length > 3) {
      return value.replace(/^(\d{3})(\d{0,2})/, "$1-$2");
    }
    return value;
  };

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    if (!startStr) return 0;
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const getStatusInfo = (days: number, isDelivered: boolean) => {
    if (isDelivered) return { label: '🟢 ENTREGUE', color: 'text-green-600', bg: 'bg-green-50', dot: 'bg-green-500', key: 'entregues', btn: 'bg-green-100 text-green-700' };
    if (days > 120) return { label: '🔴 URGENTE', color: 'text-red-600', bg: 'bg-red-50', dot: 'bg-red-500', key: 'urgente', btn: 'bg-red-100 text-red-700' };
    if (days > 90) return { label: '🟡 ATENÇÃO', color: 'text-amber-500', bg: 'bg-amber-50', dot: 'bg-amber-500', key: 'atencao', btn: 'bg-amber-100 text-amber-700' };
    return { label: '🟢 NO PRAZO', color: 'text-emerald-600', bg: 'bg-emerald-50', dot: 'bg-emerald-500', key: 'noprazo', btn: 'bg-emerald-100 text-emerald-700' };
  };

  const counts = clients.reduce((acc, c) => {
    const isDelivered = c.currentStageId === '7';
    const days = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);
    const info = getStatusInfo(days, isDelivered);

    if (!isDelivered) acc.ativos++;
    acc[info.key as 'entregues' | 'urgente' | 'atencao' | 'noprazo']++;

    return acc;
  }, { ativos: 0, entregues: 0, noprazo: 0, atencao: 0, urgente: 0 });

  const filteredClients = clients.filter(c => {
    const matchesSearch = c.name.toLowerCase().includes(searchTerm.toLowerCase()) || c.prgd.toLowerCase().includes(searchTerm.toLowerCase());
    if (!matchesSearch) return false;
    if (!statusFilter) return true;
    const isDelivered = c.currentStageId === '7';
    const days = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);
    const info = getStatusInfo(days, isDelivered);
    if (statusFilter === 'ativos') return !isDelivered;
    return info.key === statusFilter;
  });

  const triggerWhatsApp = (client: Client, stage: Stage, additionalData: Record<string, string> = {}) => {
    if (!client.phone) return;
    const combinedData = { ...(client.stageData || {}), ...additionalData };
    const generated = generateTemplateContent(stage, client, combinedData);
    if (!generated.body) return;

    const cleanPhone = client.phone.replace(/\D/g, '');
    const phoneWithCountry = cleanPhone.startsWith('55') ? cleanPhone : `55${cleanPhone}`;
    const encodedText = encodeURIComponent(generated.body);
    window.open(`https://api.whatsapp.com/send?phone=${phoneWithCountry}&text=${encodedText}`, '_blank');
  };

  const onDragStart = (id: string) => setDraggedClientId(id);
  const onDragOver = (e: React.DragEvent) => e.preventDefault();

  const onDrop = (stageId: string) => {
    if (draggedClientId) {
      const client = clients.find(c => c.id === draggedClientId);
      const targetStage = STAGES.find(s => s.id === stageId);

      if (client && targetStage) {
        const requiredFields = targetStage.requiredFields || [];
        const missingFields = requiredFields.filter(field => {
          const value = client.stageData ? (client.stageData[field] as any) : undefined;
          return !value || typeof value !== 'string' || value.trim() === '';
        });

        if (missingFields.length > 0) {
          setPendingTransition({
            client,
            targetStage,
            fieldValues: missingFields.reduce((acc, field) => ({ ...acc, [field]: '' }), {})
          });
        } else {
          onUpdateClientStage(draggedClientId, stageId);
          if (targetStage.template) triggerWhatsApp(client, targetStage);
        }
      }
      setDraggedClientId(null);
    }
  };

  const handleConfirmPendingTransition = () => {
    if (!pendingTransition) return;
    const { client, targetStage, fieldValues } = pendingTransition;
    if (Object.values(fieldValues).some((v: unknown) => !(v as string).trim())) {
      alert("Por favor, preencha todos os campos.");
      return;
    }
    onUpdateClientStage(client.id, targetStage.id, fieldValues);
    if (targetStage.template) triggerWhatsApp(client, targetStage, fieldValues);
    setPendingTransition(null);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingClient) {
      onEditClient({ ...editingClient, name: formData.name || '', clientNumber: formData.clientNumber || '', prgd: formData.prgd || '', phone: formData.phone || '' });
    } else {
      const now = new Date().toISOString();
      onCreateClient({
        id: Date.now().toString(),
        name: formData.name || '',
        clientNumber: formData.clientNumber || '',
        prgd: formData.prgd || '',
        phone: formData.phone || '',
        projectName: `Projeto ${formData.name}`,
        additionalNotes: '',
        currentStageId: STAGES[0].id,
        createdAt: now,
        stageHistory: { [STAGES[0].id]: now },
        stageData: {}
      });
    }
    closeModal();
  };

  const closeModal = () => {
    setIsCreating(false);
    setEditingClient(null);
    setFormData({ name: '', clientNumber: '', prgd: '', phone: '' });
