          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-md animate-scale-up border border-white/20 overflow-hidden">
            <div className="p-8 pb-4 flex justify-between items-center border-b border-gray-50 bg-amber-50/50">
              <div className="flex items-center gap-3">
                <div className="bg-amber-100 text-amber-600 p-2 rounded-xl"><CalendarDays size={20} /></div>
                <h2 className="text-xl font-black text-brand-900 uppercase tracking-tighter">Informação Necessária</h2>
              </div>
              <button onClick={() => setPendingTransition(null)} className="p-2 hover:bg-white rounded-full transition text-gray-400"><X size={20} /></button>
