                                    className="bg-white p-5 rounded-[2.2rem] border-2 border-emerald-500 shadow-lg hover:shadow-2xl transition-all cursor-grab active:cursor-grabbing group relative overflow-hidden flex flex-col gap-3 min-h-[300px]"
                                >
                                    <div className="flex justify-between items-start">
                                        <div className="flex items-center gap-3">
                                            <div className="bg-emerald-500 text-white p-2 rounded-xl shadow-md"><Trophy size={16} /></div>
                                            <div>
                                                <h4 className="font-black text-brand-900 uppercase text-[11px] leading-tight truncate max-w-[140px]">{client.name}</h4>
