import React, { useState, useEffect } from 'react';
import { Stage, Client, GeneratedContent } from '../types.ts';
import { generateTemplateContent } from '../services/templateService.ts';
import { 
  Copy, 
  Phone, 
  Zap, 
  Edit2, 
  Save, 
  Star, 
  History, 
  CheckCircle2, 
  Trophy, 
  Clock, 
  Calendar,
  AlertCircle,
  Flag,
  ArrowRight,
  Timer,
  CheckCircle,
  ChevronRight
} from 'lucide-react';
import { STAGES } from '../constants.ts';

interface ContentGeneratorProps {
  stage: Stage;
  client: Client;
  onUpdateNotes: (notes: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

export const ContentGenerator: React.FC<ContentGeneratorProps> = ({ stage, client, onUpdateNotes, onUpdateClientStage }) => {
  const [fieldValues, setFieldValues] = useState<Record<string, string>>({});
  const [isEditing, setIsEditing] = useState(false);
  const [editableBody, setEditableBody] = useState('');

  useEffect(() => {
    setFieldValues(client.stageData || {});
    setIsEditing(false);
  }, [stage.id, client.id]);

  useEffect(() => {
    if (!isEditing) {
      const generated = generateTemplateContent(stage, client, { ...client.stageData, ...fieldValues });
      setEditableBody(generated.body);
    }
  }, [fieldValues, stage, client, isEditing]);

  const handleFieldChange = (variable: string, value: string) => {
    setFieldValues(prev => ({ ...prev, [variable]: value }));
  };

  const openWhatsApp = (text: string) => {
    const cleanPhone = client.phone.replace(/\D/g, '');
    const phoneWithCountry = cleanPhone.startsWith('55') ? cleanPhone : `55${cleanPhone}`;
    const encodedText = encodeURIComponent(text);
    window.open(`https://api.whatsapp.com/send?phone=${phoneWithCountry}&text=${encodedText}`, '_blank');
  };

  const requiredFields = stage.requiredFields || [];
  const allFieldsFilled = requiredFields.every(f => {
    const val = fieldValues[f] || client.stageData?.[f];
    return typeof val === 'string' && val.trim().length > 0;
  });

  const handleWhatsAppClick = () => {
    if (!client.phone) {
      alert("⚠️ Erro: Cliente sem telefone cadastrado!");
      return;
    }
    if (!allFieldsFilled) {
      alert(`⚠️ Atenção: Preencha os campos obrigatórios (${requiredFields.join(', ')}) antes de enviar.`);
      return;
    }
    openWhatsApp(editableBody);
    onUpdateClientStage(client.id, client.currentStageId, fieldValues);
  };

  const handleSaveAndAdvance = () => {
    if (!allFieldsFilled) {
      alert(`⚠️ Bloqueado: Preencha os campos obrigatórios.`);
      return;
    }
    onUpdateClientStage(client.id, stage.id, fieldValues);
    if (stage.template) openWhatsApp(editableBody);
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(editableBody);
    alert('Mensagem copiada para a área de transferência!');
  };

  const calculateMetrics = () => {
    const start = new Date(client.createdAt);
    const deadline = new Date(start);
    deadline.setDate(deadline.getDate() + 120);

    const isCompleted = client.currentStageId === '7';
    const historyValue = isCompleted ? (client.stageHistory['7'] as string | undefined) : undefined;
    const now = historyValue ? new Date(historyValue as string) : new Date();

    const totalDays = Math.floor(Math.abs(now.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
    const remainingDays = Math.max(0, 120 - totalDays);
    const daysDiffSLA = 120 - totalDays;
    const isEarly = daysDiffSLA >= 0;

    const stageEntryStr = (client.stageHistory[client.currentStageId] as string | undefined) || client.createdAt;
    const stageEntry = new Date(stageEntryStr as string);
    const daysInCurrentStage = Math.floor(Math.abs(new Date().getTime() - stageEntry.getTime()) / (1000 * 60 * 60 * 24));

    let score = 5;
    if (totalDays > 120) score -= 2; else if (totalDays > 90) score -= 1;
    if (!isCompleted) {
      if (daysInCurrentStage > 30) score -= 2; else if (daysInCurrentStage > 15) score -= 1;
    }
    score = Math.max(1, score);

    const slaPercent = Math.min(100, (totalDays / 120) * 100);
    let slaColor = 'bg-emerald-500';
    if (totalDays > 120) slaColor = 'bg-red-600';
    else if (totalDays > 90) slaColor = 'bg-amber-500';

    return { 
      totalDays, 
      remainingDays, 
      daysInCurrentStage, 
      score, 
      slaPercent, 
      slaColor, 
      isEarly,
      daysDiffSLA,
      start: start.toLocaleDateString('pt-BR'),
      deadline: deadline.toLocaleDateString('pt-BR'),
      completion: now.toLocaleDateString('pt-BR')
    };
  };

  const metrics = calculateMetrics();

  const renderHistory = (compact = false) => {
    const historyEntries = Object.entries(client.stageHistory)
      .map(([id, date]) => ({
        stage: STAGES.find(s => s.id === id),
        date: new Date(date as string)
      }))
      .filter(e => e.stage)
      .sort((a, b) => b.date.getTime() - a.date.getTime());

    return (
      <div className={`flex flex-col h-full ${compact ? '' : 'mt-2'}`}>
        {!compact && (
          <h3 className="text-[10px] font-black text-brand-900 uppercase tracking-widest flex items-center gap-2 mb-4">
            <History size={14} className="text-brand-600" /> Histórico da Jornada
          </h3>
        )}
        <div className="flex-1 overflow-y-auto pr-2 space-y-3 custom-scroll">
          {historyEntries.map((entry, idx) => (
            <div key={idx} className="flex items-center gap-4 bg-white p-4 rounded-2xl border border-gray-100 shadow-sm hover:border-brand-200 transition-all">
              <div className="bg-emerald-50 p-2 rounded-xl border border-emerald-100">
                <CheckCircle2 size={16} className="text-emerald-500" />
              </div>
              <div className="flex-1 overflow-hidden">
                <p className="text-[11px] font-black text-brand-900 uppercase truncate">{entry.stage?.title}</p>
                <p className="text-[9px] text-gray-400 font-bold">{entry.date.toLocaleDateString('pt-BR')} às {entry.date.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })}</p>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  };

  // ==========================================================
  // --- REDESIGN DA TELA INTERNA PARA O STATUS ENTREGUE ---
  // ==========================================================
  if (stage.id === '7') {
    return (
      <div className="bg-white rounded-[2.5rem] shadow-2xl border border-gray-200 h-full overflow-hidden flex flex-col animate-in fade-in zoom-in duration-500">
        {/* Header Superior - Identidade Loop */}
        <div className="bg-brand-900 p-8 flex flex-col md:flex-row justify-between items-center gap-6 relative">
          <div className="absolute top-0 right-0 w-64 h-64 bg-brand-800 rounded-full -mr-32 -mt-32 opacity-20"></div>

          <div className="flex items-center gap-6 relative z-10">
            <div className="bg-emerald-500 text-white p-5 rounded-[2.2rem] shadow-2xl border-4 border-emerald-400/30">
              <Trophy size={48} />
            </div>
            <div>
              <h2 className="text-3xl font-black text-white uppercase tracking-tighter leading-tight">{client.name}</h2>
              <div className="flex items-center gap-3 mt-2">
                {/* BADGE DE PERFORMANCE - ESTILO FILTRO DO HEADER */}
                <div className={`inline-flex items-center px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-widest shadow-lg border ${metrics.isEarly ? 'bg-emerald-600 text-white border-emerald-700' : 'bg-red-600 text-white border-red-700'}`}>
                   {metrics.isEarly ? `ENTREGUE NO PRAZO (-${Math.abs(metrics.daysDiffSLA)}D)` : `ENTREGUE EM ATRASO (+${Math.abs(metrics.daysDiffSLA)}D)`}
                </div>
                <div className="flex gap-1 ml-2">
                  {[1,2,3,4,5].map(s => <Star key={s} size={16} fill={s <= metrics.score ? "#dbb832" : "transparent"} className={s <= metrics.score ? "text-gold-400" : "text-brand-700"} />)}
                </div>
              </div>
            </div>
          </div>

          <div className="bg-white/10 backdrop-blur-md p-6 rounded-[2rem] border border-white/10 text-right min-w-[200px]">
             <span className="text-[10px] font-black text-brand-300 uppercase tracking-widest block mb-1">Status Final</span>
             <span className="text-2xl font-black text-white uppercase tracking-tighter">CONCLUÍDO ✅</span>
          </div>
        </div>

        {/* Grid de Métricas SLA */}
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6 p-8 bg-gray-50/50 border-b border-gray-100">
          <div className="bg-white p-6 rounded-[2rem] border border-gray-100 shadow-sm">
            <span className="text-[9px] font-black text-gray-400 uppercase tracking-[0.2em] block mb-2">Data de Início</span>
            <div className="flex items-center gap-3 text-brand-900">
               <Calendar size={20} className="text-brand-600" />
               <span className="text-xl font-black">{metrics.start}</span>
            </div>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-gray-100 shadow-sm">
            <span className="text-[9px] font-black text-gray-400 uppercase tracking-[0.2em] block mb-2">Conclusão Final</span>
            <div className="flex items-center gap-3 text-brand-900">
               <CheckCircle size={20} className="text-emerald-500" />
               <span className="text-xl font-black">{metrics.completion}</span>
            </div>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-gray-100 shadow-sm">
            <span className="text-[9px] font-black text-gray-400 uppercase tracking-[0.2em] block mb-2">Tempo de Jornada</span>
            <div className="flex items-center gap-3 text-brand-900">
               <Clock size={20} className="text-amber-500" />
               <span className="text-2xl font-black">{metrics.totalDays} <span className="text-xs text-gray-300">dias</span></span>
            </div>
          </div>
          <div className="bg-brand-900 p-6 rounded-[2rem] border border-brand-800 shadow-xl text-white">
            <span className="text-[9px] font-black text-brand-400 uppercase tracking-[0.2em] block mb-2">Meta SLA (120d)</span>
            <div className="flex items-center justify-between">
               <span className="text-2xl font-black">{Math.round((metrics.totalDays / 120) * 100)}%</span>
               <div className="h-2 flex-1 mx-4 bg-white/10 rounded-full overflow-hidden">
                 <div className={`h-full ${metrics.slaColor}`} style={{ width: `${metrics.slaPercent}%` }}></div>
               </div>
            </div>
          </div>
        </div>

        {/* Conteúdo Principal (Histórico com Scroll) */}
        <div className="flex-1 flex flex-col md:flex-row p-8 gap-8 min-h-0">
          {/* Coluna Esquerda: Histórico com Scroll */}
          <div className="flex-1 flex flex-col min-h-0 bg-gray-50/30 p-8 rounded-[2.5rem] border border-gray-100 shadow-inner">
             {renderHistory()}
          </div>

          {/* Coluna Direita: Feedback e Encerramento */}
          <div className="md:w-96 flex flex-col gap-6">
            <div className="bg-white p-8 rounded-[2.5rem] border border-gray-100 shadow-lg flex flex-col items-center text-center">
              <div className="w-20 h-20 bg-emerald-50 rounded-full flex items-center justify-center text-emerald-500 mb-6 border border-emerald-100">
                <CheckCircle2 size={40} />
              </div>
              <h4 className="text-lg font-black text-brand-900 uppercase tracking-tight mb-2">Operação de Sucesso</h4>
              <p className="text-xs text-gray-400 font-bold leading-relaxed">Este projeto foi concluído seguindo todos os protocolos de qualidade da Loop Energia. O cliente já está gerando sua própria energia.</p>

              <div className="w-full h-px bg-gray-100 my-8"></div>

              <div className="w-full space-y-4">
                <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest text-gray-400 px-2">
                  <span>Qualidade Loop</span>
                  <span className="text-gold-500">Premium</span>
                </div>
                <div className="flex justify-center gap-1">
                  {[1,2,3,4,5].map(s => <Star key={s} size={24} fill={s <= metrics.score ? "#dbb832" : "transparent"} className={s <= metrics.score ? "text-gold-500" : "text-gray-100"} />)}
                </div>
              </div>
            </div>

            <div className="mt-auto bg-brand-50 p-6 rounded-[2rem] border border-brand-100 flex items-center gap-4">
               <Zap className="text-brand-600 shrink-0" size={32} />
               <div>
                 <p className="text-[10px] font-black text-brand-900 uppercase tracking-widest">Suporte Pós-Venda</p>
                 <p className="text-[11px] text-brand-600 font-bold">O canal de monitoramento continua ativo para este cliente.</p>
               </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // TELA PARA OUTRAS ETAPAS (MANTIDO O PADRÃO)
  return (
    <div className="bg-white rounded-[2.5rem] shadow-lg border border-gray-200 flex flex-col h-full overflow-hidden">
      <div className="bg-brand-600 p-6 flex justify-between items-center text-white shrink-0">
        <div className="flex items-center gap-4">
           <div className="bg-white/20 p-3 rounded-2xl backdrop-blur-sm">
             <Zap size={24} className="text-gold-400 fill-current" />
           </div>
           <div>
            <h2 className="text-xl font-black uppercase tracking-tight">Etapa {stage.stepNumber}: {stage.title}</h2>
            <p className="text-brand-100 text-xs font-bold uppercase tracking-wider">{stage.description}</p>
          </div>
        </div>
        <button onClick={() => setIsEditing(!isEditing)} className="p-3 bg-white/10 hover:bg-white/20 rounded-2xl transition group">
          {isEditing ? <Save size={20} /> : <Edit2 size={20} className="group-hover:rotate-12 transition-transform" />}
        </button>
      </div>

      <div className="flex flex-col lg:flex-row flex-1 min-h-0">
        <div className="lg:w-80 p-6 border-r border-gray-100 bg-gray-50/50 flex flex-col gap-6 overflow-y-auto custom-scroll">

           <div className="bg-white p-5 rounded-3xl border border-brand-100 shadow-sm relative overflow-hidden">
             <div className="flex justify-between items-center mb-4">
               <h3 className="text-[10px] font-black text-brand-600 uppercase tracking-widest">Saúde do Projeto</h3>
               <div className="flex gap-0.5">
                  {[1,2,3,4,5].map(s => <Star key={s} size={12} fill={s <= metrics.score ? "#dbb832" : "transparent"} className={s <= metrics.score ? "text-gold-500" : "text-gray-200"} />)}
               </div>
             </div>

             <div className="space-y-4">
               <div>
                 <div className="flex justify-between text-[9px] font-black uppercase text-gray-400 mb-1.5">
                    <span>Progresso SLA (120d)</span>
                    <span className={metrics.totalDays > 120 ? 'text-red-600' : 'text-brand-900'}>{metrics.totalDays} / 120 dias</span>
                 </div>
                 <div className="h-2 w-full bg-gray-100 rounded-full overflow-hidden">
                   <div className={`h-full transition-all duration-1000 ${metrics.slaColor}`} style={{ width: `${metrics.slaPercent}%` }}></div>
                 </div>
               </div>

               <div className="grid grid-cols-2 gap-2">
                 <div className="bg-gray-50 p-3 rounded-2xl border border-gray-100">
                    <p className="text-[8px] font-black text-gray-400 uppercase mb-1 flex items-center gap-1"><Calendar size={10}/> Início</p>
                    <p className="text-[11px] font-black text-brand-900">{metrics.start}</p>
                 </div>
                 <div className="bg-brand-900 p-3 rounded-2xl border border-brand-800">
                    <p className="text-[8px] font-black text-brand-300 uppercase mb-1 flex items-center gap-1"><Flag size={10}/> Prazo</p>
                    <p className="text-[11px] font-black text-white">{metrics.deadline}</p>
                 </div>
               </div>

               <div className="flex items-center justify-between bg-brand-50 p-3 rounded-2xl border border-brand-100">
                 <div className="flex items-center gap-2">
                    <Timer size={16} className="text-brand-600" />
                    <div>
                      <p className="text-[8px] font-black text-gray-400 uppercase leading-none">Restam</p>
                      <p className="text-sm font-black text-brand-900 mt-0.5">{metrics.remainingDays} dias</p>
                    </div>
                 </div>
                 <div className="text-right">
                    <p className="text-[8px] font-black text-gray-400 uppercase leading-none">Nesta Etapa</p>
                    <p className="text-sm font-black text-brand-900 mt-0.5">{metrics.daysInCurrentStage}d</p>
                 </div>
               </div>
             </div>
           </div>

           {requiredFields.length > 0 && (
             <div className="space-y-4">
               <h3 className="text-[10px] font-black text-amber-600 uppercase tracking-widest flex items-center gap-2">
                 <AlertCircle size={14} /> Campos da Etapa
               </h3>
               {requiredFields.map(field => (
                 <div key={field}>
                   <label className="text-[9px] font-black uppercase text-gray-500 mb-1.5 block tracking-widest ml-1">{field}</label>
                   <input 
                     className={`w-full p-4 bg-white border rounded-2xl text-sm font-bold outline-none transition-all ${!fieldValues[field] && !client.stageData?.[field] ? 'border-amber-200' : 'border-gray-200 focus:border-brand-500'}`}
                     value={fieldValues[field] || (client.stageData?.[field] as any) || ''}
                     onChange={e => handleFieldChange(field, e.target.value)}
                     placeholder={`Preencha o campo ${field}...`}
                   />
                 </div>
               ))}
             </div>
           )}

           {renderHistory()}
        </div>

        <div className="flex-1 p-6 flex flex-col gap-4 bg-white overflow-hidden">
          <div className="flex-1 bg-gray-50 rounded-[2rem] border border-gray-100 overflow-hidden flex flex-col shadow-inner">
            <div className="px-6 py-3 border-b border-gray-100 bg-white/50 flex justify-between items-center">
              <span className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em]">Visualização da Mensagem</span>
              <button onClick={copyToClipboard} className="text-[10px] font-black text-brand-600 uppercase hover:underline flex items-center gap-1">
                <Copy size={12} /> Copiar
              </button>
            </div>

            {isEditing ? (
              <textarea 
                className="flex-1 p-8 text-sm font-sans font-medium leading-relaxed bg-transparent outline-none resize-none text-slate-700"
                value={editableBody}
                onChange={e => setEditableBody(e.target.value)}
              />
            ) : (
              <div className="flex-1 p-8 text-sm font-sans font-medium leading-relaxed whitespace-pre-wrap text-slate-700 overflow-y-auto custom-scroll">
                {editableBody}
              </div>
            )}
          </div>

          <div className="space-y-3">
            <button 
              onClick={handleWhatsAppClick}
              disabled={!allFieldsFilled}
              className={`w-full py-5 rounded-2xl font-black uppercase tracking-[0.2em] flex items-center justify-center gap-3 transition-all shadow-xl
                ${allFieldsFilled ? 'bg-[#25D366] text-white hover:bg-[#1fb355] hover:scale-[1.01]' : 'bg-gray-200 text-gray-400 cursor-not-allowed opacity-60'}`}
            >
              <Phone size={22} fill="currentColor" /> Enviar Mensagem
            </button>

            {allFieldsFilled && stage.id !== client.currentStageId && (
              <button 
                onClick={handleSaveAndAdvance}
                className="w-full py-4 bg-brand-900 text-white rounded-2xl font-black uppercase text-[10px] tracking-widest border border-brand-800 hover:bg-black transition-all flex items-center justify-center gap-2 group"
              >
                Salvar e Avançar para {stage.title} <ArrowRight size={14} className="group-hover:translate-x-1 transition-transform" />
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Stage, Client, GeneratedContent } from '../types.ts';
import { generateTemplateContent } from '../services/templateService.ts';
import { 
  Copy, 
  Phone, 
  Zap, 
  Edit2, 
  Save, 
  Star, 
  History, 
  CheckCircle2, 
  Trophy, 
  Clock, 
  Calendar,
  AlertCircle,
  Flag,
  ArrowRight,
  Timer,
  CheckCircle,
  ChevronRight
} from 'lucide-react';
import { STAGES } from '../constants.ts';

interface ContentGeneratorProps {
  stage: Stage;
  client: Client;
  onUpdateNotes: (notes: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

export const ContentGenerator: React.FC<ContentGeneratorProps> = ({ stage, client, onUpdateNotes, onUpdateClientStage }) => {
  const [fieldValues, setFieldValues] = useState<Record<string, string>>({});
  const [isEditing, setIsEditing] = useState(false);
  const [editableBody, setEditableBody] = useState('');

  useEffect(() => {
    setFieldValues(client.stageData || {});
    setIsEditing(false);
  }, [stage.id, client.id]);

  useEffect(() => {
    if (!isEditing) {
      const generated = generateTemplateContent(stage, client, { ...client.stageData, ...fieldValues });
      setEditableBody(generated.body);
    }
  }, [fieldValues, stage, client, isEditing]);

  const handleFieldChange = (variable: string, value: string) => {
    setFieldValues(prev => ({ ...prev, [variable]: value }));
  };

  const openWhatsApp = (text: string) => {
    const cleanPhone = client.phone.replace(/\D/g, '');
    const phoneWithCountry = cleanPhone.startsWith('55') ? cleanPhone : `55${cleanPhone}`;
    const encodedText = encodeURIComponent(text);
    window.open(`https://api.whatsapp.com/send?phone=${phoneWithCountry}&text=${encodedText}`, '_blank');
  };

  const requiredFields = stage.requiredFields || [];
  const allFieldsFilled = requiredFields.every(f => {
    const val = fieldValues[f] || client.stageData?.[f];
    return typeof val === 'string' && val.trim().length > 0;
  });

  const handleWhatsAppClick = () => {
    if (!client.phone) {
      alert("⚠️ Erro: Cliente sem telefone cadastrado!");
      return;
    }
    if (!allFieldsFilled) {
      alert(`⚠️ Atenção: Preencha os campos obrigatórios (${requiredFields.join(', ')}) antes de enviar.`);
      return;
    }
    openWhatsApp(editableBody);
    onUpdateClientStage(client.id, client.currentStageId, fieldValues);
  };

  const handleSaveAndAdvance = () => {
    if (!allFieldsFilled) {
      alert(`⚠️ Bloqueado: Preencha os campos obrigatórios.`);
      return;
    }
    onUpdateClientStage(client.id, stage.id, fieldValues);
    if (stage.template) openWhatsApp(editableBody);
  };

  const copyToClipboard = () => {
    navigator.clipboard.writeText(editableBody);
    alert('Mensagem copiada para a área de transferência!');
  };

  const calculateMetrics = () => {
    const start = new Date(client.createdAt);
    const deadline = new Date(start);
    deadline.setDate(deadline.getDate() + 120);

    const isCompleted = client.currentStageId === '7';
    const historyValue = isCompleted ? (client.stageHistory['7'] as string | undefined) : undefined;
    const now = historyValue ? new Date(historyValue as string) : new Date();

    const totalDays = Math.floor(Math.abs(now.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
    const remainingDays = Math.max(0, 120 - totalDays);
    const daysDiffSLA = 120 - totalDays;
    const isEarly = daysDiffSLA >= 0;

    const stageEntryStr = (client.stageHistory[client.currentStageId] as string | undefined) || client.createdAt;
    const stageEntry = new Date(stageEntryStr as string);
    const daysInCurrentStage = Math.floor(Math.abs(new Date().getTime() - stageEntry.getTime()) / (1000 * 60 * 60 * 24));

    let score = 5;
    if (totalDays > 120) score -= 2; else if (totalDays > 90) score -= 1;
    if (!isCompleted) {
      if (daysInCurrentStage > 30) score -= 2; else if (daysInCurrentStage > 15) score -= 1;
    }
    score = Math.max(1, score);

    const slaPercent = Math.min(100, (totalDays / 120) * 100);
    let slaColor = 'bg-emerald-500';
    if (totalDays > 120) slaColor = 'bg-red-600';
    else if (totalDays > 90) slaColor = 'bg-amber-500';

    return { 
      totalDays, 
      remainingDays, 
      daysInCurrentStage, 
      score, 
      slaPercent, 
      slaColor, 
      isEarly,
      daysDiffSLA,
      start: start.toLocaleDateString('pt-BR'),
      deadline: deadline.toLocaleDateString('pt-BR'),
      completion: now.toLocaleDateString('pt-BR')
    };
  };

  const metrics = calculateMetrics();

  const renderHistory = (compact = false) => {
    const historyEntries = Object.entries(client.stageHistory)
      .map(([id, date]) => ({
        stage: STAGES.find(s => s.id === id),
        date: new Date(date as string)
      }))
      .filter(e => e.stage)
      .sort((a, b) => b.date.getTime() - a.date.getTime());

    return (
      <div className={`flex flex-col h-full ${compact ? '' : 'mt-2'}`}>
        {!compact && (
          <h3 className="text-[10px] font-black text-brand-900 uppercase tracking-widest flex items-center gap-2 mb-4">
            <History size={14} className="text-brand-600" /> Histórico da Jornada
          </h3>
        )}
        <div className="flex-1 overflow-y-auto pr-2 space-y-3 custom-scroll">
          {historyEntries.map((entry, idx) => (
            <div key={idx} className="flex items-center gap-4 bg-white p-4 rounded-2xl border border-gray-100 shadow-sm hover:border-brand-200 transition-all">
              <div className="bg-emerald-50 p-2 rounded-xl border border-emerald-100">
                <CheckCircle2 size={16} className="text-emerald-500" />
              </div>
              <div className="flex-1 overflow-hidden">
                <p className="text-[11px] font-black text-brand-900 uppercase truncate">{entry.stage?.title}</p>
                <p className="text-[9px] text-gray-400 font-bold">{entry.date.toLocaleDateString('pt-BR')} às {entry.date.toLocaleTimeString('pt-BR', { hour: '2-digit', minute: '2-digit' })}</p>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  };

  // ==========================================================
  // --- REDESIGN DA TELA INTERNA PARA O STATUS ENTREGUE ---
  // ==========================================================
  if (stage.id === '7') {
    return (
      <div className="bg-white rounded-[2.5rem] shadow-2xl border border-gray-200 h-full overflow-y-auto custom-scroll flex flex-col animate-in fade-in zoom-in duration-500">
        {/* Header Superior - Identidade Loop */}
        <div className="bg-brand-900 p-8 flex flex-col md:flex-row justify-between items-center gap-6 relative shrink-0">
          <div className="absolute top-0 right-0 w-64 h-64 bg-brand-800 rounded-full -mr-32 -mt-32 opacity-20"></div>

          <div className="flex items-center gap-6 relative z-10">
            <div className="bg-emerald-500 text-white p-5 rounded-[2.2rem] shadow-2xl border-4 border-emerald-400/30">
              <Trophy size={48} />
            </div>
            <div>
              <h2 className="text-3xl font-black text-white uppercase tracking-tighter leading-tight">{client.name}</h2>
              <div className="flex items-center gap-3 mt-2">
                <div className={`inline-flex items-center px-5 py-2 rounded-full text-[10px] font-black uppercase tracking-widest shadow-lg border ${metrics.isEarly ? 'bg-emerald-600 text-white border-emerald-700' : 'bg-red-600 text-white border-red-700'}`}>
                   {metrics.isEarly ? `ENTREGUE NO PRAZO (-${Math.abs(metrics.daysDiffSLA)}D)` : `ENTREGUE EM ATRASO (+${Math.abs(metrics.daysDiffSLA)}D)`}
                </div>
                <div className="flex gap-1 ml-2">
                  {[1,2,3,4,5].map(s => <Star key={s} size={16} fill={s <= metrics.score ? "#dbb832" : "transparent"} className={s <= metrics.score ? "text-gold-400" : "text-brand-700"} />)}
