          </div>
        </div>

        {/* Grid de Métricas SLA - Responsivo para não cortar */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6 p-8 bg-gray-50/50 border-b border-gray-100 shrink-0">
          <div className="bg-white p-6 rounded-[2rem] border border-gray-100 shadow-sm">
            <span className="text-[9px] font-black text-gray-400 uppercase tracking-[0.2em] block mb-2">Data de Início</span>
            <div className="flex items-center gap-3 text-brand-900">
               <Calendar size={20} className="text-brand-600" />
               <span className="text-xl font-black">{metrics.start}</span>
            </div>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-gray-100 shadow-sm">
            <span className="text-[9px] font-black text-gray-400 uppercase tracking-[0.2em] block mb-2">Conclusão Final</span>
            <div className="flex items-center gap-3 text-brand-900">
               <CheckCircle size={20} className="text-emerald-500" />
               <span className="text-xl font-black">{metrics.completion}</span>
            </div>
          </div>
          <div className="bg-white p-6 rounded-[2rem] border border-gray-100 shadow-sm">
            <span className="text-[9px] font-black text-gray-400 uppercase tracking-[0.2em] block mb-2">Tempo de Jornada</span>
            <div className="flex items-center gap-3 text-brand-900">
               <Clock size={20} className="text-amber-500" />
               <span className="text-2xl font-black">{metrics.totalDays} <span className="text-xs text-gray-300">dias</span></span>
            </div>
          </div>
          <div className="bg-brand-900 p-6 rounded-[2rem] border border-brand-800 shadow-xl text-white">
            <span className="text-[9px] font-black text-brand-400 uppercase tracking-[0.2em] block mb-2">Meta SLA (120d)</span>
            <div className="flex items-center justify-between">
               <span className="text-2xl font-black">{Math.round((metrics.totalDays / 120) * 100)}%</span>
               <div className="h-2 flex-1 mx-4 bg-white/10 rounded-full overflow-hidden">
                 <div className={`h-full ${metrics.slaColor}`} style={{ width: `${metrics.slaPercent}%` }}></div>
               </div>
            </div>
          </div>
        </div>

        {/* Conteúdo Principal */}
        <div className="flex-1 flex flex-col md:flex-row p-8 gap-8">
          <div className="flex-1 flex flex-col min-h-[300px] bg-gray-50/30 p-8 rounded-[2.5rem] border border-gray-100 shadow-inner">
             {renderHistory()}
          </div>

          <div className="md:w-96 flex flex-col gap-6">
            <div className="bg-white p-8 rounded-[2.5rem] border border-gray-100 shadow-lg flex flex-col items-center text-center">
              <div className="w-20 h-20 bg-emerald-50 rounded-full flex items-center justify-center text-emerald-500 mb-6 border border-emerald-100">
                <CheckCircle2 size={40} />
              </div>
              <h4 className="text-lg font-black text-brand-900 uppercase tracking-tight mb-2">Operação de Sucesso</h4>
              <p className="text-xs text-gray-400 font-bold leading-relaxed">Este projeto foi concluído seguindo todos os protocolos de qualidade da Loop Energia. O cliente já está gerando sua própria energia.</p>

              <div className="w-full h-px bg-gray-100 my-8"></div>

              <div className="w-full space-y-4">
                <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest text-gray-400 px-2">
                  <span>Qualidade Loop</span>
                  <span className="text-gold-500">Premium</span>
                </div>
                <div className="flex justify-center gap-1">
                  {[1,2,3,4,5].map(s => <Star key={s} size={24} fill={s <= metrics.score ? "#dbb832" : "transparent"} className={s <= metrics.score ? "text-gold-500" : "text-gray-100"} />)}
                </div>
              </div>
            </div>

            <div className="bg-brand-50 p-6 rounded-[2rem] border border-brand-100 flex items-center gap-4">
               <Zap className="text-brand-600 shrink-0" size={32} />
               <div>
                 <p className="text-[10px] font-black text-brand-900 uppercase tracking-widest">Suporte Pós-Venda</p>
                 <p className="text-[11px] text-brand-600 font-bold">O canal de monitoramento continua ativo.</p>
               </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  // TELA PARA OUTRAS ETAPAS
  return (
    <div className="bg-white rounded-[2.5rem] shadow-lg border border-gray-200 flex flex-col h-full overflow-y-auto custom-scroll">
      <div className="bg-brand-600 p-6 flex justify-between items-center text-white shrink-0">
        <div className="flex items-center gap-4">
           <div className="bg-white/20 p-3 rounded-2xl backdrop-blur-sm">
             <Zap size={24} className="text-gold-400 fill-current" />
           </div>
           <div>
            <h2 className="text-xl font-black uppercase tracking-tight">Etapa {stage.stepNumber}: {stage.title}</h2>
            <p className="text-brand-100 text-xs font-bold uppercase tracking-wider">{stage.description}</p>
          </div>
        </div>
        <button onClick={() => setIsEditing(!isEditing)} className="p-3 bg-white/10 hover:bg-white/20 rounded-2xl transition group">
          {isEditing ? <Save size={20} /> : <Edit2 size={20} className="group-hover:rotate-12 transition-transform" />}
        </button>
      </div>

      <div className="flex flex-col lg:flex-row flex-1">
        {/* BLOCO LATERAL DE SAÚDE DO PROJETO - CORREÇÃO DE CORTE */}
        <div className="lg:w-80 p-6 border-r border-gray-100 bg-gray-50/50 flex flex-col gap-6 shrink-0">

           <div className="bg-white p-6 rounded-[2rem] border border-brand-100 shadow-sm relative overflow-visible">
             <div className="flex justify-between items-center mb-6">
               <h3 className="text-[10px] font-black text-brand-600 uppercase tracking-widest">Saúde do Projeto</h3>
               <div className="flex gap-0.5">
                  {[1,2,3,4,5].map(s => <Star key={s} size={12} fill={s <= metrics.score ? "#dbb832" : "transparent"} className={s <= metrics.score ? "text-gold-500" : "text-gray-200"} />)}
               </div>
             </div>

             <div className="space-y-6">
               <div>
                 <div className="flex justify-between text-[9px] font-black uppercase text-gray-400 mb-2">
                    <span>Progresso SLA (120d)</span>
                    <span className={metrics.totalDays > 120 ? 'text-red-600' : 'text-brand-900'}>{metrics.totalDays} / 120 dias</span>
                 </div>
                 <div className="h-2.5 w-full bg-gray-100 rounded-full overflow-hidden border border-gray-50">
                   <div className={`h-full transition-all duration-1000 ${metrics.slaColor}`} style={{ width: `${metrics.slaPercent}%` }}></div>
                 </div>
               </div>

               <div className="grid grid-cols-2 gap-3">
                 <div className="bg-gray-50 p-4 rounded-2xl border border-gray-100">
                    <p className="text-[8px] font-black text-gray-400 uppercase mb-1 flex items-center gap-1"><Calendar size={10}/> Início</p>
                    <p className="text-[11px] font-black text-brand-900">{metrics.start}</p>
                 </div>
                 <div className="bg-brand-900 p-4 rounded-2xl border border-brand-800 shadow-md">
                    <p className="text-[8px] font-black text-brand-300 uppercase mb-1 flex items-center gap-1"><Flag size={10}/> Prazo</p>
                    <p className="text-[11px] font-black text-white">{metrics.deadline}</p>
                 </div>
               </div>

               <div className="flex items-center justify-between bg-brand-50 p-4 rounded-2xl border border-brand-100 shadow-inner">
                 <div className="flex items-center gap-3">
                    <Timer size={18} className="text-brand-600" />
                    <div>
                      <p className="text-[8px] font-black text-gray-400 uppercase leading-none">Restam</p>
                      <p className="text-sm font-black text-brand-900 mt-1">{metrics.remainingDays} dias</p>
                    </div>
                 </div>
                 <div className="text-right">
                    <p className="text-[8px] font-black text-gray-400 uppercase leading-none">Na Etapa</p>
                    <p className="text-sm font-black text-brand-900 mt-1">{metrics.daysInCurrentStage}d</p>
                 </div>
               </div>
             </div>
           </div>

           {requiredFields.length > 0 && (
             <div className="space-y-4">
               <h3 className="text-[10px] font-black text-amber-600 uppercase tracking-widest flex items-center gap-2 px-1">
                 <AlertCircle size={14} /> Campos da Etapa
               </h3>
               {requiredFields.map(field => (
                 <div key={field}>
                   <label className="text-[9px] font-black uppercase text-gray-500 mb-1.5 block tracking-widest ml-1">{field}</label>
                   <input 
                     className={`w-full p-4 bg-white border rounded-2xl text-sm font-bold outline-none transition-all ${!fieldValues[field] && !client.stageData?.[field] ? 'border-amber-200' : 'border-gray-200 focus:border-brand-500'}`}
                     value={fieldValues[field] || (client.stageData?.[field] as any) || ''}
                     onChange={e => handleFieldChange(field, e.target.value)}
                     placeholder={`Preencha o campo ${field}...`}
                   />
                 </div>
               ))}
             </div>
           )}

           <div className="flex-1 min-h-[250px]">
              {renderHistory()}
           </div>
        </div>

        <div className="flex-1 p-8 flex flex-col gap-6 bg-white min-h-[500px]">
          <div className="flex-1 bg-gray-50 rounded-[2.5rem] border border-gray-100 overflow-hidden flex flex-col shadow-inner">
            <div className="px-8 py-4 border-b border-gray-100 bg-white/50 flex justify-between items-center shrink-0">
              <span className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em]">Visualização da Mensagem</span>
              <button onClick={copyToClipboard} className="text-[10px] font-black text-brand-600 uppercase hover:underline flex items-center gap-2">
                <Copy size={14} /> Copiar Texto
              </button>
            </div>

            {isEditing ? (
              <textarea 
                className="flex-1 p-8 text-base font-sans font-medium leading-relaxed bg-transparent outline-none resize-none text-slate-700"
                value={editableBody}
                onChange={e => setEditableBody(e.target.value)}
              />
            ) : (
              <div className="flex-1 p-8 text-base font-sans font-medium leading-relaxed whitespace-pre-wrap text-slate-700 overflow-y-auto custom-scroll">
                {editableBody}
              </div>
            )}
          </div>

          <div className="space-y-4 shrink-0">
            <button 
              onClick={handleWhatsAppClick}
              disabled={!allFieldsFilled}
              className={`w-full py-6 rounded-[2rem] font-black uppercase tracking-[0.2em] flex items-center justify-center gap-4 transition-all shadow-xl text-sm
                ${allFieldsFilled ? 'bg-[#25D366] text-white hover:bg-[#1fb355] hover:scale-[1.01]' : 'bg-gray-200 text-gray-400 cursor-not-allowed opacity-60'}`}
            >
              <Phone size={24} fill="currentColor" /> Enviar Mensagem via WhatsApp
            </button>

            {allFieldsFilled && stage.id !== client.currentStageId && (
              <button 
                onClick={handleSaveAndAdvance}
                className="w-full py-5 bg-brand-900 text-white rounded-[2rem] font-black uppercase text-[11px] tracking-widest border border-brand-800 hover:bg-black transition-all flex items-center justify-center gap-3 group shadow-lg"
              >
                Salvar e Avançar para Próxima Etapa <ArrowRight size={16} className="group-hover:translate-x-1 transition-transform" />
              </button>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Client, Stage } from '../types.ts';
import { Plus, Search, User, Zap, List, Kanban, X, ChevronRight, Clock, Trash2, Edit3, CalendarDays, ArrowRightLeft, GripVertical, CheckCircle2, Star, Calendar, Flag, Phone, Timer, AlertCircle, CheckCircle, Trophy } from 'lucide-react';
import { STAGES, STEP_ICONS } from '../constants.ts';
import { generateTemplateContent } from '../services/templateService.ts';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onEditClient: (client: Client) => void;
  onDeleteClient: (clientId: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

type ViewMode = 'list' | 'pipeline';
type FilterStatus = 'ativos' | 'entregues' | 'noprazo' | 'atencao' | 'urgente' | null;

interface PendingTransition {
  client: Client;
  targetStage: Stage;
  fieldValues: Record<string, string>;
}

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onEditClient, onDeleteClient, onUpdateClientStage }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'list' | 'pipeline'>('list'); 
  const [statusFilter, setStatusFilter] = useState<FilterStatus>(null);
  const [draggedClientId, setDraggedClientId] = useState<string | null>(null);
  const [pendingTransition, setPendingTransition] = useState<PendingTransition | null>(null);

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '', clientNumber: '', prgd: '', phone: '',
  });

  const formatPhone = (value: string) => {
    if (!value) return "";
    value = value.replace(/\D/g, "");
    value = value.substring(0, 11);
    if (value.length > 10) {
      return value.replace(/^(\d{2})(\d{5})(\d{4}).*/, "($1) $2-$3");
    } else if (value.length > 5) {
      return value.replace(/^(\d{2})(\d{4})(\d{0,4}).*/, "($1) $2-$3");
    } else if (value.length > 2) {
      return value.replace(/^(\d{2})(\d{0,5})/, "($1) $2");
    } else {
      return value.replace(/^(\d*)/, "($1");
    }
  };

  const formatPRGD = (value: string) => {
    if (!value) return "";
    value = value.replace(/\D/g, "");
    value = value.substring(0, 5);
    if (value.length > 3) {
      return value.replace(/^(\d{3})(\d{0,2})/, "$1-$2");
    }
    return value;
  };

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    if (!startStr) return 0;
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const getStatusInfo = (days: number, isDelivered: boolean) => {
    if (isDelivered) return { label: '🟢 ENTREGUE', color: 'text-green-600', bg: 'bg-green-50', dot: 'bg-green-500', key: 'entregues', btn: 'bg-green-100 text-green-700' };
    if (days > 120) return { label: '🔴 URGENTE', color: 'text-red-600', bg: 'bg-red-50', dot: 'bg-red-500', key: 'urgente', btn: 'bg-red-100 text-red-700' };
    // MUDANÇA SOLICITADA: Atenção começa aos 75 dias para agir antes dos 90
    if (days > 75) return { label: '🟡 ATENÇÃO', color: 'text-amber-500', bg: 'bg-amber-50', dot: 'bg-amber-500', key: 'atencao', btn: 'bg-amber-100 text-amber-700' };
    return { label: '🟢 NO PRAZO', color: 'text-emerald-600', bg: 'bg-emerald-50', dot: 'bg-emerald-500', key: 'noprazo', btn: 'bg-emerald-100 text-emerald-700' };
  };

  const counts = clients.reduce((acc, c) => {
    const isDelivered = c.currentStageId === '7';
    const days = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);
    const info = getStatusInfo(days, isDelivered);

    if (!isDelivered) acc.ativos++;
    acc[info.key as 'entregues' | 'urgente' | 'atencao' | 'noprazo']++;

    return acc;
  }, { ativos: 0, entregues: 0, noprazo: 0, atencao: 0, urgente: 0 });

  const filteredClients = clients.filter(c => {
    const matchesSearch = c.name.toLowerCase().includes(searchTerm.toLowerCase()) || c.prgd.toLowerCase().includes(searchTerm.toLowerCase());
    if (!matchesSearch) return false;
    if (!statusFilter) return true;
    const isDelivered = c.currentStageId === '7';
    const days = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);
    const info = getStatusInfo(days, isDelivered);
    if (statusFilter === 'ativos') return !isDelivered;
    return info.key === statusFilter;
  });

  const triggerWhatsApp = (client: Client, stage: Stage, additionalData: Record<string, string> = {}) => {
    if (!client.phone) return;
    const combinedData = { ...(client.stageData || {}), ...additionalData };
    const generated = generateTemplateContent(stage, client, combinedData);
    if (!generated.body) return;

    const cleanPhone = client.phone.replace(/\D/g, '');
    const phoneWithCountry = cleanPhone.startsWith('55') ? cleanPhone : `55${cleanPhone}`;
    const encodedText = encodeURIComponent(generated.body);
    window.open(`https://api.whatsapp.com/send?phone=${phoneWithCountry}&text=${encodedText}`, '_blank');
  };

  const onDragStart = (id: string) => setDraggedClientId(id);
  const onDragOver = (e: React.DragEvent) => e.preventDefault();

  const onDrop = (stageId: string) => {
    if (draggedClientId) {
      const client = clients.find(c => c.id === draggedClientId);
      const targetStage = STAGES.find(s => s.id === stageId);

      if (client && targetStage) {
        const requiredFields = targetStage.requiredFields || [];
        const missingFields = requiredFields.filter(field => {
          const value = client.stageData ? (client.stageData[field] as any) : undefined;
          return !value || typeof value !== 'string' || value.trim() === '';
        });

        if (missingFields.length > 0) {
          setPendingTransition({
            client,
            targetStage,
            fieldValues: missingFields.reduce((acc, field) => ({ ...acc, [field]: '' }), {})
          });
        } else {
          onUpdateClientStage(draggedClientId, stageId);
          if (targetStage.template) triggerWhatsApp(client, targetStage);
        }
      }
      setDraggedClientId(null);
    }
  };

  const handleConfirmPendingTransition = () => {
    if (!pendingTransition) return;
    const { client, targetStage, fieldValues } = pendingTransition;
    if (Object.values(fieldValues).some((v: unknown) => !(v as string).trim())) {
      alert("Por favor, preencha todos os campos.");
      return;
    }
    onUpdateClientStage(client.id, targetStage.id, fieldValues);
    if (targetStage.template) triggerWhatsApp(client, targetStage, fieldValues);
    setPendingTransition(null);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (editingClient) {
      onEditClient({ ...editingClient, name: formData.name || '', clientNumber: formData.clientNumber || '', prgd: formData.prgd || '', phone: formData.phone || '' });
    } else {
      const now = new Date().toISOString();
      onCreateClient({
        id: Date.now().toString(),
        name: formData.name || '',
        clientNumber: formData.clientNumber || '',
        prgd: formData.prgd || '',
        phone: formData.phone || '',
        projectName: `Projeto ${formData.name}`,
        additionalNotes: '',
        currentStageId: STAGES[0].id,
        createdAt: now,
        stageHistory: { [STAGES[0].id]: now },
        stageData: {}
      });
    }
    closeModal();
  };

  const closeModal = () => {
    setIsCreating(false);
    setEditingClient(null);
    setFormData({ name: '', clientNumber: '', prgd: '', phone: '' });
  };

  return (
    <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-200 h-full flex flex-col relative overflow-hidden">

      {pendingTransition && (
        <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-md z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-md animate-scale-up border border-white/20 overflow-hidden">
            <div className="p-8 pb-4 flex justify-between items-center border-b border-gray-50 bg-amber-50/50">
              <div className="flex items-center gap-3">
                <div className="bg-amber-100 text-amber-600 p-2 rounded-xl"><CalendarDays size={20} /></div>
                <h2 className="text-xl font-black text-brand-900 uppercase tracking-tighter">Informação Necessária</h2>
              </div>
              <button onClick={() => setPendingTransition(null)} className="p-2 hover:bg-white rounded-full transition text-gray-400"><X size={20} /></button>
            </div>
            <div className="p-8 space-y-6">
              <p className="text-xs font-bold text-gray-400 uppercase tracking-widest leading-relaxed">
                Para mover <span className="text-brand-600 font-black">{pendingTransition.client.name}</span> para a etapa de <span className="text-brand-600 font-black">{pendingTransition.targetStage.title}</span>, informe:
              </p>
              <div className="space-y-4">
                {Object.keys(pendingTransition.fieldValues).map(field => (
                  <div key={field} className="group">
                    <label className="text-[10px] font-black uppercase text-gray-400 tracking-widest mb-1.5 block ml-1">{field}</label>
                    <input autoFocus required placeholder={field === 'data prevista' ? 'Ex: 15/10/2024' : 'Preencha aqui...'}
                      className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white focus:border-brand-300 transition-all text-sm font-bold"
                      value={pendingTransition.fieldValues[field]}
                      onChange={e => setPendingTransition({...pendingTransition, fieldValues: { ...pendingTransition.fieldValues, [field]: e.target.value }})}
                    />
                  </div>
                ))}
              </div>
              <button onClick={handleConfirmPendingTransition} className="w-full bg-brand-600 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-brand-700 shadow-xl transition-all flex items-center justify-center gap-2">
                Confirmar e Abrir WhatsApp <ArrowRightLeft size={16} />
              </button>
            </div>
          </div>
        </div>
      )}

      {isCreating && (
          <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-4">
              <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-xl animate-scale-up border border-white/20 overflow-hidden">
                  <div className="p-8 pb-4 flex justify-between items-center border-b border-gray-50 bg-gray-50/50">
                      <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">{editingClient ? 'Editar Cadastro' : 'Novo Cliente'}</h2>
                      <button onClick={closeModal} className="p-2 hover:bg-white rounded-full transition text-gray-400"><X size={24} /></button>
                  </div>
                  <form onSubmit={handleSubmit} className="p-8 space-y-6">
                      <div className="space-y-4">
                        <div className="group">
                          <label className="text-[10px] font-black uppercase text-brand-900 tracking-widest mb-2 block">Titular do Projeto</label>
                          <input required value={formData.name} placeholder="Nome Completo" className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white transition-all" onChange={e => setFormData({...formData, name: e.target.value})} />
                        </div>
                        <div className="grid grid-cols-2 gap-4">
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-900 tracking-widest mb-2 block">Telefone</label>
                            <input 
                              required 
                              placeholder="(00) 00000-0000" 
                              className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white transition-all" 
                              value={formData.phone} 
                              onChange={e => setFormData({...formData, phone: formatPhone(e.target.value)})} 
                            />
                          </div>
                          <div className="group">
                            <label className="text-[10px] font-black uppercase text-brand-900 tracking-widest mb-2 block">Nº PRGD</label>
                            <input 
                              required 
                              value={formData.prgd} 
                              placeholder="000-00" 
                              className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl outline-none focus:bg-white transition-all" 
                              onChange={e => setFormData({...formData, prgd: formatPRGD(e.target.value)})} 
                            />
                          </div>
                        </div>
                      </div>
                      <button type="submit" className="w-full bg-brand-600 text-white py-4 rounded-2xl font-black uppercase tracking-widest text-sm hover:bg-brand-700 shadow-xl transition-all">
                        {editingClient ? 'SALVAR ALTERAÇÕES' : 'CADASTRAR CLIENTE'}
                      </button>
                  </form>
              </div>
          </div>
      )}

      <div className="p-6 border-b flex flex-col gap-6 bg-gray-50/50">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <div>
                <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter leading-tight">Gestão de Carteira</h2>
                <div className="flex flex-wrap items-center gap-2 mt-2">
                    <button onClick={() => setStatusFilter(statusFilter === 'ativos' ? null : 'ativos')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'ativos' ? 'bg-brand-600 text-white shadow-sm' : 'bg-white text-brand-600 hover:border-brand-300'}`}>
                      {counts.ativos} Ativos
                    </button>
                    <button onClick={() => setStatusFilter(statusFilter === 'entregues' ? null : 'entregues')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'entregues' ? 'bg-green-600 text-white shadow-sm' : 'bg-white text-green-600 hover:border-green-300'}`}>
                      {counts.entregues} Entregues
                    </button>
                    <div className="h-4 w-px bg-gray-300 mx-2"></div>
                    <button onClick={() => setStatusFilter(statusFilter === 'noprazo' ? null : 'noprazo')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'noprazo' ? 'bg-emerald-600 text-white shadow-sm' : 'bg-emerald-50 text-emerald-700'}`}>
                      {counts.noprazo} No Prazo
                    </button>
                    <button onClick={() => setStatusFilter(statusFilter === 'atencao' ? null : 'atencao')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'atencao' ? 'bg-amber-500 text-white shadow-sm' : 'bg-amber-50 text-amber-700'}`}>
                      {counts.atencao} Atenção
                    </button>
                    <button onClick={() => setStatusFilter(statusFilter === 'urgente' ? null : 'urgente')} className={`text-[9px] font-black px-3.5 py-1.5 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'urgente' ? 'bg-red-600 text-white shadow-sm' : 'bg-red-50 text-red-700'}`}>
                      {counts.urgente} Urgente
                    </button>
                </div>
            </div>

            <div className="flex bg-gray-100 p-1 rounded-2xl border border-gray-200">
                <button onClick={() => setViewMode('list')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'list' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-400'}`}>
                    <List size={14} /> Lista
                </button>
                <button onClick={() => setViewMode('pipeline')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'pipeline' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-400'}`}>
                    <Kanban size={14} /> Pipeline
                </button>
            </div>
        </div>

        <div className="flex flex-col md:flex-row gap-4">
            <div className="relative flex-1">
                <Search className="absolute left-4 top-3.5 text-gray-300" size={18} />
                <input placeholder="Filtrar por nome ou PRGD..." className="w-full pl-12 p-3.5 rounded-2xl border bg-white outline-none focus:border-brand-300 font-medium text-sm" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
            </div>
            <button onClick={() => setIsCreating(true)} className="bg-brand-600 text-white px-8 py-3.5 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-brand-700 transition-all flex items-center justify-center gap-2">
                <Plus size={18} /> Novo Cliente
            </button>
        </div>
      </div>

      <div className="flex-1 overflow-hidden bg-gray-100/30">
        {viewMode === 'list' ? (
          <div className="p-6 overflow-auto h-full scrollbar-hide">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6 pb-8">
                {filteredClients.map(client => (
                    <div key={client.id} onClick={() => onSelectClient(client)}>
                       <ClientCardItem 
                          client={client} 
                          onEdit={(e: React.MouseEvent) => { e.stopPropagation(); setEditingClient(client); setFormData({name: client.name, prgd: client.prgd, phone: client.phone}); setIsCreating(true); }}
                          onDelete={(e: React.MouseEvent) => { e.stopPropagation(); if(confirm("Excluir?")) onDeleteClient(client.id); }}
                          calculateDays={calculateDaysElapsed}
                          getStatus={getStatusInfo}
                       />
                    </div>
                ))}
            </div>
          </div>
        ) : (
          <div className="flex overflow-x-auto h-full p-6 gap-6 snap-x custom-scroll">
            {STAGES.map(stage => {
              const stageClients = filteredClients.filter(c => c.currentStageId === stage.id);
              const Icon = STEP_ICONS[stage.stepNumber] || Zap;
              return (
                <div 
                  key={stage.id} 
                  className="min-w-[320px] flex flex-col h-full snap-start"
                  onDragOver={onDragOver}
                  onDrop={() => onDrop(stage.id)}
                >
                  <div className="flex items-center justify-between mb-4 px-2">
                    <div className="flex items-center gap-3">
                        <div className="bg-brand-900 text-gold-400 p-2.5 rounded-xl shadow-lg border border-brand-800"><Icon size={16} /></div>
                        <h3 className="text-[11px] font-black uppercase text-brand-900 tracking-tight">{stage.title}</h3>
                    </div>
                    <span className="text-[10px] font-black text-brand-600 bg-brand-50 px-2.5 py-1 rounded-full">{stageClients.length}</span>
                  </div>

                  <div className={`flex-1 overflow-y-auto space-y-4 p-3 rounded-3xl bg-gray-100/60 border-2 border-transparent transition-all ${draggedClientId ? 'border-dashed border-brand-300' : ''} custom-scroll`}>
                    {stageClients.map(client => {
                        const totalDays = calculateDaysElapsed(client.createdAt);
                        const isDelivered = client.currentStageId === '7';
                        const status = getStatusInfo(totalDays, isDelivered);

                        const stageEntryStr = (client.stageHistory[client.currentStageId] as any) || client.createdAt;
                        const stageEntry = new Date(stageEntryStr);
                        const daysInStage = Math.floor(Math.abs(new Date().getTime() - stageEntry.getTime()) / (1000 * 60 * 60 * 24));

                        // Score Logic
                        let score = 5;
                        if (totalDays > 120) score -= 2; else if (totalDays > 90) score -= 1;
                        if (daysInStage > 30) score -= 2; else if (daysInStage > 15) score -= 1;
                        score = Math.max(1, score);

                        // Layout Pipeline Card (Especial para Entregue)
                        if (isDelivered) {
                            return (
                                <div 
                                    key={client.id} 
                                    draggable 
                                    onDragStart={() => onDragStart(client.id)}
                                    onClick={() => onSelectClient(client)} 
                                    className="bg-white p-5 rounded-[2.2rem] border-2 border-emerald-500 shadow-lg hover:shadow-2xl transition-all cursor-grab active:cursor-grabbing group relative overflow-hidden flex flex-col gap-3 h-[420px]"
                                >
                                    <div className="flex justify-between items-start">
                                        <div className="flex items-center gap-3 overflow-hidden">
                                            <div className="bg-emerald-500 text-white p-2.5 rounded-2xl shadow-md shrink-0"><Trophy size={18} /></div>
                                            <div className="overflow-hidden">
                                                <h4 className="font-black text-brand-900 uppercase text-[11px] leading-tight truncate">{client.name}</h4>
                                                <div className="flex gap-0.5 mt-1">
                                                    {[1,2,3,4,5].map(s => <Star key={s} size={9} fill={s <= score ? "#dbb832" : "transparent"} className={s <= score ? "text-gold-500" : "text-gray-100"} />)}
                                                </div>
                                            </div>
                                        </div>
                                        <button onClick={(e) => { e.stopPropagation(); if(confirm("Excluir?")) onDeleteClient(client.id); }} className="p-1.5 bg-gray-50 text-gray-400 hover:text-red-500 rounded-lg transition shrink-0"><Trash2 size={12} /></button>
                                    </div>

                                    {/* Badge Estilo Filtro - Pipeline */}
                                    <div className="bg-emerald-600 text-white text-[9px] font-black uppercase tracking-widest py-1.5 px-3 rounded-full text-center shadow-md border border-emerald-700">
                                        ENTREGUE NO PRAZO
                                    </div>

                                    <div className="grid grid-cols-2 gap-2 text-[9px] font-bold">
                                        <div className="bg-gray-50 p-2.5 rounded-xl border border-gray-100">
                                            <span className="text-[7px] font-black text-gray-400 uppercase block mb-0.5">Início</span>
                                            <span className="text-brand-900">{new Date(client.createdAt).toLocaleDateString('pt-BR')}</span>
                                        </div>
                                        <div className="bg-brand-900 p-2.5 rounded-xl border border-brand-800 text-white">
                                            <span className="text-[7px] font-black text-brand-300 uppercase block mb-0.5">Final</span>
                                            <span>{new Date(client.stageHistory['7']).toLocaleDateString('pt-BR')}</span>
                                        </div>
                                    </div>

                                    {/* Histórico Compacto com Scroll no Pipeline */}
                                    <div className="flex-1 flex flex-col min-h-0 bg-gray-50/50 rounded-[1.5rem] p-3 border border-gray-100 overflow-hidden mt-1">
                                        <span className="text-[7px] font-black text-gray-400 uppercase tracking-widest mb-2 px-1">Linha do Tempo</span>
                                        <div className="overflow-y-auto space-y-1.5 custom-scroll pr-1 flex-1">
                                            {Object.entries(client.stageHistory).reverse().map(([id, date]) => (
                                                <div key={id} className="flex items-center gap-2 bg-white p-2 rounded-lg border border-gray-50 shadow-sm">
                                                    <CheckCircle2 size={10} className="text-emerald-500 shrink-0" />
                                                    <div className="overflow-hidden">
                                                      <span className="text-[8px] font-black text-brand-900 uppercase truncate block">{STAGES.find(s => s.id === id)?.title}</span>
                                                      <span className="text-[7px] text-gray-400 font-bold block">{new Date(date as string).toLocaleDateString('pt-BR')}</span>
                                                    </div>
                                                </div>
                                            ))}
                                        </div>
                                    </div>
                                </div>
                            );
                        }

                        // Pipeline Card Ativo (Original)
                        const startD = new Date(client.createdAt);
                        const deadlineD = new Date(startD);
                        deadlineD.setDate(deadlineD.getDate() + 120);
                        const triggers = [];
                        if (totalDays <= 90) triggers.push(91 - totalDays); else if (totalDays <= 120) triggers.push(121 - totalDays);
                        if (daysInStage <= 15) triggers.push(16 - daysInStage); else if (daysInStage <= 30) triggers.push(31 - daysInStage);
                        const daysToLoseStar = triggers.length > 0 ? Math.min(...triggers) : null;

                        return (
                            <div 
                                key={client.id} 
                                draggable 
                                onDragStart={() => onDragStart(client.id)}
                                onClick={() => onSelectClient(client)} 
                                className={`bg-white p-5 rounded-[2.2rem] border-2 shadow-sm hover:shadow-xl transition-all cursor-grab active:cursor-grabbing group relative overflow-hidden flex flex-col min-h-[160px] ${totalDays > 120 ? 'border-red-100' : totalDays > 75 ? 'border-amber-100' : 'border-white'}`}
                            >
                                <div className="flex justify-between items-start mb-4">
                                    <div className="flex items-center gap-3">
                                        <div className="relative flex h-3 w-3">
                                          <span className={`animate-ping absolute inline-flex h-full w-full rounded-full opacity-75 ${status.dot}`}></span>
                                          <span className={`relative inline-flex rounded-full h-3 w-3 ${status.dot}`}></span>
                                        </div>
                                        <div>
                                            <h4 className="font-black text-brand-900 uppercase text-[11px] group-hover:text-brand-600 leading-none truncate max-w-[150px]">{client.name}</h4>
                                            <div className="flex gap-0.5 mt-2">
                                              {[1,2,3,4,5].map(s => <Star key={s} size={9} fill={s <= score ? "#dbb832" : "transparent"} className={s <= score ? "text-gold-500" : "text-gray-100"} />)}
                                            </div>
                                        </div>
                                    </div>
                                    <button onClick={(e) => { e.stopPropagation(); if(confirm("Excluir?")) onDeleteClient(client.id); }} className="text-gray-200 hover:text-red-500 transition opacity-0 group-hover:opacity-100"><Trash2 size={12} /></button>
                                </div>
                                <div className="grid grid-cols-2 gap-y-3 mb-4">
                                  <div className="flex flex-col">
                                    <span className="text-[7px] font-black text-gray-400 uppercase tracking-widest">Prazo Final</span>
                                    <span className="text-[10px] font-black text-brand-900">{deadlineD.toLocaleDateString('pt-BR', {day: '2-digit', month: '2-digit', year: '2-digit'})}</span>
                                  </div>
                                  <div className="flex flex-col text-right">
                                    <span className="text-[7px] font-black text-gray-400 uppercase tracking-widest">Na Etapa</span>
                                    <span className="text-[10px] font-black text-brand-900">{daysInStage} dias</span>
                                  </div>
                                </div>
                                <div className="mt-auto flex items-center justify-between border-t border-gray-50 pt-3">
                                  <div className="flex items-center gap-1.5 overflow-hidden">
                                    <Timer size={10} className="text-gray-300 shrink-0" />
                                    <span className="text-[8px] font-black text-gray-400 uppercase truncate">{daysToLoseStar !== null ? `Estrela: ${daysToLoseStar}d` : 'Score Máx.'}</span>
                                  </div>
                                  <div className={`text-[8px] font-black px-2.5 py-1 rounded-full border whitespace-nowrap ${status.color} ${status.bg} border-current uppercase tracking-tight`}>{status.label.replace(/🟢|🟡|🔴/g, '').trim()}</div>
                                </div>
                            </div>
                        );
                    })}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

const ClientCardItem = ({ client, onEdit, onDelete, calculateDays, getStatus }: any) => {
    const isDelivered = client.currentStageId === '7';
    const totalDays = calculateDays(client.createdAt, isDelivered ? client.stageHistory['7'] : undefined);
    const status = getStatus(totalDays, isDelivered);
    const currentStage = STAGES.find(s => s.id === client.currentStageId);
    const Icon = STEP_ICONS[currentStage?.stepNumber || '1'];

    const stageEntryStr = (client.stageHistory[client.currentStageId] as any) || client.createdAt;
    const stageEntry = new Date(stageEntryStr);
    const daysInStage = Math.floor(Math.abs(new Date().getTime() - stageEntry.getTime()) / (1000 * 60 * 60 * 24));

    let score = 5;
    if (totalDays > 120) score -= 2; else if (totalDays > 90) score -= 1;
    if (!isDelivered) {
        if (daysInStage > 30) score -= 2; else if (daysInStage > 15) score -= 1;
    }
    score = Math.max(1, score);

    const startD = new Date(client.createdAt);
    const deadlineD = new Date(startD);
    deadlineD.setDate(deadlineD.getDate() + 120);
    const remainingDays = Math.max(0, 120 - totalDays);
    const slaPercent = Math.min(100, (totalDays / 120) * 100);

    const completionDateStr = isDelivered ? client.stageHistory['7'] : null;
    const completionDate = completionDateStr ? new Date(completionDateStr) : null;
    const daysDiffSLA = 120 - totalDays;
    const isEarly = daysDiffSLA >= 0;

    const historyEntries = Object.entries(client.stageHistory)
      .map(([id, date]) => ({
        stage: STAGES.find(s => s.id === id),
        date: new Date(date as string)
      }))
      .filter(e => e.stage)
      .sort((a, b) => b.date.getTime() - a.date.getTime());

    if (isDelivered) {
      return (
        <div className="bg-white border-2 border-emerald-500 rounded-[2.5rem] p-7 hover:shadow-2xl transition-all group relative flex flex-col gap-5 overflow-hidden h-[540px]">
            <div className="flex justify-between items-start">
                <div className="flex gap-4 items-center overflow-hidden">
                    <div className="bg-emerald-500 text-white p-4 rounded-[2rem] shadow-lg border-2 border-emerald-100 shrink-0">
                      <Trophy size={28} />
                    </div>
                    <div className="overflow-hidden">
                        <h3 className="font-black text-brand-900 uppercase text-lg truncate leading-tight">{client.name}</h3>
                        <div className={`mt-2 inline-flex items-center px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest shadow-md transition-all border ${isEarly ? 'bg-emerald-600 text-white border-emerald-700' : 'bg-red-600 text-white border-red-700'}`}>
                          {isEarly ? `ENTREGUE NO PRAZO (-${Math.abs(daysDiffSLA)}D)` : `ENTREGUE EM ATRASO (+${Math.abs(daysDiffSLA)}D)`}
                        </div>
                    </div>
                </div>
                <div className="flex gap-1.5 shrink-0">
                  <button onClick={onEdit} className="p-2.5 bg-gray-50 hover:bg-brand-600 text-gray-400 hover:text-white rounded-2xl transition-all"><Edit3 size={18}/></button>
                  <button onClick={onDelete} className="p-2.5 bg-gray-50 hover:bg-red-600 text-gray-400 hover:text-white rounded-2xl transition-all"><Trash2 size={18}/></button>
                </div>
            </div>

            <div className="bg-emerald-50/50 rounded-[2rem] p-5 border border-emerald-100/50 flex items-center justify-between shadow-inner">
              <div className="flex flex-col">
                <span className="text-[8px] font-black text-emerald-600 uppercase tracking-widest mb-1.5">Avaliação de Qualidade</span>
                <div className="flex gap-0.5">
                  {[1,2,3,4,5].map(s => <Star key={s} size={16} fill={s <= score ? "#dbb832" : "transparent"} className={s <= score ? "text-gold-500" : "text-gray-200"} />)}
                </div>
              </div>
              <div className="text-right">
                <span className="text-[8px] font-black text-gray-400 uppercase tracking-widest mb-1.5 block">Jornada Total</span>
                <span className="text-2xl font-black text-brand-900 leading-none">{totalDays} <span className="text-xs text-gray-400 uppercase">dias</span></span>
              </div>
            </div>

            <div className="grid grid-cols-2 gap-3">
              <div className="bg-gray-50 p-4 rounded-2xl border border-gray-100">
                <span className="text-[7px] font-black text-gray-400 uppercase tracking-widest block mb-1">Iniciado em</span>
                <span className="text-[12px] font-bold text-brand-900">{startD.toLocaleDateString('pt-BR')}</span>
              </div>
              <div className="bg-brand-900 p-4 rounded-2xl border border-brand-800 text-white shadow-md">
                <span className="text-[7px] font-black text-brand-300 uppercase tracking-widest block mb-1">Finalizado em</span>
                <span className="text-[12px] font-bold">{completionDate?.toLocaleDateString('pt-BR')}</span>
              </div>
            </div>

            <div className="flex-1 flex flex-col min-h-0 bg-gray-50/30 p-4 rounded-[2rem] border border-gray-100 overflow-hidden shadow-inner">
               <span className="text-[9px] font-black text-gray-400 uppercase tracking-[0.2em] mb-3 px-1">Histórico da Jornada</span>
               <div className="overflow-y-auto pr-2 space-y-2.5 custom-scroll flex-1">
                 {historyEntries.map((entry, idx) => (
                   <div key={idx} className="flex items-center gap-3 bg-white p-3 rounded-xl border border-gray-50 shadow-sm hover:border-brand-100 transition-colors">
                      <div className="shrink-0 bg-emerald-50 p-1.5 rounded-lg border border-emerald-100/50">
                        <CheckCircle2 size={12} className="text-emerald-500" />
                      </div>
                      <div className="flex-1 overflow-hidden">
                        <p className="text-[9px] font-black text-brand-900 uppercase truncate leading-tight">{entry.stage?.title}</p>
                        <p className="text-[7px] text-gray-400 font-bold">{entry.date.toLocaleDateString('pt-BR')} às {entry.date.toLocaleTimeString('pt-BR', {hour: '2-digit', minute: '2-digit'})}</p>
                      </div>
                   </div>
                 ))}
               </div>
            </div>

            <div className="pt-3 border-t border-gray-100 flex items-center justify-between text-emerald-600 shrink-0">
                <div className="flex items-center gap-2">
                  <CheckCircle size={18} />
                  <span className="text-[10px] font-black uppercase tracking-[0.2em]">Operação Finalizada</span>
                </div>
                <div className="bg-emerald-50 p-2 rounded-xl border border-emerald-100">
                   <ChevronRight size={16} />
                </div>
            </div>
        </div>
      );
    }

    return (
        <div className="bg-white border border-gray-100 rounded-[2.5rem] p-7 hover:border-brand-400 cursor-pointer transition-all shadow-sm hover:shadow-2xl group relative overflow-hidden flex flex-col gap-6">
            <div className="flex justify-between items-start">
                <div className="flex gap-4 items-center">
                    <div className="bg-brand-50 p-4 rounded-3xl group-hover:bg-brand-600 group-hover:text-white transition-all shadow-sm">
                      <User size={26} />
                    </div>
                    <div>
                        <h3 className="font-black text-brand-900 uppercase text-lg truncate max-w-[180px] leading-tight">{client.name}</h3>
                        <div className="flex gap-0.5 mt-1.5">
                          {[1,2,3,4,5].map(s => <Star key={s} size={12} fill={s <= score ? "#dbb832" : "transparent"} className={s <= score ? "text-gold-500" : "text-gray-100"} />)}
                        </div>
                    </div>
                </div>
                <div className="flex gap-2">
                  <button onClick={onEdit} className="p-2.5 bg-gray-50 hover:bg-brand-600 text-gray-400 hover:text-white rounded-2xl transition-all"><Edit3 size={18}/></button>
                  <button onClick={onDelete} className="p-2.5 bg-gray-50 hover:bg-red-600 text-gray-400 hover:text-white rounded-2xl transition-all"><Trash2 size={18}/></button>
                </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              <div className="flex items-center gap-3 bg-gray-50/80 px-4 py-2.5 rounded-2xl border border-gray-100">
                <span className="text-[9px] font-black text-brand-600 uppercase tracking-widest bg-brand-100 px-1.5 py-0.5 rounded-md">PRGD</span>
                <span className="text-[11px] font-black text-brand-900 uppercase tracking-tight">{client.prgd || '---'}</span>
              </div>
              <div className="flex items-center gap-3 bg-gray-50/80 px-4 py-2.5 rounded-2xl border border-gray-100">
                <Phone size={14} className="text-brand-600" />
                <span className="text-[11px] font-bold text-brand-900">{client.phone || '(00) 00000-0000'}</span>
              </div>
            </div>

            <div className="space-y-2">
              <div className="flex justify-between items-center text-[9px] font-black uppercase tracking-widest text-gray-400">
                <span className="flex items-center gap-1"><Timer size={10} /> Jornada SLA 120 dias</span>
                <span className={remainingDays <= 15 ? 'text-red-600' : 'text-brand-900'}>{remainingDays} dias restantes</span>
              </div>
              <div className="h-2.5 w-full bg-gray-100 rounded-full overflow-hidden border border-gray-50 relative">
                <div 
                  className={`h-full transition-all duration-1000 ${totalDays > 120 ? 'bg-red-500' : totalDays > 75 ? 'bg-amber-500' : 'bg-emerald-500'}`} 
                  style={{ width: `${slaPercent}%` }}
                ></div>
              </div>
              <div className="flex justify-between text-[8px] font-black text-gray-300 uppercase">
                <span>Iniciado: {startD.toLocaleDateString('pt-BR')}</span>
                <span>Entrega: {deadlineD.toLocaleDateString('pt-BR')}</span>
              </div>
            </div>

