import React, { useState, useEffect } from 'react';
import { Timeline } from './components/Timeline.tsx';
import { ContentGenerator } from './components/ContentGenerator.tsx';
import { ClientList } from './components/ClientList.tsx';
import { Dashboard } from './components/Dashboard.tsx';
import { Login } from './components/Login.tsx';
import { STAGES } from './constants.ts';
import { Client, Stage } from './types.ts';
import { ArrowLeft, BarChart3, LayoutList, Zap, LogOut } from 'lucide-react';
import { generateTemplateContent } from './services/templateService.ts';

export default function App() {
  const [userMode, setUserMode] = useState<'admin' | 'visitor' | null>(null);
  const [view, setView] = useState<'list' | 'detail' | 'dashboard'>('list');
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [currentStageId, setCurrentStageId] = useState<string>(STAGES[0].id);
  const [clients, setClients] = useState<Client[]>([]);

  useEffect(() => {
    const saved = localStorage.getItem('gev_loop_clients');
    if (saved) {
      try {
        setClients(JSON.parse(saved));
      } catch (e) {
        console.error("Erro ao carregar dados", e);
      }
    }

    const savedUser = localStorage.getItem('gev_loop_user');
    if (savedUser) {
      setUserMode(savedUser as 'admin' | 'visitor');
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('gev_loop_clients', JSON.stringify(clients));
  }, [clients]);

  const handleLogin = (mode: 'admin' | 'visitor') => {
    setUserMode(mode);
    localStorage.setItem('gev_loop_user', mode);
  };

  const handleLogout = () => {
    setUserMode(null);
    localStorage.removeItem('gev_loop_user');
    setView('list');
    setSelectedClientId(null);
  };

  const handleCreateClient = (newClient: Client) => {
    setClients(prev => [newClient, ...prev]);
    handleSelectClient(newClient);

    const firstStage = STAGES[0];
    if (firstStage && firstStage.template && newClient.phone) {
      const generated = generateTemplateContent(firstStage, newClient, {});
      const cleanPhone = newClient.phone.replace(/\D/g, '');
      const phoneWithCountry = cleanPhone.startsWith('55') ? cleanPhone : `55${cleanPhone}`;
      const encodedText = encodeURIComponent(generated.body);
      window.open(`https://api.whatsapp.com/send?phone=${phoneWithCountry}&text=${encodedText}`, '_blank');
    }
  };

  const handleEditClient = (updatedClient: Client) => {
    setClients(prev => prev.map(c => c.id === updatedClient.id ? updatedClient : c));
  };

  const handleDeleteClient = (clientId: string) => {
    setClients(prev => prev.filter(c => c.id !== clientId));
    if (selectedClientId === clientId) {
      setView('list');
      setSelectedClientId(null);
    }
  };

  const handleSelectClient = (client: Client) => {
    setSelectedClientId(client.id);
    setCurrentStageId(client.currentStageId || STAGES[0].id);
    setView('detail');
  };

  const handleUpdateNotes = (notes: string) => {
    if (!selectedClientId) return;
    setClients(prev => prev.map(c => 
      c.id === selectedClientId ? { ...c, additionalNotes: notes } : c
    ));
  };

  const handleUpdateClientStage = (clientId: string, newStageId: string, stageData?: Record<string, string>) => {
    const now = new Date().toISOString();
    setClients(prev => prev.map(c => {
      if (c.id === clientId) {
        return { 
          ...c, 
          currentStageId: newStageId, 
          stageData: { ...c.stageData, ...stageData },
          stageHistory: { ...c.stageHistory, [newStageId]: now }
        };
      }
      return c;
    }));
    if (selectedClientId === clientId) {
      setCurrentStageId(newStageId);
    }
  };

  if (!userMode) {
    return <Login onLogin={handleLogin} />;
  }

  const selectedClient = clients.find(c => c.id === selectedClientId);
  const currentStage = STAGES.find(s => s.id === currentStageId) || STAGES[0];

  return (
    <div className="h-screen bg-gray-50 flex flex-col overflow-hidden font-sans">
      <header className="bg-brand-900 h-16 sm:h-20 shrink-0 shadow-lg relative z-50 border-b border-brand-800">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 h-full flex items-center justify-between">
          <div className="flex items-center gap-4">
            {view === 'detail' && (
              <button onClick={() => setView('list')} className="p-2 hover:bg-white/10 rounded-full text-gold-400 transition">
                <ArrowLeft size={20} />
              </button>
            )}
            <div className="flex flex-col">
              <h1 className="text-xl sm:text-2xl font-black text-white uppercase tracking-tighter leading-none">
                LOOP <span className="text-gold-500">ENERGIA</span>
              </h1>
              <p className="text-[8px] text-brand-400 uppercase tracking-widest font-bold mt-1">Gestão de Experiência do Cliente</p>
            </div>
          </div>

          <div className="flex items-center gap-4">
             <nav className="flex bg-brand-800/40 p-1 rounded-xl border border-brand-700/50">
                <button 
                  onClick={() => setView('list')}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${view !== 'dashboard' && view !== 'detail' ? 'bg-brand-600 text-white shadow-lg' : 'text-brand-300 hover:text-white'}`}
                >
                  <LayoutList size={14} /> <span className="hidden sm:inline">Carteira</span>
                </button>
                <button 
                  onClick={() => setView('dashboard')}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${view === 'dashboard' ? 'bg-brand-600 text-white shadow-lg' : 'text-brand-300 hover:text-white'}`}
                >
                  <BarChart3 size={14} /> <span className="hidden sm:inline">Dashboard</span>
                </button>
             </nav>
             <button 
               onClick={handleLogout}
               className="bg-brand-800 p-2.5 rounded-full text-gold-400 border border-brand-700 hover:bg-red-900/40 hover:text-red-400 transition-colors"
               title="Sair do Sistema"
             >
               <LogOut size={18} />
             </button>
          </div>
        </div>
      </header>

      <main className="flex-1 overflow-hidden max-w-7xl mx-auto w-full px-4 sm:px-6 py-4">
        {view === 'list' ? (
          <ClientList 
            clients={clients} 
            onSelectClient={handleSelectClient} 
            onCreateClient={handleCreateClient}
            onEditClient={handleEditClient}
            onDeleteClient={handleDeleteClient}
            onUpdateClientStage={handleUpdateClientStage}
            isAdmin={userMode === 'admin'}
          />
        ) : view === 'dashboard' ? (
          <Dashboard clients={clients} />
        ) : (
          <div className="flex flex-col h-full gap-4">
            <Timeline 
              currentStageId={currentStageId} 
              onSelectStage={(s) => setCurrentStageId(s.id)} 
            />
            <div className="flex-1 min-h-0">
              {selectedClient && (
                <ContentGenerator 
                  stage={currentStage}
                  client={selectedClient}
                  onUpdateNotes={handleUpdateNotes}
                  onUpdateClientStage={handleUpdateClientStage}
                />
              )}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

import React, { useState } from 'react';
import { Client, Stage } from '../types.ts';
import { Plus, Search, User, Zap, List, Kanban, X, ChevronRight, Clock, Star } from 'lucide-react';
import { STAGES, STEP_ICONS } from '../constants.ts';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onEditClient: (client: Client) => void;
  onDeleteClient: (clientId: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
  isAdmin?: boolean;
}

type ViewMode = 'list' | 'pipeline';
type FilterStatus = 'ativos' | 'entregues' | 'noprazo' | 'atencao' | 'urgente' | null;

interface PendingTransition {
  client: Client;
  targetStage: Stage;
  fieldValues: Record<string, string>;
}

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onEditClient, onDeleteClient, onUpdateClientStage, isAdmin = true }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<ViewMode>('list'); 
  const [statusFilter, setStatusFilter] = useState<FilterStatus>(null);
  const [draggedClientId, setDraggedClientId] = useState<string | null>(null);
  const [pendingTransition, setPendingTransition] = useState<PendingTransition | null>(null);

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '', clientNumber: '', prgd: '', phone: '',
  });

  const formatPhone = (value: string) => {
    if (!value) return "";
    value = value.replace(/\D/g, "");
    value = value.substring(0, 11);
    if (value.length > 10) return value.replace(/^(\d{2})(\d{5})(\d{4}).*/, "($1) $2-$3");
    if (value.length > 5) return value.replace(/^(\d{2})(\d{4})(\d{0,4}).*/, "($1) $2-$3");
    if (value.length > 2) return value.replace(/^(\d{2})(\d{0,5})/, "($1) $2");
    return value.replace(/^(\d*)/, "($1");
  };

  const formatPRGD = (value: string) => {
    if (!value) return "";
    value = value.replace(/\D/g, "");
    value = value.substring(0, 5);
    if (value.length > 3) return value.replace(/^(\d{3})(\d{0,2})/, "$1-$2");
    return value;
  };

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    if (!startStr) return 0;
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const getStatusInfo = (days: number, isDelivered: boolean) => {
    if (isDelivered) return { label: '🟢 ENTREGUE', color: 'text-green-600', bg: 'bg-green-50', dot: 'bg-green-500', key: 'entregues' };
    if (days > 120) return { label: '🔴 URGENTE', color: 'text-red-600', bg: 'bg-red-50', dot: 'bg-red-500', key: 'urgente' };
    if (days > 75) return { label: '🟡 ATENÇÃO', color: 'text-amber-500', bg: 'bg-amber-50', dot: 'bg-amber-500', key: 'atencao' };
    return { label: '🟢 NO PRAZO', color: 'text-emerald-600', bg: 'bg-emerald-50', dot: 'bg-emerald-500', key: 'noprazo' };
  };

  const counts = clients.reduce((acc, c) => {
    const isDelivered = c.currentStageId === '7';
    const days = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);
    const info = getStatusInfo(days, isDelivered);
    if (!isDelivered) acc.ativos++;
    acc[info.key as 'entregues' | 'urgente' | 'atencao' | 'noprazo']++;
    return acc;
  }, { ativos: 0, entregues: 0, noprazo: 0, atencao: 0, urgente: 0 });

  const filteredClients = clients.filter(c => {
    const matchesSearch = c.name.toLowerCase().includes(searchTerm.toLowerCase()) || c.prgd.toLowerCase().includes(searchTerm.toLowerCase());
    if (!matchesSearch) return false;
    if (!statusFilter) return true;
    const isDelivered = c.currentStageId === '7';
    const days = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);
    const info = getStatusInfo(days, isDelivered);
    if (statusFilter === 'ativos') return !isDelivered;
    return info.key === statusFilter;
  });

  const onDrop = (stageId: string) => {
    if (draggedClientId && isAdmin) {
      const client = clients.find(c => c.id === draggedClientId);
      const targetStage = STAGES.find(s => s.id === stageId);
      if (client && targetStage) {
        const missingFields = (targetStage.requiredFields || []).filter(f => !client.stageData?.[f]);
        if (missingFields.length > 0) {
          setPendingTransition({ client, targetStage, fieldValues: missingFields.reduce((acc, f) => ({ ...acc, [f]: '' }), {}) });
        } else {
          onUpdateClientStage(draggedClientId, stageId);
        }
      }
      setDraggedClientId(null);
    }
  };

  const closeModal = () => {
    setIsCreating(false);
    setFormData({ name: '', clientNumber: '', prgd: '', phone: '' });
  };

  return (
    <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-200 h-full flex flex-col relative overflow-hidden">

      {pendingTransition && (
        <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-md z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] p-8 max-w-md w-full shadow-2xl">
            <h2 className="text-xl font-black text-brand-900 mb-4">Informação Necessária</h2>
            {Object.keys(pendingTransition.fieldValues).map(f => (
              <input key={f} className="w-full p-4 bg-gray-50 border rounded-2xl mb-4" placeholder={f} onChange={e => setPendingTransition({...pendingTransition, fieldValues: {...pendingTransition.fieldValues, [f]: e.target.value}})} />
            ))}
            <button onClick={() => { onUpdateClientStage(pendingTransition.client.id, pendingTransition.targetStage.id, pendingTransition.fieldValues); setPendingTransition(null); }} className="w-full bg-brand-600 text-white py-4 rounded-2xl font-black uppercase">Confirmar</button>
          </div>
        </div>
      )}

      {isCreating && (
          <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-4">
              <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-xl overflow-hidden">
                  <div className="p-8 border-b bg-gray-50 flex justify-between items-center">
                      <h2 className="text-2xl font-black text-brand-600 uppercase">Novo Cliente</h2>
                      <button onClick={closeModal} className="p-2 text-gray-400"><X size={24} /></button>
                  </div>
                  <form onSubmit={(e) => { e.preventDefault(); onCreateClient({ id: Date.now().toString(), name: formData.name!, clientNumber: '', prgd: formData.prgd!, phone: formData.phone!, projectName: '', additionalNotes: '', currentStageId: STAGES[0].id, createdAt: new Date().toISOString(), stageHistory: {}, stageData: {} }); closeModal(); }} className="p-8 space-y-4">
                      <input required className="w-full p-4 bg-gray-50 border rounded-2xl" placeholder="Nome do Cliente" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
                      <input required className="w-full p-4 bg-gray-50 border rounded-2xl" placeholder="WhatsApp" value={formData.phone} onChange={e => setFormData({...formData, phone: formatPhone(e.target.value)})} />
                      <input required className="w-full p-4 bg-gray-50 border rounded-2xl" placeholder="PRGD" value={formData.prgd} onChange={e => setFormData({...formData, prgd: formatPRGD(e.target.value)})} />
                      <button type="submit" className="w-full bg-brand-600 text-white py-4 rounded-2xl font-black uppercase">Cadastrar</button>
                  </form>
              </div>
          </div>
      )}

      <div className="p-6 border-b flex flex-col gap-6 bg-gray-50/50">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <div>
                <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">Gestão de Carteira</h2>
                <div className="flex flex-wrap items-center gap-2 mt-2">
                    <button onClick={() => setStatusFilter('ativos')} className={`text-[9px] font-black px-3 py-1 rounded-full uppercase border ${statusFilter === 'ativos' ? 'bg-brand-600 text-white shadow-md' : 'bg-white text-gray-400'}`}>{counts.ativos} Ativos</button>
                    <button onClick={() => setStatusFilter('noprazo')} className={`text-[9px] font-black px-3 py-1 rounded-full uppercase border ${statusFilter === 'noprazo' ? 'bg-emerald-600 text-white shadow-md' : 'bg-white text-emerald-500'}`}>{counts.noprazo} No Prazo</button>
                    <button onClick={() => setStatusFilter('atencao')} className={`text-[9px] font-black px-3 py-1 rounded-full uppercase border ${statusFilter === 'atencao' ? 'bg-amber-500 text-white shadow-md' : 'bg-white text-amber-500'}`}>{counts.atencao} Atenção</button>
                    <button onClick={() => setStatusFilter('urgente')} className={`text-[9px] font-black px-3 py-1 rounded-full uppercase border ${statusFilter === 'urgente' ? 'bg-red-600 text-white shadow-md' : 'bg-white text-red-500'}`}>{counts.urgente} Urgente</button>
                    <button onClick={() => setStatusFilter('entregues')} className={`text-[9px] font-black px-3 py-1 rounded-full uppercase border ${statusFilter === 'entregues' ? 'bg-green-600 text-white shadow-md' : 'bg-white text-gray-400'}`}>{counts.entregues} Entregues</button>
                    <button onClick={() => setStatusFilter(null)} className="text-[9px] font-black px-3 py-1 rounded-full uppercase border bg-gray-100 text-gray-400">Limpar</button>
                </div>
            </div>

            <div className="flex bg-gray-100 p-1 rounded-2xl border">
                <button onClick={() => setViewMode('list')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'list' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-400'}`}><List size={14} /> Lista</button>
                <button onClick={() => setViewMode('pipeline')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'pipeline' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-400'}`}><Kanban size={14} /> Pipeline</button>
            </div>
        </div>

        <div className="flex flex-col md:flex-row gap-4">
            <div className="relative flex-1">
                <Search className="absolute left-4 top-3.5 text-gray-300" size={18} />
                <input placeholder="Filtrar por nome ou PRGD..." className="w-full pl-12 p-3.5 rounded-2xl border bg-white outline-none focus:border-brand-300 font-medium text-sm" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
            </div>
            {isAdmin && <button onClick={() => setIsCreating(true)} className="bg-brand-600 text-white px-8 py-3.5 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl flex items-center justify-center gap-2"><Plus size={18} /> Novo Cliente</button>}
        </div>
      </div>

      <div className="flex-1 overflow-hidden bg-gray-100/30">
        {viewMode === 'list' ? (
          <div className="p-6 overflow-auto h-full grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredClients.map(c => <div key={c.id} onClick={() => onSelectClient(c)}><ClientCardItem client={c} isAdmin={isAdmin} calculateDays={calculateDaysElapsed} getStatus={getStatusInfo} /></div>)}
          </div>
        ) : (
          <div className="flex overflow-x-auto h-full p-6 gap-6 snap-x custom-scroll">
            {STAGES.map(stage => {
              const stageClients = filteredClients.filter(c => c.currentStageId === stage.id);
              const Icon = STEP_ICONS[stage.stepNumber] || Zap;
              return (
                <div key={stage.id} className="min-w-[320px] flex flex-col h-full snap-start" onDragOver={(e) => e.preventDefault()} onDrop={() => onDrop(stage.id)}>
                  <div className="flex items-center justify-between mb-4 px-2">
                    <div className="flex items-center gap-3">
                        <div className="bg-brand-900 text-gold-400 p-2.5 rounded-xl border border-brand-800"><Icon size={16} /></div>
                        <h3 className="text-[11px] font-black uppercase text-brand-900 tracking-tight">{stage.title}</h3>
                    </div>
                    <span className="text-[10px] font-black text-brand-600 bg-brand-50 px-2.5 py-1 rounded-full">{stageClients.length}</span>
                  </div>
                  <div className="flex-1 overflow-y-auto space-y-4 p-3 rounded-3xl bg-gray-100/60 custom-scroll">
                    {stageClients.map(client => (
                      <div key={client.id} draggable={isAdmin} onDragStart={() => setDraggedClientId(client.id)} onClick={() => onSelectClient(client)} className="bg-white p-5 rounded-[2.2rem] border-2 border-white shadow-sm hover:shadow-xl transition-all cursor-grab active:cursor-grabbing">
                         <h4 className="font-black text-brand-900 uppercase text-[11px] truncate">{client.name}</h4>
                         <div className="flex justify-between items-center mt-3 pt-3 border-t border-gray-50">
                            <span className="text-[8px] font-black text-gray-400 uppercase">PRGD: {client.prgd}</span>
                            <div className="flex gap-0.5">
                               {[1,2,3,4,5].map(s => <Star key={s} size={8} fill={s <= 4 ? "#dbb832" : "transparent"} className="text-gold-400" />)}
                            </div>
                         </div>
                      </div>
                    ))}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

const ClientCardItem = ({ client, calculateDays, getStatus, isAdmin }: any) => {
    const isDelivered = client.currentStageId === '7';
    const totalDays = calculateDays(client.createdAt, isDelivered ? client.stageHistory['7'] : undefined);
    const status = getStatus(totalDays, isDelivered);
    const currentStage = STAGES.find(s => s.id === client.currentStageId);
    return (
        <div className="bg-white border border-gray-100 rounded-[2.5rem] p-6 hover:shadow-xl transition-all cursor-pointer group flex flex-col gap-4">
            <div className="flex justify-between items-start">
                <div className="flex gap-3 items-center">
                    <div className="bg-brand-50 p-3 rounded-2xl group-hover:bg-brand-600 group-hover:text-white transition-all"><User size={20} /></div>
                    <h3 className="font-black text-brand-900 uppercase text-sm truncate max-w-[140px] leading-tight">{client.name}</h3>
                </div>
                <div className={`px-3 py-1 rounded-full text-[8px] font-black uppercase border ${status.color} ${status.bg} border-current`}>{status.label.replace(/🟢|🟡|🔴/g, '')}</div>
            </div>
            <div className="flex justify-between text-[10px] font-bold text-gray-400">
               <span>PRGD: {client.prgd || '---'}</span>
               <span className="flex items-center gap-1"><Clock size={10} /> {totalDays} dias</span>
            </div>
            <div className="pt-3 border-t border-gray-50 flex items-center justify-between">
                <div className="flex items-center gap-2">
                    <div className="bg-brand-900 text-gold-400 p-2 rounded-lg"><Zap size={14} /></div>
                    <span className="text-[10px] font-black text-brand-900 uppercase truncate max-w-[120px]">{currentStage?.title}</span>
                </div>
                <ChevronRight size={16} className="text-gray-300" />
            </div>
        </div>
    );
};

import React, { useState, useEffect } from 'react';
import { Stage, Client, GeneratedContent } from '../types.ts';
import { generateTemplateContent } from '../services/templateService.ts';
import { 
  Copy, 
  Phone, 
  Zap, 
  Trophy, 
  Clock, 
  CheckCircle2, 
  ArrowRight,
} from 'lucide-react';

interface ContentGeneratorProps {
  stage: Stage;
  client: Client;
  onUpdateNotes: (notes: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

export const ContentGenerator: React.FC<ContentGeneratorProps> = ({ stage, client, onUpdateNotes, onUpdateClientStage }) => {
  const [fieldValues, setFieldValues] = useState<Record<string, string>>({});
  const [editableBody, setEditableBody] = useState('');

  useEffect(() => {
    setFieldValues(client.stageData || {});
  }, [stage.id, client.id]);

  useEffect(() => {
    const generated = generateTemplateContent(stage, client, { ...client.stageData, ...fieldValues });
    setEditableBody(generated.body);
  }, [fieldValues, stage, client]);

  const calculateMetrics = () => {
    const start = new Date(client.createdAt);
    const deadline = new Date(start);
    deadline.setDate(deadline.getDate() + 120);
    const isCompleted = client.currentStageId === '7';
    const now = isCompleted ? new Date(client.stageHistory['7']) : new Date();
    const totalDays = Math.floor(Math.abs(now.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
    const slaPercent = Math.min(100, (totalDays / 120) * 100);
    return { totalDays, slaPercent };
  };

  const metrics = calculateMetrics();

  if (stage.id === '7') {
    return (
      <div className="bg-white rounded-[2.5rem] shadow-2xl border border-gray-200 h-full overflow-hidden flex flex-col items-center justify-center p-12 text-center">
        <div className="bg-emerald-500 text-white p-8 rounded-[3rem] shadow-xl mb-8"><Trophy size={64} /></div>
        <h2 className="text-3xl font-black text-brand-900 uppercase tracking-tighter mb-4">{client.name}</h2>
        <p className="text-sm text-gray-400 font-bold uppercase tracking-widest mb-12">Projeto Concluído com Sucesso ✅</p>

        <div className="max-w-md w-full bg-gray-50 rounded-[2.5rem] p-8 border border-gray-100">
             <div className="w-16 h-16 bg-white rounded-full flex items-center justify-center text-emerald-500 mx-auto mb-6 shadow-sm"><CheckCircle2 size={32} /></div>
             <h4 className="text-sm font-black text-brand-900 uppercase tracking-tight mb-2">RELATÓRIO DE SLA</h4>
             <p className="text-[10px] font-bold text-gray-400 uppercase mb-6">Entrega finalizada em {metrics.totalDays} dias</p>
             <div className="w-full h-2 bg-white rounded-full overflow-hidden border">
                <div className="h-full bg-emerald-500" style={{width: `${metrics.slaPercent}%`}}></div>
             </div>
        </div>
      </div>
    );
  }

  return (
    <div className="bg-white rounded-[2.5rem] shadow-lg border border-gray-200 flex flex-col h-full overflow-hidden">
      <div className="bg-brand-600 p-6 flex justify-between items-center text-white shrink-0">
        <div className="flex items-center gap-4">
           <div className="bg-white/20 p-3 rounded-2xl backdrop-blur-sm"><Zap size={24} className="text-gold-400 fill-current" /></div>
           <div>
            <h2 className="text-xl font-black uppercase tracking-tight">Etapa {stage.stepNumber}: {stage.title}</h2>
            <p className="text-brand-100 text-xs font-bold uppercase tracking-wider">{stage.description}</p>
          </div>
        </div>
      </div>

      <div className="flex-1 p-8 flex flex-col gap-6 bg-white overflow-y-auto custom-scroll">
          <div className="flex-1 bg-gray-50 rounded-[2.5rem] border border-gray-100 overflow-hidden flex flex-col shadow-inner">
            <div className="px-8 py-4 border-b border-gray-100 bg-white/50 flex justify-between items-center shrink-0">
              <span className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em]">Visualização da Mensagem</span>
              <button onClick={() => navigator.clipboard.writeText(editableBody)} className="text-[10px] font-black text-brand-600 uppercase hover:underline flex items-center gap-2"><Copy size={14} /> Copiar</button>
            </div>
            <div className="flex-1 p-8 text-base font-sans font-medium leading-relaxed whitespace-pre-wrap text-slate-700">
                {editableBody}
            </div>
          </div>

          <div className="space-y-4">
            <button onClick={() => { const clean = client.phone.replace(/\D/g, ''); window.open(`https://api.whatsapp.com/send?phone=${clean.startsWith('55') ? clean : '55'+clean}&text=${encodeURIComponent(editableBody)}`, '_blank'); }} className="w-full py-6 bg-[#25D366] text-white rounded-[2rem] font-black uppercase tracking-widest flex items-center justify-center gap-4 transition-all shadow-xl hover:scale-[1.01]"><Phone size={24} fill="currentColor" /> Enviar Mensagem</button>
            {stage.id !== client.currentStageId && <button onClick={() => onUpdateClientStage(client.id, stage.id, fieldValues)} className="w-full py-5 bg-brand-900 text-white rounded-[2rem] font-black uppercase text-[11px] tracking-widest hover:bg-black transition-all flex items-center justify-center gap-3">Salvar e Avançar <ArrowRight size={16} /></button>}
          </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Client, Stage } from '../types.ts';
import { Plus, Search, User, Zap, List, Kanban, X, ChevronRight, Clock, Star } from 'lucide-react';
import { STAGES, STEP_ICONS } from '../constants.ts';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onEditClient: (client: Client) => void;
  onDeleteClient: (clientId: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
  isAdmin?: boolean;
}

type ViewMode = 'list' | 'pipeline';
type FilterStatus = 'ativos' | 'entregues' | 'noprazo' | 'atencao' | 'urgente' | null;

interface PendingTransition {
  client: Client;
  targetStage: Stage;
  fieldValues: Record<string, string>;
}

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onEditClient, onDeleteClient, onUpdateClientStage, isAdmin = true }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<ViewMode>('list'); 
  const [statusFilter, setStatusFilter] = useState<FilterStatus>(null);
  const [draggedClientId, setDraggedClientId] = useState<string | null>(null);
  const [pendingTransition, setPendingTransition] = useState<PendingTransition | null>(null);

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '', clientNumber: '', prgd: '', phone: '',
  });

  const formatPhone = (value: string) => {
    if (!value) return "";
    value = value.replace(/\D/g, "");
    value = value.substring(0, 11);
    if (value.length > 10) return value.replace(/^(\d{2})(\d{5})(\d{4}).*/, "($1) $2-$3");
    if (value.length > 5) return value.replace(/^(\d{2})(\d{4})(\d{0,4}).*/, "($1) $2-$3");
    if (value.length > 2) return value.replace(/^(\d{2})(\d{0,5})/, "($1) $2");
    return value.replace(/^(\d*)/, "($1");
  };

  const formatPRGD = (value: string) => {
    if (!value) return "";
    value = value.replace(/\D/g, "");
    value = value.substring(0, 5);
    if (value.length > 3) return value.replace(/^(\d{3})(\d{0,2})/, "$1-$2");
    return value;
  };

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    if (!startStr) return 0;
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const getStatusInfo = (days: number, isDelivered: boolean) => {
    if (isDelivered) return { label: '🟢 ENTREGUE', color: 'text-green-600', bg: 'bg-green-50', dot: 'bg-green-500', key: 'entregues' };
    if (days > 120) return { label: '🔴 URGENTE', color: 'text-red-600', bg: 'bg-red-50', dot: 'bg-red-500', key: 'urgente' };
    if (days > 75) return { label: '🟡 ATENÇÃO', color: 'text-amber-500', bg: 'bg-amber-50', dot: 'bg-amber-500', key: 'atencao' };
    return { label: '🟢 NO PRAZO', color: 'text-emerald-600', bg: 'bg-emerald-50', dot: 'bg-emerald-500', key: 'noprazo' };
  };

  const counts = clients.reduce((acc, c) => {
    const isDelivered = c.currentStageId === '7';
    const days = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);
    const info = getStatusInfo(days, isDelivered);

    if (!isDelivered) {
      acc.ativos++;
      acc[info.key as 'urgente' | 'atencao' | 'noprazo']++;
    } else {
      acc.entregues++;
    }
    return acc;
  }, { ativos: 0, entregues: 0, noprazo: 0, atencao: 0, urgente: 0 });

  const filteredClients = clients.filter(c => {
    const matchesSearch = c.name.toLowerCase().includes(searchTerm.toLowerCase()) || c.prgd.toLowerCase().includes(searchTerm.toLowerCase());
    if (!matchesSearch) return false;

    const isDelivered = c.currentStageId === '7';
    const days = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);
    const info = getStatusInfo(days, isDelivered);

    if (!statusFilter) return true;
    if (statusFilter === 'ativos') return !isDelivered;
    if (statusFilter === 'entregues') return isDelivered;

    // Filtros específicos de prazo só se aplicam a não entregues
    if (!isDelivered && info.key === statusFilter) return true;

    return false;
  });

  const onDrop = (stageId: string) => {
    if (draggedClientId && isAdmin) {
      const client = clients.find(c => c.id === draggedClientId);
      const targetStage = STAGES.find(s => s.id === stageId);
      if (client && targetStage) {
        const missingFields = (targetStage.requiredFields || []).filter(f => !client.stageData?.[f]);
        if (missingFields.length > 0) {
          setPendingTransition({ client, targetStage, fieldValues: missingFields.reduce((acc, f) => ({ ...acc, [f]: '' }), {}) });
        } else {
          onUpdateClientStage(draggedClientId, stageId);
        }
      }
      setDraggedClientId(null);
    }
  };

  const closeModal = () => {
    setIsCreating(false);
    setFormData({ name: '', clientNumber: '', prgd: '', phone: '' });
  };

  return (
    <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-200 h-full flex flex-col relative overflow-hidden">

      {pendingTransition && (
        <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-md z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] p-8 max-w-md w-full shadow-2xl">
            <h2 className="text-xl font-black text-brand-900 mb-4">Informação Necessária</h2>
            {Object.keys(pendingTransition.fieldValues).map(f => (
              <input key={f} className="w-full p-4 bg-gray-50 border rounded-2xl mb-4" placeholder={f} onChange={e => setPendingTransition({...pendingTransition, fieldValues: {...pendingTransition.fieldValues, [f]: e.target.value}})} />
            ))}
            <button onClick={() => { onUpdateClientStage(pendingTransition.client.id, pendingTransition.targetStage.id, pendingTransition.fieldValues); setPendingTransition(null); }} className="w-full bg-brand-600 text-white py-4 rounded-2xl font-black uppercase">Confirmar</button>
          </div>
        </div>
      )}

      {isCreating && (
          <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-4">
              <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-xl overflow-hidden">
                  <div className="p-8 border-b bg-gray-50 flex justify-between items-center">
                      <h2 className="text-2xl font-black text-brand-600 uppercase">Novo Cliente</h2>
                      <button onClick={closeModal} className="p-2 text-gray-400"><X size={24} /></button>
                  </div>
                  <form onSubmit={(e) => { e.preventDefault(); onCreateClient({ id: Date.now().toString(), name: formData.name!, clientNumber: '', prgd: formData.prgd!, phone: formData.phone!, projectName: '', additionalNotes: '', currentStageId: STAGES[0].id, createdAt: new Date().toISOString(), stageHistory: {}, stageData: {} }); closeModal(); }} className="p-8 space-y-4">
                      <input required className="w-full p-4 bg-gray-50 border rounded-2xl" placeholder="Nome do Cliente" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
                      <input required className="w-full p-4 bg-gray-50 border rounded-2xl" placeholder="WhatsApp" value={formData.phone} onChange={e => setFormData({...formData, phone: formatPhone(e.target.value)})} />
                      <input required className="w-full p-4 bg-gray-50 border rounded-2xl" placeholder="PRGD" value={formData.prgd} onChange={e => setFormData({...formData, prgd: formatPRGD(e.target.value)})} />
                      <button type="submit" className="w-full bg-brand-600 text-white py-4 rounded-2xl font-black uppercase">Cadastrar</button>
                  </form>
              </div>
          </div>
      )}

      <div className="p-6 border-b flex flex-col gap-6 bg-gray-50/50">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <div>
                <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">Gestão de Carteira</h2>
                <div className="flex flex-wrap items-center gap-2 mt-2">
                    <button onClick={() => setStatusFilter('ativos')} className={`text-[9px] font-black px-3 py-1 rounded-full uppercase border transition-all ${statusFilter === 'ativos' ? 'bg-brand-600 text-white shadow-md border-brand-600' : 'bg-white text-gray-400 border-gray-200'}`}>{counts.ativos} Ativos</button>
                    <button onClick={() => setStatusFilter('noprazo')} className={`text-[9px] font-black px-3 py-1 rounded-full uppercase border transition-all ${statusFilter === 'noprazo' ? 'bg-emerald-600 text-white shadow-md border-emerald-600' : 'bg-white text-emerald-500 border-emerald-100'}`}>{counts.noprazo} No Prazo</button>
                    <button onClick={() => setStatusFilter('atencao')} className={`text-[9px] font-black px-3 py-1 rounded-full uppercase border transition-all ${statusFilter === 'atencao' ? 'bg-amber-500 text-white shadow-md border-amber-500' : 'bg-white text-amber-500 border-amber-100'}`}>{counts.atencao} Atenção</button>
                    <button onClick={() => setStatusFilter('urgente')} className={`text-[9px] font-black px-3 py-1 rounded-full uppercase border transition-all ${statusFilter === 'urgente' ? 'bg-red-600 text-white shadow-md border-red-600' : 'bg-white text-red-500 border-red-100'}`}>{counts.urgente} Urgente</button>
                    <button onClick={() => setStatusFilter('entregues')} className={`text-[9px] font-black px-3 py-1 rounded-full uppercase border transition-all ${statusFilter === 'entregues' ? 'bg-green-600 text-white shadow-md border-green-600' : 'bg-white text-gray-400 border-gray-200'}`}>{counts.entregues} Entregues</button>
                    <button onClick={() => setStatusFilter(null)} className="text-[9px] font-black px-3 py-1 rounded-full uppercase border bg-gray-100 text-gray-400 border-gray-200 hover:bg-gray-200 transition-colors">Todos</button>
                </div>
            </div>

            <div className="flex bg-gray-100 p-1 rounded-2xl border">
                <button onClick={() => setViewMode('list')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'list' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-400'}`}><List size={14} /> Lista</button>
                <button onClick={() => setViewMode('pipeline')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'pipeline' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-400'}`}><Kanban size={14} /> Pipeline</button>
            </div>
        </div>

        <div className="flex flex-col md:flex-row gap-4">
            <div className="relative flex-1">
                <Search className="absolute left-4 top-3.5 text-gray-300" size={18} />
                <input placeholder="Filtrar por nome ou PRGD..." className="w-full pl-12 p-3.5 rounded-2xl border bg-white outline-none focus:border-brand-300 font-medium text-sm" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
            </div>
            {isAdmin && <button onClick={() => setIsCreating(true)} className="bg-brand-600 text-white px-8 py-3.5 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl flex items-center justify-center gap-2 hover:bg-brand-700 transition-all"><Plus size={18} /> Novo Cliente</button>}
        </div>
      </div>

      <div className="flex-1 overflow-hidden bg-gray-100/30">
        {viewMode === 'list' ? (
