import React, { useState, useEffect } from 'react';
import { Timeline } from './components/Timeline.tsx';
import { ContentGenerator } from './components/ContentGenerator.tsx';
import { ClientList } from './components/ClientList.tsx';
import { Dashboard } from './components/Dashboard.tsx';
import { ReferralModule } from './components/ReferralModule.tsx';
import { Login } from './components/Login.tsx';
import { STAGES } from './constants.ts';
import { Client, Stage } from './types.ts';
import { ArrowLeft, BarChart3, LayoutList, Zap, LogOut, MessageSquare, Users } from 'lucide-react';
import { generateTemplateContent } from './services/templateService.ts';

export default function App() {
  const [userMode, setUserMode] = useState<'admin' | 'visitor' | null>(null);
  const [view, setView] = useState<'list' | 'detail' | 'dashboard'>('list');
  const [detailTab, setDetailTab] = useState<'journey' | 'referrals'>('journey');
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [currentStageId, setCurrentStageId] = useState<string>(STAGES[0].id);
  const [clients, setClients] = useState<Client[]>([]);

  useEffect(() => {
    const saved = localStorage.getItem('gev_loop_clients');
    if (saved) {
      try {
        setClients(JSON.parse(saved));
      } catch (e) {
        console.error("Erro ao carregar dados", e);
      }
    }

    const savedUser = localStorage.getItem('gev_loop_user');
    if (savedUser) {
      setUserMode(savedUser as 'admin' | 'visitor');
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('gev_loop_clients', JSON.stringify(clients));
  }, [clients]);

  const handleLogin = (mode: 'admin' | 'visitor') => {
    setUserMode(mode);
    localStorage.setItem('gev_loop_user', mode);
  };

  const handleLogout = () => {
    setUserMode(null);
    localStorage.removeItem('gev_loop_user');
    setView('list');
    setSelectedClientId(null);
  };

  const handleCreateClient = (newClient: Client) => {
    setClients(prev => [newClient, ...prev]);
    handleSelectClient(newClient);

    const firstStage = STAGES[0];
    if (firstStage && firstStage.template && newClient.phone) {
      const generated = generateTemplateContent(firstStage, newClient, {});
      const cleanPhone = newClient.phone.replace(/\D/g, '');
      const phoneWithCountry = cleanPhone.startsWith('55') ? cleanPhone : `55${cleanPhone}`;
      const encodedText = encodeURIComponent(generated.body);
      window.open(`https://api.whatsapp.com/send?phone=${phoneWithCountry}&text=${encodedText}`, '_blank');
    }
  };

  const handleEditClient = (updatedClient: Client) => {
    setClients(prev => prev.map(c => c.id === updatedClient.id ? updatedClient : c));
  };

  const handleDeleteClient = (clientId: string) => {
    setClients(prev => prev.filter(c => c.id !== clientId));
    if (selectedClientId === clientId) {
      setView('list');
      setSelectedClientId(null);
    }
  };

  const handleSelectClient = (client: Client) => {
    setSelectedClientId(client.id);
    setCurrentStageId(client.currentStageId || STAGES[0].id);
    setDetailTab('journey');
    setView('detail');
  };

  const handleUpdateNotes = (notes: string) => {
    if (!selectedClientId) return;
    setClients(prev => prev.map(c => 
      c.id === selectedClientId ? { ...c, additionalNotes: notes } : c
    ));
  };

  const handleUpdateClientStage = (clientId: string, newStageId: string, stageData?: Record<string, string>) => {
    const now = new Date().toISOString();
    setClients(prev => prev.map(c => {
      if (c.id === clientId) {
        return { 
          ...c, 
          currentStageId: newStageId, 
          stageData: { ...c.stageData, ...stageData },
          stageHistory: { ...c.stageHistory, [newStageId]: now }
        };
      }
      return c;
    }));
    if (selectedClientId === clientId) {
      setCurrentStageId(newStageId);
    }
  };

  if (!userMode) {
    return <Login onLogin={handleLogin} />;
  }

  const selectedClient = clients.find(c => c.id === selectedClientId);
  const currentStage = STAGES.find(s => s.id === currentStageId) || STAGES[0];

  return (
    <div className="h-screen bg-gray-50 flex flex-col overflow-hidden font-sans">
      <header className="bg-brand-900 h-16 sm:h-20 shrink-0 shadow-lg relative z-50 border-b border-brand-800">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 h-full flex items-center justify-between">
          <div className="flex items-center gap-4">
            {view === 'detail' && (
              <button onClick={() => setView('list')} className="p-2 hover:bg-white/10 rounded-full text-gold-400 transition">
                <ArrowLeft size={20} />
              </button>
            )}
            <div className="flex flex-col">
              <h1 className="text-xl sm:text-2xl font-black text-white uppercase tracking-tighter leading-none">
                LOOP <span className="text-gold-500">ENERGIA</span>
              </h1>
              <p className="text-[8px] text-brand-400 uppercase tracking-widest font-bold mt-1">Gestão de Experiência do Cliente</p>
            </div>
          </div>

          <div className="flex items-center gap-4">
             <nav className="flex bg-brand-800/40 p-1 rounded-xl border border-brand-700/50">
                <button 
                  onClick={() => setView('list')}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${view !== 'dashboard' && view !== 'detail' ? 'bg-brand-600 text-white shadow-lg' : 'text-brand-300 hover:text-white'}`}
                >
                  <LayoutList size={14} /> <span className="hidden sm:inline">Carteira</span>
                </button>
                <button 
                  onClick={() => setView('dashboard')}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${view === 'dashboard' ? 'bg-brand-600 text-white shadow-lg' : 'text-brand-300 hover:text-white'}`}
                >
                  <BarChart3 size={14} /> <span className="hidden sm:inline">Dashboard</span>
                </button>
             </nav>
             <button 
               onClick={handleLogout}
               className="bg-brand-800 p-2.5 rounded-full text-gold-400 border border-brand-700 hover:bg-red-900/40 hover:text-red-400 transition-colors"
               title="Sair do Sistema"
             >
               <LogOut size={18} />
             </button>
          </div>
        </div>
      </header>

      <main className="flex-1 overflow-hidden max-w-7xl mx-auto w-full px-4 sm:px-6 py-4">
        {view === 'list' ? (
          <ClientList 
            clients={clients} 
            onSelectClient={handleSelectClient} 
            onCreateClient={handleCreateClient}
            onEditClient={handleEditClient}
            onDeleteClient={handleDeleteClient}
            onUpdateClientStage={handleUpdateClientStage}
            isAdmin={userMode === 'admin'}
          />
        ) : view === 'dashboard' ? (
          <Dashboard clients={clients} />
        ) : (
          <div className="flex flex-col h-full gap-4">
            <div className="flex justify-between items-center bg-white p-4 rounded-[2rem] border border-gray-200 shadow-sm shrink-0">
               <div className="flex items-center gap-4">
                  <div className="bg-brand-900 text-gold-400 p-2.5 rounded-xl"><Zap size={20} /></div>
                  <h2 className="text-lg font-black text-brand-900 uppercase truncate max-w-[200px]">{selectedClient?.name}</h2>
               </div>
               <nav className="flex bg-gray-100 p-1 rounded-2xl border">
                  <button 
                    onClick={() => setDetailTab('journey')}
                    className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${detailTab === 'journey' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-400'}`}
                  >
                    <MessageSquare size={14} /> Jornada
                  </button>
                  <button 
                    onClick={() => setDetailTab('referrals')}
                    className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${detailTab === 'referrals' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-400'}`}
                  >
                    <Users size={14} /> Indicações
                  </button>
               </nav>
            </div>

            {detailTab === 'journey' ? (
              <>
                <Timeline 
                  currentStageId={currentStageId} 
                  onSelectStage={(s) => setCurrentStageId(s.id)} 
                />
                <div className="flex-1 min-h-0">
                  {selectedClient && (
                    <ContentGenerator 
                      stage={currentStage}
                      client={selectedClient}
                      onUpdateNotes={handleUpdateNotes}
                      onUpdateClientStage={handleUpdateClientStage}
                    />
                  )}
                </div>
              </>
            ) : (
              <div className="flex-1 min-h-0">
                {selectedClient && <ReferralModule client={selectedClient} />}
              </div>
            )}
          </div>
        )}
      </main>
    </div>
  );
}

