import React, { useState, useEffect } from 'react';
import { Stage, Client } from '../types.ts';
import { generateTemplateContent } from '../services/templateService.ts';
import { Copy, Phone, Zap, Trophy, Clock, CheckCircle2, ArrowRight, History, Star, Calendar, Flag, Timer, TrendingUp, AlertCircle, Info } from 'lucide-react';
import { STAGES } from '../constants.ts';

interface ContentGeneratorProps {
  stage: Stage;
  client: Client;
  onUpdateNotes: (notes: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

export const ContentGenerator: React.FC<ContentGeneratorProps> = ({ stage, client, onUpdateNotes, onUpdateClientStage }) => {
  const [fieldValues, setFieldValues] = useState<Record<string, string>>({});
  const [editableBody, setEditableBody] = useState('');

  useEffect(() => {
    setFieldValues(client.stageData || {});
  }, [stage.id, client.id]);

  useEffect(() => {
    const generated = generateTemplateContent(stage, client, { ...client.stageData, ...fieldValues });
    setEditableBody(generated.body);
  }, [fieldValues, stage, client]);

  const calculateMetrics = () => {
    const start = new Date(client.createdAt);
    const deadline = new Date(start);
    deadline.setDate(deadline.getDate() + 120);
    const isCompleted = client.currentStageId === '7';
    const now = isCompleted ? new Date(client.stageHistory['7']) : new Date();
    const totalDays = Math.floor(Math.abs(now.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));

    // SLA Progress
    const slaPercent = Math.min(100, (totalDays / 120) * 100);
    const slaColor = totalDays > 120 ? 'bg-red-500' : totalDays > 75 ? 'bg-amber-500' : 'bg-emerald-500';
    const slaText = totalDays > 120 ? 'URGENTE' : totalDays > 75 ? 'ATENÇÃO' : 'NO PRAZO';

    // Time in current stage
    const stageEntryStr = (client.stageHistory[client.currentStageId] as any) || client.createdAt;
    const stageEntry = new Date(stageEntryStr);
    const daysInStage = Math.floor(Math.abs(new Date().getTime() - stageEntry.getTime()) / (1000 * 60 * 60 * 24));

    // Calculate Internal Score (Team Score)
    let score = 5;
    if (totalDays > 120) score -= 2;
    else if (totalDays > 90) score -= 1;
    if (daysInStage > 20) score -= 1;

    return { 
      totalDays, 
      slaPercent, 
      slaColor, 
      slaText, 
      daysInStage, 
      start: start.toLocaleDateString('pt-BR'), 
      deadline: deadline.toLocaleDateString('pt-BR'),
      score: Math.max(1, score)
    };
  };

  const metrics = calculateMetrics();

  const renderStageHistory = () => {
    // Reconstruct history with durations
    const historyEntries = Object.entries(client.stageHistory)
      .map(([id, date]) => ({ id, date: new Date(date as string) }))
      .sort((a, b) => a.date.getTime() - b.date.getTime());

    return (
      <div className="space-y-3">
        {historyEntries.map((entry, i) => {
          const s = STAGES.find(st => st.id === entry.id);
          const nextEntry = historyEntries[i+1];
          const duration = nextEntry 
            ? Math.floor((nextEntry.date.getTime() - entry.date.getTime()) / (1000 * 60 * 60 * 24))
            : Math.floor((new Date().getTime() - entry.date.getTime()) / (1000 * 60 * 60 * 24));

          return (
            <div key={entry.id} className="flex gap-3 relative">
              {i !== historyEntries.length - 1 && <div className="absolute left-[11px] top-6 bottom-0 w-0.5 bg-gray-100"></div>}
              <div className={`w-6 h-6 rounded-full flex items-center justify-center shrink-0 z-10 ${i === historyEntries.length - 1 ? 'bg-brand-600 text-white' : 'bg-emerald-100 text-emerald-600'}`}>
                <CheckCircle2 size={14} />
              </div>
              <div className="flex-1 pb-4">
                <div className="flex justify-between items-start">
                  <p className="text-[10px] font-black text-brand-900 uppercase tracking-tight">{s?.title || 'Etapa Concluída'}</p>
                  <span className="text-[9px] font-bold text-gray-400">{entry.date.toLocaleDateString('pt-BR')}</span>
                </div>
                <p className="text-[9px] font-bold text-brand-500 uppercase mt-0.5">Duração: {duration} {duration === 1 ? 'dia' : 'dias'}</p>
              </div>
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="bg-white rounded-[2.5rem] shadow-xl border border-gray-200 flex flex-col h-full overflow-hidden">
      {/* HEADER DE STATUS RÁPIDO */}
      <div className="bg-brand-900 p-6 flex flex-col md:flex-row justify-between items-center gap-4 border-b border-brand-800">
        <div className="flex items-center gap-5">
           <div className="bg-brand-800 p-4 rounded-3xl border border-brand-700 shadow-inner">
              <Zap size={28} className="text-gold-400 fill-current" />
           </div>
           <div>
              <div className="flex items-center gap-3">
                <h2 className="text-xl font-black text-white uppercase tracking-tighter">Etapa {stage.stepNumber}: {stage.title}</h2>
                <span className={`px-3 py-1 rounded-full text-[9px] font-black text-white tracking-widest ${metrics.slaColor}`}>
                  {metrics.slaText}
                </span>
              </div>
              <p className="text-brand-300 text-xs font-bold uppercase tracking-widest mt-1">{stage.description}</p>
           </div>
        </div>
        <div className="flex items-center gap-6 bg-brand-800/50 px-6 py-3 rounded-[1.8rem] border border-brand-700/50">
           <div className="text-center">
             <p className="text-[8px] font-black text-brand-400 uppercase mb-0.5">Tempo Total</p>
             <p className="text-lg font-black text-white leading-none">{metrics.totalDays}d</p>
           </div>
           <div className="w-px h-8 bg-brand-700"></div>
           <div className="text-center">
             <p className="text-[8px] font-black text-brand-400 uppercase mb-0.5">Nesta Etapa</p>
             <p className="text-lg font-black text-gold-400 leading-none">{metrics.daysInStage}d</p>
           </div>
        </div>
      </div>

      <div className="flex flex-1 overflow-hidden">
        {/* SIDEBAR DE MÉTRICAS E HISTÓRICO */}
        <aside className="w-full lg:w-96 border-r border-gray-100 bg-gray-50/50 flex flex-col overflow-y-auto custom-scroll p-6 gap-6">

          {/* Score da Equipe */}
          <div className="bg-white p-5 rounded-[2.2rem] border border-gray-100 shadow-sm">
             <div className="flex justify-between items-center mb-4">
                <h3 className="text-[10px] font-black text-brand-900 uppercase tracking-widest flex items-center gap-2">
                  <Star size={14} className="text-gold-500 fill-current" /> Score Loop GEV
                </h3>
                <span className="text-xs font-black text-brand-600 bg-brand-50 px-2 py-0.5 rounded-lg border border-brand-100">
                  {metrics.score.toFixed(1)}
                </span>
             </div>
             <div className="flex justify-center gap-1.5 py-2 bg-gray-50 rounded-2xl border border-gray-100">
                {[1,2,3,4,5].map(s => (
                  <Star key={s} size={20} fill={s <= metrics.score ? "#dbb832" : "transparent"} className={s <= metrics.score ? "text-gold-500" : "text-gray-200"} />
                ))}
             </div>
             <p className="text-[8px] font-bold text-gray-400 text-center mt-3 uppercase tracking-tighter">Pontuação baseada no cumprimento do SLA de 120 dias</p>
          </div>

          {/* SLA & Calendário */}
          <div className="bg-white p-5 rounded-[2.2rem] border border-gray-100 shadow-sm space-y-4">
            <h3 className="text-[10px] font-black text-brand-900 uppercase tracking-widest flex items-center gap-2">
              <Timer size={14} className="text-brand-600" /> Prazo e Saúde
            </h3>
            <div className="space-y-1.5">
               <div className="flex justify-between text-[9px] font-black uppercase text-gray-400">
                  <span>Progresso SLA</span>
                  <span className={metrics.totalDays > 120 ? 'text-red-500' : 'text-brand-600'}>{metrics.totalDays} / 120 dias</span>
               </div>
               <div className="h-3 w-full bg-gray-100 rounded-full overflow-hidden border border-gray-200 shadow-inner">
                  <div className={`h-full transition-all duration-1000 ${metrics.slaColor}`} style={{ width: `${metrics.slaPercent}%` }}></div>
               </div>
            </div>
            <div className="grid grid-cols-2 gap-3 pt-2">
               <div className="bg-gray-50 p-3 rounded-2xl border border-gray-100 text-center">
                  <p className="text-[8px] font-black text-gray-400 uppercase mb-1">Início</p>
                  <p className="text-[11px] font-black text-brand-900">{metrics.start}</p>
               </div>
               <div className="bg-brand-900 p-3 rounded-2xl text-center border border-brand-800 shadow-md">
                  <p className="text-[8px] font-black text-brand-300 uppercase mb-1">Prazo</p>
                  <p className="text-[11px] font-black text-white">{metrics.deadline}</p>
               </div>
            </div>
          </div>

          {/* Histórico com Duração */}
          <div className="bg-white p-6 rounded-[2.2rem] border border-gray-100 shadow-sm flex-1 flex flex-col">
            <h3 className="text-[10px] font-black text-brand-900 uppercase tracking-widest flex items-center gap-2 mb-6 border-b border-gray-50 pb-4">
               <History size={16} className="text-brand-500" /> Jornada percorrida
            </h3>
            <div className="flex-1">
               {renderStageHistory()}
            </div>
          </div>
        </aside>

        {/* ÁREA PRINCIPAL: CAMPOS E MENSAGEM */}
        <main className="flex-1 p-8 overflow-y-auto custom-scroll flex flex-col gap-8 bg-white">

          {/* Campos Requeridos */}
          {stage.requiredFields && stage.requiredFields.length > 0 && (
            <section className="animate-in fade-in slide-in-from-top-4 duration-500">
               <div className="flex items-center gap-2 mb-4">
                  <TrendingUp size={16} className="text-brand-600" />
                  <h3 className="text-[11px] font-black text-brand-900 uppercase tracking-widest">Informações desta Etapa</h3>
               </div>
               <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  {stage.requiredFields.map(f => (
                    <div key={f} className="group">
                       <label className="text-[9px] font-black uppercase text-gray-400 mb-1.5 block ml-1 tracking-widest group-focus-within:text-brand-600 transition-colors">{f}</label>
                       <input 
                         className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl text-sm font-bold outline-none focus:bg-white focus:border-brand-500 focus:ring-4 focus:ring-brand-500/5 transition-all" 
                         value={fieldValues[f] || ''} 
                         onChange={e => setFieldValues({...fieldValues, [f]: e.target.value})} 
                         placeholder={`Inserir ${f}...`}
                       />
                    </div>
                  ))}
               </div>
            </section>
          )}

          {/* Pré-visualização da Mensagem */}
          <section className="flex-1 flex flex-col min-h-[400px]">
             <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2">
                   <MessageSquare size={16} className="text-brand-600" />
                   <h3 className="text-[11px] font-black text-brand-900 uppercase tracking-widest">Mensagem do Cliente</h3>
                </div>
                <button 
                   onClick={() => {
                     navigator.clipboard.writeText(editableBody);
                     alert('Mensagem copiada!');
