                   className="flex items-center gap-2 px-4 py-2 bg-gray-50 hover:bg-brand-50 text-brand-600 rounded-xl text-[10px] font-black uppercase tracking-widest border border-gray-100 transition-all active:scale-95 shadow-sm"
                >
                  <Copy size={14} /> Copiar Texto
                </button>
             </div>

             <div className="flex-1 bg-gray-50/80 rounded-[2.5rem] border border-gray-100 p-8 relative group">
                <div className="absolute top-4 right-8 text-[8px] font-black text-gray-300 uppercase tracking-widest">Preview Loop GEV</div>
                <div className="text-slate-700 text-[15px] font-medium leading-relaxed whitespace-pre-wrap font-sans">
                  {editableBody || <span className="text-gray-300 italic">Nenhum template disponível para esta etapa...</span>}
