          {/* Ações de Finalização */}
          <footer className="grid grid-cols-1 md:grid-cols-2 gap-4 pt-4 border-t border-gray-50">
             <button 
               onClick={() => {
                 const clean = client.phone.replace(/\D/g, '');
                 const phoneWithCountry = clean.startsWith('55') ? clean : '55'+clean;
                 window.open(`https://api.whatsapp.com/send?phone=${phoneWithCountry}&text=${encodeURIComponent(editableBody)}`, '_blank');
               }} 
               className="py-5 bg-[#25D366] text-white rounded-[2rem] font-black uppercase tracking-widest text-xs flex items-center justify-center gap-3 shadow-xl hover:shadow-green-500/20 hover:scale-[1.02] active:scale-98 transition-all"
             >
               <Phone size={20} fill="currentColor" /> Abrir WhatsApp Agora
             </button>

             {stage.id !== client.currentStageId ? (
               <button 
                 onClick={() => onUpdateClientStage(client.id, stage.id, fieldValues)} 
                 className="py-5 bg-brand-900 text-white rounded-[2rem] font-black uppercase tracking-widest text-xs flex items-center justify-center gap-3 shadow-xl hover:bg-black hover:scale-[1.02] active:scale-98 transition-all"
               >
                 Salvar e Avançar Etapa <ArrowRight size={18} />
               </button>
             ) : (
               <div className="bg-emerald-50 border border-emerald-100 rounded-[2rem] flex items-center justify-center gap-3 text-emerald-600 font-black uppercase text-[10px] tracking-widest">
                 <CheckCircle2 size={18} /> Etapa Atual do Cliente
               </div>
             )}
          </footer>
        </main>
      </div>
    </div>
  );
};

