               <div className="bg-brand-50 p-4 rounded-2xl border border-brand-100">
                  <p className="text-[9px] font-black text-brand-600 uppercase mb-1">Data Prazo</p>
                  <p className="text-[12px] font-black text-brand-900">{metrics.deadline}</p>
