import React, { useState, useEffect } from 'react';
import { Timeline } from './components/Timeline.tsx';
import { ContentGenerator } from './components/ContentGenerator.tsx';
import { ClientList } from './components/ClientList.tsx';
import { Dashboard } from './components/Dashboard.tsx';
import { ReferralModule } from './components/ReferralModule.tsx';
import { STAGES } from './constants.ts';
import { Client, Stage } from './types.ts';
import { ArrowLeft, BarChart3, LayoutList, Zap, MessageSquare, Users } from 'lucide-react';
import { generateTemplateContent } from './services/templateService.ts';

export default function App() {
  const [userMode] = useState<'admin'>('admin');
  const [view, setView] = useState<'list' | 'detail' | 'dashboard'>('list');
  const [detailTab, setDetailTab] = useState<'journey' | 'referrals'>('journey');
  const [selectedClientId, setSelectedClientId] = useState<string | null>(null);
  const [currentStageId, setCurrentStageId] = useState<string>(STAGES[0].id);
  const [clients, setClients] = useState<Client[]>([]);

  useEffect(() => {
    const saved = localStorage.getItem('gev_loop_clients');
    if (saved) {
      try {
        setClients(JSON.parse(saved));
      } catch (e) {
        console.error("Erro ao carregar dados", e);
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('gev_loop_clients', JSON.stringify(clients));
  }, [clients]);

  const handleCreateClient = (newClient: Client) => {
    const now = new Date().toISOString();
    const clientWithHistory = {
      ...newClient,
      stageHistory: { [STAGES[0].id]: now }
    };

    setClients(prev => [clientWithHistory, ...prev]);
    handleSelectClient(clientWithHistory);

    const firstStage = STAGES[0];
    if (firstStage && firstStage.template && newClient.phone) {
      const generated = generateTemplateContent(firstStage, newClient, {});
      const cleanPhone = newClient.phone.replace(/\D/g, '');
      const phoneWithCountry = cleanPhone.startsWith('55') ? cleanPhone : `55${cleanPhone}`;
      const encodedText = encodeURIComponent(generated.body);
      window.open(`https://api.whatsapp.com/send?phone=${phoneWithCountry}&text=${encodedText}`, '_blank');
    }
  };

  const handleEditClient = (updatedClient: Client) => {
    setClients(prev => prev.map(c => c.id === updatedClient.id ? updatedClient : c));
  };

  const handleDeleteClient = (clientId: string) => {
    setClients(prev => prev.filter(c => c.id !== clientId));
    if (selectedClientId === clientId) {
      setView('list');
      setSelectedClientId(null);
    }
  };

  const handleSelectClient = (client: Client) => {
    setSelectedClientId(client.id);
    setCurrentStageId(client.currentStageId || STAGES[0].id);
    setDetailTab('journey');
    setView('detail');
    // Scroll to top when selecting a client
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleUpdateNotes = (notes: string) => {
    if (!selectedClientId) return;
    setClients(prev => prev.map(c => 
      c.id === selectedClientId ? { ...c, additionalNotes: notes } : c
    ));
  };

  const handleUpdateClientStage = (clientId: string, newStageId: string, stageData?: Record<string, string>) => {
    const now = new Date().toISOString();
    setClients(prev => prev.map(c => {
      if (c.id === clientId) {
        return { 
          ...c, 
          currentStageId: newStageId, 
          stageData: { ...c.stageData, ...stageData },
          stageHistory: { ...c.stageHistory, [newStageId]: now }
        };
      }
      return c;
    }));
    if (selectedClientId === clientId) {
      setCurrentStageId(newStageId);
    }
  };

  const selectedClient = clients.find(c => c.id === selectedClientId);
  const currentStage = STAGES.find(s => s.id === currentStageId) || STAGES[0];

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col font-sans pb-10">
      <header className="bg-brand-900 h-16 sm:h-20 shrink-0 shadow-lg sticky top-0 z-[100] border-b border-brand-800">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 h-full flex items-center justify-between">
          <div className="flex items-center gap-4">
            {view === 'detail' && (
              <button onClick={() => setView('list')} className="p-2 hover:bg-white/10 rounded-full text-gold-400 transition">
                <ArrowLeft size={20} />
              </button>
            )}
            <div className="flex flex-col">
              <h1 className="text-xl sm:text-2xl font-black text-white uppercase tracking-tighter leading-none">
                LOOP <span className="text-gold-500">ENERGIA</span>
              </h1>
              <p className="text-[8px] text-brand-400 uppercase tracking-widest font-bold mt-1">Gestão de Experiência do Cliente</p>
            </div>
          </div>

          <div className="flex items-center gap-4">
             <nav className="flex bg-brand-800/40 p-1 rounded-xl border border-brand-700/50">
                <button 
                  onClick={() => setView('list')}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${view !== 'dashboard' && view !== 'detail' ? 'bg-brand-600 text-white shadow-lg' : 'text-brand-300 hover:text-white'}`}
                >
                  <LayoutList size={14} /> <span className="hidden sm:inline">Carteira</span>
                </button>
                <button 
                  onClick={() => setView('dashboard')}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all ${view === 'dashboard' ? 'bg-brand-600 text-white shadow-lg' : 'text-brand-300 hover:text-white'}`}
                >
                  <BarChart3 size={14} /> <span className="hidden sm:inline">Dashboard</span>
                </button>
             </nav>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 py-6">
        {view === 'list' ? (
          <ClientList 
            clients={clients} 
            onSelectClient={handleSelectClient} 
            onCreateClient={handleCreateClient}
            onEditClient={handleEditClient}
            onDeleteClient={handleDeleteClient}
            onUpdateClientStage={handleUpdateClientStage}
            isAdmin={userMode === 'admin'}
          />
        ) : view === 'dashboard' ? (
          <Dashboard clients={clients} />
        ) : (
          <div className="flex flex-col gap-6">
            <div className="flex flex-col md:flex-row justify-between items-center bg-white p-5 rounded-[2.5rem] border border-gray-200 shadow-sm gap-4">
               <div className="flex items-center gap-4 px-2">
                  <div className="bg-brand-900 text-gold-400 p-3 rounded-2xl shadow-lg border border-brand-800"><Zap size={24} /></div>
                  <div>
                    <h2 className="text-xl font-black text-brand-900 uppercase tracking-tight">{selectedClient?.name}</h2>
                    <p className="text-[10px] font-bold text-gray-400 uppercase tracking-widest mt-0.5">Gestão de Jornada Individual</p>
                  </div>
               </div>
               <nav className="flex bg-gray-50 p-1.5 rounded-2xl border border-gray-100">
                  <button 
                    onClick={() => setDetailTab('journey')}
                    className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-[11px] font-black uppercase transition-all ${detailTab === 'journey' ? 'bg-white text-brand-600 shadow-md' : 'text-gray-400 hover:text-gray-600'}`}
                  >
                    <MessageSquare size={16} /> Jornada
                  </button>
                  <button 
                    onClick={() => setDetailTab('referrals')}
                    className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-[11px] font-black uppercase transition-all ${detailTab === 'referrals' ? 'bg-white text-brand-600 shadow-md' : 'text-gray-400 hover:text-gray-600'}`}
                  >
                    <Users size={16} /> Indicações
                  </button>
               </nav>
            </div>

            {detailTab === 'journey' ? (
              <div className="flex flex-col gap-6">
                <Timeline 
                  currentStageId={currentStageId} 
                  onSelectStage={(s) => setCurrentStageId(s.id)} 
                />
                <div className="w-full">
                  {selectedClient && (
                    <ContentGenerator 
                      stage={currentStage}
                      client={selectedClient}
                      onUpdateNotes={handleUpdateNotes}
                      onUpdateClientStage={handleUpdateClientStage}
                    />
                  )}
                </div>
              </div>
            ) : (
              <div className="w-full">
                {selectedClient && <ReferralModule client={selectedClient} />}
              </div>
            )}
          </div>
        )}
      </main>
    </div>
  );
}

import React, { useEffect, useRef } from 'react';
import { STAGES, STEP_ICONS } from '../constants.ts';
import { Stage } from '../types.ts';
import { Check } from 'lucide-react';

interface TimelineProps {
  currentStageId: string;
  onSelectStage: (stage: Stage) => void;
}

export const Timeline: React.FC<TimelineProps> = ({ currentStageId, onSelectStage }) => {
  const currentStageIndex = STAGES.findIndex(s => s.id === currentStageId);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      const activeElement = scrollRef.current.querySelector('[data-active="true"]');
      if (activeElement) {
        activeElement.scrollIntoView({ behavior: 'smooth', block: 'nearest', inline: 'center' });
      }
    }
  }, [currentStageId]);

  return (
    <div className="bg-white rounded-[2rem] shadow-sm border border-gray-200 w-full relative overflow-hidden shrink-0">
      <div className="absolute top-0 left-0 right-0 h-1 bg-gradient-to-r from-brand-900 via-brand-600 to-gold-500"></div>

      <div 
        ref={scrollRef}
        className="flex overflow-x-auto gap-3 p-4 scrollbar-hide snap-x"
        style={{ scrollbarWidth: 'none', msOverflowStyle: 'none' }}
      >
        {STAGES.map((stage, index) => {
          const Icon = STEP_ICONS[stage.stepNumber] || STEP_ICONS['1'];
          const isActive = stage.id === currentStageId;
          const isCompleted = index < currentStageIndex;

          return (
            <div 
              key={stage.id}
              data-active={isActive}
              onClick={() => onSelectStage(stage)}
              className={`
                shrink-0 snap-center cursor-pointer transition-all duration-300
                flex flex-col items-center gap-2 p-3 rounded-2xl min-w-[130px] border
                ${isActive 
                  ? 'bg-brand-50 border-brand-200 shadow-md scale-105 z-10' 
                  : isCompleted
                    ? 'bg-gray-50 border-gold-100 opacity-80'
                    : 'bg-transparent border-transparent opacity-40 hover:opacity-100'
                }
              `}
            >
              <div 
                className={`
                  flex items-center justify-center w-10 h-10 rounded-xl border-2 transition-all shadow-sm
                  ${isActive 
                    ? 'border-brand-900 bg-brand-900 text-gold-400' 
                    : isCompleted 
                      ? 'border-gold-500 bg-gold-50 text-gold-600' 
                      : 'border-gray-200 bg-white text-gray-300'
                  }
                `}
              >
                {isCompleted ? <Check size={18} strokeWidth={3} /> : <Icon size={18} />}
              </div>

              <div className="flex flex-col items-center text-center">
                <span className={`text-[7px] uppercase font-black tracking-[0.2em] ${isActive ? 'text-brand-600' : 'text-gray-400'}`}>Passo {stage.stepNumber}</span>
                <h3 className={`text-[9px] font-black uppercase leading-tight mt-1 ${isActive ? 'text-brand-900' : 'text-gray-500'}`}>
                  {stage.title}
                </h3>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Stage, Client } from '../types.ts';
import { generateTemplateContent } from '../services/templateService.ts';
import { Copy, Phone, Zap, Trophy, Clock, CheckCircle2, ArrowRight, History, Star, Calendar, Flag, Timer, TrendingUp, AlertCircle, Info } from 'lucide-react';
import { STAGES } from '../constants.ts';

interface ContentGeneratorProps {
  stage: Stage;
  client: Client;
  onUpdateNotes: (notes: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

export const ContentGenerator: React.FC<ContentGeneratorProps> = ({ stage, client, onUpdateNotes, onUpdateClientStage }) => {
  const [fieldValues, setFieldValues] = useState<Record<string, string>>({});
  const [editableBody, setEditableBody] = useState('');

  useEffect(() => {
    setFieldValues(client.stageData || {});
  }, [stage.id, client.id]);

  useEffect(() => {
    const generated = generateTemplateContent(stage, client, { ...client.stageData, ...fieldValues });
    setEditableBody(generated.body);
  }, [fieldValues, stage, client]);

  const calculateMetrics = () => {
    const start = new Date(client.createdAt);
    const deadline = new Date(start);
    deadline.setDate(deadline.getDate() + 120);
    const isCompleted = client.currentStageId === '7';
    const now = isCompleted ? new Date(client.stageHistory['7']) : new Date();
    const totalDays = Math.floor(Math.abs(now.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));

    const slaPercent = Math.min(100, (totalDays / 120) * 100);
    const slaColor = totalDays > 120 ? 'bg-red-600' : totalDays > 75 ? 'bg-amber-500' : 'bg-emerald-600';
    const slaText = totalDays > 120 ? 'URGENTE' : totalDays > 75 ? 'ATENÇÃO' : 'NO PRAZO';

    const stageEntryStr = (client.stageHistory[client.currentStageId] as any) || client.createdAt;
    const stageEntry = new Date(stageEntryStr);
    const daysInStage = Math.floor(Math.abs(new Date().getTime() - stageEntry.getTime()) / (1000 * 60 * 60 * 24));

    let score = 5;
    if (totalDays > 120) score -= 2;
    else if (totalDays > 90) score -= 1;
    if (daysInStage > 20) score -= 1;

    return { 
      totalDays, 
      slaPercent, 
      slaColor, 
      slaText, 
      daysInStage, 
      start: start.toLocaleDateString('pt-BR'), 
      deadline: deadline.toLocaleDateString('pt-BR'),
      score: Math.max(1, score)
    };
  };

  const metrics = calculateMetrics();

  const renderStageHistory = () => {
    const historyEntries = Object.entries(client.stageHistory)
      .map(([id, date]) => ({ id, date: new Date(date as string) }))
      .sort((a, b) => a.date.getTime() - b.date.getTime());

    if (historyEntries.length === 0) {
      historyEntries.push({ id: STAGES[0].id, date: new Date(client.createdAt) });
    }

    return (
      <div className="space-y-5">
        {historyEntries.map((entry, i) => {
          const s = STAGES.find(st => st.id === entry.id);
          const nextEntry = historyEntries[i+1];
          const isCurrent = entry.id === client.currentStageId;

          const duration = nextEntry 
            ? Math.floor((nextEntry.date.getTime() - entry.date.getTime()) / (1000 * 60 * 60 * 24))
            : Math.floor((new Date().getTime() - entry.date.getTime()) / (1000 * 60 * 60 * 24));

          return (
            <div key={entry.id} className="flex gap-4 relative">
              {i !== historyEntries.length - 1 && (
                <div className="absolute left-[11.5px] top-6 bottom-[-20px] w-[2px] bg-gray-200"></div>
              )}

              <div className={`w-6 h-6 rounded-full flex items-center justify-center shrink-0 z-10 border-2 ${isCurrent ? 'bg-brand-900 border-brand-900 text-gold-400' : 'bg-white border-emerald-500 text-emerald-600'}`}>
                {isCurrent ? <Timer size={12} /> : <CheckCircle2 size={12} />}
              </div>

              <div className="flex-1">
                <div className="flex justify-between items-start">
                  <p className={`text-[11px] font-black uppercase tracking-tight ${isCurrent ? 'text-brand-900' : 'text-gray-700'}`}>
                    {s?.title || 'Etapa Concluída'}
                  </p>
                  <span className="text-[9px] font-black text-gray-500">
                    {entry.date.toLocaleDateString('pt-BR')}
                  </span>
                </div>
                <div className="flex items-center gap-2 mt-1">
                  <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-full border ${isCurrent ? 'bg-brand-50 text-brand-600 border-brand-100' : 'bg-emerald-50 text-emerald-600 border-emerald-100'}`}>
                    {isCurrent ? 'Em andamento' : 'Concluída'}
                  </span>
                  <span className="text-[10px] font-black text-brand-500 uppercase tracking-tighter">
                    • {duration} {duration === 1 ? 'dia' : 'dias'}
                  </span>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="flex flex-col gap-6">
      {/* HEADER DE STATUS COMPACTO */}
      <div className="bg-brand-900 p-6 rounded-[2.5rem] flex flex-col md:flex-row justify-between items-center gap-6 border border-brand-800 shadow-xl">
        <div className="flex items-center gap-5">
