import React, { useState, useEffect } from 'react';
import { Stage, Client } from '../types.ts';
import { generateTemplateContent } from '../services/templateService.ts';
import { Copy, Phone, Zap, Trophy, Clock, CheckCircle2, ArrowRight, History, Star, Calendar, Flag, Timer, TrendingUp, AlertCircle, Info } from 'lucide-react';
import { STAGES } from '../constants.ts';

interface ContentGeneratorProps {
  stage: Stage;
  client: Client;
  onUpdateNotes: (notes: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
}

export const ContentGenerator: React.FC<ContentGeneratorProps> = ({ stage, client, onUpdateNotes, onUpdateClientStage }) => {
  const [fieldValues, setFieldValues] = useState<Record<string, string>>({});
  const [editableBody, setEditableBody] = useState('');

  useEffect(() => {
    setFieldValues(client.stageData || {});
  }, [stage.id, client.id]);

  useEffect(() => {
    const generated = generateTemplateContent(stage, client, { ...client.stageData, ...fieldValues });
    setEditableBody(generated.body);
  }, [fieldValues, stage, client]);

  const calculateMetrics = () => {
    const start = new Date(client.createdAt);
    const deadline = new Date(start);
    deadline.setDate(deadline.getDate() + 120);
    const isCompleted = client.currentStageId === '7';
    const now = isCompleted ? new Date(client.stageHistory['7']) : new Date();
    const totalDays = Math.floor(Math.abs(now.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));

    const slaPercent = Math.min(100, (totalDays / 120) * 100);
    const slaColor = totalDays > 120 ? 'bg-red-600' : totalDays > 75 ? 'bg-amber-500' : 'bg-emerald-600';
    const slaText = totalDays > 120 ? 'URGENTE' : totalDays > 75 ? 'ATENÇÃO' : 'NO PRAZO';

    const stageEntryStr = (client.stageHistory[client.currentStageId] as any) || client.createdAt;
    const stageEntry = new Date(stageEntryStr);
    const daysInStage = Math.floor(Math.abs(new Date().getTime() - stageEntry.getTime()) / (1000 * 60 * 60 * 24));

    let score = 5;
    if (totalDays > 120) score -= 2;
    else if (totalDays > 90) score -= 1;
    if (daysInStage > 20) score -= 1;

    return { 
      totalDays, 
      slaPercent, 
      slaColor, 
      slaText, 
      daysInStage, 
      start: start.toLocaleDateString('pt-BR'), 
      deadline: deadline.toLocaleDateString('pt-BR'),
      score: Math.max(1, score)
    };
  };

  const metrics = calculateMetrics();

  const validateFields = () => {
    if (!stage.requiredFields || stage.requiredFields.length === 0) return true;

    const missingFields = stage.requiredFields.filter(f => !fieldValues[f] || fieldValues[f].trim() === '');
    if (missingFields.length > 0) {
      alert(`Atenção! Você precisa preencher os seguintes campos antes de prosseguir: ${missingFields.join(', ')}`);
      return false;
    }
    return true;
  };

  const handleWhatsApp = () => {
    if (!validateFields()) return;

    const clean = client.phone.replace(/\D/g, '');
    const phoneWithCountry = clean.startsWith('55') ? clean : '55'+clean;
    window.open(`https://api.whatsapp.com/send?phone=${phoneWithCountry}&text=${encodeURIComponent(editableBody)}`, '_blank');
  };

  const handleAdvance = () => {
    if (!validateFields()) return;

    // Atualiza etapa no sistema
    onUpdateClientStage(client.id, stage.id, fieldValues);

    // Dispara WhatsApp AUTOMATICAMENTE após o avanço
    if (stage.template) {
        handleWhatsApp();
    }
  };

  const renderStageHistory = () => {
    const historyEntries = Object.entries(client.stageHistory)
      .map(([id, date]) => ({ id, date: new Date(date as string) }))
      .sort((a, b) => a.date.getTime() - b.date.getTime());

    if (historyEntries.length === 0) {
      historyEntries.push({ id: STAGES[0].id, date: new Date(client.createdAt) });
    }

    return (
      <div className="space-y-5">
        {historyEntries.map((entry, i) => {
          const s = STAGES.find(st => st.id === entry.id);
          const nextEntry = historyEntries[i+1];
          const isCurrent = entry.id === client.currentStageId;

          const duration = nextEntry 
            ? Math.floor((nextEntry.date.getTime() - entry.date.getTime()) / (1000 * 60 * 60 * 24))
            : Math.floor((new Date().getTime() - entry.date.getTime()) / (1000 * 60 * 60 * 24));

          return (
            <div key={entry.id} className="flex gap-4 relative">
              {i !== historyEntries.length - 1 && (
                <div className="absolute left-[11.5px] top-6 bottom-[-20px] w-[2px] bg-gray-200"></div>
              )}

              <div className={`w-6 h-6 rounded-full flex items-center justify-center shrink-0 z-10 border-2 ${isCurrent ? 'bg-brand-900 border-brand-900 text-gold-400' : 'bg-white border-emerald-500 text-emerald-600'}`}>
                {isCurrent ? <Timer size={12} /> : <CheckCircle2 size={12} />}
              </div>

              <div className="flex-1">
                <div className="flex justify-between items-start">
                  <p className={`text-[11px] font-black uppercase tracking-tight ${isCurrent ? 'text-brand-900' : 'text-gray-700'}`}>
                    {s?.title || 'Etapa Concluída'}
                  </p>
                  <span className="text-[9px] font-black text-gray-500">
                    {entry.date.toLocaleDateString('pt-BR')}
                  </span>
                </div>
                <div className="flex items-center gap-2 mt-1">
                  <span className={`text-[8px] font-black uppercase px-2 py-0.5 rounded-full border ${isCurrent ? 'bg-brand-50 text-brand-600 border-brand-100' : 'bg-emerald-50 text-emerald-600 border-emerald-100'}`}>
                    {isCurrent ? 'Em andamento' : 'Concluída'}
                  </span>
                  <span className="text-[10px] font-black text-brand-500 uppercase tracking-tighter">
                    • {duration} {duration === 1 ? 'dia' : 'dias'}
                  </span>
                </div>
              </div>
            </div>
          );
        })}
      </div>
    );
  };

  return (
    <div className="flex flex-col gap-6">
      {/* HEADER DE STATUS COMPACTO */}
      <div className="bg-brand-900 p-6 rounded-[2.5rem] flex flex-col md:flex-row justify-between items-center gap-6 border border-brand-800 shadow-xl">
        <div className="flex items-center gap-5">
           <div className="bg-brand-800/80 p-4 rounded-[1.8rem] border border-brand-700 shadow-inner">
              <Zap size={24} className="text-gold-400 fill-current" />
           </div>
           <div>
              <div className="flex items-center gap-3">
                <h2 className="text-lg font-black text-white uppercase tracking-tight">Etapa {stage.stepNumber}: {stage.title}</h2>
                <span className={`px-3 py-1 rounded-full text-[9px] font-black text-white tracking-widest shadow-lg ${metrics.slaColor}`}>
                  {metrics.slaText}
                </span>
              </div>
              <p className="text-brand-300 text-[10px] font-bold uppercase tracking-[0.2em] mt-1 opacity-70">{stage.description}</p>
           </div>
        </div>

        <div className="flex items-center gap-8 bg-black/20 px-8 py-4 rounded-[2rem] border border-white/5">
           <div className="text-center">
             <p className="text-[8px] font-black text-brand-400 uppercase mb-1 tracking-widest">Jornada Total</p>
             <p className="text-xl font-black text-white leading-none">{metrics.totalDays} dias</p>
           </div>
           <div className="w-px h-8 bg-white/10"></div>
           <div className="text-center">
             <p className="text-[8px] font-black text-brand-400 uppercase mb-1 tracking-widest">Nesta Etapa</p>
             <p className="text-xl font-black text-gold-400 leading-none">{metrics.daysInStage} dias</p>
           </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 items-start">
        {/* SIDEBAR: INFO & MÉTRICAS (STICKY) */}
        <aside className="lg:col-span-4 flex flex-col gap-6 lg:sticky lg:top-[100px]">

          {/* Score Card */}
          <div className="bg-white p-6 rounded-[2.5rem] border border-gray-200 shadow-sm">
             <div className="flex justify-between items-center mb-6">
                <div>
                  <h3 className="text-[11px] font-black text-brand-900 uppercase tracking-widest flex items-center gap-2">
                    <Star size={16} className="text-gold-500 fill-current" /> Equipe Loop
                  </h3>
                  <p className="text-[9px] font-bold text-gray-400 uppercase mt-1">Score de Eficiência</p>
                </div>
                <div className="text-right">
                   <span className="text-2xl font-black text-brand-900 leading-none">{metrics.score.toFixed(1)}</span>
                </div>
             </div>
             <div className="flex justify-center gap-2 py-4 bg-gray-50 rounded-3xl border border-gray-100 mb-2">
                {[1,2,3,4,5].map(s => (
                  <Star key={s} size={24} fill={s <= metrics.score ? "#dbb832" : "transparent"} className={s <= metrics.score ? "text-gold-500" : "text-gray-200"} />
                ))}
             </div>
          </div>

          {/* Saúde do Projeto */}
          <div className="bg-white p-6 rounded-[2.5rem] border border-gray-200 shadow-sm space-y-5">
            <h3 className="text-[11px] font-black text-brand-900 uppercase tracking-widest flex items-center gap-2">
              <Timer size={16} className="text-brand-600" /> SLA & Prazos
            </h3>
            <div className="space-y-2">
               <div className="flex justify-between text-[10px] font-black uppercase text-gray-500">
                  <span>SLA 120 dias</span>
                  <span className={metrics.totalDays > 120 ? 'text-red-600' : 'text-brand-600'}>{metrics.totalDays}d consumidos</span>
               </div>
               <div className="h-4 w-full bg-gray-100 rounded-full overflow-hidden border border-gray-100">
                  <div className={`h-full transition-all duration-1000 shadow-inner ${metrics.slaColor}`} style={{ width: `${metrics.slaPercent}%` }}></div>
               </div>
            </div>
            <div className="grid grid-cols-2 gap-3">
               <div className="bg-gray-50 p-4 rounded-2xl border border-gray-100 text-center">
                  <p className="text-[8px] font-black text-gray-400 uppercase mb-1">Início</p>
                  <p className="text-[11px] font-black text-brand-900">{metrics.start}</p>
               </div>
               <div className="bg-brand-50 p-4 rounded-2xl border border-brand-100 text-center">
                  <p className="text-[8px] font-black text-gray-600 uppercase mb-1">Meta</p>
                  <p className="text-[11px] font-black text-brand-900">{metrics.deadline}</p>
               </div>
            </div>
          </div>

          {/* Histórico Corrigido & Nítido */}
          <div className="bg-white p-8 rounded-[2.5rem] border border-gray-200 shadow-sm">
            <h3 className="text-[11px] font-black text-brand-900 uppercase tracking-widest flex items-center gap-2 mb-8 border-b border-gray-50 pb-5">
               <History size={18} className="text-brand-500" /> Histórico
            </h3>
            {renderStageHistory()}
          </div>
        </aside>

        {/* ÁREA DE CONTEÚDO (MENSAGENS & CAMPOS) */}
        <main className="lg:col-span-8 flex flex-col gap-6">

          <div className="bg-white p-8 rounded-[3rem] border border-gray-200 shadow-sm space-y-10">
            {/* Inputs de Dados */}
            {stage.requiredFields && stage.requiredFields.length > 0 && (
              <section>
                 <div className="flex items-center gap-2 mb-6">
                    <TrendingUp size={18} className="text-brand-600" />
                    <h3 className="text-[12px] font-black text-brand-900 uppercase tracking-widest">Informações Necessárias</h3>
                 </div>
                 <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                    {stage.requiredFields.map(f => (
                      <div key={f}>
                         <label className="text-[10px] font-black uppercase text-gray-500 mb-2 block ml-1 tracking-widest">{f}</label>
                         <input 
                           className="w-full p-5 bg-gray-50 border-2 border-gray-100 rounded-2xl text-[15px] font-bold outline-none focus:bg-white focus:border-brand-500 transition-all" 
                           value={fieldValues[f] || ''} 
                           onChange={e => setFieldValues({...fieldValues, [f]: e.target.value})} 
                           placeholder={`Valor para ${f}`}
                         />
                      </div>
                    ))}
                 </div>
              </section>
            )}

            {/* Preview da Mensagem */}
            <section className="flex flex-col gap-4">
               <div className="flex items-center justify-between mb-2">
                  <div className="flex items-center gap-2">
                     <div className="bg-brand-50 text-brand-600 p-2 rounded-xl"><MessageSquareIcon size={18} /></div>
                     <h3 className="text-[12px] font-black text-brand-900 uppercase tracking-widest">Preview WhatsApp</h3>
                  </div>
                  <button 
                     onClick={() => {
                       navigator.clipboard.writeText(editableBody);
                       alert('Copiado!');
                     }} 
                     className="flex items-center gap-2 px-6 py-2.5 bg-gray-50 hover:bg-brand-50 text-brand-700 rounded-xl text-[10px] font-black uppercase tracking-widest border border-gray-200 transition-all active:scale-95"
                  >
                    <Copy size={16} /> Copiar
                  </button>
               </div>

               <div className="bg-gray-50/50 rounded-[2.5rem] border-2 border-dashed border-gray-200 p-8 min-h-[300px] relative">
                  <div className="absolute top-6 right-8 text-[8px] font-black text-gray-300 uppercase tracking-[0.4em]">LOOP GEV</div>
                  <div className="text-slate-800 text-[16px] font-medium leading-relaxed whitespace-pre-wrap font-sans">
                    {editableBody || <span className="text-gray-300 italic">Etapa sem template de mensagem.</span>}
                  </div>
               </div>
            </section>

            {/* Ações Finais */}
            <footer className="grid grid-cols-1 md:grid-cols-2 gap-6 pt-6 border-t border-gray-100">
               <button 
                 onClick={handleWhatsApp} 
                 className="py-6 bg-[#25D366] text-white rounded-[2rem] font-black uppercase tracking-widest text-[13px] flex items-center justify-center gap-4 shadow-xl hover:shadow-green-500/30 hover:scale-[1.01] transition-all"
               >
                 <Phone size={22} fill="currentColor" /> Enviar Mensagem
               </button>

               {stage.id !== client.currentStageId ? (
                 <button 
                   onClick={handleAdvance} 
                   className="py-6 bg-brand-900 text-white rounded-[2rem] font-black uppercase tracking-widest text-[13px] flex items-center justify-center gap-4 shadow-xl hover:bg-black hover:scale-[1.01] transition-all"
                 >
                   Avançar Etapa <ArrowRight size={22} />
                 </button>
               ) : (
                 <div className="bg-emerald-50 border-2 border-emerald-100 rounded-[2rem] flex items-center justify-center gap-4 text-emerald-700 font-black uppercase text-[12px] tracking-widest">
                   <CheckCircle2 size={24} /> Etapa Vigente
                 </div>
               )}
            </footer>
          </div>
        </main>
      </div>
    </div>
  );
};

const MessageSquareIcon = ({ size }: any) => (
  <svg width={size} height={size} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
    <path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z" />
  </svg>
);

import React, { useState } from 'react';
import { Client, Stage } from '../types.ts';
import { Plus, Search, User, Zap, List, Kanban, X, ChevronRight, Clock, Trash2, Edit3, CalendarDays, ArrowRightLeft, CheckCircle2, Star, Timer, CheckCircle, Trophy, Phone, Hash, Calendar } from 'lucide-react';
import { STAGES, STEP_ICONS } from '../constants.ts';
import { generateTemplateContent } from '../services/templateService.ts';

interface ClientListProps {
  clients: Client[];
  onSelectClient: (client: Client) => void;
  onCreateClient: (client: Client) => void;
  onEditClient: (client: Client) => void;
  onDeleteClient: (clientId: string) => void;
  onUpdateClientStage: (clientId: string, newStageId: string, stageData?: Record<string, string>) => void;
  isAdmin?: boolean;
}

type FilterStatus = 'ativos' | 'entregues' | 'noprazo' | 'atencao' | 'urgente' | null;

interface PendingTransition {
  client: Client;
  targetStage: Stage;
  fieldValues: Record<string, string>;
}

export const ClientList: React.FC<ClientListProps> = ({ clients, onSelectClient, onCreateClient, onEditClient, onDeleteClient, onUpdateClientStage, isAdmin = true }) => {
  const [isCreating, setIsCreating] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'list' | 'pipeline'>('list'); 
  const [statusFilter, setStatusFilter] = useState<FilterStatus>(null);
  const [dragOverStageId, setDragOverStageId] = useState<string | null>(null);
  const [pendingTransition, setPendingTransition] = useState<PendingTransition | null>(null);

  const [formData, setFormData] = useState<Partial<Client>>({
    name: '', clientNumber: '', prgd: '', phone: '',
  });

  const formatPhone = (value: string) => {
    if (!value) return "";
    value = value.replace(/\D/g, "");
    value = value.substring(0, 11);
    if (value.length > 10) return value.replace(/^(\d{2})(\d{5})(\d{4}).*/, "($1) $2-$3");
    if (value.length > 5) return value.replace(/^(\d{2})(\d{4})(\d{0,4}).*/, "($1) $2-$3");
    if (value.length > 2) return value.replace(/^(\d{2})(\d{0,5})/, "($1) $2");
    return value.replace(/^(\d*)/, "($1");
  };

  const formatPRGD = (value: string) => {
    if (!value) return "";
    value = value.replace(/\D/g, "");
    value = value.substring(0, 5);
    if (value.length > 3) return value.replace(/^(\d{3})(\d{0,2})/, "$1-$2");
    return value;
  };

  const calculateDaysElapsed = (startStr: string, endStr?: string) => {
    if (!startStr) return 0;
    const start = new Date(startStr);
    const end = endStr ? new Date(endStr) : new Date();
    return Math.floor(Math.abs(end.getTime() - start.getTime()) / (1000 * 60 * 60 * 24));
  };

  const getStatusInfo = (days: number, isDelivered: boolean) => {
    if (isDelivered) return { label: '🟢 ENTREGUE', color: 'text-green-600', bg: 'bg-green-50', dot: 'bg-green-500', key: 'entregues' };
    if (days > 120) return { label: '🔴 URGENTE', color: 'text-red-600', bg: 'bg-red-50', dot: 'bg-red-500', key: 'urgente' };
    if (days > 75) return { label: '🟡 ATENÇÃO', color: 'text-amber-500', bg: 'bg-amber-50', dot: 'bg-amber-500', key: 'atencao' };
    return { label: '🟢 NO PRAZO', color: 'text-emerald-600', bg: 'bg-emerald-50', dot: 'bg-emerald-500', key: 'noprazo' };
  };

  const counts = clients.reduce((acc, c) => {
    const isDelivered = c.currentStageId === '7';
    const days = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);
    const info = getStatusInfo(days, isDelivered);

    if (!isDelivered) acc.ativos++;
    acc[info.key as 'entregues' | 'urgente' | 'atencao' | 'noprazo']++;
    return acc;
  }, { ativos: 0, entregues: 0, noprazo: 0, atencao: 0, urgente: 0 });

  const filteredClients = clients.filter(c => {
    const matchesSearch = c.name.toLowerCase().includes(searchTerm.toLowerCase()) || c.prgd.toLowerCase().includes(searchTerm.toLowerCase());
    if (!matchesSearch) return false;
    if (!statusFilter) return true;
    const isDelivered = c.currentStageId === '7';
    const days = calculateDaysElapsed(c.createdAt, isDelivered ? c.stageHistory['7'] : undefined);
    const info = getStatusInfo(days, isDelivered);
    if (statusFilter === 'ativos') return !isDelivered;
    return info.key === statusFilter;
  });

  const triggerWhatsApp = (client: Client, stage: Stage, additionalData: Record<string, string> = {}) => {
    if (!client.phone) return;
    const combinedData = { ...(client.stageData || {}), ...additionalData };
    const generated = generateTemplateContent(stage, client, combinedData);
    const cleanPhone = client.phone.replace(/\D/g, '');
    const phoneWithCountry = cleanPhone.startsWith('55') ? cleanPhone : `55${cleanPhone}`;
    window.open(`https://api.whatsapp.com/send?phone=${phoneWithCountry}&text=${encodeURIComponent(generated.body)}`, '_blank');
  };

  // FUNÇÃO DE DROP CORRIGIDA
  const onDropClient = (e: React.DragEvent, stageId: string) => {
    e.preventDefault();
    const clientId = e.dataTransfer.getData("clientId");
    setDragOverStageId(null);

    if (clientId && isAdmin) {
      const client = clients.find(c => c.id === clientId);
      const targetStage = STAGES.find(s => s.id === stageId);

      if (client && targetStage) {
        if (client.currentStageId === stageId) return;

        // Verifica campos obrigatórios (Especialmente Etapa 3)
        const missingFields = (targetStage.requiredFields || []).filter(f => !client.stageData?.[f]);

        if (missingFields.length > 0) {
          setPendingTransition({ 
            client, 
            targetStage, 
            fieldValues: missingFields.reduce((acc, f) => ({ ...acc, [f]: '' }), {}) 
          });
        } else {
          // Muda etapa e dispara WhatsApp AUTOMATICAMENTE
          onUpdateClientStage(clientId, stageId);
          if (targetStage.template) {
             triggerWhatsApp(client, targetStage);
          }
        }
      }
    }
  };

  const handleConfirmTransition = () => {
    if (!pendingTransition) return;

    const missing = Object.values(pendingTransition.fieldValues).some(v => !v || (v as string).trim() === '');
    if (missing) {
      alert("Por favor, preencha todos os campos obrigatórios.");
      return;
    }

    // 1. Atualiza no sistema
    onUpdateClientStage(pendingTransition.client.id, pendingTransition.targetStage.id, pendingTransition.fieldValues);

    // 2. Dispara WhatsApp IMEDIATAMENTE após confirmação (Etapa 3 incluída)
    if (pendingTransition.targetStage.template) {
      triggerWhatsApp(pendingTransition.client, pendingTransition.targetStage, pendingTransition.fieldValues);
    }

    setPendingTransition(null);
  };

  return (
    <div className="bg-white rounded-[2.5rem] shadow-sm border border-gray-200 h-full flex flex-col relative overflow-hidden">

      {/* Modal de Validação Etapa 3 / Campos Obrigatórios */}
      {pendingTransition && (
        <div className="fixed inset-0 bg-brand-900/70 backdrop-blur-md z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-[3rem] shadow-2xl w-full max-w-md overflow-hidden p-10 border border-white/20 animate-in zoom-in duration-300">
            <div className="bg-amber-50 p-4 rounded-2xl mb-6 flex items-center gap-3 border border-amber-100">
              <CalendarDays className="text-amber-600" size={24} />
              <h2 className="text-lg font-black text-brand-900 uppercase tracking-tighter">Dados de Entrega</h2>
            </div>
            <p className="text-[11px] text-gray-500 font-bold uppercase mb-8 tracking-widest">A etapa <span className="text-brand-600">{pendingTransition.targetStage.title}</span> exige o preenchimento da data prevista para avisar o cliente:</p>
            <div className="space-y-6">
              {Object.keys(pendingTransition.fieldValues).map(f => (
                <div key={f}>
                  <label className="text-[10px] font-black uppercase text-gray-400 block mb-2 ml-1">{f}</label>
                  <input 
                    autoFocus 
                    className="w-full p-5 bg-gray-50 border-2 border-gray-100 rounded-2xl font-black text-brand-900 outline-none focus:border-brand-500 focus:bg-white transition-all" 
                    value={pendingTransition.fieldValues[f]} 
                    onChange={e => setPendingTransition({...pendingTransition, fieldValues: {...pendingTransition.fieldValues, [f]: e.target.value}})} 
                    placeholder="Ex: 25/12/2024" 
                  />
                </div>
              ))}
            </div>
            <div className="flex gap-4 mt-10">
              <button onClick={() => setPendingTransition(null)} className="flex-1 bg-gray-100 text-gray-500 py-5 rounded-[2rem] font-black uppercase tracking-widest text-[10px] hover:bg-gray-200 transition-all">Cancelar</button>
              <button onClick={handleConfirmTransition} className="flex-[2] bg-brand-900 text-white py-5 rounded-[2rem] font-black uppercase tracking-widest text-[10px] shadow-xl hover:bg-black transition-all">Confirmar e Enviar</button>
            </div>
          </div>
        </div>
      )}

      {isCreating && (
          <div className="fixed inset-0 bg-brand-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-4">
              <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-xl overflow-hidden p-8 border border-white/20">
                  <div className="flex justify-between items-center mb-8">
                      <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter">Novo Cadastro</h2>
                      <button onClick={() => setIsCreating(false)} className="p-2 text-gray-400 hover:text-red-500 transition-colors"><X size={24} /></button>
                  </div>
                  <form onSubmit={(e) => { e.preventDefault(); onCreateClient({ id: Date.now().toString(), name: formData.name!, clientNumber: formData.clientNumber || '', prgd: formData.prgd!, phone: formData.phone!, projectName: '', additionalNotes: '', currentStageId: STAGES[0].id, createdAt: new Date().toISOString(), stageHistory: {}, stageData: {} }); setIsCreating(false); setFormData({}); }} className="space-y-6">
                      <div>
                        <label className="text-[10px] font-black uppercase text-brand-900 block mb-2 tracking-widest">Titular do Projeto</label>
                        <input required className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl font-bold outline-none focus:bg-white" placeholder="Nome Completo" value={formData.name} onChange={e => setFormData({...formData, name: e.target.value})} />
                      </div>
                      <div className="grid grid-cols-2 gap-4">
                        <div>
                          <label className="text-[10px] font-black uppercase text-brand-900 block mb-2 tracking-widest">WhatsApp</label>
                          <input required className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl font-bold outline-none focus:bg-white" placeholder="(00) 00000-0000" value={formData.phone} onChange={e => setFormData({...formData, phone: formatPhone(e.target.value)})} />
                        </div>
                        <div>
                          <label className="text-[10px] font-black uppercase text-brand-900 block mb-2 tracking-widest">Nº PRGD</label>
                          <input required className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl font-bold outline-none focus:bg-white" placeholder="000-00" value={formData.prgd} onChange={e => setFormData({...formData, prgd: formatPRGD(e.target.value)})} />
                        </div>
                      </div>
                      <div>
                          <label className="text-[10px] font-black uppercase text-brand-900 block mb-2 tracking-widest">Nº do Cliente (Opcional)</label>
                          <input className="w-full p-4 bg-gray-50 border border-gray-200 rounded-2xl font-bold outline-none focus:bg-white" placeholder="0000000" value={formData.clientNumber} onChange={e => setFormData({...formData, clientNumber: e.target.value})} />
                      </div>
                      <button type="submit" className="w-full bg-brand-600 text-white py-5 rounded-[2rem] font-black uppercase tracking-widest text-xs shadow-xl hover:bg-brand-700 transition-all mt-4">SALVAR E INICIAR JORNADA</button>
                  </form>
              </div>
          </div>
      )}

      {/* FILTROS DE STATUS */}
      <div className="p-6 border-b flex flex-col gap-6 bg-gray-50/50">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <div>
                <h2 className="text-2xl font-black text-brand-600 uppercase tracking-tighter leading-tight">Gestão de Carteira</h2>
                <div className="flex flex-wrap items-center gap-2 mt-2">
                    <button onClick={() => setStatusFilter(statusFilter === 'ativos' ? null : 'ativos')} className={`text-[9px] font-black px-4 py-2 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'ativos' ? 'bg-brand-600 text-white shadow-md' : 'bg-white text-brand-600 border-brand-100 hover:border-brand-300'}`}>
                      {counts.ativos} Ativos
                    </button>
                    <button onClick={() => setStatusFilter(statusFilter === 'entregues' ? null : 'entregues')} className={`text-[9px] font-black px-4 py-2 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'entregues' ? 'bg-green-600 text-white shadow-md' : 'bg-white text-green-600 border-green-100 hover:border-green-300'}`}>
                      {counts.entregues} Entregues
                    </button>
                    <div className="h-4 w-px bg-gray-200 mx-2"></div>
                    <button onClick={() => setStatusFilter(statusFilter === 'noprazo' ? null : 'noprazo')} className={`text-[9px] font-black px-4 py-2 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'noprazo' ? 'bg-emerald-600 text-white shadow-md' : 'bg-white text-emerald-600 border-emerald-100 hover:border-emerald-300'}`}>
                      {counts.noprazo} No Prazo
                    </button>
                    <button onClick={() => setStatusFilter(statusFilter === 'atencao' ? null : 'atencao')} className={`text-[9px] font-black px-4 py-2 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'atencao' ? 'bg-amber-500 text-white shadow-md' : 'bg-white text-amber-500 border-amber-100 hover:border-amber-300'}`}>
                      {counts.atencao} Atenção
                    </button>
                    <button onClick={() => setStatusFilter(statusFilter === 'urgente' ? null : 'urgente')} className={`text-[9px] font-black px-4 py-2 rounded-full uppercase tracking-widest border transition-all ${statusFilter === 'urgente' ? 'bg-red-600 text-white shadow-md' : 'bg-white text-red-600 border-red-100 hover:border-red-300'}`}>
                      {counts.urgente} Urgente
                    </button>
                </div>
            </div>

            <div className="flex bg-gray-100 p-1 rounded-2xl border border-gray-200">
                <button onClick={() => setViewMode('list')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'list' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-400'}`}>
                    <List size={14} /> Lista
                </button>
                <button onClick={() => setViewMode('pipeline')} className={`flex items-center gap-2 px-4 py-2 rounded-xl text-[10px] font-black uppercase transition-all ${viewMode === 'pipeline' ? 'bg-white text-brand-600 shadow-sm' : 'text-gray-400'}`}>
                    <Kanban size={14} /> Pipeline
                </button>
            </div>
        </div>

        <div className="flex flex-col md:flex-row gap-4">
            <div className="relative flex-1">
                <Search className="absolute left-4 top-3.5 text-gray-300" size={18} />
                <input placeholder="Filtrar por nome ou PRGD..." className="w-full pl-12 p-3.5 rounded-2xl border bg-white outline-none focus:border-brand-300 font-medium text-sm" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} />
            </div>
            {isAdmin && (
              <button onClick={() => setIsCreating(true)} className="bg-brand-600 text-white px-8 py-3.5 rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-brand-700 transition-all flex items-center justify-center gap-2">
                  <Plus size={18} /> Novo Cliente
              </button>
            )}
        </div>
      </div>

      <div className="flex-1 overflow-hidden bg-gray-100/30">
        {viewMode === 'list' ? (
          <div className="p-6 overflow-auto h-full scrollbar-hide">
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8 pb-12">
                {filteredClients.map(client => (
                    <div key={client.id} onClick={() => onSelectClient(client)}>
                       <ClientCardItem 
                          client={client} 
                          isAdmin={isAdmin}
                          calculateDays={calculateDaysElapsed}
                          getStatus={getStatusInfo}
                          onDelete={() => onDeleteClient(client.id)}
                       />
                    </div>
                ))}
            </div>
          </div>
        ) : (
          <div className="flex overflow-x-auto h-full p-6 gap-6 snap-x custom-scroll">
            {STAGES.map(stage => {
              const stageClients = filteredClients.filter(c => c.currentStageId === stage.id);
              const Icon = STEP_ICONS[stage.stepNumber] || Zap;
              const isOver = dragOverStageId === stage.id;

              return (
                <div 
                  key={stage.id} 
                  className={`min-w-[320px] flex flex-col h-full snap-start transition-all`}
                  onDragOver={(e) => { 
                    e.preventDefault(); 
                    if (isAdmin) setDragOverStageId(stage.id); 
                  }}
                  onDragLeave={() => setDragOverStageId(null)}
                  onDrop={(e) => onDropClient(e, stage.id)}
                >
                  <div className="flex items-center justify-between mb-4 px-2">
                    <div className="flex items-center gap-3">
                        <div className="bg-brand-900 text-gold-400 p-2.5 rounded-xl border border-brand-800"><Icon size={16} /></div>
                        <h3 className="text-[11px] font-black uppercase text-brand-900 tracking-tight">{stage.title}</h3>
                    </div>
                    <span className="text-[10px] font-black text-brand-600 bg-brand-50 px-2.5 py-1 rounded-full">{stageClients.length}</span>
                  </div>

                  <div className={`flex-1 overflow-y-auto space-y-4 p-3 rounded-[2.5rem] bg-gray-100/60 transition-all border-2 ${isOver ? 'border-brand-500 border-dashed bg-brand-50/50 scale-[1.01]' : 'border-transparent'} custom-scroll`}>
                    {stageClients.map(client => {
                        const days = calculateDaysElapsed(client.createdAt);
                        const isDelivered = client.currentStageId === '7';
                        const status = getStatusInfo(days, isDelivered);
                        return (
                          <div 
                            key={client.id} 
                            draggable={isAdmin} 
                            onDragStart={(e) => {
                              if (isAdmin) {
                                e.dataTransfer.setData("clientId", client.id);
                                e.dataTransfer.effectAllowed = "move";
                              }
                            }}
                            onClick={() => onSelectClient(client)} 
                            className={`bg-white p-5 rounded-[2.2rem] border-2 shadow-sm hover:shadow-xl transition-all cursor-grab active:cursor-grabbing group relative overflow-hidden ${days > 120 ? 'border-red-100' : days > 75 ? 'border-amber-100' : 'border-white'}`}
                          >
                             <div className="flex justify-between items-start mb-2">
                               <h4 className="font-black text-brand-900 uppercase text-[11px] truncate w-full group-hover:text-brand-600 transition-colors">{client.name}</h4>
                               {isAdmin && <Trash2 size={12} className="text-gray-200 hover:text-red-500 transition-all opacity-0 group-hover:opacity-100" onClick={(e) => { e.stopPropagation(); if(confirm('Excluir?')) onDeleteClient(client.id); }} />}
                             </div>
                             <div className="flex justify-between items-center mt-3 pt-3 border-t border-gray-50">
                                <span className="text-[8px] font-black text-gray-400 uppercase tracking-widest">PRGD: {client.prgd || '---'}</span>
                                <div className={`text-[8px] font-black px-2 py-0.5 rounded-full border ${status.color} ${status.bg} border-current`}>
                                   {status.label.replace(/🟢|🟡|🔴/g, '').trim()}
                                </div>
                             </div>
                          </div>
                        );
                    })}
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

