                    <div className="flex flex-col">
                        <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-0.5">Etapa do Processo</span>
                        <span className="text-[15px] font-black text-brand-900 uppercase truncate max-w-[200px] tracking-tight">{currentStage?.title}</span>
                    </div>
