                    <button onClick={(e) => { e.stopPropagation(); if(confirm("Deseja realmente excluir este cliente?")) onDelete(); }} className="p-3 bg-gray-50 hover:bg-red-600 text-gray-400 hover:text-white rounded-[1.2rem] transition-all shadow-sm">
                      <Trash2 size={18}/>
