                  )}
                  {ref.status !== 'converted' && ref.status !== 'lost' && (
                    <button onClick={() => updateStatus(ref.id, 'lost')} title="Não Convertido" className="p-3 bg-red-50 text-red-600 hover:bg-red-100 rounded-xl transition-all border border-red-100">
                      <XCircle size={18} />
